int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick numbers of the form 2*k where k is odd.
        // Or more simply, pick numbers starting from 4n and decrement by 2.
        // This ensures all numbers are even, so gcd(a,b) >= 2.
        // Also, by picking numbers far apart, we avoid divisibility.
        // Specifically, picking numbers from 4n down to 2n+2 (all even)
        // will give n numbers.
        // Example: n=2, range 1 to 8. Pick 8, 6.
        // Example: n=3, range 1 to 12. Pick 12, 10, 8.
        // Example: n=4, range 1 to 16. Pick 16, 14, 12, 10.
        // Let's verify this strategy.
        // All numbers are even, so gcd(a,b) >= 2. Condition 1 is satisfied.
        // For divisibility:
        // Let the chosen numbers be C = {2k, 2(k-1), ..., 2(k-n+1)}
        // where 2k = 4n, so k = 2n.
        // The set is {4n, 4n-2, 4n-4, ..., 4n-2(n-1)} = {4n, 4n-2, ..., 2n+2}.
        // Let a = 2x and b = 2y be two numbers from this set, with a > b.
        // So 2n+2 <= b < a <= 4n.
        // If a divides b, then 2x divides 2y, which means x divides y.
        // But a > b implies x > y. If x divides y and x > y, this is only possible if y=0, which is not the case.
        // So a cannot divide b.
        // If b divides a, then 2y divides 2x, which means y divides x.
        // We have 2n+2 <= 2y < 2x <= 4n.
        // So n+1 <= y < x <= 2n.
        // If y divides x, then x = m * y for some integer m.
        // Since x > y, m must be >= 2.
        // So x >= 2y.
        // But we know x <= 2n and y >= n+1.
        // If x >= 2y, then x >= 2(n+1) = 2n+2.
        // This contradicts x <= 2n.
        // Therefore, y cannot divide x.
        // This strategy works.

        for (int i = 0; i < n; ++i) {
            std::cout << 4 * n - 2 * i << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        }
    }

    // To maximize the number, we want as many '1's as possible, then '0's.
    // Each '1' uses 'o', 'n', 'e'.
    // Each '0' uses 'z', 'e', 'r', 'o'.

    // First, determine the number of '1's we can form.
    // 'n' is unique to 'one'.
    // 'z' is unique to 'zero'.
    int num_ones = count_n; // Each 'n' can only be used for a '1'.

    // After forming 'num_ones' '1's, we use up 'num_ones' 'o's and 'num_ones' 'e's.
    count_o -= num_ones;
    count_e -= num_ones;

    // Now, determine the number of '0's we can form from the remaining letters.
    // Each '0' requires 'z', 'e', 'r', 'o'.
    int num_zeros = 0;
    if (count_z > 0 && count_e > 0 && count_r > 0 && count_o > 0) {
        num_zeros = std::min({count_z, count_e, count_r, count_o});
    }

    // Print '1's
    for (int i = 0; i < num_ones; ++i) {
        std::cout << "1";
        if (i < num_ones - 1 || num_zeros > 0) {
            std::cout << " ";
        }
    }

    // Print '0's
    for (int i = 0; i < num_zeros; ++i) {
        std::cout << "0";
        if (i < num_zeros - 1) {
            std::cout << " ";
        }
    }
    std::cout << std::endl;

    return 0;
}

