#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it matches naturally.
            // Update has_pos_one/has_neg_one for elements to its left.
            if (a[i] == 1) has_pos_one = true;
            if (a[i] == -1) has_neg_one = true;
            continue;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) { // Cannot increase if no '1' is available to its left
                possible = false;
                break;
            }
        } else { // a[i] > b[i], Need to decrease a[i]
            if (!has_neg_one) { // Cannot decrease if no '-1' is available to its left
                possible = false;
                break;
            }
        }

        // If a[i] is 1 or -1, it can be used by elements to its left.
        // But its value is now effectively b[i], which might not be 1 or -1.
        // The problem states "Add a_i to a_j". The a_i here refers to the *original* a_i.
        // No, the problem states "j-th element of the array becomes equal to a_i + a_j".
        // This implies a_i is the *current* value of a_i.
        // However, the crucial observation is that a_i for i < j is never modified by operations on a_j.
        // So, when we consider a_j, the values a_1, ..., a_{j-1} are fixed at their initial values.
        // This means the `has_pos_one` and `has_neg_one` flags should reflect the *initial* values of a[k] for k < i.
        // The current loop iterates from right to left.
        // When processing a[i], `has_pos_one` and `has_neg_one` should reflect if there's a 1 or -1 in a[0...i-1].
        // So, we should update these flags *after* processing a[i] and before moving to a[i-1].
        // The flags `has_pos_one` and `has_neg_one` are correctly maintained for elements to the *left* of the current `i`.
        // When we are at index `i`, `a[i]` itself is not available to modify `a[i]`.
        // The flags `has_pos_one` and `has_neg_one` should track if there's a 1 or -1 in `a[0...i-1]`.
        // The current logic for `has_pos_one` and `has_neg_one` is correct because it tracks elements from `a[0]` to `a[i-1]`.
        // When we are at `i`, `a[i]` itself is not yet considered for its contribution to `has_pos_one` or `has_neg_one` for `a[i-1]`.
        // The flags are updated *after* checking `a[i]` against `b[i]`.
        // So, when we check `a[i]`, `has_pos_one` and `has_neg_one` correctly reflect `a[0...i-1]`.
        // Then, `a[i]`'s original value is added to the pool for `a[0...i-1]` for the next iteration `i-1`.

        // The flags are updated correctly.
        if (a[i] == 1) has_pos_one = true;
        if (a[i] == -1) has_neg_one = true;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

