#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is based on the observation that if p[i] is not n,
        // then there must be some p[j] > p[i], and for that j, min(p[i], p[j]) = p[i].
        // So max_val_in_row would be p[i].
        // If p[i] is n, then for all j, min(p[i], p[j]) = p[j].
        // So max_val_in_row would be max(p[j] for j!=i) which is n-1.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        // If l == r, we need to find any divisor of l (except 1).
        // Since l >= 2, l itself is a divisor.
        // If l is prime, l is the only divisor > 1.
        // If l is composite, it has smaller divisors.
        // The problem asks for *any* answer if multiple exist.
        // The smallest prime factor is always a good candidate.
        // For example, if l=4, 2 is a divisor. If l=6, 2 or 3.
        // The problem statement implies we just need to pick one.
        // The simplest is to pick 2 if l is even, otherwise l itself (if l is prime)
        // or its smallest prime factor.
        // However, the problem asks for the integer that we wrote down the maximum number of times.
        // If l == r, any divisor of l (except 1) is written down exactly once.
        // So any divisor of l (except 1) is a valid answer.
        // The simplest is to return 2 if l is even, otherwise l itself (which is a divisor).
        // But the problem implies we should pick the one that would be chosen if l != r.
        // The logic for l != r will pick 2 if it's the best.
        // If l is odd, 2 is not a divisor.
        // If l is odd, and l=r, then 2 is not a divisor of l.
        // In this case, 3 might be a divisor, or 5, etc.
        // The problem states "If there are multiple answers, print any of them."
        // For l=r, any divisor of l (except 1) is equally valid.
        // The smallest divisor > 1 is usually 2. If l is odd, it's the smallest prime factor of l.
        // For l=r, the count for any divisor d > 1 is 1 if d divides l, and 0 otherwise.
        // So we just need to find *any* divisor of l > 1.
        // Since l >= 2, l itself is a divisor.
        // So, if l == r, l is a valid answer.
        // But the general logic below will handle this.
        // If l=r=19, output 19.
        // If l=r=20, output 2.
        // The general logic for l != r will pick 2 if it's the most frequent.
        // If l=r, and l is even, 2 is a divisor. Count for 2 is 1.
        // Count for l is 1.
        // The general logic will pick 2.
        // If l=r, and l is odd, 2 is not a divisor. Count for 2 is 0.
        // Count for l is 1.
        // The general logic will pick l.
        // So the general logic works for l=r too.
    }

    // The number 2 is the most frequent divisor for most ranges.
    // This is because numbers divisible by 2 occur every 2 integers.
    // Numbers divisible by 3 occur every 3 integers, etc.
    // So, 2 will always have the highest or tied-highest frequency.
