int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_staircase_cells = 0;
        long long k_val = 1; // Represents 2^k - 1 for the number of stairs
        while (true) {
            // Calculate cells for a staircase with (2*k_val - 1) stairs
            // Number of stairs = 2*k_val - 1
            // Cells = (2*k_val - 1) * (2*k_val) / 2 = (2*k_val - 1) * k_val
            // This is the cost for the current staircase.
            // The sequence of costs is:
            // k_val=1: (2*1-1)*1 = 1*1 = 1
            // k_val=2: (2*2-1)*2 = 3*2 = 6
            // k_val=4: (2*4-1)*4 = 7*4 = 28
            // k_val=8: (2*8-1)*8 = 15*8 = 120
            // ...
            long long cost = k_val * (2 * k_val - 1);

            if (x >= cost) {
                x -= cost;
                count++;
                // Next k_val is 2 * current k_val
                // Check for overflow before multiplying
                if (k_val > 1000000000000000000LL / 2) { // Max x is 10^18, so k_val can't exceed 10^18.
                                                         // 2*k_val-1 can be up to 2*10^18.
                                                         // cost = k_val * (2*k_val-1) can be up to 10^18 * (2*10^18) = 2*10^36, which overflows long long.
                                                         // However, we only care if cost <= x.
                                                         // If k_val * (2*k_val-1) > x, we stop.
                                                         // The largest k_val for which cost <= 10^18 is when k_val approx sqrt(10^18/2) approx 0.7 * 10^9.
                                                         // So k_val will not overflow long long.
                    break; // k_val would overflow or cost would be too large
                }
                k_val *= 2;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
