int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_R_pos = -1, it means the frog is at cell 0.
                             // If last_R_pos = k, it means the frog is at cell k.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The previous 'R' or start was at last_R_pos.
                // The gap is (i+1) - (last_R_pos + 1) + 1 = i - last_R_pos.
                // Or, more simply, the distance from last_R_pos to i+1 is (i+1) - last_R_pos.
                max_gap = std::max(max_gap, (i + 1) - (last_R_pos + 1) + 1);
                last_R_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' to n+1.
        // If last_R_pos = -1, it means all characters are 'L'. The frog must jump from 0 to n+1 directly.
        // The distance is (n+1) - 0 = n+1.
        // If last_R_pos = k, the last 'R' was at cell k+1. The frog needs to jump from k+1 to n+1.
        // The distance is (n+1) - (k+1) = n - k.
        max_gap = std::max(max_gap, (n + 1) - (last_R_pos + 1) + 1);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    if (p[0] < 1 || p[0] > n) { // q_1 must be within [1, n]
        possible = false;
    } else {
        used_numbers.insert(p[0]);
    }

    for (int i = 1; i < n; ++i) {
        if (!possible) break;

        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (p[i] < 1 || p[i] > n || used_numbers.count(p[i])) {
                possible = false;
                break;
            }
            used_numbers.insert(p[i]);
        } else { // q[i] == q[i-1]
            // p_i must be some value x such that 1 <= x <= q_i and x is not used.
            // To maximize chances, pick the smallest available number.
            // The smallest available number must be less than q_i.
            // If all numbers less than q_i are used, then it's impossible.
            p[i] = -1; // Placeholder for not found
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Fill in the remaining p_i values where q_i == q_{i-1}
    // Use a min-priority queue or a set to keep track of available numbers efficiently.
    // A set of available numbers is good here.
    std::set<int> available_for_fill;
    for (int i = 1; i <= n; ++i) {
        if (used_numbers.find(i) == used_numbers.end()) {
            available_for_fill.insert(i);
        }
    }

    for (int i = 1; i < n; ++i) {
        if (p[i] == -1) { // This means q[i] == q[i-1]
            // Find the largest available number that is less than or equal to q[i]
            auto it = available_for_fill.upper_bound(q[i]);
            if (it == available_for_fill.begin()) { // No number <= q[i] is available
                possible = false;
                break;
            }
            --it; // This is the largest available number <= q[i]
            p[i] = *it;
            available_for_fill.erase(it);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

