int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // The remaining students are (c - mid) coders, (m - mid) mathematicians, and x unspecialized.
            // Total remaining students: (c - mid) + (m - mid) + x
            // Each team needs 3 members. 'mid' teams need 3 * 'mid' members.
            // We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, we need 'mid' more students to fill the teams (3 * mid - mid - mid = mid).
            // These 'mid' additional students can come from the remaining coders, mathematicians, or unspecialized.
            // The total pool of students available for these 'mid' additional slots is (c - mid) + (m - mid) + x.
            // If this pool is sufficient (i.e., >= mid), then 'mid' teams are possible.
            if ((c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

