int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // (n-1)/2 for 0-indexed array

    // 1. Make the median element equal to s
    operations += std::abs(a[median_idx] - s);
    a[median_idx] = s; // Conceptually change it for subsequent checks

    // 2. Ensure elements to the left of median are <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // 3. Ensure elements to the right of median are >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This will be 'k' in the problem description, but we iterate 'i' and find 'k'

    for (int i = 0; i < n; ++i) {
        // For a fixed x[i], we need to find all x[k] such that x[k] - x[i] <= d.
        // Since x is sorted, we can use a two-pointer approach or std::upper_bound.
        // Let's use a two-pointer approach for efficiency.
        // 'right_ptr' will always be >= 'i'.
        // We want to find the largest index 'k_max' such that x[k_max] - x[i] <= d.
        // All points x[j] where i < j < k_max will form a valid triplet with x[i] and x[k_max].

        // Advance right_ptr until x[right_ptr] - x[i] > d or right_ptr reaches end
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, right_ptr is the first index such that x[right_ptr] - x[i] > d,
        // or right_ptr == n.
        // So, all valid 'k' for the current 'i' are in the range [i+2, right_ptr-1].
        // The number of points available to be 'k' is (right_ptr - 1) - (i + 2) + 1 = right_ptr - i - 2.
        // This is the number of points x[k] such that x[k] - x[i] <= d AND k > i+1.

        // Let's re-evaluate:
        // For a fixed 'i', we are looking for 'j' and 'k' such that i < j < k and x[k] - x[i] <= d.
        // The 'right_ptr' points to the first element *greater* than x[i] + d.
        // So, all elements from x[i+1] up to x[right_ptr-1] satisfy the condition with x[i] as the leftmost point.
        // The number of points in this range (excluding x[i] itself) is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let this count be `num_valid_points_after_i`.
        // These are the points `x[i+1], ..., x[right_ptr-1]`.
        // From these `num_valid_points_after_i` points, we need to choose 2 points to be `x[j]` and `x[k]`.
        // The number of ways to choose 2 points from `m` points is `m * (m - 1) / 2`.
        // Here, `m = right_ptr - 1 - i`.
        // We need at least 2 points after x[i] to form a triplet, so `m >= 2`.
        // This means `right_ptr - 1 - i >= 2`, or `right_ptr - i >= 3`.

        long long m = right_ptr - 1 - i; // Number of points x[p] such that i < p < right_ptr.
                                         // These are potential candidates for j and k.
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<ElementB> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(A.begin(), A.end(), compareElementA);

    // Sort B in ascending order
    std::sort(B.begin(), B.end(), compareElementB);

    // Create the result array
    std::vector<long long> result(m);

    // The optimal strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // However, we need to assign A_i values to the original indices of B_j.
    // So, we iterate through sorted A and sorted B.
    // The largest A[m-1] should be paired with the B_j that has the largest value.
    // The smallest A[0] should be paired with the B_j that has the smallest value.
    // This means A[i] (sorted) should be assigned to the original index of B[i] (sorted).
    for (int i = 0; i < m; ++i) {
        result[B[i].original_index] = A[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

