int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    long long count01 = 0; // count of indices where a[i] = '0' and b[i] = '1'
    long long count10 = 0; // count of indices where a[i] = '1' and b[i] = '0'

    for (int i = 0; i < n; ++i) {
        if (a[i] == '0' && b[i] == '1') {
            count01++;
        } else if (a[i] == '1' && b[i] == '0') {
            count10++;
        }
    }

    // The number of pairs of (0->1, 1->0) that can be swapped
    // is min(count01, count10).
    // Each such swap effectively fixes two positions.
    // The cost of such a swap is 1 (flip at i) + 1 (flip at j) = 2
    // OR |i-j| if we swap.
    // The problem states "Swap any two bits at indices i and j respectively".
    // This means we can swap a '0' from a[i] to a[j] and a '1' from a[j] to a[i].
    // If a[i] = '0', b[i] = '1' and a[j] = '1', b[j] = '0',
    // swapping a[i] and a[j] makes a[i] = '1' and a[j] = '0'.
    // Both positions are fixed. The cost is |i-j|.
    // This is always better than flipping both (cost 2).
    // So, we prioritize swaps.

    // The number of positions that can be fixed by swaps is 2 * min(count01, count10).
    // The remaining positions must be fixed by flips.
    // The remaining count01 positions need to be flipped from '0' to '1'.
    // The remaining count10 positions need to be flipped from '1' to '0'.
    // Each flip costs 1.
    // So, the total cost is min(count01, count10) * 1 (for the swap) + abs(count01 - count10) * 1 (for remaining flips).
    // This simplifies to max(count01, count10).

    // Let's re-evaluate.
    // We have `count01` positions where `a` has '0' and `b` needs '1'.
    // We have `count10` positions where `a` has '1' and `b` needs '0'.

    // Option 1: Fix everything with flips.
    // Total flips needed = count01 + count10. Cost = count01 + count10.

    // Option 2: Use swaps.
    // A swap operation `a[i] <-> a[j]` costs `|i-j|`.
    // If `a[i] = '0'`, `b[i] = '1'` and `a[j] = '1'`, `b[j] = '0'`,
    // then swapping `a[i]` and `a[j]` makes `a[i] = '1'` and `a[j] = '0'`.
    // Both positions `i` and `j` are now correct. Cost `|i-j|`.
    // This is better than two flips (cost 2) if `|i-j| < 2`.
    // If `|i-j| = 1`, cost is 1.
    // If `|i-j| = 0`, this is not a swap.
    // If `|i-j| >= 2`, cost is `|i-j|`.

    // The key insight for this problem is that we can process the string linearly.
    // We maintain counts of `0`s that need to be `1`s (`count01`)
    // and `1`s that need to be `0`s (`count10`).
    // When we encounter a `0` that needs to be `1` (`a[i] = '0'`, `b[i] = '1'`):
    //   If there's a pending `1` that needs to be `0` (`count10 > 0`),
    //   we can "swap" them. This means we take a `1` from some `j < i` (where `a[j] = '1'`, `b[j] = '0'`)
    //   and move it to `i`, and move the `0` from `i` to `j`.
    //   The cost of this swap is `|i-j|`.
    //   However, we don't know `j`.
    //   The problem is simpler: we can either flip a bit or swap two bits.
    //   Consider the state at index `i`.
    //   If `a[i] == b[i]`, nothing to do.
    //   If `a[i] != b[i]`:
    //     Case 1: `a[i] = '0'`, `b[i] = '1'`. We need a '1' here.
    //       If we have a '1' that needs to be '0' from a previous position `j < i` (i.e., `count10 > 0`),
    //       we can "swap" them. This means we take the '1' from `j` and put it at `i`,
    //       and take the '0' from `i` and put it at `j`.
    //       This fixes both `i` and `j`. The cost is `1` (for `|i-j|=1` if `j=i-1`) or `|i-j|` in general.
    //       But the problem is that we don't know `j`.
    //       The crucial observation is that if we have `count01` positions needing '1' and `count10` positions needing '0',
    //       we can pair up `min(count01, count10)` such positions.
    //       For each pair `(i, j)` where `a[i]=0, b[i]=1` and `a[j]=1, b[j]=0`, we can swap `a[i]` and `a[j]`.
    //       This costs `|i-j|`.
    //       The remaining `abs(count01 - count10)` positions must be fixed by flips, each costing 1.
    //       The total cost would be `sum(|i_k - j_k|) + abs(count01 - count10)`.
    //       To minimize `sum(|i_k - j_k|)`, we should pick `i_k` and `j_k` that are close.
    //       This suggests a greedy approach.

    // Let's track the number of '0's that need to be '1's (`zeros_to_ones`)
    // and '1's that need to be '0's (`ones_to_zeros`).
    // Iterate through the string.
    // If `a[i] == '0'` and `b[i] == '1'`:
    //   If `ones_to_zeros > 0`, it means we have a '1' at some previous index `j` that needs to be '0'.
    //   We can swap `a[j]` and `a[i]`. This fixes both. Cost is `1` (for `|i-j|=1`).
    //   Decrement `ones_to_zeros`.
    //   Add `1` to total cost.
    //   Else (`ones_to_zeros == 0`), we just have a '0' that needs to be '1'. Increment `zeros_to_ones`.
    // If `a[i] == '1'` and `b[i] == '0'`:
    //   If `zeros_to_ones > 0`, it means we have a '0' at some previous index `j` that needs to be '1'.
    //   We can swap `a[j]` and `a[i]`. This fixes both. Cost is `1`.
    //   Decrement `zeros_to_ones`.
    //   Add `1` to total cost.
    //   Else (`zeros_to_ones == 0`), we just have a '1' that needs to be '0'. Increment `ones_to_zeros`.

    // This greedy strategy works because a swap of adjacent elements costs 1.
    // If we have `a[i] = '0', b[i] = '1'` and `a[i+1] = '1', b[i+1] = '0'`,
    // swapping `a[i]` and `a[i+1]` costs `|i - (i+1)| = 1`. Both positions are fixed.
    // This is the minimum possible cost for fixing two positions simultaneously.
    // If we have `a[i] = '0', b[i] = '1'` and `a[j] = '1', b[j] = '0'` with `j > i+1`,
    // we could swap them for cost `|i-j|`.
    // Or we could flip `a[i]` (cost 1) and flip `a[j]` (cost 1), total 2.
    // If `|i-j| > 2`, then two flips are better.
    // If `|i-j| = 2`, then two flips are equal.
    // If `|i-j| = 1`, then swap is better (cost 1 vs 2 flips).

    // The problem is that we can swap *any* two bits.
    // This means we can swap `a[i]` and `a[j]` even if they are far apart.
    // The cost is `|i-j|`.
    // If we have `k` pairs of `(0->1, 1->0)` mismatches, we can perform `k` swaps.
    // The remaining `abs(count01 - count10)` mismatches must be fixed by flips.
    // Each flip costs 1. So `abs(count01 - count10)` cost for flips.
    // For the `min(count01, count10)` pairs that can be swapped:
    // We want to minimize `sum |i_p - j_p|` where `p` goes from 1 to `min(count01, count10)`.
    // This is a minimum weight perfect matching problem on a bipartite graph, which is complex.

    // Let's reconsider the example:
    // 3
    // 100
    // 001
    // a[0]=1, b[0]=0  (1->0)
    // a[1]=0, b[1]=0  (match)
    // a[2]=0, b[2]=1  (0->1)
    // count10 = 1 (at index 0)
    // count01 = 1 (at index 2)
    // We have one 1->0 mismatch and one 0->1 mismatch.
    // We can swap a[0] and a[2]. Cost = |0-2| = 2.
    // Result: a becomes 001. Total cost 2.
    // Alternatively, flip a[0] (1->0) cost 1. a becomes 000.
    // Flip a[2] (0->1) cost 1. a becomes 001. Total cost 2.
    // In this case, both options give cost 2.

    // Example 2:
    // 4
    // 0101
    // 0011
    // a[0]=0, b[0]=0 (match)
    // a[1]=1, b[1]=0 (1->0)
    // a[2]=0, b[2]=1 (0->1)
    // a[3]=1, b[3]=1 (match)
    // count10 = 1 (at index 1)
    // count01 = 1 (at index 2)
    // We have one 1->0 mismatch and one 0->1 mismatch.
    // We can swap a[1] and a[2]. Cost = |1-2| = 1.
    // Result: a becomes 0011. Total cost 1.
    // Alternatively, flip a[1] (1->0) cost 1. a becomes 0001.
    // Flip a[2] (0->1) cost 1. a becomes 0011. Total cost 2.
    // Here, swap is better.

    // The crucial observation is that if we have a `0` at `i` that needs to be `1`, and a `1` at `j` that needs to be `0`:
    // 1. We can flip `a[i]` (cost 1) and flip `a[j]` (cost 1). Total cost 2.
    // 2. We can swap `a[i]` and `a[j]` (cost `|i-j|`).
    // If `|i-j| < 2`, swapping is strictly better or equal.
    // If `|i-j| >= 2`, flipping both is better or equal.
    // So, we should only consider swaps for adjacent positions (`|i-j|=1`).
    // For non-adjacent positions, it's always better to flip both.

    // This means we can process the string greedily.
    // We iterate through the string.
    // If `a[i] != b[i]`:
    //   If `a[i] = '0'` and `b[i] = '1'`:
    //     If `i+1 < n` and `a[i+1] = '1'` and `b[i+1] = '0'`:
    //       We can swap `a[i]` and `a[i+1]`. Cost 1. Both fixed.
    //       Increment `cost`. Skip `i+1` in the next iteration.
    //       `i` becomes `i+1` effectively.
    //     Else:
    //       We must flip `a[i]`. Cost 1.
    //       Increment `cost`.
    //   If `a[i] = '1'` and `b[i] = '0'`:
    //     If `i+1 < n` and `a[i+1] = '0'` and `b[i+1] = '1'`:
    //       We can swap `a[i]` and `a[i+1]`. Cost 1. Both fixed.
    //       Increment `cost`. Skip `i+1`.
    //     Else:
    //       We must flip `a[i]`. Cost 1.
    //       Increment `cost`.

    // This greedy strategy is correct.
    // Why? Consider any optimal solution.
    // It consists of some flips and some swaps.
    // Any swap `(i, j)` with `|i-j| > 1` can be replaced by two flips at `i` and `j`
    // if `a[i]` needs to be `b[i]` and `a[j]` needs to be `b[j]` and `a[i]` and `a[j]` are different.
    // The cost of two flips is 2. The cost of swap is `|i-j|`.
    // If `|i-j| > 1`, then `|i-j| >= 2`. So two flips are always better or equal.
    // This means in an optimal solution, all swaps must be between adjacent positions (`|i-j|=1`).
    // If `a[i] = '0', b[i] = '1'` and `a[i+1] = '1', b[i+1] = '0'`,
    // we can swap `a[i]` and `a[i+1]` for cost 1. This fixes both.
    // If we don't swap them, we would have to flip `a[i]` (cost 1) and flip `a[i+1]` (cost 1), total 2.
    // So, it's always optimal to perform an adjacent swap if possible.
    // The greedy strategy does exactly this: it prioritizes adjacent swaps.
    // If an adjacent swap is not possible, it means the current mismatch `a[i] != b[i]` cannot be paired with `a[i+1] != b[i+1]`
    // to form an adjacent swap. In this case, `a[i]` must be flipped.

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            // Mismatch at index i
            if (i + 1 < n && a[i+1] != b[i+1] && a[i] != a[i+1]) {
                // Mismatch at i and i+1, and they are different bits
                // e.g., a[i]=0, b[i]=1 and a[i+1]=1, b[i+1]=0
                // or a[i]=1, b[i]=0 and a[i+1]=0, b[i+1]=1
                // This is exactly the condition for an adjacent swap.
                cost++;
                i++; // Skip next character as it's also fixed
            } else {
                // Cannot perform an adjacent swap, must flip current bit
                cost++;
            }
        }
    }

    std::cout << cost << std::endl;

    return 0;
}

