int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        std::map<char, int> counts;
        for (char ch : s) {
            counts[ch]++;
        }

        char most_frequent_char = ' ';
        int max_count = -1;

        // Iterate in a fixed order to ensure consistent tie-breaking if needed,
        // though for this problem, any tie-breaker works.
        // R, P, S is a common order.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_char = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_char = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_char = 'S';
        }

        // If all counts are 0 (empty string, though n >= 1), this logic still works.
        // If n=1, most_frequent_char will be the single char in s.

        char winning_move;
        if (most_frequent_char == 'R') {
            winning_move = 'P'; // Paper beats Rock
        } else if (most_frequent_char == 'S') {
            winning_move = 'R'; // Rock beats Scissors
        } else { // most_frequent_char == 'P'
            winning_move = 'S'; // Scissors beats Paper
        }

        for (size_t i = 0; i < s.length(); ++i) {
            std::cout << winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;
    int a_ptr_left = 0;
    int a_ptr_right = n - 1;

    // Friends who get w_i = 1 integers
    // These friends should get the largest available integers,
    // as their happiness is 2 * integer.
    // Since w is sorted, these are the first elements in w.
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_right];
            a_ptr_right--;
        } else {
            // All remaining w_i will be > 1
            // Break and handle them in the next loop
            // This relies on w being sorted.
            break;
        }
    }

    // Friends who get w_i > 1 integers
    // These friends should get one largest available integer (for max_val)
    // and one smallest available integer (for min_val).
    // The remaining w_i - 2 integers don't affect max/min, so they can be
    // any other available integers. To maximize sum of min_val, we should
    // give the smallest available integers to these friends.
    // We iterate w in reverse order for w_i > 1 to assign largest max_val first.
    // The largest w_i values will consume more elements from the left.
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_right]; // Max value for this friend
            a_ptr_right--;

            total_happiness += a[a_ptr_left]; // Min value for this friend
            a_ptr_left += (w[i] - 1); // Consume w_i - 1 smallest elements
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

