int calculate_score(const std::string& s) {
    int score = 0;
    if (s.empty()) {
        return 0;
    }
    if (s[0] == 'W') {
        score += 1;
    }
    for (size_t i = 1; i < s.length(); ++i) {
        if (s[i] == 'W') {
            if (s[i-1] == 'W') {
                score += 2;
            } else {
                score += 1;
            }
        }
    }
    return score;
}

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    if (k == 0) {
        std::cout << calculate_score(s) << std::endl;
        return;
    }

    int initial_wins = 0;
    for (char c : s) {
        if (c == 'W') {
            initial_wins++;
        }
    }

    if (initial_wins + k >= n) { // Can make all games 'W'
        std::cout << 1 + (n - 1) * 2 << std::endl;
        return;
    }

    // Find the first and last 'W'
    int first_w = -1, last_w = -1;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (first_w == -1) {
                first_w = i;
            }
            last_w = i;
        }
    }

    if (first_w == -1) { // No 'W's initially
        // Change k 'L's to 'W's. Best to make them consecutive.
        // If k > 0, we can always get at least 1 point.
        // If k=1, score is 1.
        // If k>1, score is 1 + (k-1)*2.
        std::cout << 1 + std::max(0, k - 1) * 2 << std::endl;
        return;
    }

    // Collect lengths of 'L' segments between 'W's
    std::vector<int> gaps;
    int current_gap = 0;
    for (int i = first_w + 1; i <= last_w; ++i) {
        if (s[i] == 'L') {
            current_gap++;
        } else { // s[i] == 'W'
            if (current_gap > 0) {
                gaps.push_back(current_gap);
            }
            current_gap = 0;
        }
    }
    std::sort(gaps.begin(), gaps.end());

    // Fill internal gaps first
    for (int gap_len : gaps) {
        if (k >= gap_len) {
            k -= gap_len;
            // Changing these L's to W's connects two W segments.
            // This means the last W of the first segment now contributes 2 instead of 1 (if it was 1),
            // and the first W of the second segment now contributes 2 instead of 1 (if it was 1).
            // The net effect is that each L in the gap, when changed to W, contributes 2 points
            // because it's surrounded by Ws.
            // The two Ws that were separated now become part of a longer chain.
            // The score calculation handles this naturally.
            // For example, W L W -> W W W.
            // Original: 1 + 1 = 2. New: 1 + 2 + 2 = 5. Diff = 3.
            // The L changed to W. It costs 1 k. It adds 2 points for itself.
            // The W before it now gets 2 points instead of 1. (+1)
            // The W after it now gets 2 points instead of 1. (+1)
            // Total +4 for 1 L.
            // No, this is not how it works.
            // W L W (score 1+1=2) -> W W W (score 1+2+2=5).
            // The L becomes W. It gets 2 points.
            // The W before it was 1, now 2. (+1)
            // The W after it was 1, now 2. (+1)
            // Total +4.
            // This is wrong. The score calculation is based on the final string.
            // If we fill a gap of length `g`, we use `g` changes.
            // The `g` new 'W's contribute `2*g` points.
            // The 'W' before the gap now gets 2 points (if it was 1).
            // The 'W' after the gap now gets 2 points (if it was 1).
            // The `calculate_score` function will correctly sum up the points.
            // So, we just need to apply the changes to `s`.
            for (int i = first_w + 1; i <= last_w; ++i) {
                if (s[i] == 'L') {
                    current_gap--;
                    s[i] = 'W';
                    if (current_gap == 0) break; // Filled this gap
                }
            }
            // Re-find first_w and last_w for the next gap iteration
            // This is inefficient. A better way is to just mark the L's as W's in the original string.
            // Let's re-think.
            // The current approach of modifying `s` and then calculating score is correct.
            // The issue is how to apply changes to `s` for gaps.
            // We need to iterate through `s` and fill the gaps.
            // A better way to apply changes:
            // Iterate through `s` and find the actual indices of gaps.
        } else {
            break; // Cannot fill this gap
        }
    }

    // Re-calculate score after filling internal gaps
    // This is not optimal. We should apply changes to the string `s` directly.
    // Let's restart the logic for applying changes.

    // Create a temporary string to apply changes
    std::string temp_s = s;

    // Fill internal gaps
    std::vector<std::pair<int, int>> gap_indices; // {length, start_index}
    current_gap = 0;
    for (int i = first_w + 1; i <= last_w; ++i) {
        if (temp_s[i] == 'L') {
            current_gap++;
        } else { // temp_s[i] == 'W'
            if (current_gap > 0) {
                gap_indices.push_back({current_gap, i - current_gap});
            }
            current_gap = 0;
        }
    }
    std::sort(gap_indices.begin(), gap_indices.end());

    for (auto const& [len, start_idx] : gap_indices) {
        if (k >= len) {
            k -= len;
            for (int i = 0; i < len; ++i) {
                temp_s[start_idx + i] = 'W';
            }
        } else {
            break;
        }
    }

    // Fill 'L's before the first 'W'
    for (int i = first_w - 1; i >= 0 && k > 0; --i) {
        if (temp_s[i] == 'L') {
            temp_s[i] = 'W';
            k--;
        }
    }

    // Fill 'L's after the last 'W'
    for (int i = last_w + 1; i < n && k > 0; ++i) {
        if (temp_s[i] == 'L') {
            temp_s[i] = 'W';
            k--;
        }
    }

    std::cout << calculate_score(temp_s) << std::endl;
}

