    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % MOD;
        } else { // s[i] == 'a'
            // Each 'a' needs to move past all 'b's to its right.
            // If there are 'k' 'b's to its right, it takes 'k' steps.
            // After these 'k' steps, this 'a' effectively becomes 'bba'.
            // The 'a' moves to the right, and a new 'b' is introduced.
            // This new 'b' is now to the right of any 'a's further left.
            // So, the number of 'b's that subsequent 'a's will encounter doubles.
            total_steps = (total_steps + b_count) % MOD;
            b_count = (b_count * 2) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

