void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need S' = 2 * X'
    // Let S_orig = current_sum, X_orig = current_xor_sum
    // We want to find b1, b2, b3 such that
    // (S_orig + b1 + b2 + b3) = 2 * (X_orig ^ b1 ^ b2 ^ b3)

    // Strategy: Append at most 2 elements.
    // Let's try to append two elements, say X_orig and S_orig + X_orig.
    // This is a common trick for problems involving sum and XOR.
    // Let b1 = X_orig
    // Let b2 = S_orig + X_orig
    //
    // New XOR sum: X' = X_orig ^ b1 ^ b2
    //                 = X_orig ^ X_orig ^ (S_orig + X_orig)
    //                 = 0 ^ (S_orig + X_orig)
    //                 = S_orig + X_orig
    //
    // New Sum: S' = S_orig + b1 + b2
    //              = S_orig + X_orig + (S_orig + X_orig)
    //              = 2 * S_orig + 2 * X_orig
    //              = 2 * (S_orig + X_orig)
    //
    // Check condition: S' = 2 * X'
    // 2 * (S_orig + X_orig) = 2 * (S_orig + X_orig)
    // This holds true!

    // So, we can always append two elements: X_orig and S_orig + X_orig.
    // The problem states we can append at most 3 elements.
    // This strategy uses 2 elements.

    // Output the number of elements to append (2)
    // Output the elements themselves (current_xor_sum and current_sum + current_xor_sum)
    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

