int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_sequences = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        if (chain[0] == 1) { // This chain starts with 1
            int current_val = 1;
            int j = 0;
            while (j < m && chain[j] == current_val) {
                correct_sequences++;
                current_val++;
                j++;
            }
            // The remaining part of this chain (if any) needs to be disassembled
            // and reassembled.
            // Each matryoshka from chain[j] to chain[m-1] needs to be taken out.
            // The number of matryoshkas to take out is (m - j).
            // Each take-out operation costs 1.
            total_operations += (m - j);
        } else {
            // This chain does not start with 1.
            // All matryoshkas in this chain need to be taken out.
            // The number of matryoshkas to take out is (m - 1).
            // Each take-out operation costs 1.
            total_operations += (m - 1);
        }
    }

    // After disassembling, we have `n` individual matryoshkas.
    // We have `correct_sequences` matryoshkas that are already in their correct place
    // as part of the 1 -> 2 -> ... -> correct_sequences sequence.
    // We need to assemble the remaining `n - correct_sequences` matryoshkas.
    // Each assembly operation costs 1.
    total_operations += (n - correct_sequences);

    std::cout << total_operations << std::endl;

    return 0;
}

