// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means x must not be a multiple of q.
        // The strategy is to remove prime factors from p that are also in q,
        // such that p is no longer divisible by q, but we remove as little as possible.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 1;

        for (long long factor : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by 'factor' until it's no longer divisible by 'factor'
            // or until current_p is no longer divisible by q.
            while (current_p % factor == 0 && current_p % q == 0) {
                current_p /= factor;
            }
            // After this loop, current_p is a divisor of original p.
            // If current_p is not divisible by q, it's a candidate for max_x.
            // If current_p is still divisible by q, it means 'factor' alone wasn't enough
            // to break the divisibility by q (e.g., q has other prime factors or higher power).
            // In this case, current_p is not a valid candidate for x.
            // However, the problem guarantees an answer exists.
            // The logic is that if we divide p by a prime factor 'f' of q,
            // we get p/f. If p/f is not divisible by q, then p/f is a candidate.
            // We want the largest such p/f.
            // So, for each prime factor 'f' of q, we find the largest k such that p / f^k is not divisible by q.
            // The largest such p / f^k over all f will be our answer.

            long long temp_p = p;
            while (temp_p % q == 0) { // While temp_p is still a multiple of q
                temp_p /= factor; // Divide by the current prime factor of q
            }
            // After the loop, temp_p is p / (factor^k) for some k, and temp_p is not divisible by q.
            // This temp_p is a candidate for x.
            max_x = std::max(max_x, temp_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_pattern(k, '?');

    // Step 1: Determine the fixed pattern for each remainder modulo k
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            if (fixed_pattern[i % k] == '?') {
                fixed_pattern[i % k] = s[i];
            } else if (fixed_pattern[i % k] != s[i]) {
                // Conflict: s[i] contradicts an already determined character for this position modulo k
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Count 0s, 1s, and ?s in the fixed pattern
    int count0 = 0;
    int count1 = 0;
    int count_q = 0;
    for (int i = 0; i < k; ++i) {
        if (fixed_pattern[i] == '0') {
            count0++;
        } else if (fixed_pattern[i] == '1') {
            count1++;
        } else { // fixed_pattern[i] == '?'
            count_q++;
        }
    }

    // Step 3: Check if it's possible to fill '?'s to satisfy k/2 zeros and k/2 ones
    int target_half = k / 2;
    if (count0 > target_half || count1 > target_half) {
        std::cout << "NO\n";
        return;
    }

    // We need (target_half - count0) more zeros and (target_half - count1) more ones.
    // The remaining '?'s must be able to cover these counts.
    // The total number of '?'s is count_q.
    // (target_half - count0) + (target_half - count1) must be <= count_q.
    // This is equivalent to: 2 * target_half - (count0 + count1) <= count_q
    // Since 2 * target_half = k, and count0 + count1 + count_q = k,
    // this condition simplifies to k - (count0 + count1) <= count_q, which is true if count0 + count1 + count_q = k.
    // The actual check is that we have enough '?'s to fill the deficit.
    // The number of '?'s that must become '0' is target_half - count0.
    // The number of '?'s that must become '1' is target_half - count1.
    // The sum of these must be less than or equal to the total '?'s available.
    if ((target_half - count0) + (target_half - count1) <= count_q) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

