#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int p = 0; p <= 9; ++p) { // p is the pivot digit
        std::string current_coloring(n, ' ');
        char last_digit_color1 = '0'; // Represents the last digit assigned to color 1
        char first_digit_color2 = '9' + 1; // Represents the first digit assigned to color 2

        bool possible_for_p = true;
        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit < p + '0') {
                current_coloring[i] = '1';
                if (digit < last_digit_color1) { // S1 must be non-decreasing
                    possible_for_p = false;
                    break;
                }
                last_digit_color1 = digit;
            } else if (digit > p + '0') {
                current_coloring[i] = '2';
                if (digit > first_digit_color2) { // S2 must be non-decreasing
                    possible_for_p = false;
                    break;
                }
                first_digit_color2 = digit;
            }
        }

        if (!possible_for_p) {
            continue;
        }

        // Now handle digits equal to p
        // Digits equal to p that appear before the first digit > p must be color 1
        // Digits equal to p that appear after the last digit < p must be color 2
        // This is equivalent to finding the first occurrence of p that we want to color 2.
        // All p's before that are 1, all p's after that are 2.
        // This split point for p's must respect the overall non-decreasing property.

        // Find the first index `k` such that s[k] == p + '0' and we assign it to color 2.
        // All s[i] == p + '0' for i < k are assigned to color 1.
        // All s[i] == p + '0' for i >= k are assigned to color 2.
        // The value of `k` can range from 0 to n.
        // If k=0, all p's are color 2. If k=n, all p's are color 1.

        // Let's try to find the optimal split point for digits equal to 'p'.
        // We want to assign '1' to as many 'p's as possible, then '2'.
        // The split point for 'p's is determined by the last_digit_color1 and first_digit_color2.
        // All 'p's before the split point must be >= last_digit_color1.
        // All 'p's after the split point must be <= first_digit_color2.
        // Since all these digits are 'p', this is always true.
        // The critical condition is that the last '1' (which could be a 'p') must be <= the first '2' (which could be a 'p').

        // Let's try to find the "transition point" for digits equal to 'p'.
        // All 'p's before this point are '1', all 'p's after are '2'.
        // This transition point must be chosen such that the overall sequence is sorted.
        // The last digit of S1 must be <= the first digit of S2.
        // If S1 ends with a digit < p, and S2 starts with a digit > p, then any split of p's works.
        // If S1 ends with p, and S2 starts with p, then any split of p's works.
        // If S1 ends with a digit < p, and S2 starts with p, then any split of p's works.
        // If S1 ends with p, and S2 starts with a digit > p, then any split of p's works.

        // The only constraint is that the last digit of S1 (if S1 is not empty) must be <= the first digit of S2 (if S2 is not empty).
        // If we assign all 'p's to '1', then last_digit_color1 becomes 'p'.
        // If we assign all 'p's to '2', then first_digit_color2 becomes 'p'.

        // Let's try to find the first index `idx_p_to_2` where a digit `p` is colored '2'.
        // All `p`s before `idx_p_to_2` are colored '1'.
        // All `p`s at or after `idx_p_to_2` are colored '2'.
        // If no `p`s are colored '2', `idx_p_to_2` can be `n`.
        // If no `p`s are colored '1', `idx_p_to_2` can be `0`.

        // We need to find the smallest `idx_p_to_2` such that:
        // 1. All digits `d_i < p` are '1'.
        // 2. All digits `d_i > p` are '2'.
        // 3. For `d_i = p`: if `i < idx_p_to_2`, `d_i` is '1'; if `i >= idx_p_to_2`, `d_i` is '2'.

        // Let's iterate through all possible split points for 'p' digits.
        // The split point `k` means digits `s[i] == p+'0'` for `i < k` are '1', and for `i >= k` are '2'.
        // We need to find the first `k` (from 0 to n) that works.
        // If `k=0`, all `p`s are '2'. If `k=n`, all `p`s are '1'.

        int best_k = -1;
        for (int k = 0; k <= n; ++k) { // k is the split point for digits equal to p
            std::string temp_coloring = current_coloring;
            char current_last_1 = last_digit_color1;
            char current_first_2 = first_digit_color2;

            // Apply split for 'p' digits
            for (int i = 0; i < n; ++i) {
                if (s[i] == p + '0') {
                    if (i < k) {
                        temp_coloring[i] = '1';
                        current_last_1 = std::max(current_last_1, s[i]);
                    } else {
                        temp_coloring[i] = '2';
                        current_first_2 = std::min(current_first_2, s[i]);
                    }
                }
            }

            // Check if this coloring is valid
            std::string s1_str = "";
            std::string s2_str = "";
            bool valid_split = true;

            for (int i = 0; i < n; ++i) {
                if (temp_coloring[i] == '1') {
                    s1_str += s[i];
                } else if (temp_coloring[i] == '2') {
                    s2_str += s[i];
                } else { // Should not happen if current_coloring was fully populated for non-p digits
                    valid_split = false;
                    break;
                }
            }

            if (!valid_split) continue;

            // Check S1 non-decreasing
            for (size_t i = 0; i + 1 < s1_str.length(); ++i) {
                if (s1_str[i] > s1_str[i+1]) {
                    valid_split = false;
                    break;
                }
            }
            if (!valid_split) continue;

            // Check S2 non-decreasing
            for (size_t i = 0; i + 1 < s2_str.length(); ++i) {
                if (s2_str[i] > s2_str[i+1]) {
                    valid_split = false;
                    break;
                }
            }
            if (!valid_split) continue;

            // Check S1_last <= S2_first
            if (!s1_str.empty() && !s2_str.empty()) {
                if (s1_str.back() > s2_str.front()) {
                    valid_split = false;
                }
            }

            if (valid_split) {
                result = temp_coloring;
                found_solution = true;
                break; // Found a valid split for this 'p', move to next test case
            }
        }

        if (found_solution) {
            break; // Found a solution for this test case
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

