#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left part (jars 1 to n)
    // S_L[k] = sum of values for jars 1 to k
    // Value is +1 for type 1, -1 for type 2
    std::vector<int> s_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        s_left[i + 1] = s_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right part (jars n+1 to 2n)
    // S_R[k] = sum of values for jars 2n-k+1 to 2n
    std::vector<int> s_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        s_right[i + 1] = s_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the left (k_L)
    // to achieve a certain balance sum (s_left[k_L])
    // The key is the balance sum, value is k_L
    std::map<int, int> left_balance_to_k;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int balance = s_left[k_L];
        if (left_balance_to_k.find(balance) == left_balance_to_k.end()) {
            left_balance_to_k[balance] = k_L;
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with max possible

    // Iterate through possible number of jars eaten from the right (k_R)
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_right_balance = s_right[k_R];
        // We need s_left[k_L] + s_right[k_R] = 0
        // So, s_left[k_L] must be -current_right_balance
        int target_left_balance = -current_right_balance;

        if (left_balance_to_k.count(target_left_balance)) {
            int k_L = left_balance_to_k[target_left_balance];
            min_jars_eaten = std::min(min_jars_eaten, k_L + k_R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

