int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;
        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;

        long long num_zeros = n - m;

        // To minimize substrings of all zeros, distribute zeros as evenly as possible
        // among m+1 potential blocks (before first '1', between '1's, after last '1').
        // The optimal strategy is to place '1's such that the blocks of '0's are as equal in length as possible.
        // This means we have m '1's, which divide the string into m+1 segments of '0's.
        // The '1's themselves are not part of the '0' blocks.
        // The '1's are placed to separate the '0's.
        // Consider the m '1's. They create m-1 gaps between them, plus a segment before the first '1' and after the last '1'.
        // So there are m+1 potential blocks of zeros.
        // We have num_zeros '0's to distribute into these m+1 blocks.

        // Number of blocks of zeros that will have length floor(num_zeros / (m+1))
        long long k = num_zeros / (m + 1);
        // Number of blocks of zeros that will have length k+1
        long long r = num_zeros % (m + 1);

        // Number of blocks of length k+1
        long long count_k_plus_1 = r;
        // Number of blocks of length k
        long long count_k = (m + 1) - r;

        long long substrings_of_zeros = 0;
        if (k > 0) {
            substrings_of_zeros += count_k * k * (k + 1) / 2;
        }
        if (k + 1 > 0) { // This condition is always true if r > 0, or if k+1 is 1 (i.e., k=0, r>0)
            substrings_of_zeros += count_k_plus_1 * (k + 1) * (k + 2) / 2;
        }

        long long max_f_s = total_substrings - substrings_of_zeros;

        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits are 1
    int current_or_mask = 0;    // All bits are 0
    int current_xor_mask = 0;   // All bits are 0

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_and_mask &= x;
            current_or_mask &= x;
            current_xor_mask &= x;
        } else if (op_char == '|') {
            current_and_mask |= x;
            current_or_mask |= x;
            current_xor_mask |= x;
        } else if (op_char == '^') {
            current_and_mask ^= x;
            current_or_mask ^= x;
            current_xor_mask ^= x;
        }
    }

    // Now we have the final transformation for 0 and 1.
    // For an input bit 'b':
    // If b=0, the output bit is (0 & current_and_mask) | current_or_mask ^ current_xor_mask
    // which simplifies to current_or_mask ^ current_xor_mask. Let's call this 'val0'.
    // If b=1, the output bit is (1 & current_and_mask) | current_or_mask ^ current_xor_mask
    // which simplifies to current_and_mask | current_or_mask ^ current_xor_mask. Let's call this 'val1'.

    // Let's re-evaluate the logic for val0 and val1.
    // The state of a bit 'b' after all operations can be represented by:
    // (b & A) | O ^ X
    // where A, O, X are the combined masks.
    //
    // For an initial bit 0: (0 & A) | O ^ X = 0 | O ^ X = O ^ X
    // For an initial bit 1: (1 & A) | O ^ X = A | O ^ X
    //
    // So, let's track the final state of 0 and 1.
    int final_val0 = 0;
    int final_val1 = 1023; // All bits set to 1

    // Re-simulate the operations on final_val0 and final_val1
    // This is the correct way to combine operations.
    // The variables current_and_mask, current_or_mask, current_xor_mask
    // were tracking the combined effect on the *masks themselves*, not on the input value.
    // Let's re-initialize and track the effect on 0 and 1023 (all 1s).
    // This is equivalent to tracking the effect on each bit independently.
    // final_val0 will store the result for input 0.
    // final_val1 will store the result for input 1023 (all 1s).

    std::cin.clear();
    std::cin.seekg(0); // Rewind input stream to the beginning

    std::string dummy_line;
    std::getline(std::cin, dummy_line); // Read n again, discard

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            final_val0 &= x;
            final_val1 &= x;
        } else if (op_char == '|') {
            final_val0 |= x;
            final_val1 |= x;
        } else if (op_char == '^') {
            final_val0 ^= x;
            final_val1 ^= x;
        }
    }

    // Now, final_val0 is the result for input 0.
    // final_val1 is the result for input 1023 (all 1s).
    //
    // Let the simplified program be: (input & A_new) | O_new ^ X_new
    //
    // For input 0: (0 & A_new) | O_new ^ X_new = O_new ^ X_new = final_val0
    // For input 1023: (1023 & A_new) | O_new ^ X_new = A_new | O_new ^ X_new = final_val1
    //
    // We need to find A_new, O_new, X_new.
    //
    // From O_new ^ X_new = final_val0, we know that for each bit j:
    // (O_new)_j ^ (X_new)_j = (final_val0)_j
    //
    // From A_new | O_new ^ X_new = final_val1, we know that for each bit j:
    // (A_new)_j | (O_new)_j ^ (X_new)_j = (final_val1)_j
    // (A_new)_j | (final_val0)_j = (final_val1)_j
    //
    // This gives us:
    // (A_new)_j = 1 if (final_val0)_j = 0 and (final_val1)_j = 1
    // (A_new)_j = 0 if (final_val0)_j = 0 and (final_val1)_j = 0
    // (A_new)_j = 0 if (final_val0)_j = 1 and (final_val1)_j = 1
    // (A_new)_j is undefined if (final_val0)_j = 1 and (final_val1)_j = 0 (this case should not happen, as A_new | final_val0 must be final_val1)
    //
    // In summary, (A_new)_j = (final_val1)_j & ~ (final_val0)_j
    // Or more simply, A_new = final_val1 & (~final_val0)
    //
    // Let's define A_new, O_new, X_new.
    //
    // A_new: For a bit j, if input 0 maps to 0 and input 1 maps to 1, then A_new_j must be 1.
    //        If input 0 maps to 0 and input 1 maps to 0, then A_new_j must be 0.
    //        If input 0 maps to 1 and input 1 maps to 1, then A_new_j must be 0.
    //        If input 0 maps to 1 and input 1 maps to 0, this implies a XOR operation.
    //
    // Let's analyze bit by bit. For each bit position `j` (0 to 9):
    // Let `b0 = (final_val0 >> j) & 1`
    // Let `b1 = (final_val1 >> j) & 1`
    //
    // Case 1: `b0 = 0, b1 = 0`
    //   Input bit `x_j` always becomes 0. This means `(x_j & 0) | 0 ^ 0` or `(x_j & 1) | 0 ^ 1` etc.
    //   This can be achieved by `& 0` for this bit.
    //   So, `A_new_j = 0`, `O_new_j = 0`, `X_new_j = 0`.
    //
    // Case 2: `b0 = 0, b1 = 1`
    //   Input bit `x_j` becomes `x_j`. This means `(x_j & 1) | 0 ^ 0`.
    //   So, `A_new_j = 1`, `O_new_j = 0`, `X_new_j = 0`.
    //
    // Case 3: `b0 = 1, b1 = 0`
    //   Input bit `x_j` becomes `~x_j`. This means `(x_j & 1) | 0 ^ 1`.
    //   So, `A_new_j = 1`, `O_new_j = 0`, `X_new_j = 1`.
    //
    // Case 4: `b0 = 1, b1 = 1`
    //   Input bit `x_j` always becomes 1. This means `(x_j & 0) | 1 ^ 0`.
    //   So, `A_new_j = 0`, `O_new_j = 1`, `X_new_j = 0`.
    //
    // Let's construct the new masks:
    int A_new = 0; // Mask for & operation
    int O_new = 0; // Mask for | operation
    int X_new = 0; // Mask for ^ operation

    for (int j = 0; j < 10; ++j) {
        int b0 = (final_val0 >> j) & 1;
        int b1 = (final_val1 >> j) & 1;

        if (b0 == 0 && b1 == 0) {
            // x_j -> 0. Achieved by & (0 for this bit)
            // A_new_j = 0, O_new_j = 0, X_new_j = 0
        } else if (b0 == 0 && b1 == 1) {
            // x_j -> x_j. Achieved by & (1 for this bit)
            A_new |= (1 << j);
            // O_new_j = 0, X_new_j = 0
        } else if (b0 == 1 && b1 == 0) {
            // x_j -> ~x_j. Achieved by & (1 for this bit) ^ (1 for this bit)
            A_new |= (1 << j);
            X_new |= (1 << j);
            // O_new_j = 0
        } else if (b0 == 1 && b1 == 1) {
            // x_j -> 1. Achieved by | (1 for this bit)
            O_new |= (1 << j);
            // A_new_j = 0, X_new_j = 0
        }
    }

    std::vector<std::pair<char, int>> simplified_ops;
    if (A_new != 1023) { // If A_new is not all 1s, we need an & operation
        simplified_ops.push_back({'&', A_new});
    }
    if (O_new != 0) { // If O_new is not all 0s, we need an | operation
        simplified_ops.push_back({'|', O_new});
    }
    if (X_new != 0) { // If X_new is not all 0s, we need an ^ operation
        simplified_ops.push_back({'^', X_new});
    }

    std::cout << simplified_ops.size() << "\n";
    for (const auto& op : simplified_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, then increment by d for new blocks

    while (X > 0) {
        long long k = 0;
        // Find largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        if (X == 1) { // Special case for X=1, 2^0-1=0, but we need 1 element
            k = 1;
        } else {
            k = std::floor(std::log2(X + 1));
        }

        // If 2^k - 1 > X, we need to reduce k
        // This can happen if X+1 is not a power of 2, e.g., X=5, X+1=6, log2(6) approx 2.58, k=2.
        // 2^2 - 1 = 3 <= 5. This is correct.
        // If X=7, X+1=8, log2(8)=3, k=3. 2^3-1=7 <= 7. Correct.
        // The floor(log2(X+1)) correctly gives the largest k such that 2^k <= X+1.
        // So 2^k-1 <= X.
        // The only edge case is if X+1 is a power of 2, say X+1 = 2^k_max.
        // Then 2^k_max - 1 = X.
        // If X+1 is not a power of 2, say X+1 = 2^k_max + R, where R > 0.
        // Then floor(log2(X+1)) = k_max.
        // 2^k_max - 1 < X.
        // So k is always chosen such that 2^k - 1 <= X.

        // Add k elements of current_val to the result array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }

        // Subtract the count of subsequences formed by these k elements
        X -= (1LL << k) - 1;

        // Increment current_val for the next block
        current_val += d;

        // Check for overflow before adding d again
        if (current_val > 1000000000000000000LL - d && X > 0) { // If current_val + d would overflow
            // This condition is a bit tricky. If current_val is already very large,
            // and we still have X > 0, it means we need to add more blocks.
            // If current_val + d exceeds 10^18, we can't form a valid array.
            // However, the problem states a_i < 10^18.
            // If current_val is already >= 10^18, it's an issue.
            // If current_val + d would exceed 10^18, it's an issue.
            // The maximum number of elements is 10^4.
            // The maximum value of d is 10^9.
            // If we add 10^4 blocks, each incrementing by d, current_val could be 1 + 10^4 * 10^9 = 10^13.
            // This is well within 10^18.
            // The only way current_val could exceed 10^18 is if d is very large and X is very large,
            // requiring many blocks.
            // But the number of blocks is at most 60 (since 2^60 is approx 10^18).
            // So current_val will not exceed 10^18.
            // The check `current_val > 1000000000000000000LL - d` is a safeguard, but likely not hit.
        }
    }

    if (result_array.size() > 10000) {
        // This case should not be hit based on constraints and logic.
        // Max X is 10^9. Max k is 30 (2^30-1 approx 10^9).
        // If X=10^9, k=30. X becomes 0. Array size 30.
        // If X=10^9, d=1.
        // k=30. X -= 2^30-1. current_val = 1+1.
        // k=29. X -= 2^29-1. current_val = 1+2.
        // ...
        // The number of blocks is at most 60 (for X up to 2^60-1).
        // Each block adds at most 60 elements.
        // So total elements is at most 60 * 60 = 3600.
        // This is well within 10^4.
        std::cout << -1 << std::endl;
        return 0;
    }

    std::cout << result_array.size() << std::endl;
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_nodes(n, false);

    // Iterate through the removal sequence in reverse
    // This means we are effectively adding nodes back to the graph
    // and calculating APSP for the graph with these nodes.
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The node being "added" back

        active_nodes[k] = true; // Mark node k as active

        // Floyd-Warshall update step:
        // Consider node k as an intermediate node for all pairs of currently active nodes.
        for (int i = 0; i < n; ++i) {
            if (!active_nodes[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_nodes[j]) continue;

                // Path i -> k -> j
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // Also, consider newly active node k as a source/destination
        // for paths through other active nodes.
        // This is crucial for correctness: when k becomes active, it can be an endpoint
        // or an intermediate node. The previous loop handles k as an intermediate.
        // The following loops ensure that paths involving k as an endpoint are also updated
        // using other active nodes as intermediates.
        // This is essentially running Floyd-Warshall on the subgraph of active_nodes,
        // with k being the latest node added.
        for (int i = 0; i < n; ++i) {
            if (!active_nodes[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_nodes[j]) continue;

                // Path i -> (any active node) -> j
                // This is already covered by the triple loop above if we consider
                // the order of k, i, j.
                // The standard Floyd-Warshall structure is:
                // for k_prime (intermediate)
                //   for i_prime (source)
                //     for j_prime (dest)
                //       dist[i_prime][j_prime] = min(dist[i_prime][j_prime], dist[i_prime][k_prime] + dist[k_prime][j_prime])
                // Here, k is the *newest* intermediate node. So we need to update all pairs (i,j)
                // using k as an intermediate.
                // And then, for any pair (i,j) where i or j is k, we need to update paths
                // using other active nodes as intermediates.
                // The triple loop above (i, j, k) effectively does this for the current set of active nodes.
                // The order of loops (k, i, j) is important.
                // The current implementation is:
                // for each new active node `k`:
                //   for each active node `i`:
                //     for each active node `j`:
                //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
                // This correctly updates all paths using `k` as an intermediate.
                // It also implicitly updates paths where `i` or `j` is `k` because `k` is in the set of active nodes.
                // For example, if `i=k`, then `dist[k][j] = min(dist[k][j], dist[k][k] + dist[k][j])` which is `dist[k][j]`.
                // If `i=k`, then `dist[k][j] = min(dist[k][j], dist[k][p] + dist[p][j])` for any other active `p`.
                // This is what the standard Floyd-Warshall does.
                // So, the triple loop above is sufficient.
            }
        }

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_nodes[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_nodes[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before x_1, before x_2, ...)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

