#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;
        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        long long min_coord = std::min(abs_n, abs_m);
        long long max_coord = std::max(abs_n, abs_m);

        if (k < max_coord) {
            std::cout << -1 << "\n";
            continue;
        }

        long long ans;
        if ((k - max_coord) % 2 == 0) {
            // If k and max_coord have the same parity, we can reach max_coord
            // in max_coord moves, and then spend the remaining (k - max_coord)
            // moves by oscillating. Each oscillation takes 2 moves and doesn't
            // change the parity of coordinates.
            ans = k;
        } else {
            // If k and max_coord have different parity, we need to adjust.
            // This means we must have an odd number of "extra" moves.
            // We can reach max_coord in max_coord moves.
            // The remaining (k - max_coord) moves is odd.
            // We can use (k - max_coord - 1) moves for oscillation,
            // and one move to change parity.
            //
            // Case 1: n and m have different parities.
            // This means max_coord and min_coord have different parities.
            // If we reach (max_coord, min_coord) in max_coord moves,
            // the parity of the current point (max_coord, min_coord)
            // is (max_coord % 2, min_coord % 2).
            // The parity of (0,0) is (0,0).
            // The parity of (x,y) after t moves is (t % 2, t % 2) if all moves are diagonal.
            // The parity of (x,y) after t moves is (t % 2, 0) or (0, t % 2) if all moves are straight.
            //
            // A move changes (x,y) to (x+dx, y+dy).
            // Parity of x changes if dx is odd. Parity of y changes if dy is odd.
            // Diagonal move: dx, dy are odd. Both x and y parities flip.
            // Straight move: one of dx, dy is odd, the other is 0. One of x, y parities flips.
            //
            // After t moves, the parity of (x,y) is (t % 2, t % 2) if all moves are diagonal.
            // After t moves, the parity of (x,y) is (t % 2, 0) or (0, t % 2) if all moves are straight.
            //
            // The parity of (x,y) after k moves is (k % 2, k % 2) if all moves are diagonal.
