#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a_suffix(n); // a_suffix[0] is unused, a_suffix[1] is a_2, ..., a_suffix[n-1] is a_n
    for (int i = 1; i < n; ++i) {
        std::cin >> a_suffix[i];
    }

    std::vector<long long> dp_y(n + 1, -2); // Stores final y for x=k, y=0, starting with step 2. -2 means uncomputed, -1 means infinite loop.
    std::vector<long long> dp_x_next(n + 1, -2); // Stores final x for x=k, y=0, starting with step 2.

    for (int start_val_a1 = 1; start_val_a1 < n; ++start_val_a1) {
        long long current_x = start_val_a1;
        long long current_y = 0;

        // First step (step 2)
        // x = x + a[x], y = y + a[x]
        // Here a[x] is start_val_a1
        current_y += start_val_a1;
        current_x += start_val_a1;

        // Check termination after first step
        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Second step (step 3)
        // x = x - a[x], y = y + a[x]
        // Here a[x] is a_suffix[current_x - 1]
        long long val_at_current_x = a_suffix[current_x - 1];
        current_y += val_at_current_x;
        current_x -= val_at_current_x;

        // Check termination after second step
        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Now we are at a state (current_x, current_y) and the next step is step 2.
        // This is exactly the state that dp_y[current_x] and dp_x_next[current_x] are designed for.
        // We need to compute dp_y[current_x] and dp_x_next[current_x] if not already computed.

        if (dp_y[current_x] == -2) { // Not computed yet
            std::vector<int> path;
            long long temp_x = current_x;
            long long temp_y_accum = 0; // Accumulates y changes from this point until a known state or loop

            while (temp_x > 0 && temp_x <= n && dp_y[temp_x] == -2) {
                path.push_back(temp_x);
                dp_y[temp_x] = -1; // Mark as visited (potential loop)

                // Step 2
                long long val_a_temp_x = a_suffix[temp_x - 1];
                temp_y_accum += val_a_temp_x;
                temp_x += val_a_temp_x;

                if (temp_x <= 0 || temp_x > n) { // Terminates
                    for (int node : path) {
                        dp_y[node] = temp_y_accum;
                        dp_x_next[node] = temp_x;
                    }
                    break;
                }

                // Step 3
                val_a_temp_x = a_suffix[temp_x - 1];
                temp_y_accum += val_a_temp_x;
                temp_x -= val_a_temp_x;

                if (temp_x <= 0 || temp_x > n) { // Terminates
                    for (int node : path) {
                        dp_y[node] = temp_y_accum;
                        dp_x_next[node] = temp_x;
                    }
                    break;
                }
            }

            // After loop, temp_x is either out of bounds, or points to a known state (dp_y[temp_x] != -2)
            if (temp_x > 0 && temp_x <= n && dp_y[temp_x] != -1) { // Reached a previously computed state
                for (int node : path) {
                    if (dp_y[temp_x] == -1) { // If the known state is an infinite loop
                        dp_y[node] = -1;
                        dp_x_next[node] = -1;
                    } else {
                        dp_y[node] = temp_y_accum + dp_y[temp_x];
                        dp_x_next[node] = dp_x_next[temp_x];
                    }
                }
            } else if (temp_x > 0 && temp_x <= n && dp_y[temp_x] == -1) { // Reached an infinite loop state
                for (int node : path) {
                    dp_y[node] = -1;
                    dp_x_next[node] = -1;
                }
            }
            // If temp_x is out of bounds, the values were already set in the loop
        }

        if (dp_y[current_x] == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y + dp_y[current_x] << "\n";
        }
    }

    return 0;
}

