int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r such that [l, r] contains a bad triplet.
                                                // Using 1-based indexing for l and r here.
                                                // Initialize with n+1, meaning no such r found yet.

    // Iterate through all possible x and k to find bad triplets (x, x+k, x+2k)
    // x is 0-indexed, k is 1-indexed.
    // The problem uses 1-based indexing for s_x, s_{x+k}, s_{x+2k}.
    // If s_x = s_{x+k} = s_{x+2k} (0-indexed), then the corresponding 1-based indices are x+1, x+k+1, x+2k+1.
    // For a given bad triplet, any range [l, r] such that l <= x+1 and x+2k+1 <= r will satisfy the condition.
    // We are interested in the smallest possible r for a given l.
    // So, for a bad triplet (x, x+k, x+2k), it implies that for any l' from 1 to x+1,
    // the range [l', x+2k+1] is a valid range.
    // This means min_r_for_l[l'] can be at most x+2k+1.

    for (int x = 0; x < n; ++x) {
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a bad triplet (x, x+k, x+2k) (0-indexed)
                // The corresponding 1-based indices are x_1 = x+1 and r_1 = x+2k+1.
                // This triplet makes any range [l_val, r_val] valid if l_val <= x_1 and r_1 <= r_val.
                // We want to update min_r_for_l[l_val] with r_1.
                // Since we are iterating x from left to right, and k from small to large,
                // x+2k+1 will be increasing.
                // For a fixed x, as k increases, x+2k+1 increases.
                // For a fixed k, as x increases, x+2k+1 increases.
                // So, the first time we find a bad triplet for a given x, it gives the smallest r_1 for that x.
                // However, we need to update for all l_val <= x+1.
                // The smallest r_1 for a given l_val is what we need.
                // So, for each l_val from 1 to x+1, we can potentially update min_r_for_l[l_val].
                // We take the minimum of current min_r_for_l[l_val] and x+2k+1.

                // The maximum possible value for x+1 is n.
                // The maximum possible value for x+2k+1 is n.

                // The loop for l_val can be optimized.
                // We only need to update min_r_for_l[x+1] with x+2k+1.
                // The propagation for smaller l_val will be handled in the next step.
                min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 2 * k + 1);
            }
        }
    }

    // Propagate minimum r values:
    // If min_r_for_l[l] is R, then for any l' < l, min_r_for_l[l'] must be <= R.
    // This is because if [l, R] contains a bad triplet, then [l', R] also contains it.
    // So, min_r_for_l[l] = min(min_r_for_l[l], min_r_for_l[l+1]).
    // We iterate from n-1 down to 1.
    for (int l = n - 1; l >= 1; --l) {
        min_r_for_l[l] = std::min(min_r_for_l[l], min_r_for_l[l + 1]);
    }

    long long total_count = 0;
    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If there is at least one valid r for this l
            // All r from min_r_for_l[l] to n are valid for this l.
            // Number of such r values is n - min_r_for_l[l] + 1.
            total_count += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
    int partition;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one partition (e.g., partition 1)
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-2].value + elements[n-1].value
    // goodness = max_f - min_f
    long long goodness_all_same = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);

    std::vector<int> best_partition(n);
    for (int i = 0; i < n; ++i) {
        best_partition[elements[i].original_index] = 1;
    }
    long long min_goodness = goodness_all_same;

    // Case 2: Try to put elements[0] in one partition (e.g., 1) and elements[1] in another (e.g., 2)
    // This forces f(elements[0], elements[1]) = elements[0].value + elements[1].value + h
    // To minimize max_f - min_f, we want to make min_f as large as possible and max_f as small as possible.
    //
    // Consider a partition where elements[0] is in S1, elements[1] is in S2.
    // The smallest possible sum within a partition is elements[0].value + elements[2].value (if S1 has elements[0], elements[2])
    // or elements[1].value + elements[2].value (if S2 has elements[1], elements[2])
    // The smallest possible sum across partitions is elements[0].value + elements[1].value + h
    //
    // Let's try a specific partition:
    // elements[0] in S1
    // elements[1] in S2
    // elements[2]...elements[n-1] in S2
    //
    // Values of f:
    // 1. elements[0].value + elements[1].value + h (between S1 and S2)
    // 2. elements[0].value + elements[k].value + h for k >= 2 (between S1 and S2)
    // 3. elements[j].value + elements[k].value for j,k >= 1 (within S2)
    //
    // min_f candidates:
    //   elements[0].value + elements[1].value + h
    //   elements[1].value + elements[2].value (if n >= 3)
    //   elements[0].value + elements[2].value + h (if n >= 3)
    //
    // max_f candidates:
    //   elements[n-2].value + elements[n-1].value
    //   elements[0].value + elements[n-1].value + h
    //
    // Let's analyze two specific partitions that are often optimal for this type of problem:
    //
    // Partition A: elements[0] in S1, all others in S2.
    // min_f_A = min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    // max_f_A = max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)
    //
    // Partition B: elements[0], elements[1] in S1, all others in S2.
    // min_f_B = min(elements[0].value + elements[1].value, elements[0].value + elements[2].value + h, elements[1].value + elements[2].value + h, elements[2].value + elements[3].value)
    // max_f_B = max(elements[0].value + elements[n-1].value + h, elements[1].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)
    //
    // The problem constraints (N up to 10^5) suggest an O(N log N) or O(N) solution.
    // The key observation is that the minimum and maximum values of `a_i + a_j` are always formed by the smallest and largest elements.
    //
    // Let `min_sum_in = elements[0].value + elements[1].value`
    // Let `max_sum_in = elements[n-2].value + elements[n-1].value`
    //
    // If we put all elements in one partition, `min_f = min_sum_in`, `max_f = max_sum_in`. Goodness = `max_sum_in - min_sum_in`.
    //
    // If we split elements, we introduce `+h` terms.
    // The smallest possible `a_i + a_j` is `elements[0].value + elements[1].value`.
    // The largest possible `a_i + a_j` is `elements[n-2].value + elements[n-1].value`.
    //
    // Consider the partition where `elements[0]` is in partition 1, and all other `elements[1...n-1]` are in partition 2.
    //
    // Minimum f value:
    //   - `elements[0].value + elements[1].value + h` (between partitions)
    //   - `elements[1].value + elements[2].value` (within partition 2, if n >= 3)
    //
    // Maximum f value:
    //   - `elements[0].value + elements[n-1].value + h` (between partitions)
    //   - `elements[n-2].value + elements[n-1].value` (within partition 2, if n >= 3)
    //
    // Let's calculate goodness for this specific partition:
    // S1 = {elements[0]}
    // S2 = {elements[1], ..., elements[n-1]}
    //
    // min_f_val:
    //   If n=2: only `elements[0].value + elements[1].value + h`
    //   If n>=3: `std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)`
    //
    // max_f_val:
    //   If n=2: only `elements[0].value + elements[1].value + h`
    //   If n>=3: `std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)`
    //
    // Let's simplify.
    // The minimum possible sum `a_i + a_j` is `elements[0].value + elements[1].value`.
    // The maximum possible sum `a_i + a_j` is `elements[n-2].value + elements[n-1].value`.
    //
    // If we put `elements[0]` in S1 and `elements[1]` in S2, then `elements[0].value + elements[1].value + h` is a value of f.
    //
    // Consider the partition where `elements[0]` is in S1, and all other `elements[1...n-1]` are in S2.
    //
    // The minimum possible `f` value will be `min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)` (if n >= 3, otherwise just the first term).
    // The maximum possible `f` value will be `max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)` (if n >= 3, otherwise just the first term).
    //
    // Let's calculate this goodness:
    long long current_min_f, current_max_f;
    if (n == 2) {
        current_min_f = elements[0].value + elements[1].value + h;
        current_max_f = elements[0].value + elements[1].value + h;
    } else {
        current_min_f = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
        current_max_f = std::max(elements[0].value + elements[n - 1].value + h, elements[n - 2].value + elements[n - 1].value);
    }
    long long goodness_split_first = current_max_f - current_min_f;

    if (goodness_split_first < min_goodness) {
        min_goodness = goodness_split_first;
        best_partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            best_partition[elements[i].original_index] = 2;
        }
    }

    // Consider the partition where `elements[0]` and `elements[1]` are in S1, and all other `elements[2...n-1]` are in S2.
    // This is only possible if n >= 2. If n=2, this is the same as all in S1.
    // If n=3, S1={e0, e1}, S2={e2}.
    // If n=2, this case is identical to the "all same" case.
    if (n >= 3) {
        // S1 = {elements[0], elements[1]}
        // S2 = {elements[2], ..., elements[n-1]}
        //
        // min_f_val:
        //   elements[0].value + elements[1].value (within S1)
        //   elements[0].value + elements[2].value + h (between S1 and S2)
        //   elements[1].value + elements[2].value + h (between S1 and S2)
        //   elements[2].value + elements[3].value (within S2, if n >= 4)
        //
        // max_f_val:
        //   elements[0].value + elements[n-1].value + h (between S1 and S2)
        //   elements[1].value + elements[n-1].value + h (between S1 and S2)
        //   elements[n-2].value + elements[n-1].value (within S2, if n >= 4)
        //
        current_min_f = elements[0].value + elements[1].value; // Smallest within S1
        current_min_f = std::min(current_min_f, elements[0].value + elements[2].value + h); // Smallest between S1 and S2
        current_min_f = std::min(current_min_f, elements[1].value + elements[2].value + h); // Smallest between S1 and S2
        if (n >= 4) {
            current_min_f = std::min(current_min_f, elements[2].value + elements[3].value); // Smallest within S2
        }

        current_max_f = elements[n - 2].value + elements[n - 1].value; // Largest within S2 (if n >= 4)
        current_max_f = std::max(current_max_f, elements[0].value + elements[n - 1].value + h); // Largest between S1 and S2
        current_max_f = std::max(current_max_f, elements[1].value + elements[n - 1].value + h); // Largest between S1 and S2

        // If n=3, S2 only has elements[2]. No pairs within S2.
        if (n == 3) {
            current_max_f = std::max(elements[0].value + elements[2].value + h, elements[1].value + elements[2].value + h);
        }

        long long goodness_split_first_two = current_max_f - current_min_f;

        if (goodness_split_first_two < min_goodness) {
            min_goodness = goodness_split_first_two;
            best_partition[elements[0].original_index] = 1;
            best_partition[elements[1].original_index] = 1;
            for (int i = 2; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // s = s1s2. New string s' = s2s1.
    // s' must be a palindrome and s' != s.
    // This is possible if s is not a "half-palindrome" (e.g., "abccba" is, "otto" is not)
    // and s2s1 is a palindrome.
    // For s2s1 to be a palindrome, s1 must be the reverse of s2.
    // Since s is already a palindrome, s = s_rev.
    // If s1 = s2_rev, then s = s2_rev s2.
    // Then s_rev = s2_rev s2_rev_rev = s2_rev s2.
    // This means s is of the form X X_rev.
    // Example: "otto". s1="ot", s2="to". s2s1="toot". "toot" is palindrome. "toot" != "otto". k=1.
    // Example: "kinnikkinnik". s1="kinnik", s2="kinnik". s2s1="kinnikkinnik". s2s1 == s. Not valid.
    // Example: "nolon". s1="no", s2="lon". s2s1="lonno". Not palindrome.
    // Example: "abccba". s1="abc", s2="cba". s2s1="cbaabc". Palindrome. s2s1 != s. k=1.

    // A simpler check for k=1:
    // If s can be cut into s_prefix and s_suffix such that s_suffix + s_prefix is a palindrome
    // AND s_suffix + s_prefix != s.
    // This is true if there exists *any* cut point i (1 <= i < n) such that s[i...n-1] + s[0...i-1] is a palindrome
    // AND s[i...n-1] + s[0...i-1] != s.
    // Since s is a palindrome, s[0...i-1] is the reverse of s[n-i...n-1].
    // And s[i...n-1] is the reverse of s[0...n-i-1].
    // So s_suffix + s_prefix is a palindrome if and only if s_prefix is the reverse of s_suffix.
    // This means s = s_prefix s_suffix where s_prefix = reverse(s_suffix).
    // Example: "otto". s_prefix="ot", s_suffix="to". reverse("to")="ot". So s_prefix = reverse(s_suffix).
    // Then s_suffix + s_prefix = "to" + "ot" = "toot", which is a palindrome and != "otto". So k=1.
    // Example: "abccba". s_prefix="abc", s_suffix="cba". reverse("cba")="abc". So s_prefix = reverse(s_suffix).
    // Then s_suffix + s_prefix = "cba" + "abc" = "cbaabc", which is a palindrome and != "abccba". So k=1.
    // This condition is equivalent to checking if s is of the form X X_rev.
    // If s is of the form X X_rev, then s_suffix + s_prefix = X_rev X.
    // This is a palindrome. We just need to check if X_rev X != X X_rev.
    // This is true if X != X_rev.
    // If X = X_rev, then s = X X.
    // Example: "kinnikkinnik". X="kinnik". X is not a palindrome. X_rev="kinnik_rev".
    // s_prefix="kinnik", s_suffix="kinnik". s_suffix + s_prefix = "kinnikkinnik" == s. Not valid.
    // The condition for k=1 is that there exists a cut point `i` such that `s.substr(i) + s.substr(0, i)` is a palindrome AND is not equal to `s`.
    // We can iterate through all possible cut points.
    bool found_k1 = false;
    for (int i = 1; i < n; ++i) {
        std::string s_prime = s.substr(i) + s.substr(0, i);
        if (s_prime != s && is_palindrome(s_prime)) {
            found_k1 = true;
            break;
        }
    }
    if (found_k1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    // Check for k=2
    // This means 3 pieces: s = p0 p1 p2.
    // We can rearrange them.
    // The problem statement gives an example: "nolon" -> "no|l|on" -> "on|l|no".
    // "onlno" is a palindrome and != "nolon".
    // This implies that if we can't do it with k=1, we might be able to do it with k=2.
    // The only case where k=2 might be impossible is if all characters in s are the same.
    // If all characters are the same, e.g., "aaaa", "qqqq".
    // Any permutation of substrings will result in the same string "aaaa".
    // So, if all characters are the same, it's impossible.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }
    if (all_same) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Consider s = "nolon". n=5.
    // s[0] = 'n', s[1] = 'o', s[2] = 'l', s[3] = 'o', s[4] = 'n'.
    // Since s is a palindrome, s[i] == s[n-1-i].
    // If not all characters are the same, there must be at least two distinct characters.
    // Since s is a palindrome, if s[0] != s[1], then s[n-1] != s[n-2].
    // If s[0] != s[1], then s[0] != s[n-2] (since s[1] == s[n-2]).
    // If s[0] != s[1], then s[0] != s[n-1] (since s[0] == s[n-1]).
    // If s[0] != s[1], then s[0] != s[n-2].
    // Consider the string s' formed by taking s[1...n-2] and putting s[0] at the end and s[n-1] at the beginning.
    // s' = s[n-1] + s[1...n-2] + s[0].
    // Since s is a palindrome, s[n-1] == s[0].
    // So s' = s[0] + s[1...n-2] + s[0]. This is just s.
    // This doesn't work.

    // Let's use the example "nolon".
    // s = "nolon".
    // Cut: "no" | "l" | "on". Pieces: p0="no", p1="l", p2="on".
    // Rearrange: p2 | p1 | p0 = "on" | "l" | "no" = "onlno".
    // "onlno" is a palindrome. "onlno" != "nolon".
    // This is a k=2 solution.

    // Why is k=2 always possible if not all characters are the same?
    // If not all characters are the same, then there exists some `i` such that `s[i] != s[0]`.
    // Since `s` is a palindrome, `s[i] == s[n-1-i]`.
    // If `s[i] != s[0]`, then `s[n-1-i] != s[0]`.
    // This means `s` is not of the form `c c ... c`.
    // Consider the string `s_middle = s.substr(1, n-2)`.
    // `s_middle` is also a palindrome.
    // If `s_middle` is not empty (i.e., `n > 2`), we can form `s[n-1] + s_middle + s[0]`.
    // Since `s[n-1] == s[0]`, this is `s[0] + s_middle + s[0]`, which is `s`.
    // This is not a new string.

    // The key insight for k=2 is that if not all characters are the same,
    // then there must be at least one character `c` such that `s[0] != c` and `c` appears in `s`.
    // Since `s` is a palindrome, `s[0] == s[n-1]`.
    // If `n` is odd, `n = 2m+1`. `s = s_0 s_1 ... s_m ... s_1 s_0`.
    // If `n` is even, `n = 2m`. `s = s_0 s_1 ... s_{m-1} s_{m-1} ... s_1 s_0`.
    // Consider the string `s_prefix = s.substr(0, n/2)`.
    // If `s_prefix` is not all the same character, then there exists `j < n/2` such that `s[j] != s[0]`.
    // If `s_prefix` is all the same character, then `s = s[0]...s[0]s[0]...s[0]`.
    // This means all characters in `s` are the same, which we've already handled.
    // So, if not all characters are the same, then `s_prefix` must contain at least two distinct characters.
    // This means there is some `j < n/2` such that `s[j] != s[0]`.
    // Since `s` is a palindrome, `s[j] == s[n-1-j]`.
    // So `s[n-1-j] != s[0]`.
    // This means `s` has at least two distinct characters, and these distinct characters are not just at the ends.
    // For example, "abacaba". `s[0]='a'`, `s[1]='b'`. `s[1] != s[0]`.
    // Cut `s` into `s[0]`, `s[1...n-2]`, `s[n-1]`.
    // Pieces: `s[0]`, `s.substr(1, n-2)`, `s[n-1]`.
    // Rearrange to `s[n-1] + s.substr(1, n-2) + s[0]`.
    // This is `s[0] + s.substr(1, n-2) + s[0]`, which is `s`. This doesn't work.

    // The example "nolon" -> "onlno" uses cuts `no|l|on`.
    // This is `s[0...1] | s[2] | s[3...4]`.
    // Pieces: `s[0...1]`, `s[2]`, `s[3...4]`.
    // Rearranged: `s[3...4] + s[2] + s[0...1]`.
    // `s[3...4]` is `on`. `s[2]` is `l`. `s[0...1]` is `no`.
    // Result: `onlno`. This is a palindrome.
    // This is a specific type of cut: `s[0...i-1] | s[i...n-1-i] | s[n-i...n-1]`.
    // And then rearrange to `s[n-i...n-1] | s[i...n-1-i] | s[0...i-1]`.
    // Let `P1 = s[0...i-1]`, `P2 = s[i...n-1-i]`, `P3 = s[n-i...n-1]`.
    // Since `s` is a palindrome, `P1` is the reverse of `P3`.
    // So `P3 + P2 + P1` is `reverse(P1) + P2 + P1`.
    // For this to be a palindrome, `reverse(P1) + P2 + P1` must be equal to `reverse(P1) + reverse(P2) + reverse(reverse(P1))`.
    // Which means `reverse(P1) + P2 + P1` must be equal to `reverse(P1) + reverse(P2) + P1`.
    // This implies `P2` must be a palindrome.
    // In the "nolon" example: `i=2`. `P1="no"`, `P2="l"`, `P3="on"`.
    // `P2="l"` is a palindrome. `P3+P2+P1 = "onlno"`. This is a palindrome.
    // And "onlno" != "nolon".
    // This works if `P2` is a palindrome and `P3+P2+P1 != s`.
    // `P3+P2+P1 = reverse(P1) + P2 + P1`.
    // `s = P1 + P2 + P3 = P1 + P2 + reverse(P1)`.
    // We need `reverse(P1) + P2 + P1 != P1 + P2 + reverse(P1)`.
    // This is true if `P1 != reverse(P1)`.
    // If `P1` is not a palindrome, then `P1 != reverse(P1)`.
    // If `P1` is a palindrome, then `P1 = reverse(P1)`.
    // Then `reverse(P1) + P2 + P1 = P1 + P2 + P1`.
    // And `P1 + P2 + reverse(P1) = P1 + P2 + P1`.
    // In this case, the new string is equal to the original string.
    // So, this strategy works if we can find an `i` such that:
    // 1. `P2 = s.substr(i, n-2*i)` is a palindrome.
    // 2. `P1 = s.substr(0, i)` is NOT a palindrome.
    // This requires `n-2*i >= 0`, so `i <= n/2`.
    // We need to find such an `i` where `1 <= i <= n/2`.
    // If `n` is odd, `n=2m+1`. `i` can go up to `m`. `P2` would be `s.substr(m, 1)`.
    // If `n` is even, `n=2m`. `i` can go up to `m-1`. `P2` would be `s.substr(m-1, 2)`.
    // The middle part `P2` is always a palindrome because `s` is a palindrome.
    // `s.substr(i, n-2*i)` is a substring of a palindrome, symmetric around the center of `s`.
    // So `s.substr(i, n-2*i)` is always a palindrome.
    // Thus, we just need to find an `i` such that `1 <= i <= n/2` and `s.substr(0, i)` is NOT a palindrome.
    // If such an `i` exists, then `k=2` is possible.
    // If for all `i` from `1` to `n/2`, `s.substr(0, i)` IS a palindrome,
    // then `s[0...0]` is a palindrome (always true).
    // `s[0...1]` is a palindrome.
    // `s[0...2]` is a palindrome.
    // ...
    // `s[0...n/2-1]` is a palindrome.
    // This implies that `s[0] == s[1] == s[2] == ... == s[n/2-1]`.
    // Because if `s[0...j]` is a palindrome, then `s[0] == s[j]`.
    // If `s[0...j+1]` is a palindrome, then `s[0] == s[j+1]`.
    // So if all prefixes `s[0...i-1]` for `1 <= i <= n/2` are palindromes,
    // then `s[0] == s[1] == ... == s[n/2-1]`.
    // Since `s` itself is a palindrome, `s[j] == s[n-1-j]`.
    // This means `s[0] == s[1] == ... == s[n-1]`.
    // So, if all characters are the same, then `s.substr(0, i)` is always a palindrome.
    // If not all characters are the same, then there must be some `j` such that `s[j] != s[0]`.
    // Let `j_min` be the smallest such `j`.
    // Then `s.substr(0, j_min+1)` is not a palindrome (because `s[0] != s[j_min]`).
    // If `j_min < n/2`, then we can pick `i = j_min+1`.
    // Then `s.substr(0, i)` is not a palindrome.
    // This means `k=2` is possible.
    // The only case where `j_min >= n/2` is if `s[0] == s[1] == ... == s[n/2-1]`.
    // But if `s` is not all same characters, then there must be some `j` such that `s[j] != s[0]`.
    // If `j >= n/2`, then `s[n-1-j]` is also not equal to `s[0]`.
    // And `n-1-j < n/2`. This contradicts `j_min >= n/2`.
    // Therefore, if not all characters are the same, there must exist `j_min < n/2` such that `s[j_min] != s[0]`.
    // This implies that `s.substr(0, j_min+1)` is not a palindrome.
    // So we can always find such an `i` (namely `j_min+1`).
    // Thus, if not all characters are the same, `k=2` is always possible.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n && p_idx < m; ++h_idx) {
        long long current_head_pos = h[h_idx];
        long long head_left_reach = current_head_pos - T;
        long long head_right_reach = current_head_pos + T;

        // If the current head cannot reach the current target track p[p_idx],
        // it means this head is too far to the left or T is too small.
        // We need to find a head that can reach p[p_idx].
        // If p[p_idx] is already beyond head_right_reach, this head cannot cover it.
        // We must advance p_idx until it's within reach or we run out of heads.
        if (p[p_idx] > head_right_reach) {
            continue; // This head cannot reach p[p_idx], try next head
        }

        // This head can potentially cover p[p_idx].
        // We want to cover as many tracks as possible to the right using this head.
        // The head can cover tracks in the range [max(p[p_idx], head_left_reach), head_right_reach].
        // The actual range covered by this head is [current_head_pos - T, current_head_pos + T].
        // We need to cover p[p_idx], and then subsequent p_k's.
        // The head can cover all p_k such that p_k <= head_right_reach.
        // If p[p_idx] is to the left of head_left_reach, this head cannot cover p[p_idx]
        // without moving left. But we are trying to cover p[p_idx] with this head.
        // The head can cover p[p_idx] if p[p_idx] is in [current_head_pos - T, current_head_pos + T].
        // If p[p_idx] < current_head_pos - T, this head cannot cover p[p_idx].
        // This implies that the previous head should have covered p[p_idx] or T is too small.
        // But we are iterating heads from left to right.
        // If p[p_idx] is not covered by previous heads, and current head cannot reach it,
        // then it's impossible.

        // The crucial part: if p[p_idx] is covered by the current head,
