        //    Specifically, if a divides b, then b = k*a for some integer k.
        //    Since a != b, k must be >= 2.
        //    So b >= 2a.
        //    If a > 2n, then b >= 2a > 2*(2n) = 4n.
        //    But all chosen numbers are <= 4n.
        //    This means no chosen 'a' can divide another chosen 'b'.
        // We need to pick n such numbers.
        // The available even numbers in the range (2n, 4n] are:
        // 2n+2, 2n+4, ..., 4n.
        // Let's count how many there are:
        // (4n - (2n+2))/2 + 1 = (2n-2)/2 + 1 = n-1+1 = n.
        // So there are exactly n even numbers in this range.
        // These are the numbers we should pick.

        for (int i = 0; i < n; ++i) {
            std::cout << 2 * (n + 1 + i) << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

