int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k; // k can be up to 10^4, sum of k over test cases 10^4.
                     // a_i can be up to k.
                     // (k - a_j) / a_min_val can be up to (10^4 - 1) / 1 = 9999.
                     // n can be up to 1000.
                     // Total operations can be (n-1) * 9999 ~ 1000 * 10000 = 10^7.
                     // long long for total_spells is appropriate.
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = k + 1; // Initialize with a value larger than any possible a_i
        int min_idx = -1;

        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_spells = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself, and we are using min_val as source
            }
            // For each other pile a[i], we can add min_val to it as many times as possible
            // without exceeding k.
            // The number of times is (k - current_a_i) / min_val.
            total_spells += (k - a[i]) / min_val;
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

