int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;
    int count_n = 0;

    for (char c : s) {
        if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        } else if (c == 'n') {
            count_n++;
        }
    }

    // To form "one": needs 'o', 'n', 'e'
    // To form "zero": needs 'z', 'e', 'r', 'o'

    // Maximize 1s first
    int num_ones = count_n; // 'n' is unique to "one" among 'o', 'n', 'e' for "one" and 'z', 'e', 'r', 'o' for "zero"
                            // If we have 'n', it must be used for "one".
                            // The number of 'o's and 'e's must also be sufficient.
                            // However, 'n' is the most restrictive for "one" if we consider all letters.
                            // Let's re-evaluate.
                            // 'n' is only used in "one". So, count_n directly gives the max number of "one"s.
                            // The other letters 'o' and 'e' are shared.
                            // If we have `k` 'n's, we can form `k` "one"s.
                            // This uses `k` 'o's and `k` 'e's.

    num_ones = count_n; // Each 'n' must form a '1'.

    // After forming num_ones '1's, we use up:
    // num_ones 'o's
    // num_ones 'n's
    // num_ones 'e's

    // Remaining letters for '0's:
    // 'z's: count_z
    // 'e's: count_e - num_ones
    // 'r's: count_r
    // 'o's: count_o - num_ones

    // To form "zero": needs 'z', 'e', 'r', 'o'
    // The number of "zero"s is limited by the minimum of available 'z', 'e', 'r', 'o'.
    int num_zeros = std::min({count_z, count_e - num_ones, count_r, count_o - num_ones});
    // Note: count_e - num_ones and count_o - num_ones could be negative if num_ones was too large.
    // However, num_ones is count_n.
    // The problem guarantees that it is possible to rearrange the letters.
    // This implies that count_o >= num_ones and count_e >= num_ones.
    // So, count_e - num_ones >= 0 and count_o - num_ones >= 0.

    bool first_output = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_output) {
            std::cout << " ";
        }
        std::cout << 1;
        first_output = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_output) {
            std::cout << " ";
        }
        std::cout << 0;
        first_output = false;
    }
    std::cout << std::endl;

    return 0;
}

