    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks required for k torches:
        // k sticks for the torches themselves
        // k * y sticks to buy k coal
        // So, total_sticks_required = k + k * y
        long long total_sticks_required = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_required - 1) additional sticks
        // using the first trade offer.
        long long sticks_to_gain = total_sticks_required - 1;

        // Each trade of type 1 (1 stick -> x sticks) gives a net gain of (x - 1) sticks.
        // Number of type 1 trades needed = ceil(sticks_to_gain / (x - 1))
        // Using integer division: (A + B - 1) / B for ceil(A/B)
        long long num_type1_trades = (sticks_to_gain + (x - 1) - 1) / (x - 1);

        // Total trades = number of type 1 trades + number of type 2 trades
        // Number of type 2 trades is k (to get k coal)
        long long total_trades = num_type1_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by this power of two
        // up to 2048. For example, if we have three 512s,
        // we can combine two 512s to get 1024, and then we have one 512 left.
        // The 1024 can be added to the sum.
        // The remaining 512 can also be added.
        // Effectively, we are summing up all numbers that are <= 2048.
        // The operations allow us to consolidate smaller numbers into larger ones.
        // The total sum of numbers <= 2048 is what matters.
        // If this sum is >= 2048, we can always form 2048.
        // Example: {1024, 512, 512}. Sum = 2048.
        // Combine 512, 512 -> 1024. Multiset becomes {1024, 1024}.
        // Combine 1024, 1024 -> 2048.
        // Example: {1024, 1024}. Sum = 2048.
        // Combine 1024, 1024 -> 2048.
        // Example: {1, 1, ..., 1} (2048 times). Sum = 2048.
        // We can combine pairs of 1s to get 2s, pairs of 2s to get 4s, etc.,
        // until we get 2048.
        current_sum += val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

