}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s, t;
    std::cin >> s >> t;

    // If the strings are already equal, it's possible.
    if (s == t) {
        std::cout << "YES\n";
        return;
    }

    // The operation allows any character to propagate to an adjacent position.
    // This means if a character 'c' exists anywhere in string s,
    // it can eventually be made to appear at any position in s,
    // provided there's a path of adjacent operations.
    // However, the problem asks if s can be transformed into t.
    // This implies that we need to find a common character that can be
    // propagated throughout both strings to make them identical.
    //
    // If there is at least one common character between string s and string t,
    // say character 'x', then:
    // 1. In string s, 'x' can be propagated to any position.
    //    For example, if s = "axb", we can make it "xxx" by:
    //    s_1 = s_2 -> "xxb"
    //    s_3 = s_2 -> "xxx"
    //    This means if 'x' exists in s, we can transform s into "xxx...x".
    // 2. Similarly, if 'x' exists in string t, we can transform t into "xxx...x".
    //
    // Therefore, if there is at least one character that exists in both string s
    // AND string t, then we can transform both s and t into a string consisting
    // solely of that common character. For example, if 'a' is in s and 'a' is in t,
    // we can make s become "aaa...a" and t become "aaa...a".
    // Since both strings would then be equal, the answer is YES.
    //
    // If there is NO common character between string s and string t,
    // then no such 'x' exists. In this case, we cannot pick a character
    // that is present in both strings to make them identical.
    // Any character 'c' present only in s cannot be used to transform t
    // because 'c' is not in t. Similarly for characters only in t.
    // Thus, if there's no common character, it's impossible.

    // We can use a frequency array (or a boolean array) for characters 'a' through 'z'.
    std::vector<bool> s_chars(26, false);
    for (char c : s) {
        s_chars[c - 'a'] = true;
    }

    bool common_char_found = false;
    for (char c : t) {
        if (s_chars[c - 'a']) {
            common_char_found = true;
            break;
        }
    }

    if (common_char_found) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

