    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_dist = 0;
        int last_R_pos = 0; // Represents the last position from which a right jump was possible (or start at 0)

        // Iterate through the string, considering positions 1 to n.
        // The string s has characters s_1 to s_n.
        // In 0-indexed string, s[i-1] corresponds to cell i.
        // We are interested in the distance between consecutive 'R' cells (or 0 and first 'R', or last 'R' and n+1).
        // The frog can always jump from 0 to any cell up to d.
        // If it lands on an 'R' cell, say cell i, it can jump to any cell in [i+1, min(n+1, i+d)].
        // If it lands on an 'L' cell, it can only jump left. This means to make progress,
        // it must have jumped *over* this 'L' cell from a previous 'R' cell.
        // So, effectively, the frog must be able to jump from the last 'R' cell (or 0)
        // to the next 'R' cell (or n+1), skipping any 'L' cells in between.

        // The positions we care about are 0, and then all indices i+1 where s[i] == 'R', and finally n+1.
        // Let's collect these "safe" positions.
        // The distance between two consecutive safe positions must be <= d.
        // The maximum of these distances will be the minimum d required.

        // Add 0 as the starting point.
        // Then add all indices i+1 where s[i] == 'R'.
        // Finally, add n+1 as the destination.

        std::vector<int> safe_positions;
        safe_positions.push_back(0);

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                safe_positions.push_back(i + 1);
            }
        }
        safe_positions.push_back(n + 1);

        for (size_t i = 0; i < safe_positions.size() - 1; ++i) {
            max_dist = std::max(max_dist, safe_positions[i+1] - safe_positions[i]);
        }

        std::cout << max_dist << "\n";
    }
    return 0;
}

