int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any p[i] is 0. If so, it means all a[i][j] for j!=i were 0.
    // This implies p[i] must be 1 (the smallest possible value in a permutation).
    // This case happens if n=2 and a is {{0,1},{1,0}}. Then p[0]=1, p[1]=1.
    // Or if n=2 and a is {{0,0},{0,0}}. This is not possible as values are 1 to n.
    // The problem states values are 1 to n. So if max_val_in_row is 0, it means
    // all a[i][j] for j!=i were 0. This can only happen if n=1, but n>=2.
    // For n>=2, the smallest possible value for any p[i] is 1.
    // If p[i] is 1, then for any j!=i, a[i][j] = min(p[i], p[j]) = min(1, p[j]) = 1.
    // So if max_val_in_row is 0, it means all a[i][j] for j!=i were 0.
    // This is only possible if n=1, which is not allowed.
    // The only way max_val_in_row can be 0 is if n=1, but n>=2.
    // So max_val_in_row will always be at least 1 for n>=2.
    // The only case where p[i] could be 0 is if all a[i][j] for j!=i are 0.
    // This would mean p[i] is 0, which is not allowed in a permutation of 1 to n.
    // The problem guarantees a solution exists.
    // The only scenario where max_val_in_row could be less than n is if p[i] is not n.
    // If p[i] is n, then max_val_in_row could be n or less.
    // If p[i] is not n, then there must be some p[k] = n.
    // For that k, p[k] = n. Then for any j!=k, a[k][j] = min(n, p[j]) = p[j].
    // So max_val_in_row for index k would be max(p[j] for j!=k).
    // This max would be n-1 if n is present in p.
    // This logic is getting complicated. Let's simplify.

    // The values in p are from 1 to n.
    // If all p[i] are distinct and cover 1 to n, then one of them must be n.
    // Let's say p[k] = n.
    // Then for any j != k, a[k][j] = min(p[k], p[j]) = min(n, p[j]) = p[j].
    // So, max_{j != k} (a[k][j]) = max_{j != k} (p[j]).
    // Since p is a permutation of 1 to n, and p[k]=n, the set {p[j] | j != k} is {1, 2, ..., n-1}.
    // Thus, max_{j != k} (p[j]) = n-1.
    // So, if p[k] = n, then max_val_in_row for index k will be n-1.

    // If p[i] is not n, then p[i] < n.
    // For any j != i, a[i][j] = min(p[i], p[j]).
    // So, max_{j != i} (a[i][j]) <= p[i].
    // Also, there must be some j_0 such that p[j_0] >= p[i].
    // If p[j_0] >= p[i], then a[i][j_0] = min(p[i], p[j_0]) = p[i].
    // So, max_{j != i} (a[i][j]) = p[i].

    // Combining these:
    // If p[i] = n, then max_val_in_row for index i is n-1.
    // If p[i] < n, then max_val_in_row for index i is p[i].

    // This means that if we calculate max_val_in_row for each i,
    // exactly one of these values will be n-1 (corresponding to p[i]=n),
    // and all other values will be p[i] (corresponding to p[i]<n).
    // So, we can identify the element that should be n.
    // All other elements are already correctly determined as p[i] = max_val_in_row.

    bool n_assigned = false;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n - 1 && !n_assigned) {
            // This is the candidate for p[i] = n.
            // We need to check if n has already been assigned.
            // If there are multiple (n-1)s, only one can be n.
            // The problem guarantees a solution, so there will be exactly one such case.
            // Or, if n=2, p[0]=1, p[1]=1. One of them should be 2.
            // If n=2, a={{0,1},{1,0}}. max_val_in_row for both is 1.
            // So p becomes {1,1}. One of them must be 2.
            // The logic is: if n is not present in the calculated p values,
            // then one of the (n-1) values must be n.
            // If n is present, then all values are correct.
            // The problem guarantees a solution.
            // The values in p are max_j!=i(min(p_i, p_j)).
            // If p_i = N, then max_j!=i(min(N, p_j)) = max_j!=i(p_j) = N-1.
            // If p_i < N, then max_j!=i(min(p_i, p_j)) = p_i.
            // So, the values in our `p` array (calculated as max_val_in_row)
            // will contain all values from 1 to N-1, and one value of N-1 (for the N).
            // So, we need to find the missing value (N) and replace one of the N-1s.

            // Count occurrences of each value in p.
            // If n is not present, then one of the (n-1)s must be n.
            // The problem guarantees a solution.
            // The values in p are max_val_in_row.
            // If n is not present in the set {p[0], ..., p[n-1]},
            // then one of the p[i] values that is n-1 must actually be n.
            // Since the problem guarantees a solution, there will be exactly one such case.
            // We can find the maximum value in the current `p` array.
            // If this maximum is less than n, then we need to change one of the elements.
            // The element that should be changed is the one that corresponds to the actual 'n' in the permutation.
            // This element will have max_val_in_row = n-1.
            // So, we find the first occurrence of n-1 and change it to n.
            // This is only if n is not already present in the `p` array.

            // Let's check if 'n' is present in the current `p` array.
            bool found_n = false;
            for (int k = 0; k < n; ++k) {
                if (p[k] == n) {
                    found_n = true;
                    break;
                }
            }

            if (!found_n) {
                // If 'n' is not found, it means the element that should be 'n'
                // currently has a value of 'n-1' in our `p` array.
                // We need to find one such 'n-1' and change it to 'n'.
                // Since there's guaranteed to be a solution, there will be at least one 'n-1'.
                // We can just pick the first one.
                p[i] = n;
                n_assigned = true; // Mark that we've assigned 'n'
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_values.insert(q[0]);

    // For i from 1 to n-1
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is strictly greater than q_{i-1}, then p_i must be q_i.
            // This is because q_i = max(q_{i-1}, p_i), so p_i must be at least q_i.
            // And p_i cannot be greater than q_i because q_i is the maximum up to p_i.
            p[i] = q[i];
            if (used_values.count(p[i])) {
                // This should not happen if q is valid, as q_i is increasing.
                // But as a safety check.
                possible = false;
                break;
            }
            used_values.insert(p[i]);
        } else {
            // If q_i == q_{i-1}, then p_i must be some value <= q_i (which is q_{i-1}).
            // We need to pick the smallest available value that is not yet used.
            // The values available are 1 to n, excluding those already in p_1...p_{i-1}.
            // We need to find the smallest unused value that is <= q_i.
            // The largest possible value for p_i in this case is q_i.
            // We will fill these positions later with remaining unused values.
            p[i] = 0; // Mark as placeholder for now
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Collect all unused values from 1 to n
    std::vector<int> unused_nums;
    for (int i = 1; i <= n; ++i) {
        if (used_values.find(i) == used_values.end()) {
            unused_nums.push_back(i);
        }
    }
    std::sort(unused_nums.rbegin(), unused_nums.rend()); // Sort in descending order for greedy assignment

    // Fill in the placeholders (p[i] == 0)
    for (int i = 1; i < n; ++i) {
        if (p[i] == 0) {
            if (unused_nums.empty()) {
                possible = false; // Not enough unused numbers
                break;
            }
            int val_to_assign = unused_nums.back();
            unused_nums.pop_back();

            // Check if the assigned value satisfies the condition p_i <= q_i
            // Since we are picking the smallest available, this is the best chance.
            // If even the smallest available is too large, it's impossible.
            if (val_to_assign > q[i]) {
                possible = false;
                break;
            }
            p[i] = val_to_assign;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        // Final check: ensure all p_i are distinct and within [1, n]
        // This is implicitly handled by using a set for used_values and filling from unused_nums.
        // Also, check if the constructed p generates the given q.
        // This is the crucial part.
        int current_max = 0;
        for (int i = 0; i < n; ++i) {
            current_max = std::max(current_max, p[i]);
            if (current_max != q[i]) {
                possible = false;
                break;
            }
        }

        if (!possible) {
            std::cout << -1 << "\n";
        } else {
            for (int i = 0; i < n; ++i) {
                std::cout << p[i] << (i == n - 1 ? "" : " ");
            }
            std::cout << "\n";
        }
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

