int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_stair_cells = 1; // Cells for a 1-stair staircase
        long long k_val = 1; // Represents 2^k - 1, starting with k=1 (n=1)

        while (true) {
            // Calculate cells for the next nice staircase (n = 2*k_val + 1)
            // This is equivalent to n = 2^(k+1) - 1
            // The number of cells for a staircase with n stairs is n * (n + 1) / 2
            // For n = 2^k - 1, the number of cells is (2^k - 1) * (2^k) / 2
            // Let m = 2^k. Then cells = (m-1)*m/2.
            // The problem states that the cost of a staircase with n stairs is (2^k - 1) * 2^k / 2
            // where n = 2^k - 1.
            // The sequence of n values for nice staircases is 1, 3, 7, 15, ... (2^k - 1)
            // The sequence of cells for these staircases is:
            // n=1: 1 * 2 / 2 = 1
            // n=3: 3 * 4 / 2 = 6
            // n=7: 7 * 8 / 2 = 28
            // n=15: 15 * 16 / 2 = 120
            // The cost of the *next* staircase is (2*k_val + 1) * (2*k_val + 2) / 2
            // which simplifies to (2*k_val + 1) * (k_val + 1)
            // This is the cost of a staircase with n = 2^(k+1) - 1 stairs.
            // The current k_val is 2^k - 1.
            // The next k_val will be 2^(k+1) - 1.
            // The cost of the staircase with n = 2^(k+1) - 1 stairs is (2^(k+1) - 1) * (2^(k+1)) / 2.
            // Let's use the variable `k_val` to represent `2^k - 1`.
            // So, for the first staircase, k_val = 1 (n=1). Cost = 1.
            // For the second staircase, k_val = 3 (n=3). Cost = 6.
            // For the third staircase, k_val = 7 (n=7). Cost = 28.
            // The cost of the staircase with `n` stairs is `n * (n + 1) / 2`.
            // If `n = 2^k - 1`, then `n+1 = 2^k`.
            // So cost is `(2^k - 1) * 2^k / 2`.
            // Let's track `k_val` as `2^k - 1`.
            // The cost of the staircase corresponding to `k_val` is `k_val * (k_val + 1) / 2`.
            // The next `k_val` will be `2 * k_val + 1`.

            long long cost_of_current_staircase = k_val * (k_val + 1) / 2;

            if (x >= cost_of_current_staircase) {
                x -= cost_of_current_staircase;
                count++;
                // Calculate the next k_val (which is 2 * current_k_val + 1)
                // This corresponds to the next nice staircase size (2^(k+1) - 1)
                // Check for overflow before multiplying
                if (k_val > (2000000000000000000LL / 2)) { // x is up to 10^18, so k_val can be large.
                                                            // k_val * (k_val+1)/2 can be up to 10^18.
                                                            // k_val can be up to sqrt(2 * 10^18) approx 1.4 * 10^9.
                                                            // 2 * k_val + 1 can be up to 2.8 * 10^9.
                                                            // This fits in long long.
                                                            // The next cost (2*k_val+1)*(2*k_val+2)/2 could overflow.
                                                            // (2*k_val+1)*(k_val+1)
                                                            // If k_val is 1.4 * 10^9, then (2*k_val+1)*(k_val+1) is approx (2.8*10^9)*(1.4*10^9) = 3.92 * 10^18.
                                                            // This is fine for long long.
                                                            // The next k_val itself (2*k_val+1) can be up to 2.8 * 10^9.
                                                            // The next cost calculation: (next_k_val * (next_k_val + 1) / 2)
                                                            // If next_k_val is 2.8 * 10^9, then next_k_val * (next_k_val + 1) is approx (2.8*10^9)^2 = 7.84 * 10^18.
                                                            // This is fine for long long.
                                                            // The maximum value for k_val is when cost_of_current_staircase is around 10^18.
                                                            // k_val * (k_val + 1) / 2 approx 10^18 => k_val^2 approx 2 * 10^18 => k_val approx 1.414 * 10^9.
                                                            // The next k_val would be 2 * (1.414 * 10^9) + 1 approx 2.828 * 10^9.
                                                            // The cost for this next k_val would be (2.828 * 10^9) * (2.828 * 10^9 + 1) / 2 approx 4 * 10^18.
                                                            // This is still within long long range (max approx 9 * 10^18).
                                                            // So, direct multiplication is fine.
                    break; // Prevent overflow if k_val gets too large for the next cost calculation
                }
                k_val = 2 * k_val + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

