#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = n;

    // The strategy is to generate k-1 distinct differences first,
    // and then fill the rest of the permutation with differences of 1.
    // We achieve k-1 distinct differences by alternating between
    // the smallest available number and the largest available number.
    // This generates differences: (n-1), (n-2), ..., (n-k+1).
    // For example, if n=5, k=3:
    // k-1 = 2. We want 2 distinct large differences.
    // p_1 = 1, p_2 = 5. Diff = 4. (k-1=2, so 2nd largest diff)
    // p_3 = 2. Diff = 3. (k-1=1, so 1st largest diff)
    // Now we have used 1, 5, 2. Remaining: 3, 4.
    // We have generated differences 4, 3. These are k-1 distinct differences.
    // The remaining elements should be filled to produce difference 1.
    // So, p_4 = 3, p_5 = 4.
    // Final permutation: 1 5 2 3 4.
    // Differences: |1-5|=4, |5-2|=3, |2-3|=1, |3-4|=1.
    // Distinct differences: {1, 3, 4}. Count = 3. This matches k.

    for (int i = 0; i < k; ++i) {
        if (i % 2 == 0) { // Take from left (smallest available)
            std::cout << left << " ";
            left++;
        } else { // Take from right (largest available)
            std::cout << right << " ";
            right--;
        }
    }

    // After generating k elements using the alternating strategy,
    // we have generated k-1 distinct differences.
    // The remaining n-k elements should be printed in increasing or decreasing order
    // to produce only difference 1.
    // The last element printed determines whether we continue from 'left' or 'right'.
    // If the last element was 'left-1', we continue with 'left', 'left+1', ...
    // If the last element was 'right+1', we continue with 'right', 'right-1', ...
    // In our loop, if i is even, we print left and increment left.
    // If i is odd, we print right and decrement right.
    // So, if k is odd, the last element printed was 'left-1'. We continue with 'left'.
    // If k is even, the last element printed was 'right+1'. We continue with 'right'.

    if (k % 2 == 1) { // Last element printed was from 'left' side (e.g., 1, 2, 3...)
        // Print remaining elements in increasing order
        for (int i = left; i <= right; ++i) {
            std::cout << i << (i == right ? "" : " ");
        }
    } else { // Last element printed was from 'right' side (e.g., n, n-1, n-2...)
        // Print remaining elements in decreasing order
        for (int i = right; i >= left; --i) {
            std::cout << i << (i == left ? "" : " ");
        }
    }
    std::cout << std::endl;

    return 0;
}

