#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This marks the end of the initial non-decreasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now `a[i...n-1]` is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j] > a[j+1]
    // This marks the end of the initial non-increasing suffix
    // starting from `i`
    int j = i;
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now `a[j...i]` is non-increasing.
    // The segment `a[j...n-1]` is a "mountain" shape (non-increasing then non-decreasing).

    std::cout << j << std::endl;
}

