int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        std::string s;
        std::cin >> s;
        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        int horz_moves = std::min(counts['L'], counts['R']);
        int vert_moves = std::min(counts['U'], counts['D']);

        std::string result = "";
        int total_moves = 0;

        if (horz_moves == 0 && vert_moves == 0) {
            total_moves = 0;
            result = "";
        } else if (horz_moves == 0) { // Only vertical moves possible
            if (vert_moves > 0) {
                total_moves = 2;
                result = "UD";
            } else {
                total_moves = 0;
                result = "";
            }
        } else if (vert_moves == 0) { // Only horizontal moves possible
            if (horz_moves > 0) {
                total_moves = 2;
                result = "LR";
            } else {
                total_moves = 0;
                result = "";
            }
        } else { // Both horizontal and vertical moves possible
            total_moves = 2 * horz_moves + 2 * vert_moves;
            for (int i = 0; i < horz_moves; ++i) result += 'L';
            for (int i = 0; i < vert_moves; ++i) result += 'U';
            for (int i = 0; i < horz_moves; ++i) result += 'R';
            for (int i = 0; i < vert_moves; ++i) result += 'D';
        }

        std::cout << total_moves << "\n";
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // For m > 1, we extend the segment to include 'm'.
        // The new number 'm' is at pos[m].
        // We need to update current_min_idx and current_max_idx to cover the range [1, ..., m].
        // This means the segment must span from min(pos[1], ..., pos[m]) to max(pos[1], ..., pos[m]).
        if (m > 1) {
            current_min_idx = std::min(current_min_idx, pos[m]);
            current_max_idx = std::max(current_max_idx, pos[m]);
        }

        // A number 'm' is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // contains exactly the numbers 1, 2, ..., m.
        // This is true if and only if the length of this subsegment is exactly 'm'.
        // The length is (current_max_idx - current_min_idx + 1).
        if ((current_max_idx - current_min_idx + 1) == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n <= 2) {
        std::cout << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return;
    }

    std::vector<int> result_subsequence;
    result_subsequence.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum
        // p[i] is a peak if p[i-1] < p[i] and p[i] > p[i+1]
        // p[i] is a valley if p[i-1] > p[i] and p[i] < p[i+1]
        bool is_peak = (p[i] > p[i-1] && p[i] > p[i+1]);
        bool is_valley = (p[i] < p[i-1] && p[i] < p[i+1]);

        if (is_peak || is_valley) {
            result_subsequence.push_back(p[i]);
        }
    }
    result_subsequence.push_back(p[n-1]);

    std::cout << result_subsequence.size() << "\n";
    for (size_t i = 0; i < result_subsequence.size(); ++i) {
        std::cout << result_subsequence[i] << (i == result_subsequence.size() - 1 ? "" : " ");
    }
    std::cout << "\n";
}

