int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int diff_01_count = 0; // count of positions where a[i] = '0', b[i] = '1'
    int diff_10_count = 0; // count of positions where a[i] = '1', b[i] = '0'

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] = '0', b[i] = '1'
                if (diff_10_count > 0) { // We have a '1' at some j where b[j] = '0'
                    cost += 1; // Swap a[i] and a[j] costs 1 (effectively, we pair them up)
                    diff_10_count--; // One '10' mismatch resolved
                } else {
                    diff_01_count++; // No '10' mismatch to pair with, increment '01' mismatch count
                }
            } else { // a[i] = '1', b[i] = '0'
                if (diff_01_count > 0) { // We have a '0' at some j where b[j] = '1'
                    cost += 1; // Swap a[i] and a[j] costs 1
                    diff_01_count--; // One '01' mismatch resolved
                } else {
                    diff_10_count++; // No '01' mismatch to pair with, increment '10' mismatch count
                }
            }
        }
    }

    // After pairing up as many '01' and '10' mismatches as possible with cost 1 each,
    // any remaining mismatches must be resolved by flipping.
    // Each remaining '01' mismatch needs a flip (cost 1).
    // Each remaining '10' mismatch needs a flip (cost 1).
    cost += diff_01_count;
    cost += diff_10_count;

    std::cout << cost << std::endl;

    return 0;
}

