        }
    }

    // 3. Ensure elements to the right of median are >= s
    // Iterate from median_idx + 1 up to n - 1
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        } else {
            // Since the array is sorted, if a[i] >= s,
            // all elements a[i+1]...a[n-1] are also >= s.
            // No further operations needed on the right side.
            break;
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

