#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (a == 1) ans1 = "Ya";
        if (b == 1) ans2 = "Ya";
        if (c == 1) ans3 = "Ya";
        if (d == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
        return;
    }

    // Determine if the final product can be positive or negative.
    // The sign of the final product depends on the parity of negative numbers multiplied.
    // Each multiplication of two negative numbers results in a positive number.
    // Each multiplication of a negative and a positive number results in a negative number.
    // The total number of negative toys is A + B.
    // Each step reduces the total number of toys by 1.
    // The number of multiplications is total_toys - 1.
    // Let N_neg be the count of toys with negative values (from boxes 1 and 2).
    // Let N_pos be the count of toys with positive values (from boxes 3 and 4).
    // The final sign is negative if an odd number of negative values are involved in the final product.
    // This is equivalent to the parity of the initial count of negative toys (A+B).
    // If (A+B) is odd, the final product can be negative.
    // If (A+B) is even, the final product can be positive.
    // However, this is not entirely true. We can choose the order of operations.
    // For example, if we have -2, -0.5, 0.5, 2.
    // A=1, B=1, C=1, D=1. A+B=2 (even).
    // (-2 * -0.5) = 1 (pos)
    // (0.5 * 2) = 1 (pos)
    // (1 * 1) = 1 (pos) -> final positive.
    // But what if we do:
    // (-2 * 0.5) = -1 (neg)
    // (-0.5 * 2) = -1 (neg)
    // (-1 * -1) = 1 (pos) -> final positive.
    // The final sign is always positive if A+B is even.
    // The final sign is always negative if A+B is odd.
    // This is because each multiplication changes the total count of negative numbers by 0 or 2.
    // E.g., neg * neg -> pos (2 negs become 0 negs, change -2)
    //       neg * pos -> neg (1 neg becomes 1 neg, change 0)
    //       pos * pos -> pos (0 negs become 0 negs, change 0)
    // So the parity of negative numbers is invariant.
    // Thus, if (A+B) is odd, the final toy must be negative.
    // If (A+B) is even, the final toy must be positive.

    bool final_can_be_negative = ((a + b) % 2 != 0);
    bool final_can_be_positive = ((a + b) % 2 == 0);

    // Box 1: (-inf, -1]
    // Box 2: (-1, 0)
    // Box 3: (0, 1)
    // Box 4: [1, inf)

    // Can be Box 1 (negative, <= -1)
    // Requires final_can_be_negative.
    // To get <= -1, we need at least one toy with absolute value >= 1.
    // This means A+D > 0.
    // If A+D == 0, all initial toys have absolute value < 1.
    // Product of numbers with absolute value < 1 will always be < 1 (in absolute value).
    // So if A+D == 0, the final toy cannot be in Box 1 or Box 4.
    if (final_can_be_negative && (a + d > 0)) {
        ans1 = "Ya";
    }

    // Can be Box 2 (negative, > -1 and < 0)
    // Requires final_can_be_negative.
    // This is always possible if final_can_be_negative.
    // We can always construct values that result in (-1, 0).
    // E.g., if A+D > 0, we can multiply a large absolute value with a small absolute value.
    // If A+D == 0, all initial toys are in B or C. Their product will be in (-1, 1).
    // If A+D == 0 and final_can_be_negative (i.e., B is odd), then the product will be in (-1, 0).
    if (final_can_be_negative) {
        ans2 = "Ya";
    }

    // Can be Box 3 (positive, > 0 and < 1)
    // Requires final_can_be_positive.
    // This is always possible if final_can_be_positive.
    // Similar logic to Box 2.
    if (final_can_be_positive) {
        ans3 = "Ya";
    }

    // Can be Box 4 (positive, >= 1)
    // Requires final_can_be_positive.
    // To get >= 1, we need at least one toy with absolute value >= 1.
    // This means A+D > 0.
    if (final_can_be_positive && (a + d > 0)) {
        ans4 = "Ya";
    }

    // Special case: If all initial toys are in B and C (i.e., A=0, D=0).
    // All initial toys have absolute value < 1.
    // Any product of such toys will also have absolute value < 1.
    // So, the final toy cannot be in Box 1 or Box 4.
    if (a == 0 && d == 0) {
        ans1 = "Tidak";
        ans4 = "Tidak";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

