// Function to check if a subarray is a permutation
// This function is not used in the optimized solution, but conceptually
// it's what we're trying to achieve with prefix/suffix checks.
/*
bool is_permutation(const std::vector<int>& arr, int start, int end, int length) {
    if (length <= 0) return false;
    std::vector<bool> seen(length + 1, false);
    for (int i = start; i <= end; ++i) {
        if (arr[i] < 1 || arr[i] > length || seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
    }
    return true;
}
*/

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        int current_val = a[i];
        if (current_val < 1 || current_val > n || seen_prefix[current_val]) {
            possible_prefix = false;
        }
        if (possible_prefix) {
            seen_prefix[current_val] = true;
            max_val_prefix = std::max(max_val_prefix, current_val);
            if (max_val_prefix == i + 1) { // If max value seen so far is equal to current length
                is_prefix_perm[i + 1] = true;
            }
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int current_val = a[i];
        int current_len = n - i; // Length of suffix starting at i
        if (current_val < 1 || current_val > n || seen_suffix[current_val]) {
            possible_suffix = false;
        }
        if (possible_suffix) {
            seen_suffix[current_val] = true;
            max_val_suffix = std::max(max_val_suffix, current_val);
            if (max_val_suffix == current_len) { // If max value seen so far is equal to current length
                is_suffix_perm[current_len] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

