char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Determine the most frequent move in the bot's string
        // Prioritize R, then P, then S for tie-breaking if needed,
        // though any tie-breaking is fine as long as it's consistent.
        // The problem statement implies any optimal answer is fine.
        // Let's just iterate through R, P, S and pick the first one with max count.
        // This is equivalent to picking the one that appears first in the string
        // if counts are equal, but we need to check all three.

        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        // If all counts are 0 (empty string, not possible by constraints),
        // or if n=1 and s="R", then most_frequent_bot_move will be 'R'.
        // If n=1 and s="P", then most_frequent_bot_move will be 'P'.
        // If n=1 and s="S", then most_frequent_bot_move will be 'S'.
        // This logic correctly finds the most frequent.

        char our_winning_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w in ascending order

    long long total_happiness = 0;

    // Friends with w_i = 1: they get 2 * largest available numbers
    // These are the friends with the smallest w_i values after sorting.
    // They should get the largest available numbers from 'a'.
    // Iterate w from largest to smallest.
    // Friends with w_i = 1 should get the largest numbers.
    // Friends with w_i > 1 should get the next largest numbers as their max,
    // and the smallest available numbers as their min.

    // The k largest numbers from 'a' will be the 'max_val' for each friend.
    // Add these to total_happiness.
    // These are a[n-1], a[n-2], ..., a[n-k].
    for (int i = 0; i < k; ++i) {
        total_happiness += a[n - 1 - i];
    }

    // Now, we need to assign the 'min_val' for each friend.
    // Friends with w_i = 1: their min_val is the same as their max_val.
    // We already added their max_val (which is also their min_val) once.
    // So, for these friends, we need to add their max_val again.
    // These are the friends with w_i = 1.
    // Since w is sorted, these are at the beginning of the sorted w array.
    // We iterate w from smallest to largest.
    int current_a_idx = 0; // Pointer for the smallest available numbers in 'a'

    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            // This friend received one of the k largest numbers as their max_val.
            // Since w_i = 1, this is also their min_val.
            // We already added it once, so add it again.
            // The largest numbers are a[n-1], a[n-2], ..., a[n-k].
            // The friends with w_i=1 should get the largest of these.
            // Since w is sorted, the friends with w_i=1 are at the beginning.
            // The largest numbers from 'a' are assigned to friends with w_i=1.
            // The largest w_i=1 friends get a[n-1], a[n-2], etc.
            // The smallest w_i=1 friends get a[n-k_prime] where k_prime is count of w_i=1.
            // The problem statement implies that the k largest numbers are assigned as max_val.
            // The specific assignment of which largest number goes to which friend with w_i=1 doesn't matter for sum,
            // as long as they all get one of the k largest.
            // We already added a[n-1-i] for the max_val.
            // For w[i]=1, the max_val is also the min_val. So we add it again.
            // The largest k numbers are a[n-1], a[n-2], ..., a[n-k].
            // The friends with w_i=1 should get the largest of these.
            // The friends with w_i > 1 should get the remaining largest numbers as their max_val.
            // The problem is that w is sorted, so w[0]...w[count_ones-1] are the ones.
            // These friends should get the largest available numbers from a.
            // The largest numbers are a[n-1], a[n-2], ...
            // The friends with w_i=1 should get the largest of these.
            // So, for each w[i]=1, we add a[n-1-j] again, where j is the index of this w[i] among the w_i=1 friends.
            // This is equivalent to adding a[n-1-i] again for the first 'count_ones' friends.
            // This is because the largest k numbers are already added as max_val.
            // For w_i=1, max_val == min_val. So we need to add max_val again.
            // The largest numbers are assigned to friends with w_i=1.
            // The friends with w_i=1 are at the beginning of the sorted w array.
            // The largest numbers from 'a' are at the end of the sorted 'a' array.
            // So, the friends w[0], w[1], ..., w[count_ones-1] (all equal to 1)
            // will get a[n-1], a[n-2], ..., a[n-count_ones] as their single number.
            // We already added these as max_val. Now add them again as min_val.
            total_happiness += a[n - 1 - i];
        } else {
            // This friend receives w[i] integers, where w[i] > 1.
            // Their max_val is one of the k largest numbers (already added).
            // Their min_val should be one of the smallest available numbers.
            // To maximize sum, we give them the smallest available numbers.
            // The smallest available numbers are from the beginning of 'a'.
            // This friend needs w[i] - 1 additional numbers (besides their max_val).
            // The smallest of these w[i] numbers will be their min_val.
            // So, we assign a[current_a_idx] as their min_val.
            total_happiness += a[current_a_idx];
            current_a_idx += (w[i] - 1); // Consume w[i]-1 smallest numbers
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining N-1 is odd. Opponent takes 1. Then N-2 is even.
                // This path is generally worse for Chanek if N/2 is a good option.

                // Option 2: Take N/2 coins
                // This is usually the optimal move for Chanek if N is even and N/2 is also even.
                // If N/2 is odd, then taking N/2 leaves an odd number for opponent,
                // who will take 1, leaving an even number for Chanek.

                // Consider N = 4:
                // Chanek takes 1: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 1+1=2. Opponent: 1+1=2.
                // Chanek takes 4/2=2: N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 2+1=3. Opponent: 1.
                // Chanek prefers 3. So take N/2.

                // Consider N = 6:
                // Chanek takes 1: N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 1+2+1=4. Opponent: 1+1=2.
                // Chanek takes 6/2=3: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // Both give 4.

                // Consider N = 10:
                // Chanek takes 1: N=9. Opponent takes 1. N=8. Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 1+4+1=6. Opponent: 1+2+1=4.
                // Chanek takes 10/2=5: N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 5+2+1=8. Opponent: 1+1+1=3.
                // Chanek prefers 8. So take N/2.

                // The only tricky case is when N is even, and N/2 is odd, and N/2 is not 1.
                // Example: N=6. N/2=3 (odd).
                // If Chanek takes 1: N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                // Chanek: 1+2+1=4. Opponent: 1+1=2.
                // If Chanek takes N/2=3: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // In this case, both yield 4.

                // What if N is a power of 2? N = 2^k.
                // If Chanek takes 1: N=2^k-1 (odd). Opponent takes 1. N=2^k-2 (even).
                // If Chanek takes N/2: N=2^(k-1).
                // This is a recursive structure.
                // For N=2, Chanek takes 1. Chanek gets 1.
                // For N=4, Chanek takes 2. Chanek gets 3.
                // For N=8, Chanek takes 4. Chanek gets 7.
                // For N=2^k, Chanek takes 2^(k-1). Chanek gets 2^k - 1.
                // This is always better than taking 1.

                // The only time taking 1 is better than taking N/2 is if N/2 leads to a state where the opponent gets a lot.
                // This happens if N/2 is odd, and N/2 is not 1.
                // If N/2 is odd and N/2 > 1, then the opponent will take 1, leaving N/2-1 (even).
                // If N/2 is 1, then N=2. Chanek takes 1.
                // If N is even:
                //   If N is a power of 2 (N = 2^k, k >= 1): Chanek takes N/2.
                //   If N is even but not a power of 2:
                //     N = 2^k * M, where M is odd and M > 1.
                //     If Chanek takes N/2: N becomes 2^(k-1) * M.
                //     If Chanek takes 1: N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                //
                // Let's consider the case where N is even.
                // If N/2 is odd (i.e., N = 2 * (odd number)).
                //   Example: N=6. N/2=3.
                //   Chanek takes 1: N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                //   Chanek: 1+2+1=4. Opponent: 1+1=2.
                //   Chanek takes 3: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                //   Chanek: 3+1=4. Opponent: 1+1=2.
                //   In this case, both moves yield the same result for Chanek.
                //   So, if N/2 is odd, taking 1 is equivalent to taking N/2.
                //   It's simpler to just take 1 if N/2 is odd, as it avoids the N/2 branch.
                //   However, the problem states "maximize the number of coins".
                //   If N/2 is odd, and N/2 > 1, then taking 1 is always optimal for Chanek.
                //   Why? If Chanek takes N/2, the opponent faces an odd number N/2. Opponent takes 1.
                //   If Chanek takes 1, the opponent faces an odd number N-1. Opponent takes 1.
                //   This logic is flawed. The opponent will always try to maximize their own coins.

                // Let's re-evaluate the optimal strategy for even N.
                // If N is even:
                //   Option A: Take 1. Remaining N-1 (odd). Opponent takes 1. Remaining N-2 (even).
                //   Option B: Take N/2. Remaining N/2.
                //
                // If N/2 is odd (N = 2 * odd_number, e.g., 6, 10, 14, ...):
                //   Option A: Chanek gets 1. Opponent faces N-1 (odd). Opponent takes 1. Chanek faces N-2 (even).
                //   Option B: Chanek gets N/2. Opponent faces N/2 (odd). Opponent takes 1. Chanek faces N/2-1 (even).
                //   In this scenario, taking 1 is always better or equal to taking N/2.
                //   Example N=6:
                //     A: Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                //        Chanek: 1 + (2+1) = 4. Opponent: 1+1 = 2.
                //     B: Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                //        Chanek: 3 + 1 = 4. Opponent: 1+1 = 2.
                //   Both give 4. So taking 1 is fine.
                //   The only exception is N=2. N/2=1. Chanek takes 1. Chanek gets 1.
                //   If N=2, N/2 is 1 (odd). Chanek takes 1. Chanek gets 1.
                //   So if N/2 is odd, Chanek takes 1.

                // If N/2 is even (N = 4 * some_number, e.g., 4, 8, 12, ...):
                //   Option A: Chanek takes 1. N-1 (odd). Opponent takes 1. N-2 (even).
                //   Option B: Chanek takes N/2. N/2 (even).
                //   In this scenario, taking N/2 is always better.
                //   Example N=4:
                //     A: Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
