                //     B: Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                //        Chanek: 2+1=3. Opponent: 1.
                //   Chanek prefers 3. So take N/2.
                //
                // So the strategy for Chanek is:
                // If N is odd: take 1.
                // If N is even:
                //   If N/2 is odd (i.e., N = 2 * (odd number)): take 1.
                //   If N/2 is even (i.e., N = 4 * (any number)): take N/2.
                // This can be simplified:
                // If N is odd: take 1.
                // If N is even:
                //   If N % 4 == 2 (N = 2, 6, 10, ...): take 1.
                //   If N % 4 == 0 (N = 4, 8, 12, ...): take N/2.

                if (n % 4 == 0) { // N is a multiple of 4
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N is even, but N % 4 == 2 (e.g., 2, 6, 10, ...)
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1; // Opponent takes 1
            } else { // N is even
                // Opponent also plays optimally to maximize their own coins.
                // Same logic as Chanek's turn.
                if (n % 4 == 0) { // N is a multiple of 4
                    n /= 2; // Opponent takes N/2
                } else { // N is even, but N % 4 == 2
                    n -= 1; // Opponent takes 1
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

