#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    std::vector<long long> prime_factors_q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            prime_factors_q.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back(temp_q);
    }

    for (long long factor_q : prime_factors_q) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= factor_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // For std::min/max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Precompute prefix sums for counts of 'x', 'y', 'z'
    // counts[0][i] stores count of 'x' in s[0...i-1]
    // counts[1][i] stores count of 'y' in s[0...i-1]
    // counts[2][i] stores count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        counts[0][i + 1] = counts[0][i];
        counts[1][i + 1] = counts[1][i];
        counts[2][i + 1] = counts[2][i];
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r; // 1-indexed

        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Get counts of 'x', 'y', 'z' in the substring s[l-1...r-1]
        int count_x = counts[0][r] - counts[0][l - 1];
        int count_y = counts[1][r] - counts[1][l - 1];
        int count_z = counts[2][r] - counts[2][l - 1];

        // The algorithm terminates correctly if the counts of 'x', 'y', 'z'
        // in any 3-character window can be made equal or differ by at most 1.
        // This is equivalent to checking if the total counts of 'x', 'y', 'z'
        // in the entire substring s[l-1...r-1] can be rearranged such that
        // the counts differ by at most 1.
        // This means max_count - min_count <= 1.

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_sequences = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        if (m == 0) continue; // Should not happen based on constraints m_i >= 1

        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // Count existing correct nestings within this chain
        // A chain a_1 -> a_2 -> ... -> a_m has m-1 existing nestings.
        // We need to count how many of these are of the form x -> x+1.
        // The problem states a_i1 is nested into a_i2, etc.
        // So, a_j is nested into a_{j+1}.
        // We are looking for pairs (a_j, a_{j+1}) such that a_{j+1} = a_j + 1.

        // If the first doll in a chain is 1, it means this chain potentially starts with 1 -> 2 -> ...
        // This is a special case for counting correct sequences.
        // The sequence 1 -> 2 -> ... -> X is one contiguous block of correct nestings.
        // We count how many such blocks exist.
        // If a chain starts with 1, and continues 1 -> 2 -> 3 -> ... -> X,
        // then this contributes one "correct sequence" starting at 1.
        // The number of dolls in this sequence is X.
        // The number of correct nestings is X-1.

        if (chain[0] == 1) {
            int current_val = 1;
            int current_correct_length = 0;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_val) {
                    current_correct_length++;
                    current_val++;
                } else {
                    break; // Sequence 1 -> 2 -> ... broken
                }
            }
            correct_sequences = current_correct_length; // This will be the length of the 1->2->... sequence
        }
    }

    // Total operations to achieve 1 -> 2 -> ... -> n:
    // 1. Disassemble all existing chains into individual dolls.
    //    Each chain of length m_i has m_i - 1 nestings.
    //    Total nestings across all chains is (m_1 - 1) + ... + (m_k - 1) = (sum m_i) - k = n - k.
    //    So, n - k "get out" operations are needed to disassemble everything.
    // 2. Assemble the final chain 1 -> 2 -> ... -> n.
    //    This requires n - 1 "put in" operations.
    // Total operations if we disassemble everything and reassemble: (n - k) + (n - 1).

    // However, some operations are "correct" and don't need to be undone/redone.
    // The sequence 1 -> 2 -> ... -> correct_sequences is already formed.
    // This means (correct_sequences - 1) nestings are already in place and correct.
    // These (correct_sequences - 1) nestings do not need to be disassembled or reassembled.

    // Number of "get out" operations saved: (correct_sequences - 1)
    // Number of "put in" operations saved: (correct_sequences - 1)

    // Total operations = (n - k) + (n - 1) - 2 * (correct_sequences - 1)
    // This formula is for the case where correct_sequences >= 1.
    // If correct_sequences is 0 (no chain starts with 1, or 1 is not followed by 2),
    // then no operations are saved from the 1->2->... sequence.
    // The formula should be:
    // (n - k) + (n - 1) - (correct_sequences > 0 ? 2 * (correct_sequences - 1) : 0)

    // Let's re-evaluate:
    // Total dolls: n
    // Total chains: k
    // Total existing nestings: n - k
    // Total nestings needed in final state: n - 1

    // Operations to disassemble:
    // We need to break all existing nestings that are NOT part of the final 1->2->...->n sequence.
    // The number of existing nestings is n - k.
    // The number of correct nestings in the 1->2->... sequence is (correct_sequences - 1).
    // So, number of "get out" operations = (n - k) - (correct_sequences - 1).
    // (Note: if correct_sequences is 0 or 1, then (correct_sequences - 1) is <= 0, meaning 0 saved operations.
    //  So, max(0, correct_sequences - 1) should be used for saved operations.)
    long long saved_disassemble_ops = std::max(0, correct_sequences - 1);
    long long disassemble_ops = (n - k) - saved_disassemble_ops;

    // Operations to assemble:
    // We need to create n - 1 nestings.
    // The number of correct nestings in the 1->2->... sequence is (correct_sequences - 1).
    // So, number of "put in" operations = (n - 1) - (correct_sequences - 1).
    long long saved_assemble_ops = std::max(0, correct_sequences - 1);
    long long assemble_ops = (n - 1) - saved_assemble_ops;

    total_operations = disassemble_ops + assemble_ops;

    std::cout << total_operations << std::endl;

    return 0;
}

