void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    int p = -1; // The digit value that separates color 1 and color 2

    // Iterate through possible split points 'p' from 0 to 9
    for (int current_p = 0; current_p <= 9; ++current_p) {
        std::string current_result(n, ' ');
        char last1 = '0'; // Last digit placed in color 1
        char last2 = '0'; // Last digit placed in color 2
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit < current_p + '0') {
                // Must be color 1
                if (digit < last1) {
                    possible_p = false;
                    break;
                }
                current_result[i] = '1';
                last1 = digit;
            } else if (digit > current_p + '0') {
                // Must be color 2
                if (digit < last2) {
                    possible_p = false;
                    break;
                }
                current_result[i] = '2';
                last2 = digit;
            } else { // digit == current_p + '0'
                // Can be either color 1 or color 2
                // Try to put it in color 2 if possible, to keep color 1 digits smaller
                if (digit >= last2) {
                    current_result[i] = '2';
                    last2 = digit;
                } else if (digit >= last1) {
                    current_result[i] = '1';
                    last1 = digit;
                } else {
                    possible_p = false;
                    break;
                }
            }
        }

        if (possible_p) {
            std::cout << current_result << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

