#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<int> fixed_char(k, -1); // -1 for unknown, 0 for '0', 1 for '1'
    bool possible = true;

    // Step 1: Propagate constraints based on s[i] == s[i+k]
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            int char_val = s[i] - '0';
            if (fixed_char[i % k] == -1) {
                fixed_char[i % k] = char_val;
            } else if (fixed_char[i % k] != char_val) {
                possible = false;
                break;
            }
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Step 2: Check the first k characters for balance
    int count0 = 0;
    int count1 = 0;
    int count_q = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_char[i] == 0) {
            count0++;
        } else if (fixed_char[i] == 1) {
            count1++;
        } else { // fixed_char[i] == -1, meaning it's a '?' in this position
            count_q++;
        }
    }

    // Check if it's possible to achieve k/2 zeros and k/2 ones
    if (count0 > k / 2 || count1 > k / 2) {
        possible = false;
    } else {
        // We need (k/2 - count0) more zeros and (k/2 - count1) more ones
        // The remaining '?'s must be able to cover this
        if (count_q < (k / 2 - count0) + (k / 2 - count1)) {
            possible = false;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

