int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // If b=1, then b-1=0, sum_r = 0.
    // If b > 1, then b-1 >= 1.
    long long sum_r;
    if (b == 1) {
        sum_r = 0;
    } else {
        sum_r = (b - 1);
        sum_r = (sum_r * b) % MOD;
        // We need to divide by 2. This is equivalent to multiplying by modular inverse of 2.
        // Modular inverse of 2 modulo 10^9+7 is (10^9+7+1)/2 = 500000004.
        long long inv2 = 500000004;
        sum_r = (sum_r * inv2) % MOD;
    }

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // sum_k_term = sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // sum_k_term = b * sum_{k=1 to a} k + a
    // sum_{k=1 to a} k = a * (a+1) / 2
    long long sum_k_val = (a % MOD);
    sum_k_val = (sum_k_val * ((a + 1) % MOD)) % MOD;
    long long inv2 = 500000004; // Modular inverse of 2
    sum_k_val = (sum_k_val * inv2) % MOD;

    long long sum_k_term = (b % MOD);
    sum_k_term = (sum_k_term * sum_k_val) % MOD;
    sum_k_term = (sum_k_term + (a % MOD)) % MOD;

    // Total sum = (sum_r * sum_k_term) % MOD
    long long total_sum = (sum_r * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> d(n);
    std::deque<int> q;

    // Calculate d_i for left-to-right pass
    for (int i = 0; i < n; ++i) {
        while (!q.empty() && h[q.back()] >= h[i]) {
            q.pop_back();
        }
        long long prev_d = q.empty() ? 0 : d[q.back()];
        d[i] = prev_d + (i - (q.empty() ? -1 : q.back()));
        q.push_back(i);
    }

    q.clear();
    // Calculate d_i for right-to-left pass and take minimum
    for (int i = n - 1; i >= 0; --i) {
        while (!q.empty() && h[q.back()] >= h[i]) {
            q.pop_back();
        }
        long long prev_d = q.empty() ? 0 : d[q.back()];
        d[i] = std::min(d[i], prev_d + ((q.empty() ? n : q.back()) - i));
        q.push_back(i);
    }

    long long max_d = 0;
    for (int i = 0; i < n; ++i) {
        max_d = std::max(max_d, d[i]);
    }

    std::cout << max_d << std::endl;

    return 0;
}

