int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 0) {
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));
    if (k == 0) { // Should not happen for n >= 1, but as a safeguard
        k = 1;
    }

    std::vector<int> p(n);
    int current_val = n;
    int idx = 0;

    while (current_val > 0) {
        int block_start = std::max(1, current_val - k + 1);
        for (int i = current_val; i >= block_start; --i) {
            p[idx++] = i;
        }
        current_val = block_start - 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int total_s = 0;
    int total_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            total_s++;
        } else {
            total_b++;
        }
    }

    int initial_diff = total_s - total_b;

    if (initial_diff == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Calculate prefix sums for the left side (jars 0 to n-1)
    // and suffix sums for the right side (jars n to 2n-1)
    // The difference is (count of 1s) - (count of 2s)

    // Map to store the minimum number of jars eaten from the left
    // to achieve a certain difference.
    // Key: difference (s_count - b_count)
    // Value: number of jars eaten from left (k_l)
    std::map<int, int> left_diff_to_k_l;
    left_diff_to_k_l[0] = 0; // 0 jars eaten from left, diff is 0

    int current_diff_left = 0;
    for (int k_l = 1; k_l <= n; ++k_l) {
        if (a[n - k_l] == 1) { // Jars are 1-indexed, so a[n-k_l] is the k_l-th jar from the left
            current_diff_left++;
        } else {
            current_diff_left--;
        }
        if (left_diff_to_k_l.find(current_diff_left) == left_diff_to_k_l.end()) {
            left_diff_to_k_l[current_diff_left] = k_l;
        }
    }

    // Map to store the minimum number of jars eaten from the right
    // to achieve a certain difference.
    // Key: difference (s_count - b_count)
    // Value: number of jars eaten from right (k_r)
    std::map<int, int> right_diff_to_k_r;
    right_diff_to_k_r[0] = 0; // 0 jars eaten from right, diff is 0

    int current_diff_right = 0;
    for (int k_r = 1; k_r <= n; ++k_r) {
        if (a[n + k_r - 1] == 1) { // Jars are 1-indexed, so a[n+k_r-1] is the k_r-th jar from the right
            current_diff_right++;
        } else {
            current_diff_right--;
        }
        if (right_diff_to_k_r.find(current_diff_right) == right_diff_to_k_r.end()) {
            right_diff_to_k_r[current_diff_right] = k_r;
        }
    }

    int min_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible differences achieved by eating from the left
    // For each such difference, calculate the required difference from the right
    // to make the total remaining difference zero.
    // (initial_diff - diff_left - diff_right) = 0
    // diff_right = initial_diff - diff_left
    for (auto const& [diff_left, k_l] : left_diff_to_k_l) {
        int required_diff_right = initial_diff - diff_left;
        if (right_diff_to_k_r.count(required_diff_right)) {
            int k_r = right_diff_to_k_r[required_diff_right];
            min_eaten = std::min(min_eaten, k_l + k_r);
        }
    }

    std::cout << min_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: Dummy operation (e.g., add 0 to a[0])
        std::cout << "1 1\n";
        std::cout << "0\n";

        // Operation 3: Dummy operation (e.g., add 0 to a[0])
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // Operation 1: For elements a[0] to a[n-2]
    // We want to make a[i] a multiple of n for i from 0 to n-2.
    // We can achieve this by adding (n - (a[i] % n)) % n * n to a[i].
    // This is equivalent to adding (n - (a[i] % n) + n) % n * n to a[i]
    // to handle negative a[i] correctly.
    // Or, more simply, we want a[i] + b[i] = k*n.
    // We can make a[i] become a[i] + (n - (a[i] % n) + n) % n * n.
    // Let's use the property that a[i] + b[i] = 0 (mod n).
    // So b[i] = -a[i] (mod n).
    // We can add ((-a[i] % n) + n) % n * n to a[i].
    // This makes a[i] a multiple of n.
    // The length of the segment is n-1.
    // We need to add b_i such that b_i is a multiple of n-1.
    // This is tricky. The problem states "add a multiple of len".
    // Let's re-read: "for each number in this segment we can add a multiple of len to it".
    // This means for a_i, we add b_i = k_i * len.
    // We want a_i + b_i = 0. So b_i = -a_i.
    // This implies -a_i must be a multiple of len.
    // This is not what we want. We want to make a_i become 0.
    // The strategy is to make a_i become a multiple of n for i from 0 to n-2.
    // Then, for a[n-1], we make it 0.
    // Finally, for a[0] to a[n-2], they are multiples of n, so we can make them 0.

    // Operation 1: Target a[0] to a[n-2]
    // Segment [1, n-1], length n-1.
    // For each a[i] in this segment (i from 0 to n-2), we want to change it to a value
    // that is a multiple of n.
    // We can add b_i = k_i * (n-1) to a[i].
    // We want a[i] + k_i * (n-1) = 0 (mod n).
    // a[i] + k_i * (-1) = 0 (mod n)
    // k_i = a[i] (mod n).
    // So we need to find k_i such that k_i = a[i] (mod n) and k_i is a multiple of (n-1).
    // Let k_i = x * (n-1).
    // x * (n-1) = a[i] (mod n)
    // x * (-1) = a[i] (mod n)
    // -x = a[i] (mod n)
    // x = -a[i] (mod n)
    // So we can choose x = ((-a[i] % n) + n) % n.
    // Then b_i = x * (n-1).
    // After this operation, a[i] becomes a[i] + b_i, which is a multiple of n.

    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = (a[i] % n + n) % n; // a[i] mod n, always positive
        long long x = (n - remainder) % n; // x = -a[i] mod n
        long long b_i = x * (n - 1);
        std::cout << b_i << (i == n - 2 ? "" : " ");
        a[i] += b_i; // Update a[i]
    }
    std::cout << "\n";

    // Operation 2: Target a[n-1]
    // Segment [n, n], length 1.
    // We can add any integer to a[n-1] since len=1.
    // We want to make a[n-1] zero.
    std::cout << n << " " << n << "\n";
    std::cout << -a[n - 1] << "\n";
    a[n - 1] = 0; // Update a[n-1]

    // Operation 3: Target all elements a[0] to a[n-1]
    // Segment [1, n], length n.
    // At this point, a[0] to a[n-2] are all multiples of n (from Op 1).
    // And a[n-1] is 0 (from Op 2), which is also a multiple of n.
    // So all a[i] are multiples of n.
    // We want to add b_i = k_i * n to a[i] such that a[i] + b_i = 0.
    // So b_i = -a[i]. Since a[i] is a multiple of n, -a[i] is also a multiple of n.
    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;
        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;

        long long zeros = n - m;

        // To minimize the number of all-zero substrings, we want to distribute
        // the 'zeros' as evenly as possible among 'm+1' blocks.
        // This means we want the lengths of zero blocks to be as close as possible.
        // The 'm' ones divide the string into 'm+1' potential blocks of zeros.
        // Let k be the number of zeros in each of the 'm+1' blocks.
        // The number of blocks with length floor(zeros / (m+1)) is (m+1) - (zeros % (m+1)).
        // The number of blocks with length ceil(zeros / (m+1)) is (zeros % (m+1)).

        long long num_large_blocks = zeros % (m + 1);
        long long len_large_block = zeros / (m + 1) + 1;

        long long num_small_blocks = (m + 1) - num_large_blocks;
        long long len_small_block = zeros / (m + 1);

        long long min_zero_substrings = 0;
        if (len_large_block > 0) { // Only add if block actually exists
            min_zero_substrings += num_large_blocks * (len_large_block * (len_large_block + 1) / 2);
        }
        if (len_small_block > 0) { // Only add if block actually exists
            min_zero_substrings += num_small_blocks * (len_small_block * (len_small_block + 1) / 2);
        }

        long long max_f_s = total_substrings - min_zero_substrings;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::pair<char, int>> ops(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> ops[i].first >> ops[i].second;
    }

    int final_and_mask = 1023; // All bits initially 1
    int final_or_mask = 0;    // All bits initially 0
    int final_xor_mask = 0;   // All bits initially 0

    for (int bit = 0; bit < 10; ++bit) {
        int initial_val_0 = 0; // Represents the state of this bit if input bit is 0
        int initial_val_1 = 1; // Represents the state of this bit if input bit is 1

        for (const auto& op : ops) {
            char type = op.first;
            int constant = op.second;
            int const_bit = (constant >> bit) & 1;

            if (type == '&') {
                initial_val_0 &= const_bit;
                initial_val_1 &= const_bit;
            } else if (type == '|') {
                initial_val_0 |= const_bit;
                initial_val_1 |= const_bit;
            } else { // type == '^'
                initial_val_0 ^= const_bit;
                initial_val_1 ^= const_bit;
            }
        }

        // Determine the equivalent operation for this bit
        // (0 -> initial_val_0, 1 -> initial_val_1)
        if (initial_val_0 == 0 && initial_val_1 == 0) {
            // x -> 0. Equivalent to x & 0.
            final_and_mask &= ~(1 << bit);
            final_or_mask &= ~(1 << bit); // Ensure this bit remains 0
            final_xor_mask &= ~(1 << bit); // Ensure this bit is not flipped
        } else if (initial_val_0 == 0 && initial_val_1 == 1) {
            // x -> x. Equivalent to x & 1 | 0 ^ 0.
            // No change to final_and_mask, final_or_mask, final_xor_mask for this bit.
        } else if (initial_val_0 == 1 && initial_val_1 == 0) {
            // x -> !x. Equivalent to x ^ 1.
            final_xor_mask |= (1 << bit);
        } else { // initial_val_0 == 1 && initial_val_1 == 1
            // x -> 1. Equivalent to x | 1.
            final_or_mask |= (1 << bit);
            final_and_mask |= (1 << bit); // Ensure this bit remains 1
            final_xor_mask &= ~(1 << bit); // Ensure this bit is not flipped
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // The order of operations matters for the final result.
    // A common simplification is: (x & A) | B ^ C
    // This can be achieved with one AND, one OR, one XOR.
    // However, we need to be careful about the interaction.
    // The derived final_and_mask, final_or_mask, final_xor_mask
    // are for a sequence like: (x & final_and_mask) | final_or_mask ^ final_xor_mask.
    // This is because:
    // - final_and_mask determines which bits can be 0 (if input bit is 0) or 1 (if input bit is 1).
    // - final_or_mask determines which bits are forced to 1.
    // - final_xor_mask determines which bits are flipped.

    // Let's re-evaluate the target values for 0 and 1 after the combined operations.
    // We want to find A, B, C such that for any bit x_i:
    // ((x_i & A_i) | B_i) ^ C_i matches the target (0->val0, 1->val1).

    // For each bit:
    // Target (0 -> val0, 1 -> val1)
    // Case 1: (0 -> 0, 1 -> 0)
    //   ((x & 0) | 0) ^ 0 = 0. So A=0, B=0, C=0.
    // Case 2: (0 -> 0, 1 -> 1)
    //   ((x & 1) | 0) ^ 0 = x. So A=1, B=0, C=0.
    // Case 3: (0 -> 1, 1 -> 0)
    //   ((x & 1) | 0) ^ 1 = !x. So A=1, B=0, C=1.
    // Case 4: (0 -> 1, 1 -> 1)
    //   ((x & 0) | 1) ^ 0 = 1. So A=0, B=1, C=0.

    // Let's construct the A, B, C values based on these cases.
    int A_val = 0; // For the AND operation
    int B_val = 0; // For the OR operation
    int C_val = 0; // For the XOR operation

    for (int bit = 0; bit < 10; ++bit) {
        int initial_val_0 = 0;
        int initial_val_1 = 1;

        for (const auto& op : ops) {
            char type = op.first;
            int constant = op.second;
            int const_bit = (constant >> bit) & 1;

            if (type == '&') {
                initial_val_0 &= const_bit;
                initial_val_1 &= const_bit;
            } else if (type == '|') {
                initial_val_0 |= const_bit;
                initial_val_1 |= const_bit;
            } else { // type == '^'
                initial_val_0 ^= const_bit;
                initial_val_1 ^= const_bit;
            }
        }

        if (initial_val_0 == 0 && initial_val_1 == 0) {
            // Case 1: (0 -> 0, 1 -> 0) => A=0, B=0, C=0
            // A_val remains 0 for this bit
            // B_val remains 0 for this bit
            // C_val remains 0 for this bit
        } else if (initial_val_0 == 0 && initial_val_1 == 1) {
            // Case 2: (0 -> 0, 1 -> 1) => A=1, B=0, C=0
            A_val |= (1 << bit);
            // B_val remains 0 for this bit
            // C_val remains 0 for this bit
        } else if (initial_val_0 == 1 && initial_val_1 == 0) {
            // Case 3: (0 -> 1, 1 -> 0) => A=1, B=0, C=1
            A_val |= (1 << bit);
            // B_val remains 0 for this bit
            C_val |= (1 << bit);
        } else { // initial_val_0 == 1 && initial_val_1 == 1
            // Case 4: (0 -> 1, 1 -> 1) => A=0, B=1, C=0
            // A_val remains 0 for this bit
            B_val |= (1 << bit);
            // C_val remains 0 for this bit
        }
    }

    // Add operations if their constants are non-zero or if they are essential (like AND 0)
    // The order is AND, then OR, then XOR.
    // This order is chosen because it can represent all 4 bit transformations.
    // (x & A_val) | B_val ^ C_val
    // If A_val is 1023 (all bits 1), then & 1023 is effectively no-op for AND.
    // If B_val is 0, then | 0 is effectively no-op for OR.
    // If C_val is 0, then ^ 0 is effectively no-op for XOR.

    // We need to be careful. If A_val is 1023, we don't need an '&' operation.
    // If B_val is 0, we don't need a '|' operation.
    // If C_val is 0, we don't need a '^' operation.

    // However, the problem asks for a program that does the same thing.
    // The structure (x & A) | B ^ C is a canonical form.
    // We can always represent it with at most 3 operations.
    // Example: if A_val = 1023, B_val = 0, C_val = 0, then it's just 'x'.
    // We can output 0 lines.
    // If A_val = 1023, B_val = 0, C_val = 5, then it's 'x ^ 5'. Output 1 line.
    // If A_val = 1023, B_val = 3, C_val = 0, then it's 'x | 3'. Output 1 line.
    // If A_val = 1023, B_val = 3, C_val = 5, then it's 'x | 3 ^ 5'. Output 2 lines.
    // If A_val = 1, B_val = 0, C_val = 0, then it's 'x & 1'. Output 1 line.
    // If A_val = 1, B_val = 3, C_val = 0, then it's '(x & 1) | 3'. Output 2 lines.
    // If A_val = 1, B_val = 3, C_val = 5, then it's '(x & 1) | 3 ^ 5'. Output 3 lines.

    // So, we add operations only if their constant is not the identity for that operation.
    if (A_val != 1023) { // If A_val is not all 1s, then & A_val is needed.
        result_ops.push_back({'&', A_val});
    }
    if (B_val != 0) { // If B_val is not all 0s, then | B_val is needed.
        result_ops.push_back({'|', B_val});
    }
    if (C_val != 0) { // If C_val is not all 0s, then ^ C_val is needed.
        result_ops.push_back({'^', C_val});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, subsequent values will be current_val + d + 1

    while (X > 0) {
        long long k = 0;
        // Find largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        if (X == 1) { // Special case for X=1, 2^0-1 = 0, but we need 1 element
            k = 1;
        } else {
            k = std::floor(std::log2(X + 1));
            // Ensure 2^k - 1 does not exceed X
            if ((1LL << k) - 1 > X) {
                k--;
            }
            // Ensure k is at least 1 if X > 0
            if (k == 0 && X > 0) {
                k = 1;
            }
        }

        // If k is 0, it means X is 0, but loop condition is X > 0.
        // If X=1, k=1. If X=2, k=1. If X=3, k=2.
        // The smallest k for X > 0 is 1.
        // If X=1, k=1. (2^1-1 = 1)
        // If X=2, k=1. (2^1-1 = 1)
        // If X=3, k=2. (2^2-1 = 3)

        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }
        X -= ((1LL << k) - 1);
        current_val += (d + 1);
    }

    if (result_array.size() > 10000) {
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply median smoothing once
// Returns true if the sequence changed, false otherwise (stable)
bool apply_median_smoothing(std::vector<int>& a, std::vector<int>& b) {
    int n = a.size();
    bool changed = false;

    b[0] = a[0];
    b[n - 1] = a[n - 1];

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        if (sum >= 2) { // Median is 1 if at least two are 1
            b[i] = 1;
        } else { // Median is 0 otherwise
            b[i] = 0;
        }
        if (b[i] != a[i]) {
            changed = true;
        }
    }

    if (b[0] != a[0] || b[n-1] != a[n-1]) { // Should not happen based on rules, but for completeness
        changed = true;
    }

    a.swap(b); // Update a to the new sequence
    return changed;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable by definition
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> b(n); // Buffer for the next sequence

    // Find all blocks of identical values
    // A block is defined by its start index and value
    std::vector<std::pair<int, int>> blocks; // {start_index, value}
    if (n > 0) {
        blocks.push_back({0, a[0]});
        for (int i = 1; i < n; ++i) {
            if (a[i] != a[i - 1]) {
                blocks.push_back({i, a[i]});
            }
        }
    }

    // If there's only one block, the sequence is already stable
    if (blocks.size() <= 1) {
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Calculate initial distances for 0-1-0 and 1-0-1 patterns
    std::vector<int> left_dist(blocks.size()); // Distance to the left boundary of the block
    std::vector<int> right_dist(blocks.size()); // Distance to the right boundary of the block

    for (size_t i = 0; i < blocks.size(); ++i) {
        int block_start = blocks[i].first;
        int block_end = (i == blocks.size() - 1) ? n - 1 : blocks[i+1].first - 1;

        left_dist[i] = block_start;
        right_dist[i] = n - 1 - block_end;
    }

    int max_k = 0;
    for (size_t i = 1; i < blocks.size() - 1; ++i) {
        // Consider only alternating blocks (0-1-0 or 1-0-1)
        if (blocks[i-1].second == blocks[i+1].second && blocks[i].second != blocks[i-1].second) {
            int len_middle_block = blocks[i+1].first - blocks[i].first;
            int k_val = (len_middle_block - 1) / 2;
            max_k = std::max(max_k, k_val);
        }
    }

    // Apply smoothing max_k times
    for (int iter = 0; iter < max_k; ++iter) {
        apply_median_smoothing(a, b);
    }

    std::cout << max_k << std::endl;
