    for (int i = 0; i < n; ++i) {
        // For a fixed x[i], we need to find all x[k] such that x[k] - x[i] <= d.
        // Since x is sorted, we can advance right_ptr.
        // right_ptr should always be at least i.
        // We want to find the largest index 'k' such that x[k] <= x[i] + d.
        // The `std::upper_bound` approach is equivalent to finding the first element
        // strictly greater than x[i] + d, and then taking the element before it.
        // Or, we can use a two-pointer approach.

        // Advance right_ptr until x[right_ptr] - x[i] > d or right_ptr reaches end of array.
        // The loop condition ensures right_ptr stays within bounds and x[right_ptr] is valid.
        // We are looking for points x[k] such that x[k] <= x[i] + d.
        // The right_ptr will point to the first element *after* the valid range.
        // So, the valid indices for k are from i+1 up to right_ptr-1.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, all points x[j] where i < j < right_ptr satisfy x[j] - x[i] <= d.
        // The number of points in the range [i+1, right_ptr-1] is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. This is the number of points available to be x_j or x_k
        // after x_i is chosen, such that x_k - x_i <= d.
        // These m points are x[i+1], x[i+2], ..., x[right_ptr-1].
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        // Ensure m is non-negative. If right_ptr - 1 <= i, then m <= 0.
        long long m = (long long)right_ptr - 1 - i;
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false); // Tracks which vertices are currently in the graph

    // Process vertices in reverse order of removal
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being "added" back to the graph

        active[k] = true; // Mark vertex k as active

        // Update shortest paths using vertex k as an intermediate node
        // This is essentially one step of Floyd-Warshall
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue; // Only consider active vertices
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue; // Only consider active vertices
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After updating paths using k, also update paths from k to others and others to k
        // This is crucial because k itself is now an active vertex
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (dist[k][i] + dist[i][j] < dist[k][j]) {
                    dist[k][j] = dist[k][i] + dist[i][j];
                }
                if (dist[j][i] + dist[i][k] < dist[j][k]) {
                    dist[j][k] = dist[j][i] + dist[i][k];
                }
            }
        }

        // Re-run the full Floyd-Warshall step for all active vertices
        // This ensures all paths are updated correctly after adding k
        // The previous two loops are actually redundant if this one is done correctly.
        // The standard Floyd-Warshall structure is:
        // for k_node in all_nodes:
        //   for i_node in all_nodes:
        //     for j_node in all_nodes:
        //       dist[i_node][j_node] = min(dist[i_node][j_node], dist[i_node][k_node] + dist[k_node][j_node])
        // Here, k is the *newly added* intermediate node.
        // So we iterate over all *currently active* i and j, and use k as the intermediate.
        // Then, we also need to consider i and j as intermediate nodes for paths involving k.
        // A simpler way is to just run the standard Floyd-Warshall step for the newly added k.
        // This means, for all active i and j, update dist[i][j] using k.
        // And for k, update dist[k][j] using active i, and dist[i][k] using active j.
        // The following three loops achieve this:
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                // Path i -> k -> j
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }
        // The above loop updates paths between existing active nodes using k.
        // We also need to update paths involving k itself as an endpoint.
        // This is implicitly handled by the previous loop if i or j is k.
        // For example, if i=k, it updates dist[k][j] using k as intermediate (which is dist[k][k]+dist[k][j]).
        // This is not what we want. We want to update dist[k][j] using *other* active nodes as intermediate.
        // So, the correct way is:
        // For the newly added vertex 'k', and all other active vertices 'i' and 'j':
        // 1. Update paths from 'i' to 'j' using 'k' as an intermediate: dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // 2. Update paths from 'k' to 'j' using 'i' as an intermediate: dist[k][j] = min(dist[k][j], dist[k][i] + dist[i][j])
        // 3. Update paths from 'i' to 'k' using 'j' as an intermediate: dist[i][k] = min(dist[i][k], dist[i][j] + dist[j][k])
        // These three steps together correctly integrate the new vertex 'k' into the APSP.

        // Let's re-do the update logic for clarity and correctness.
        // When vertex 'k' is added:
        // 1. For all pairs (i, j) where i, j are currently active (including k):
        //    dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This single loop structure is the core of Floyd-Warshall.
        // It correctly updates all paths using 'k' as the *latest* intermediate node.
        // The previous loops were slightly off.
        // The standard Floyd-Warshall algorithm iterates k from 0 to n-1.
        // Here, we are iterating k from x[n-1] down to x[0].
        // So, for each k (the vertex being added), we apply the Floyd-Warshall step.
        // The crucial part is that 'i' and 'j' must also be active.

        // The correct Floyd-Warshall step for adding vertex 'k' is:
        // For all currently active vertices 'i' and 'j' (including 'k' itself):
        //   dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        //   dist[k][j] = min(dist[k][j], dist[k][i] + dist[i][j])
        //   dist[i][k] = min(dist[i][k], dist[i][j] + dist[j][k])
        // This can be simplified. The standard Floyd-Warshall step is:
        // for i in 0..n-1:
        //   for j in 0..n-1:
        //     dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // We just need to ensure i, j, and k are all active.

        // The most robust way to integrate a new vertex 'k' into the APSP:
        // For every pair of active vertices (i, j) (including k itself):
        // 1. Update path from i to j using k as an intermediate.
        // 2. Update path from k to j using i as an intermediate.
        // 3. Update path from i to k using j as an intermediate.
        // This is equivalent to running the Floyd-Warshall step for 'k' as the intermediate node,
        // but only considering active 'i' and 'j'.

        // Let's use the standard Floyd-Warshall structure for the 'k' loop:
        // For the current 'k' (the vertex just activated):
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                // Path i -> k -> j
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }
        // The above loop updates paths between any two active nodes (i,j) using the newly active 'k' as an intermediate.
        // This is sufficient. The Floyd-Warshall algorithm works by iteratively allowing more intermediate nodes.
        // When we add 'k', we are allowing 'k' to be an intermediate node for all pairs (i,j) that are currently active.
        // The order of 'k' in Floyd-Warshall matters. Here, 'k' is the *last* vertex added, so it can use all previously added vertices as intermediates.
        // And all previously added vertices can use 'k' as an intermediate.
        // The single loop structure `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])` where `k` is the outermost loop
        // correctly updates all paths.

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (from first step to last step)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v;
    long long d;
    long long p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        // Child i goes to the office
        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false; // Mark as processed

        long long current_v_cry = children[i].v;
        long long accumulated_d_cry = 0;

        // Apply v_cry and d_cry effects to subsequent children
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry from previous children who left
            if (accumulated_d_cry > 0) {
                children[j].p -= accumulated_d_cry;
            }

            // Apply current child's v_cry effect
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j leaves due to low confidence
            if (children[j].p < 0) {
                children[j].in_line = false;
                accumulated_d_cry += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a[j] to a very large value.
    // This represents an upper bound on A_0[j].
    // A_0[j] <= m_k - sum_of_d_values_applied_to_j_at_op_k
    std::vector<long long> initial_a(n, std::numeric_limits<long long>::max());

    // delta_prefix_sum[j] stores the sum of d values applied to index j
    // from type 1 operations *before* the current operation.
    // This is used to calculate the effective value of A_0[j] + delta_prefix_sum[j]
    // at the time of a type 2 operation.
    std::vector<long long> delta_prefix_sum(n, 0);

    // Iterate operations in reverse to determine initial_a bounds
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // Type 1 operation: a_j = a_j + d
            // When going in reverse, this means a_j = a_j - d
            // So, we subtract d from delta_prefix_sum for affected range.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                delta_prefix_sum[j] -= ops[i].val;
            }
        } else {
            // Type 2 operation: max(a_j) = m
            // This means for all j in [l, r], a_j <= m.
            // In terms of initial_a, A_0[j] + delta_prefix_sum[j] <= m.
            // So, A_0[j] <= m - delta_prefix_sum[j].
            // We update the upper bound for initial_a[j].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - delta_prefix_sum[j]);
            }
        }
    }

    // After iterating in reverse, initial_a[j] holds the tightest upper bound for A_0[j].
    // We can choose A_0[j] = initial_a[j] as a candidate solution.
    // If initial_a[j] is still max_long_long, it means no type 2 operation constrained it.
    // In this case, we can set it to 0 (or any value within bounds, 0 is simplest).
    // The problem states |a_i| <= 10^9.
    // max_long_long is much larger than 10^9, so if it's not constrained, 0 is a valid choice.
    for (int j = 0; j < n; ++j) {
        if (initial_a[j] == std::numeric_limits<long long>::max()) {
            initial_a[j] = 0;
        }
    }

    // Now, verify the candidate initial_a by simulating all operations forward.
    std::vector<long long> current_a = initial_a;
    delta_prefix_sum.assign(n, 0); // Reset for forward pass

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Type 1 operation: a_j = a_j + d
            // Update current_a directly for the range.
            // This is equivalent to updating delta_prefix_sum and applying it later.
            // For verification, we need the actual values.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else {
            // Type 2 operation: max(a_j) = m
            // Find the maximum in the current range and compare with ops[i].val (m_i).
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the initial array.
    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << initial_a[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using a large prime for hashing to avoid collisions, though not strictly necessary for this problem
// as we are just using it as a marker for visited states.
// A simple large number or even just 0/1 could work if we manage states carefully.
// For this problem, we need to store the result, so a map or a vector for memoization is better.

// Using a vector for memoization.
// dp[x][0] stores the result for (x, +) state
// dp[x][1] stores the result for (x, -) state
// We need to distinguish between "not visited", "currently visiting (cycle detected)", and "visited (result stored)".
// Let's use a special value for "currently visiting" to detect cycles.
// Since results are non-negative or -1, we can use 0 for "not visited", -2 for "visiting".
// Or, more robustly, use a separate state array.

enum State {
    NOT_VISITED,
    VISITING,
    VISITED
};

std::vector<long long> a_arr;
int N;
std::vector<std::vector<long long>> memo; // memo[x][0] for +a_x, memo[x][1] for -a_x
std::vector<std::vector<State>> visited_state; // visited_state[x][0/1]

long long solve(int current_x, int op_type) { // op_type: 0 for +a_x, 1 for -a_x
    if (current_x <= 0 || current_x > N) {
        return 0; // Base case: program terminates, adds 0 to y
    }

    if (visited_state[current_x][op_type] == VISITING) {
        return -1; // Cycle detected
    }
    if (visited_state[current_x][op_type] == VISITED) {
        return memo[current_x][op_type]; // Already computed
    }

    visited_state[current_x][op_type] = VISITING;

    long long val_ax = a_arr[current_x];
    long long res;

    if (op_type == 0) { // Current operation is x = x + a_x, y = y + a_x
        int next_x = current_x + val_ax;
        long long next_res = solve(next_x, 1); // Next operation is x = x - a_x, y = y + a_x
        if (next_res == -1) {
            res = -1;
        } else {
            res = val_ax + next_res;
        }
    } else { // Current operation is x = x - a_x, y = y + a_x
        int next_x = current_x - val_ax;
        long long next_res = solve(next_x, 0); // Next operation is x = x + a_x, y = y + a_x
        if (next_res == -1) {
            res = -1;
        } else {
            res = val_ax + next_res;
        }
    }

    visited_state[current_x][op_type] = VISITED;
    memo[current_x][op_type] = res;
    return res;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_arr.resize(N + 1);
    for (int i = 2; i <= N; ++i) {
        std::cin >> a_arr[i];
    }

    // Initialize memoization tables
    memo.resize(N + 1, std::vector<long long>(2));
    visited_state.resize(N + 1, std::vector<State>(2, NOT_VISITED));

    for (int i = 1; i < N; ++i) {
        // For each run, a_1 is set to i
        a_arr[1] = i;

        // Reset visited_state for each new run.
        // This is inefficient. A better approach is to clear only relevant states or use a global counter.
        // However, N is up to 2e5, so N*2 states. Clearing N*2 states N times is N^2, too slow.
        // N*2 * N = 4e10 operations.
        // The states are (x, op_type).
        // The problem asks to run the program for a_1 = 1, then a_1 = 2, ..., a_1 = N-1.
        // The values a_2, ..., a_N are fixed. Only a_1 changes.
        // This means the states (x, op_type) where x > 1 are independent of a_1.
        // We only need to recompute for states involving a_1.
        // The states (x, op_type) for x > 1 can be precomputed or memoized across runs.

        // Let's optimize the memoization reset.
        // Only the path starting from (1, 0) depends on a_1.
        // All other states (x, op_type) where x > 1 are independent of a_1.
        // So, we can compute all (x, op_type) for x > 1 once.
        // Then for each i, we just compute for (1, 0).

        // Precompute for x > 1
        // This loop is only executed once for all i.
        // The states (x, op_type) for x > 1 are independent of a_1.
        // So, we can fill memo and visited_state for x > 1 once.
        // The initial call for each i is solve(1, 0).
        // This call will eventually hit states (x, op_type) where x > 1.
        // If those states are already computed, it will use them.
        // If not, it will compute them and store them.
        // So, no explicit precomputation loop is needed.
        // The memoization table `memo` and `visited_state` should persist across the `i` loop.
        // The only state that needs to be "reset" or handled specially is `a_arr[1]`.
        // The `solve` function will correctly use the updated `a_arr[1]` for the current `i`.
        // The `visited_state` for `x=1` needs to be reset for each `i`.
        // For `x > 1`, `a_arr[x]` is constant, so their memoized results are valid across `i`.

        // Reset only the state for x=1 for the current run.
        // This is crucial for correctness and performance.
        visited_state[1][0] = NOT_VISITED;
        visited_state[1][1] = NOT_VISITED;

        long long result = solve(1, 0); // Start with x=1, y=0, first operation is +a_x
        std::cout << result << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // next_valid_r[i] stores the minimum r (0-indexed) such that s[i..r] contains a pattern.
    // If no such r exists for s[i..n-1], it's n.
    std::vector<int> next_valid_r(n + 1, n);

    // Iterate x from n-1 down to 0
    for (int x = n - 1; x >= 0; --x) {
        // Initialize next_valid_r[x] with the value from next_valid_r[x+1]
        // This means if s[x+1..r] contains a pattern, then s[x..r] also contains it.
        next_valid_r[x] = next_valid_r[x + 1];

        // Check for patterns starting at x
        // k can be 1, 2, 3, 4, 5
        // x + 2k must be <= n-1
        // So 2k <= n-1-x
        // k <= (n-1-x)/2
        // Max k is 5, so we only need to check k up to min(5, (n-1-x)/2)
        for (int k = 1; k <= 5; ++k) {
            if (x + 2 * k < n) { // Check if x+2k is a valid index
                if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                    // Found a pattern s[x] = s[x+k] = s[x+2k]
                    // The minimum r for this pattern is x + 2k
                    next_valid_r[x] = std::min(next_valid_r[x], x + 2 * k);
                }
            } else {
                // No need to check larger k values if x+2k is already out of bounds
                break;
            }
        }
    }

    // Calculate bad_pairs
    // For each l (0-indexed), if next_valid_r[l] is n, it means no pattern exists
    // in s[l..n-1]. All pairs (l, r) for r from l to n-1 are bad.
    // The number of such pairs is n - l.
    // If next_valid_r[l] is less than n, it means a pattern exists starting at l
    // or later, and the first such pattern ends at next_valid_r[l].
    // All pairs (l, r) where r < next_valid_r[l] are bad.
    // The number of such pairs is next_valid_r[l] - l.
    for (int l = 0; l < n; ++l) {
        bad_pairs += (next_valid_r[l] - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long a_min = elements[0].value;
    long long a_max = elements[n - 1].value;
    long long a_second_min = elements[1].value;
    long long a_second_max = elements[n - 2].value;

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // All pairs (a_i, a_j) are in the same subsequence.
    // min_f = a_min + a_second_min
    // max_f = a_max + a_second_max
    // Goodness = (a_max + a_second_max) - (a_min + a_second_min)
    long long goodness1 = (a_max + a_second_max) - (a_min + a_second_min);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences.
    // This is the tricky part. We need to find the optimal partition.
    // The minimum possible f value is a_min + a_second_min (if they are in the same subseq)
    // or a_min + a_min_other_subseq + h (if a_min is in one, and a_min_other_subseq is in other)
    // The maximum possible f value is a_max + a_second_max (if they are in the same subseq)
    // or a_max + a_max_other_subseq + h (if a_max is in one, and a_max_other_subseq is in other)

    // Consider the partition where a_min is in S1, and a_max is in S2.
    // Or more generally, a_min is in S1, and a_max is in S2.
    // The values a_min + a_max + h will always be present.
    // The values a_min + a_second_min (if both in S1) or a_max + a_second_max (if both in S2) might be present.

    // Let's analyze the minimum and maximum possible f values for any partition.
    // min_f_overall = min(a_i + a_j, a_k + a_l + h)
    // max_f_overall = max(a_i + a_j, a_k + a_l + h)

    // The smallest possible sum of two elements is a_min + a_second_min.
    // The largest possible sum of two elements is a_max + a_second_max.
    // The smallest possible sum of two elements from different subsequences is a_min + a_min_other_subseq + h.
    // The largest possible sum of two elements from different subsequences is a_max + a_max_other_subseq + h.

    // Consider a specific partition strategy:
    // Put elements[0] (a_min) into S1.
    // Put elements[n-1] (a_max) into S2.
    // Put elements[n-2] (a_second_max) into S2.
    // Put all other elements (elements[1] to elements[n-3]) into S1.
    // This ensures S1 has at least elements[0] and elements[1] (if n >= 2).
    // This ensures S2 has at least elements[n-1] and elements[n-2] (if n >= 2).

    // With this partition:
    // S1: {a_min, a_second_min, ..., a_{n-3}}
    // S2: {a_second_max, a_max}

    // Minimum f value:
    //   - If a_min and a_second_min are in S1: a_min + a_second_min
    //   - If a_min is in S1 and a_second_max is in S2: a_min + a_second_max + h
    //   - If a_min is in S1 and a_max is in S2: a_min + a_max + h
    // The minimum f value will be min(a_min + a_second_min, a_min + a_second_max + h).
    // Note: a_min + a_second_min is always <= a_min + a_second_max + h (since h >= 0).
    // So, min_f = a_min + a_second_min.

    // Maximum f value:
    //   - If a_max and a_second_max are in S2: a_max + a_second_max
    //   - If a_max is in S2 and a_min is in S1: a_max + a_min + h
    //   - If a_max is in S2 and a_second_min is in S1: a_max + a_second_min + h
    // The maximum f value will be max(a_max + a_second_max, a_max + a_min + h).
    // Note: a_max + a_min + h is always <= a_max + a_second_max + h.
    // So, max_f = max(a_max + a_second_max, a_max + a_min + h).

    // Goodness for this partition:
    // max(a_max + a_second_max, a_max + a_min + h) - (a_min + a_second_min)
    long long goodness2 = std::max(a_max + a_second_max, a_max + a_min + h) - (a_min + a_second_min);

    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1; // a_min in S1
    for (int i = 1; i < n - 2; ++i) {
        partition2[elements[i].original_index] = 1; // others in S1
    }
    if (n >= 2) { // a_second_max and a_max
        partition2[elements[n-2].original_index] = 2; // a_second_max in S2
        partition2[elements[n-1].original_index] = 2; // a_max in S2
    }
    if (n == 2) { // Special case for n=2, elements[0] in S1, elements[1] in S2
        partition2[elements[0].original_index] = 1;
        partition2[elements[1].original_index] = 2;
        // min_f = a_min + a_max + h
        // max_f = a_min + a_max + h
        // goodness = 0
        // This is covered by the general logic if we consider the min/max f values.
        // For n=2, S1={a_min}, S2={a_max}. Only one pair (a_min, a_max).
        // f(a_min, a_max) = a_min + a_max + h. Min and max f are both this value. Goodness is 0.
        // This is the best possible goodness.
        // Let's check if goodness2 handles this.
        // a_second_min is not well-defined for n=2.
        // Let's re-evaluate for n=2.
        // If n=2, elements[0] and elements[1].
        // Case 1: Both in S1. f = elements[0].value + elements[1].value. Goodness = 0.
        // Case 2: elements[0] in S1, elements[1] in S2. f = elements[0].value + elements[1].value + h. Goodness = 0.
        // So for n=2, goodness is always 0.
        // The code for n=2 should output 0 and 1 2.
        // My current logic for goodness1: (a_max + a_second_max) - (a_min + a_second_min)
        // For n=2, a_min=elements[0].value, a_max=elements[1].value.
        // a_second_min is elements[1].value. a_second_max is elements[0].value.
        // This is problematic.
        // Let's fix the definition of a_second_min and a_second_max for small n.
        // If n=2: a_min = elements[0].value, a_max = elements[1].value.
        // a_second_min is not used for goodness1.
        // a_second_max is not used for goodness1.
        // If n=2, goodness1 should be 0.
        // If n=2, goodness2 should be 0.
        // The problem states n >= 2.
        // If n=2, there is only one pair (a_0, a_1).
        // If they are in the same subsequence, f = a_0 + a_1. Goodness = 0.
        // If they are in different subsequences, f = a_0 + a_1 + h. Goodness = 0.
        // So for n=2, the answer is always 0.
        // Let's handle n=2 as a special case.
        if (n == 2) {
            std::cout << 0 << "\n";
            std::cout << 1 << " " << 2 << "\n";
            return 0;
        }
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s[0...i-1] and s[i...N-1].
    // We can form s' = s[i...N-1] + s[0...i-1].
    // We need s' to be a palindrome and s' != s.
    for (int i = 1; i < n; ++i) { // i is the cut point, 0 < i < N
        std::string s_prime = s.substr(i) + s.substr(0, i);
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // If k=1 didn't work, we need to check k=2.
    // This means 3 pieces.
    // The problem statement implies that if k=1 doesn't work,
    // but a solution exists, it must be k=2.
    // This is because any string can be cut into N pieces (each character)
    // and reordered to form a palindrome if the character counts allow.
    // However, the constraint is that the pieces are substrings of the original.
    //
    // Consider the structure of a palindrome s.
    // If s consists of only one distinct character (e.g., "aaaaa"),
    // then any reordering of its substrings will result in the same string,
    // which is also "aaaaa". In this case, it's impossible to get s' != s.
    //
    // Let's check if s consists of only one distinct character.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // then k=2 must be the answer.
    // Why?
    // Consider s = s_0 s_1 ... s_{N-1}.
    // Since s is a palindrome, s_0 = s_{N-1}, s_1 = s_{N-2}, etc.
    // If not all characters are the same, there must be at least two distinct characters.
    //
    // If N is odd, say N = 2m + 1.
    // s = s_0 ... s_{m-1} s_m s_{m-1} ... s_0.
    // Consider cutting s into three pieces:
    // P1 = s[0...m-1]
    // P2 = s[m]
    // P3 = s[m+1...N-1] = s[m+1...2m]
    // Note that P3 is the reverse of P1.
    // So P1 = s_0 ... s_{m-1}
    // P2 = s_m
    // P3 = s_{m-1} ... s_0
    //
    // We can reorder them as P3 + P2 + P1.
    // This forms s' = (s_{m-1} ... s_0) + (s_m) + (s_0 ... s_{m-1}).
    // This s' is a palindrome.
    // Is s' != s?
    // s = (s_0 ... s_{m-1}) + (s_m) + (s_{m-1} ... s_0)
    // s' = (s_{m-1} ... s_0) + (s_m) + (s_0 ... s_{m-1})
    // If s' == s, then (s_0 ... s_{m-1}) must be equal to (s_{m-1} ... s_0).
    // This means s[0...m-1] must be a palindrome.
    //
    // If N is even, say N = 2m.
    // s = s_0 ... s_{m-1} s_{m-1} ... s_0.
    // Consider cutting s into three pieces:
    // P1 = s[0...m-1]
    // P2 = "" (empty string, effectively 2 cuts at the same point, or 2 cuts very close)
    // P3 = s[m...N-1]
    // This is not quite right for 3 pieces.
    //
    // A simpler argument for k=2:
    // If s is not all same characters, then s[0...N/2 - 1] is not all same characters.
    // (If s[0...N/2 - 1] were all same, say 'a', then s would be 'a...a' because it's a palindrome).
    // So there exists some `j < N/2` such that `s[j] != s[0]`.
    //
    // Consider the string `s_prefix = s.substr(0, n/2)`.
    // If `s_prefix` is not a palindrome, then `s_prefix + s_suffix` (where `s_suffix` is `s.substr(n/2)`)
    // can be rearranged.
    //
    // The problem statement guarantees that if k=1 doesn't work, and it's not "Impossible", then k=2.
    // The "Impossible" case is handled by checking `all_same_char`.
    // If `s` is a palindrome and not all characters are the same, then `s` must contain at least two distinct characters.
    // For example, `s = "abacaba"`. `n=7`. `n/2 = 3`.
    // `s[0...2] = "aba"`. This is a palindrome.
    // `s[3] = 'c'`.
    // `s[4...6] = "aba"`.
    //
    // If `s` is not all same characters, then `s.substr(0, n-1)` is not all same characters.
    // Consider `s_prime = s.substr(1) + s[0]`.
    // This is a cyclic shift. If `s_prime` is a palindrome and `s_prime != s`, then `k=1`.
    //
    // The problem statement implies that if `k=1` fails and it's not "Impossible", then `k=2`.
    // This is a common pattern in competitive programming problems where the minimum `k` is asked.
    // If `k=1` fails, and the "Impossible" case (all same characters) is handled, then `k=2` is the answer.
    // This is because we can always make two cuts to achieve a different palindrome if the string is not monochromatic.
    // For example, cut `s` into `s[0]`, `s[1...N-2]`, `s[N-1]`.
    // Since `s` is a palindrome, `s[0] == s[N-1]`.
    // We can reorder them as `s[N-1] + s[1...N-2] + s[0]`. This is `s`.
    //
    // A different strategy for k=2:
    // Cut `s` into `s[0...i-1]`, `s[i...j-1]`, `s[j...N-1]`.
    //
    // The simplest argument for k=2 if k=1 fails and not all chars are same:
    // If `s` is a palindrome and not all characters are the same, then `s` must have at least two distinct characters.
    // For example, `s = "abacaba"`.
    // `k=1` check:
    // `bacabaa` (not pal)
    // `acabaab` (not pal)
    // `cabaaba` (not pal)
    // `abaacab` (not pal)
    // `baacaba` (not pal)
    // `aacabab` (not pal)
    //
    // `s = "nolon"`. `n=5`.
    // `k=1` check:
    // `olon` + `n` = `olonn` (not pal)
    // `lon` + `no` = `lonno` (not pal)
    // `on` + `nol` = `onnol` (not pal)
    // `n` + `nolo` = `nnolo` (not pal)
    // So `k=1` fails.
    // `nolon` is not all same chars. So output `2`.
    // Example solution for `nolon`: `no|l|on` -> `on|l|no`. This is `k=2`.
    //
    // `s = "otto"`. `n=4`.
    // `k=1` check:
    // `tto` + `o` = `ttoo` (not pal)
    // `to` + `ot` = `toot` (is pal, `toot != otto`). So `k=1`.
    //
    // `s = "qqqq"`. `n=4`.
    // `k=1` check:
    // `qqq` + `q` = `qqqq` (is pal, but `qqqq == qqqq`).
    // `qq` + `qq` = `qqqq` (is pal, but `qqqq == qqqq`).
    // `q` + `qqq` = `qqqq` (is pal, but `qqqq == qqqq`).
    // So `k=1` fails.
    // `qqqq` is all same chars. So output `Impossible`.
    //
    // `s = "kinnikkinnik"`. `n=12`.
    // `k=1` check:
    // `innikkinnikk` + `k` (not pal)
    // ...
    // `nik` + `kinnikkin` = `nikkinnikkin` (is pal, `nikkinnikkin != kinnikkinnik`). So `k=1`.

    // If we reach here, it means k=1 failed.
    // And we've already checked for the "Impossible" case (all same characters).
    // Therefore, the answer must be 2.
    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long head_reach_left = current_h - T;
        long long head_reach_right = current_h + T;

        // Find the first target track that this head can potentially cover
        // It must be within [head_reach_left, head_reach_right]
        // And it must be greater than or equal to the current p[p_idx]

        // If current_h is already to the right of p[p_idx] + T, this head is too far right for p[p_idx]
        // and potentially for many subsequent p's.
        // We need to find the first p[k] such that p[k] <= head_reach_right.
        // And then check if it can be covered.

        // If p[p_idx] is already to the right of head_reach_right, this head cannot cover p[p_idx]
        // and cannot cover any subsequent p's. So this head is useless for current p_idx.
        // We need to find a head that can cover p[p_idx].
        // The current head can only cover tracks in [current_h - T, current_h + T].
        // If p[p_idx] > current_h + T, this head cannot cover p[p_idx].
        // If p[p_idx] < current_h - T, this head cannot cover p[p_idx].

        // The strategy is: for each head, cover as many *uncovered* tracks as possible, starting from the leftmost uncovered track.
        // If the current head h[h_idx] cannot cover p[p_idx], we move to the next head.
        // If it can, we use it to cover p[p_idx] and all subsequent tracks it can reach.

        if (p[p_idx] > head_reach_right) {
            // This head is too far left to cover p[p_idx]
            // It means current_h + T < p[p_idx].
            // This head cannot cover p[p_idx] or any tracks to its right.
            // So we continue to the next head.
            continue;
        }

        // At this point, p[p_idx] <= head_reach_right.
        // This head *might* be able to cover p[p_idx].
        // We need to determine the effective range this head can cover, considering p[p_idx].

        long long effective_left_bound;
        long long effective_right_bound;

        if (current_h >= p[p_idx]) {
            // Head is at or to the right of p[p_idx].
            // It can move left to cover p[p_idx].
            // The leftmost track it can cover is max(p[p_idx], current_h - T).
            // The rightmost track it can cover is current_h + T.
            // The time taken to reach p[p_idx] is current_h - p[p_idx].
            // Remaining time for rightward movement is T - (current_h - p[p_idx]).
            // So it can cover up to p[p_idx] + (T - (current_h - p[p_idx])) = 2*p[p_idx] - current_h + T.
            // This is equivalent to saying it covers [p[p_idx], p[p_idx] + (T - (current_h - p[p_idx]))]
            // The rightmost point it can reach is p[p_idx] + (T - (current_h - p[p_idx]))
            // This is equivalent to current_h + T - 2*(current_h - p[p_idx]) if it moves left to p[p_idx] and then right.
            // No, this is simpler: if it covers p[p_idx], it can cover any track in [p[p_idx], p[p_idx] + (T - (current_h - p[p_idx]))].
            // The rightmost track it can cover is p[p_idx] + (T - (current_h - p[p_idx])).
            // This is the maximum rightward reach *after* covering p[p_idx].
            effective_right_bound = p[p_idx] + (T - (current_h - p[p_idx]));
        } else { // current_h < p[p_idx]
            // Head is to the left of p[p_idx].
            // It can move right to cover p[p_idx].
            // The time taken to reach p[p_idx] is p[p_idx] - current_h.
            // Remaining time for leftward movement is T - (p[p_idx] - current_h).
            // So it can cover down to p[p_idx] - (T - (p[p_idx] - current_h)) = 2*p[p_idx] - current_h - T.
            // This is equivalent to saying it covers [p[p_idx] - (T - (p[p_idx] - current_h)), p[p_idx]].
            // The rightmost point it can reach is current_h + T.
            effective_right_bound = current_h + T;
        }

        // Now, advance p_idx as long as p[p_idx] is within the effective_right_bound
        while (p_idx < m && p[p_idx] <= effective_right_bound) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between p and h is 10^10.
                                    // Max T could be 10^10.
                                    // If p[0] = 1, h[0] = 10^10, T = 10^10 - 1.
                                    // If p[m-1] = 10^10, h[n-1] = 1, T = 10^10 - 1.
                                    // Max value for p_i or h_i is 10^10.
                                    // So max T could be around 10^10.
                                    // 2 * 10^10 is a safe upper bound.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

