int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        }
    }

    // To maximize the number, we want as many '1's as possible, then '0's.
    // Each '1' uses 'o', 'n', 'e'.
    // Each '0' uses 'z', 'e', 'r', 'o'.

    // First, determine the number of '1's we can form.
    // 'n' is unique to 'one'.
    // 'z' is unique to 'zero'.
    int num_ones = count_n; // Each 'n' can only be used for a '1'.

    // After forming 'num_ones' '1's, we use up 'num_ones' 'o's and 'num_ones' 'e's.
    count_o -= num_ones;
    count_e -= num_ones;

    // Now, determine the number of '0's we can form from the remaining letters.
    // Each '0' requires 'z', 'e', 'r', 'o'.
    int num_zeros = 0;
    if (count_z > 0 && count_e > 0 && count_r > 0 && count_o > 0) {
        num_zeros = std::min({count_z, count_e, count_r, count_o});
    }

    // Print '1's
    for (int i = 0; i < num_ones; ++i) {
        std::cout << "1";
        if (i < num_ones - 1 || num_zeros > 0) {
            std::cout << " ";
        }
    }

    // Print '0's
    for (int i = 0; i < num_zeros; ++i) {
        std::cout << "0";
        if (i < num_zeros - 1) {
            std::cout << " ";
        }
    }
    std::cout << std::endl;

    return 0;
}

