    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick numbers of the form 2k, where k is odd,
        // and ensure that no two numbers are multiples of each other,
        // and all numbers are even (so gcd is at least 2).
        // Specifically, we can pick numbers 2 * (2n-1), 2 * (2n-3), ..., 2 * 1.
        // This sequence is 2, 6, 10, 14, ..., 2*(2n-1).
        // These are 2 * (odd numbers).
        // Let's try picking numbers from 2n+2, 2n+4, ..., 4n.
        // No, the example output for n=3 is 4 6 10.
        // These are 2*2, 2*3, 2*5.
        // For n=2, output is 6 4. These are 2*3, 2*2.
        // For n=4, output is 14 10 12 8. These are 2*7, 2*5, 2*6, 2*4.
        // It seems the strategy is to pick n distinct even numbers from the range [1, 4n]
        // such that none of them divide each other.
        // A simple way to achieve this is to pick numbers from the upper half of the even numbers.
        // For example, pick 2n, 2n+2, ..., 4n-2. This gives n numbers.
        // Let's check this strategy:
        // For n=2: 2*2=4, 2*2+2=6. Output: 4 6. Matches example (order doesn't matter).
        // For n=3: 2*3=6, 2*3+2=8, 2*3+4=10. Output: 6 8 10. Example output: 4 6 10.
        // My strategy gives 6 8 10.
        //   gcd(6,8)=2, 6!|8, 8!|6. OK.
        //   gcd(6,10)=2, 6!|10, 10!|6. OK.
        //   gcd(8,10)=2, 8!|10, 10!|8. OK.
        // This strategy seems valid.
        // The numbers are 2n, 2n+2, ..., 2n + 2*(n-1) = 4n-2.
        // All are even, so gcd is at least 2.
        // None divides another: if 2k divides 2j, then k divides j.
        // Here, we have k, k+1, ..., 2k-1 (if we divide by 2).
        // For n=3, numbers are 6, 8, 10. Divided by 2: 3, 4, 5.
        // No number in {3,4,5} divides another.
        // This strategy works.

        for (int i = 0; i < n; ++i) {
            std::cout << 2 * n + 2 * i << (i == n - 1 ? "" : " ");
        }
