int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need k * y sticks. Each coal trade costs y sticks and 1 trade.
        // So, k coal trades will cost k * y sticks and k trades.
        long long sticks_for_coal = k * y;

        // Total sticks required for both coal and torches:
        // k * y sticks for coal + k sticks for torches
        long long total_sticks_required = sticks_for_coal + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_required - 1) additional sticks.
        long long sticks_to_acquire_from_trades = total_sticks_required - 1;

        // Each stick trade (1 stick for x sticks) gives a net gain of (x - 1) sticks.
        // Number of stick trades needed: ceil(sticks_to_acquire_from_trades / (x - 1))
        // Using integer division for ceil(a/b): (a + b - 1) / b
        long long stick_trades = (sticks_to_acquire_from_trades + (x - 1) - 1) / (x - 1);

        // Total trades = stick trades + coal trades
        // Coal trades = k (since each coal trade gives 1 coal)
        long long total_trades = stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

