#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element.
            // The flags for has_pos_one and has_neg_one are already set based on original 'a'
            // and are relevant for elements to the right (larger indices).
            // For current 'i', we just need to ensure it can be made equal to b[i].
            // If a[i] == b[i], it's already good.
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. This requires a '1' at an index j < i.
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. This requires a '-1' at an index j < i.
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update has_pos_one and has_neg_one for elements to the left (smaller indices).
        // These flags indicate if a 1 or -1 exists in a[0...i-1].
        // For the next iteration (i-1), we need to know if a 1 or -1 exists in a[0...i-2].
        // So, if a[i] was 1 or -1, it's no longer available for elements to its left.
        // However, the problem states "choose any pair of indexes (i, j) such that 1 <= i < j <= n".
        // This means a_i is the source, and a_j is the destination.
        // When we process from right to left, for a_k, we need to check if there's a 1 or -1
        // at an index < k.
        // The `has_pos_one` and `has_neg_one` flags should track if there's a 1 or -1
        // *among a[0...i-1]* for the current iteration `i`.
        // The initial `has_pos_one` and `has_neg_one` are for `a[0...n-1]`.
        // As we iterate `i` from `n-1` down to `0`, these flags should reflect `a[0...i-1]`.
        // So, if `a[i]` was `1` or `-1`, it contributes to the flags for indices `>i`.
        // For index `i`, we need to know if there's a `1` or `-1` in `a[0...i-1]`.
        // The current `has_pos_one` and `has_neg_one` are for `a[0...i]`.
        // We need to update them to reflect `a[0...i-1]` for the next iteration.
        // This means if `a[i]` was the *only* `1` or `-1` in `a[0...i]`, then for `a[0...i-1]`
        // that specific `1` or `-1` is no longer available.

        // Let's re-evaluate the flags.
        // `has_pos_one` should be true if there exists `k < i` such that `a[k] == 1`.
        // `has_neg_one` should be true if there exists `k < i` such that `a[k] == -1`.
        // The initial `has_pos_one` and `has_neg_one` are for `a[0...n-1]`.
        // When we are at index `i`, we need to know if there's a `1` or `-1` in `a[0...i-1]`.
        // So, we should update the flags *after* checking `a[i]`.
        // If `a[i]` was `1`, it means `has_pos_one` might become false if it was the last `1`
        // in `a[0...i]`. This requires counting.

        // A simpler approach for flags:
        // `can_add_pos` = true if there is any `a[k] == 1` with `k < current_index`.
        // `can_add_neg` = true if there is any `a[k] == -1` with `k < current_index`.
        // Let's maintain these counts.
    }

    // Re-think the flag logic.
    // `has_pos_one_prefix[i]` = true if there is a 1 in `a[0...i-1]`.
    // `has_neg_one_prefix[i]` = true if there is a -1 in `a[0...i-1]`.
    // These can be precomputed.

    std::vector<bool> has_pos_one_prefix(n + 1, false); // has_pos_one_prefix[k] is true if a[0...k-1] contains 1
    std::vector<bool> has_neg_one_prefix(n + 1, false); // has_neg_one_prefix[k] is true if a[0...k-1] contains -1

    for (int i = 0; i < n; ++i) {
        has_pos_one_prefix[i+1] = has_pos_one_prefix[i] || (a[i] == 1);
        has_neg_one_prefix[i+1] = has_neg_one_prefix[i] || (a[i] == -1);
    }

    possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No change needed for a[i].
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. Requires a '1' at an index j < i.
            if (!has_pos_one_prefix[i]) { // Check if a[0...i-1] contains 1
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. Requires a '-1' at an index j < i.
            if (!has_neg_one_prefix[i]) { // Check if a[0...i-1] contains -1
                possible = false;
                break;
            }
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

