#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);
    bool n_found = false;

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) { // Only consider a_i,j where i != j
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is based on the observation that if p[i] is not n,
        // then max_{j!=i} min(p[i], p[j]) = max_{j!=i, p[j] < p[i]} p[j] (if such j exists)
        // or p[i] (if all p[j] > p[i]).
        // More simply, max_{j!=i} min(p[i], p[j]) will be p[i] if p[i] is not n,
        // because there must be some p[j] > p[i] (unless p[i] is n-1 and all others are smaller, which is not general).
        // The key insight is that if p[i] is not n, then there exists some p[k] > p[i].
        // For such p[k], min(p[i], p[k]) = p[i].
        // So, max_{j!=i} min(p[i], p[j]) will be p[i] if p[i] is not n.
        // If p[i] is n, then max_{j!=i} min(n, p[j]) = max_{j!=i} p[j] = n-1.
        if (max_val_in_row == n - 1) {
            p[i] = n;
            n_found = true;
        } else {
            p[i] = max_val_in_row;
        }
    }

    // If n was not found in any row (which implies n=2 and p={1,2} or p={2,1}),
    // it means all max_val_in_row were 1.
    // In this case, we need to assign n to one of the elements.
    // The problem guarantees a solution exists.
    // For n=2, a_0,1 = min(p_0, p_1). If p_0=1, p_1=2, then a_0,1=1. max_val_in_row for p_0 is 1.
    // If p_0=2, p_1=1, then a_0,1=1. max_val_in_row for p_0 is 1.
    // So for n=2, both p[0] and p[1] would initially be assigned 1.
    // We need to assign n to one of them.
    if (!n_found) {
        // This case only happens if n=2 and both p[0] and p[1] were assigned 1.
        // Or more generally, if all max_val_in_row were less than n-1.
        // The problem statement guarantees that there is at least one solution.
        // If n is not found, it means all p[i] were assigned values < n.
        // Since it's a permutation of 1 to n, n must be present.
        // The logic `p[i] = max_val_in_row` correctly assigns p[i] if p[i] < n.
        // If p[i] = n, then max_val_in_row is n-1.
        // So if n_found is false, it means no p[i] was n.
        // This implies that all p[i] were assigned values from 1 to n-1.
        // One of these values must be n.
        // The simplest way to fix this is to find the maximum value currently in p
        // and replace it with n. This works because if p[i] was supposed to be n,
        // its max_val_in_row would be n-1. If p[i] was supposed to be n-1,
        // its max_val_in_row would be n-1 (if n is present elsewhere) or n-2 (if n is not present).
        // The problem guarantees a solution. The logic `p[i] = max_val_in_row`
        // correctly identifies p[i] if p[i] < n. If p[i] = n, it identifies it as n-1.
        // So, if n_found is false, it means all p[i] were assigned values from 1 to n-1.
        // One of these values must be n. The one that should be n is the one that was assigned n-1.
        // If there are multiple n-1s, any one can be changed to n.
        // The simplest is to find the maximum value in p and change it to n.
        // This handles the n=2 case where p={1,1} becomes p={2,1} or p={1,2}.
        int max_p_val = 0;
        int max_p_idx = -1;
        for (int i = 0; i < n; ++i) {
            if (p[i] > max_p_val) {
                max_p_val = p[i];
                max_p_idx = i;
            }
        }
        if (max_p_idx != -1) { // Should always be true for n >= 2
            p[max_p_idx] = n;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

