#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i from 1 to n-1 (p_i+1)
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i was not a prefix max before.
                // But it's good to check for robustness.
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some unused number less than q_i.
            // We need to pick the smallest available number to maximize chances for future elements.
            // The largest available number less than q_i is q_i - 1, then q_i - 2, etc.
            // We need to find the smallest number not yet used, that is also less than q_i.
            // This is equivalent to finding the smallest number in [1, n] that is not in used_numbers.
            // We can iterate from 1 upwards or use a data structure.
            // A set of available numbers would be efficient.
            // Let's find the smallest available number.
            // The numbers that are NOT used are candidates.
            // We need to find the smallest number `x` such that `x < q[i]` and `x` is not in `used_numbers`.
            // A more direct approach: find the largest number `x` such that `x < q[i]` and `x` is not in `used_numbers`.
            // This is because we want to leave larger numbers for later if they become new maximums.
            // However, the problem asks for *any* suitable permutation.
            // The strategy of picking the smallest available number for p_i when q_i == q_{i-1}
            // is generally a good greedy approach.
            // Let's maintain a set of available numbers.
            // Or, more simply, iterate downwards from q[i]-1.

            int current_val = q[i-1]; // q[i] == q[i-1]
            int found_val = -1;
            for (int k = current_val - 1; k >= 1; --k) {
                if (!used_numbers.count(k)) {
                    found_val = k;
                    break;
                }
            }

            if (found_val != -1) {
                p[i] = found_val;
                used_numbers.insert(found_val);
            } else {
                possible = false;
                break;
            }
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        // Final check: ensure all numbers from 1 to n are used exactly once.
        // This is implicitly handled by the logic if `possible` is true.
        // If `possible` is true, `used_numbers` will contain `n` distinct elements.
        // Since all `p_i` are chosen from `[1, n]`, and `used_numbers` contains `n` distinct elements,
        // it must be that `used_numbers` contains exactly `[1, 2, ..., n]`.
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

