    int t;
    std::cin >> t;

    std::vector<long long> costs;
    long long current_n = 1;
    long long current_cost = 1; // Cost for n=1
    costs.push_back(current_cost);

    // Precompute costs for nice staircases
    // The maximum possible n for x = 10^18 is when 2^k - 1 is roughly 10^18.
    // 2^k approx 10^18 => k approx log2(10^18) = 18 * log2(10) approx 18 * 3.32 = 59.79.
    // So k can go up to around 60.
    // The cost formula is (2^k - 1) * (2^k) / 2.
    // For k=60, 2^60 is a very large number.
    // The cost is (2^k - 1) * 2^(k-1).
    // For k=1, n=1, cost = 1 * 1 / 2 = 1. (2^1-1)*2^0 = 1.
    // For k=2, n=3, cost = 3 * 2 = 6. (2^2-1)*2^1 = 3*2 = 6.
    // For k=3, n=7, cost = 7 * 4 = 28. (2^3-1)*2^2 = 7*4 = 28.
    // The formula for cost is (2^k - 1) * 2^(k-1).
    // Let n_k = 2^k - 1. The cost is n_k * (n_k + 1) / 2.
    // This is (2^k - 1) * (2^k - 1 + 1) / 2 = (2^k - 1) * 2^k / 2 = (2^k - 1) * 2^(k-1).

    // We need to be careful with overflow.
    // 2^60 is about 1.15 * 10^18.
    // (2^60 - 1) * 2^59 would overflow long long.
    // The maximum x is 10^18.
    // Let's find the maximum k such that (2^k - 1) * 2^(k-1) <= 10^18.
    // For k=1, cost = 1.
    // For k=2, cost = 3 * 2 = 6.
    // For k=3, cost = 7 * 4 = 28.
    // For k=4, cost = 15 * 8 = 120.
    // For k=5, cost = 31 * 16 = 496.
    // ...
    // For k=30, 2^30 is about 10^9.
    // (2^30 - 1) * 2^29 is about (10^9) * (0.5 * 10^9) = 0.5 * 10^18. This fits.
    // For k=31, (2^31 - 1) * 2^30 is about (2 * 10^9) * (10^9) = 2 * 10^18. This might exceed 10^18.
    // Let's calculate precisely.
    // k=30: (1073741824LL - 1) * 536870912LL = 1073741823LL * 536870912LL = 576460750999999999LL. This is < 10^18.
    // k=31: (2147483648LL - 1) * 1073741824LL = 2147483647LL * 1073741824LL = 2305843008139952128LL. This is > 10^18.
    // So we need costs up to k=30.

    for (int k = 2; k <= 30; ++k) {
        long long n_k = (1LL << k) - 1; // 2^k - 1
        long long cost_k = n_k * (1LL << (k - 1)); // (2^k - 1) * 2^(k-1)
        if (cost_k > 2000000000000000000LL) { // A bit more than 10^18 to be safe, though 10^18 is enough
            break;
        }
        costs.push_back(cost_k);
    }

    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        // Iterate through costs in descending order (greedy approach)
        // This is correct because the costs are powers of 2 related,
        // specifically, cost_k = (2^k - 1) * 2^(k-1).
        // The costs are 1, 6, 28, 120, 496, ...
        // This is a canonical coin problem.
        // If we have coins 1, 6, 28, ... and we want to make change for X,
        // a greedy approach works if the coin values satisfy certain properties.
        // Here, the costs are not directly powers of 2, but they are of the form (2^k-1)*2^(k-1).
        // Let C_k be the cost for k stairs.
        // C_1 = 1
        // C_2 = 6
        // C_3 = 28
        // C_4 = 120
        // C_5 = 496
        // C_6 = 2016
        // C_7 = 8128
        // C_8 = 32640
        // C_9 = 130816
        // C_10 = 523776
        // C_11 = 2096128
        // C_12 = 8386560
        // C_13 = 33550336
        // C_14 = 134209536
        // C_15 = 536854528
        // C_16 = 2147450880
        // C_17 = 8589869056
        // C_18 = 34359607296
        // C_19 = 137438633984
        // C_20 = 549755581440
        // C_21 = 2199022880768
        // C_22 = 8796091877376
        // C_23 = 35184371900416
        // C_24 = 140737479000000 (approx)
        // C_25 = 562949953421312
        // C_26 = 2251799813685248
        // C_27 = 9007199254740992
        // C_28 = 36028797018963968
        // C_29 = 144115187660000000 (approx)
        // C_30 = 576460750999999999

        // The greedy approach works here.
        // If we have a sum S and we can use a cost C_k, we should use the largest C_k <= S.
        // This is because C_k is significantly larger than the sum of all smaller costs.
        // Sum of C_i for i < k:
        // Sum_{i=1}^{k-1} (2^i - 1) * 2^(i-1)
        // This sum is always less than C_k.
        // For example, C_1 + C_2 = 1 + 6 = 7 < C_3 = 28.
        // C_1 + ... + C_{k-1} < C_k.
        // This property ensures that a greedy approach (always taking the largest possible staircase)
        // yields the maximum number of staircases.

        for (int i = costs.size() - 1; i >= 0; --i) {
            if (x >= costs[i]) {
                x -= costs[i];
                count++;
            }
        }
        std::cout << count << "\n";
    }

    return 0;
}

