#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point x_k such that x_k - x_i <= d

    for (int i = 0; i < n; ++i) {
        // For each fixed x_i, advance right_ptr to find the largest index 'k'
        // such that x[k] - x[i] <= d.
        // Since x is sorted, x[k] will be <= x[i] + d.
        // The right_ptr only moves forward, making this O(N) overall.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // After the loop, right_ptr points to the first element x[right_ptr]
        // such that x[right_ptr] - x[i] > d, OR right_ptr == n.
        // So, all valid x_k for the current x_i are in the range [i+1, right_ptr-1].

        // The number of points available to choose from (excluding x_i itself)
        // is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let this be 'm'. These are points x_{i+1}, ..., x_{right_ptr-1}.
        // We need to choose 2 points from these 'm' points.
        // The number of ways to choose 2 points from 'm' points is m * (m - 1) / 2.

        long long m = (long long)(right_ptr - 1) - (i + 1) + 1;
        // m = right_ptr - 1 - i;
        // This 'm' is the count of points x_j, x_k such that i < j < k and x_k - x_i <= d.
        // More precisely, 'm' is the number of points in the range (x_i, x_{right_ptr-1}].
        // If m < 2, we cannot choose two distinct points, so we add 0.
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
