int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // For 0-indexed array, this is the middle element

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Elements to the left of the median must be <= s
    // If an element a[i] < s, it's fine.
    // If an element a[i] > s, it must be decreased to s.
    // Since we want minimum operations, we only change elements that violate the median property.
    // For elements to the left of median_idx, they must be <= s.
    // If a[i] > s, we must decrease it to s. The cost is a[i] - s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of the median must be >= s
    // If an element a[i] > s, it's fine.
    // If an element a[i] < s, it must be increased to s.
    // For elements to the right of median_idx, they must be >= s.
    // If a[i] < s, we must increase it to s. The cost is s - a[i].
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

