struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<ElementB> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    std::sort(A.begin(), A.end(), compareElementA);
    std::sort(B.begin(), B.end(), compareElementB);

    std::vector<long long> result(m);

    // The problem states A_i >= B_j for all i, j.
    // This implies that A_sorted[i] >= B_sorted[j] for all i, j.
    // Specifically, A_sorted[0] >= B_sorted[m-1].
    // This means A_sorted[i] >= B_sorted[j] for any i, j.
    // So, A_sorted[i] >= B_sorted[m-1-i] is always true.

    // To maximize sum F(A'_i, B_i), we want to pair largest A with smallest B,
    // and smallest A with largest B.
    // F(n, k) = n / (k+1).
    // We want to maximize sum A'_i / (B_i + 1).
    // This is a rearrangement inequality type problem.
    // To maximize sum(x_i * y_i), we sort both x and y in the same order.
    // To maximize sum(x_i / y_i), we sort x in ascending order and y in descending order.
    // Here, we want to maximize sum(A'_i / (B_i + 1)).
    // So, we should sort A' (which is A_sorted) in ascending order,
    // and (B_i + 1) in descending order.
    // This means B_i should be sorted in descending order.

    // A is sorted ascending: A[0], A[1], ..., A[m-1]
    // B is sorted ascending: B[0], B[1], ..., B[m-1]
    // We need to pair A_sorted[i] with B_sorted[m-1-i] to achieve the desired pairing.
    // The original index of B_sorted[m-1-i] is B[m-1-i].original_index.
    // The value A_sorted[i].value should be placed at result[B[m-1-i].original_index].

    for (int i = 0; i < m; ++i) {
        result[B[m - 1 - i].original_index] = A[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

