int calculate_score(const std::string& s) {
    int score = 0;
    if (s.empty()) {
        return 0;
    }
    if (s[0] == 'W') {
        score += 1;
    }
    for (size_t i = 1; i < s.length(); ++i) {
        if (s[i] == 'W') {
            if (s[i-1] == 'W') {
                score += 2;
            } else {
                score += 1;
            }
        }
    }
    return score;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_wins = 0;
        for (char c : s) {
            if (c == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins + k == 0) { // All games are L and k=0, or all L and k changes don't make any W
            std::cout << 0 << "\n";
            continue;
        }

        if (initial_wins + k >= n) { // We can make all games W
            std::cout << 2 * n - 1 << "\n";
            continue;
        }

        // Calculate initial score
        int current_score = calculate_score(s);

        // Find segments of 'L's between 'W's
        std::vector<int> l_segments_lengths;
        int first_w = -1, last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) {
                    first_w = i;
                }
                last_w = i;
            }
        }

        if (first_w == -1) { // All games are 'L'
            std::cout << std::max(0, 2 * k - 1) << "\n"; // If k > 0, we can make k 'W's. The first 'W' gives 1, others 2.
            continue;
        }

        int current_l_length = 0;
        for (int i = first_w + 1; i < last_w; ++i) {
            if (s[i] == 'L') {
                current_l_length++;
            } else {
                if (current_l_length > 0) {
                    l_segments_lengths.push_back(current_l_length);
                }
                current_l_length = 0;
            }
        }
        if (current_l_length > 0) {
            l_segments_lengths.push_back(current_l_length);
        }

        std::sort(l_segments_lengths.begin(), l_segments_lengths.end());

        for (int length : l_segments_lengths) {
            if (k >= length) {
                k -= length;
                current_score += 2 * length + 1; // Each L becomes W, connecting two Ws. Each L gives 2 points, plus 1 for connecting.
            } else {
                current_score += 2 * k; // Use remaining k to convert Ls to Ws, but not enough to connect. Each gives 2 points.
                k = 0;
                break;
            }
        }

        // Use remaining k for 'L's at the ends
        if (k > 0) {
            // L's before first_w
            current_score += std::min(k, first_w) * 2;
            k -= std::min(k, first_w);
        }
        if (k > 0) {
            // L's after last_w
            current_score += std::min(k, n - 1 - last_w) * 2;
            k -= std::min(k, n - 1 - last_w);
        }

        std::cout << current_score << "\n";
    }
    return 0;
}

