void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;
    int a_ptr_left = 0;
    int a_ptr_right = n - 1;

    // Friends who get w_i = 1 integers
    // These friends should get the largest available integers,
    // as their happiness is 2 * integer.
    // Since w is sorted, these are the first elements in w.
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_right];
            a_ptr_right--;
        } else {
            // All remaining w_i will be > 1
            // Break and handle them in the next loop
            // This relies on w being sorted.
            break;
        }
    }

    // Friends who get w_i > 1 integers
    // These friends should get one largest available integer (for max_val)
    // and one smallest available integer (for min_val).
    // The remaining w_i - 2 integers don't affect max/min, so they can be
    // any other available integers. To maximize sum of min_val, we should
    // give the smallest available integers to these friends.
    // We iterate w in reverse order for w_i > 1 to assign largest max_val first.
    // The largest w_i values will consume more elements from the left.
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_right]; // Max value for this friend
            a_ptr_right--;

            total_happiness += a[a_ptr_left]; // Min value for this friend
            a_ptr_left += (w[i] - 1); // Consume w_i - 1 smallest elements
        }
    }

    std::cout << total_happiness << std::endl;
}

