    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will effectively "pass through" this 'b',
            // generating a new 'b' and doubling the 'a's count for future 'b's.
            // The number of 'a's that will interact with this 'b' is `count_a`.
            // Each such 'a' will contribute `count_a` steps (from previous 'a's)
            // plus 1 step for this 'a' passing this 'b'.
            // The total steps added by this 'b' is `count_a`.
            total_steps = (total_steps + count_a) % mod;
            // After this 'b' is processed by all 'a's to its left,
            // it effectively doubles the number of 'a's that will interact
            // with 'b's further to the left.
            // This is because each 'a' passing this 'b' creates a new 'b'.
            // So, the 'a's that were to the left of this 'b' now effectively
            // represent `2 * count_a` 'a's for any 'b's further left.
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are waiting to interact with 'b's to their right.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

