#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_sequences = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // If the first matryoshka in a chain is 1, it's a potential start of the main sequence.
        // We need to count how many consecutive correct nestings (j -> j+1) exist starting from 1.
        if (chain[0] == 1) {
            int current_expected = 1;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_expected) {
                    correct_sequences++;
                    current_expected++;
                } else {
                    // The sequence 1 -> 2 -> ... -> current_expected-1 is correct.
                    // Any further elements in this chain are not part of the initial correct prefix.
                    break; 
                }
            }
        }
    }

    // Total operations needed:
    // 1. Disassemble all incorrect nestings.
    //    Each chain of length `m` has `m-1` nestings.
    //    Total initial nestings = n - k (since sum of m_i = n, and each chain has m_i-1 nestings)
    //    Number of correct nestings (1->2, 2->3, ...) is `correct_sequences - 1`.
    //    So, `(n - k) - (correct_sequences - 1)` nestings need to be undone.
    //    Each undo operation costs 1 second.
    //    This simplifies to `n - k - correct_sequences + 1` operations.
    // 2. Reassemble the final chain.
    //    The final chain `1 -> 2 -> ... -> n` requires `n-1` nestings.
    //    We already have `correct_sequences - 1` of these.
    //    So, `(n-1) - (correct_sequences - 1)` new nestings need to be performed.
    //    Each new nesting operation costs 1 second.
    //    This simplifies to `n - correct_sequences` operations.

    // Total operations = (disassemble incorrect) + (assemble missing correct)
    // Total operations = ( (n - k) - (correct_sequences - 1) ) + ( (n - 1) - (correct_sequences - 1) )
    // Total operations = (n - k - correct_sequences + 1) + (n - correct_sequences)
    // Total operations = n - k - correct_sequences + 1 + n - correct_sequences
    // Total operations = 2*n - k - 2*correct_sequences + 1

    // Let's re-evaluate.
    // We need to form n-1 connections (1->2, 2->3, ..., (n-1)->n).
    // `correct_sequences - 1` of these connections are already present and correct.
    // So, `(n-1) - (correct_sequences - 1)` connections need to be *made*. This is `n - correct_sequences` 'put' operations.

    // For the 'get out' operations:
    // Each chain has `m_i` dolls. If `m_i > 1`, it has `m_i - 1` internal nestings.
    // The total number of initial nestings across all chains is `(m_1-1) + (m_2-1) + ... + (m_k-1) = (m_1+...+m_k) - k = n - k`.
    // Out of these `n-k` initial nestings, `correct_sequences - 1` are part of the final `1->2->...->n` sequence.
    // The remaining `(n-k) - (correct_sequences - 1)` nestings must be undone. These are 'get out' operations.
    // This simplifies to `n - k - correct_sequences + 1` 'get out' operations.

    total_operations = (long long)(n - correct_sequences) + (long long)(n - k - correct_sequences + 1);

    std::cout << total_operations << std::endl;

    return 0;
}

