    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        char last1 = '0';
        char last2 = '0';
        bool possible_with_pivot = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < pivot_digit + '0') {
                // Must be color 1
                if (current_digit < last1) {
                    possible_with_pivot = false;
                    break;
                }
                result[i] = '1';
                last1 = current_digit;
            } else if (current_digit > pivot_digit + '0') {
                // Must be color 2
                if (current_digit < last2) {
                    possible_with_pivot = false;
                    break;
                }
                result[i] = '2';
                last2 = current_digit;
            } else { // current_digit == pivot_digit + '0'
                // Can be color 1 or 2
                // Prioritize color 2 if it maintains non-decreasing order
                if (current_digit >= last2) {
                    result[i] = '2';
                    last2 = current_digit;
                } else if (current_digit >= last1) {
                    result[i] = '1';
                    last1 = current_digit;
                } else {
                    possible_with_pivot = false;
                    break;
                }
            }
        }

        if (possible_with_pivot) {
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
