#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_pattern(k, '?');

    // Step 1: Determine the fixed pattern for each remainder modulo k
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            if (fixed_pattern[i % k] == '?') {
                fixed_pattern[i % k] = s[i];
            } else if (fixed_pattern[i % k] != s[i]) {
                // Conflict: s[i] contradicts an already determined character for this position modulo k
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Count 0s, 1s, and ?s in the fixed pattern
    int count0 = 0;
    int count1 = 0;
    int count_q = 0;
    for (int i = 0; i < k; ++i) {
        if (fixed_pattern[i] == '0') {
            count0++;
        } else if (fixed_pattern[i] == '1') {
            count1++;
        } else { // fixed_pattern[i] == '?'
            count_q++;
        }
    }

    // Step 3: Check if it's possible to fill '?'s to satisfy k/2 zeros and k/2 ones
    int target_half = k / 2;
    if (count0 > target_half || count1 > target_half) {
        std::cout << "NO\n";
        return;
    }

    // We need (target_half - count0) more zeros and (target_half - count1) more ones.
    // The remaining '?'s must be able to cover these counts.
    // The total number of '?'s is count_q.
    // (target_half - count0) + (target_half - count1) must be <= count_q.
    // This is equivalent to: 2 * target_half - (count0 + count1) <= count_q
    // Since 2 * target_half = k, and count0 + count1 + count_q = k,
    // this condition simplifies to k - (count0 + count1) <= count_q, which is true if count0 + count1 + count_q = k.
    // The actual check is that we have enough '?'s to fill the deficit.
    // The number of '?'s that must become '0' is target_half - count0.
    // The number of '?'s that must become '1' is target_half - count1.
    // The sum of these must be less than or equal to the total '?'s available.
    if ((target_half - count0) + (target_half - count1) <= count_q) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

