#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_val
    long long sum_r_val = (b - 1);
    sum_r_val %= MOD;
    long long b_mod = b % MOD;
    sum_r_val = (sum_r_val * b_mod) % MOD;

    // We need to divide by 2. Modular inverse of 2 modulo 10^9+7 is (10^9+8)/2 = 500000004
    long long inv2 = 500000004;
    sum_r_val = (sum_r_val * inv2) % MOD;

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_kb_plus_1_val
    // sum_{k=1 to a} (k*b + 1) = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a
    long long sum_k_val = a;
    sum_k_val %= MOD;
    long long a_plus_1_mod = (a + 1) % MOD;
    sum_k_val = (sum_k_val * a_plus_1_mod) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD; // (a * (a+1) / 2)

    long long sum_kb_plus_1_val = (b_mod * sum_k_val) % MOD;
    long long a_mod = a % MOD;
    sum_kb_plus_1_val = (sum_kb_plus_1_val + a_mod) % MOD;

    long long total_sum = (sum_r_val * sum_kb_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

