    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_val = (dq.empty() ? 0 : L[dq.back()]);
        L[i] = prev_val + 1;
        dq.push_back(i);
    }

    dq.clear();
    std::vector<long long> R(n);
    for (int i = n - 1; i >= 0; --i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_val = (dq.empty() ? 0 : R[dq.back()]);
        R[i] = prev_val + 1;
        dq.push_back(i);
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min({h[i], L[i], R[i]}));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

