int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << 1 << " " << 1 << "\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: Dummy operation (e.g., add 0 to a[0])
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";

        // Operation 3: Dummy operation (e.g., add 0 to a[0])
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
        return 0;
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // Select segment [1, n-1] (0-indexed: [0, n-2])
    // For each a[i] in this segment, add (n - (a[i] % n)) % n * n
    // This makes a[i] a multiple of n.
    // The length of this segment is n-1.
    // We need to add a multiple of (n-1).
    // This strategy is flawed. The problem states "add a multiple of len".
    // The strategy should be:
    // For each a[i], we want to add x_i such that (a[i] + x_i) % n == 0.
    // And x_i must be a multiple of len.
    // This is tricky.

    // Let's use the standard trick for n > 1.
    // Operation 1: Make a[0]...a[n-2] multiples of n.
    // Segment: [1, n-1] (0-indexed: [0, n-2])
    // Length: n-1
    std::cout << 1 << " " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = (a[i] % n + n) % n; // Ensure positive remainder
        long long to_add = remainder * (n - 1); // This is a multiple of (n-1)
        // We want a[i] + x_i to be a multiple of n.
        // a[i] + x_i = k*n
        // x_i = k*n - a[i]
        // x_i must be a multiple of (n-1).
        // Let's try to make a[i] become a multiple of n.
        // We need to add (n - (a[i] % n)) % n to a[i] to make it a multiple of n.
        // Let this value be `val_to_add`.
        // We need `val_to_add` to be a multiple of `n-1`.
        // This is not directly possible.

        // The standard solution for this problem type:
        // Operation 1: For elements a[0]...a[n-2]
        // Select segment [1, n-1] (0-indexed: [0, n-2])
        // Length is n-1.
        // For each a[i], we want to add x_i such that (a[i] + x_i) % n == 0.
        // And x_i must be a multiple of (n-1).
        // Let a[i] = q*n + r, where 0 <= r < n.
        // We want to add x_i such that a[i] + x_i = k*n.
        // So x_i = k*n - a[i].
        // We need x_i to be a multiple of (n-1).
        // Consider a[i] * (n-1).
        // (a[i] * (n-1)) % n = (a[i] * (-1)) % n = (-a[i]) % n.
        // So if we add a[i] * (n-1) to a[i], it becomes a[i] + a[i]*(n-1) = a[i]*n.
        // This is a multiple of n.
        // And a[i]*(n-1) is a multiple of (n-1).
        // So, for each a[i] in [0, n-2], add a[i]*(n-1).
        // This makes a[i] become a[i]*n.
        // Then, in the next step, we can make it 0.
        long long add_val = a[i] * (n - 1);
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val;
    }
    std::cout << "\n";

    // Operation 2: For the last element a[n-1]
    // Select segment [n, n] (0-indexed: [n-1, n-1])
    // Length is 1.
    // Add -a[n-1] to a[n-1]. This is a multiple of 1.
    std::cout << n << " " << n << "\n";
    std::cout << -a[n - 1] << "\n";
    a[n - 1] = 0;

    // Operation 3: For all elements a[0]...a[n-1]
    // Select segment [1, n] (0-indexed: [0, n-1])
    // Length is n.
    // At this point, a[0]...a[n-2] are all multiples of n (specifically, a[i]*n).
    // a[n-1] is 0.
    // For each a[i], add -a[i]. Since a[i] is a multiple of n, -a[i] is also a multiple of n.
    std::cout << 1 << " " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for two test values: 0 and 1023 (all bits set)
    // We need to track how 0 and 1023 transform.
    // Let's use 0 and -1 (which is all bits set in 2's complement, effectively 1023 for 10 bits)
    // Or, more simply, track how 0 and 1 transform for each bit.
    // Let's track the final value for an input of 0 and an input of 1023.
    // This is not quite right. We need to track how each bit transforms.
    // For each bit position (0 to 9), we need to know:
    // 1. What happens if the input bit is 0? (output_bit_for_input_0)
    // 2. What happens if the input bit is 1? (output_bit_for_input_1)

    // Let's represent the state for each bit position.
    // For each bit `j` (0 to 9):
    // `val_0[j]` will be the `j`-th bit of the result if the input `x` has `j`-th bit 0.
    // `val_1[j]` will be the `j`-th bit of the result if the input `x` has `j`-th bit 1.
    // Initially, if input bit is 0, output bit is 0. If input bit is 1, output bit is 1.
    // So, `val_0[j] = 0` and `val_1[j] = 1` for all `j`.

    // We can represent this more compactly.
    // Let `current_val_if_input_is_0` be the value that 0 transforms into.
    // Let `current_val_if_input_is_1023` be the value that 1023 transforms into.
    // Initially:
    int current_val_if_input_is_0 = 0;
    int current_val_if_input_is_1023 = 1023; // All 10 bits set

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_if_input_is_0 &= x;
            current_val_if_input_is_1023 &= x;
        } else if (op_char == '|') {
            current_val_if_input_is_0 |= x;
            current_val_if_input_is_1023 |= x;
        } else if (op_char == '^') {
            current_val_if_input_is_0 ^= x;
            current_val_if_input_is_1023 ^= x;
        }
    }

    // Now we have the final transformed values for input 0 and input 1023.
    // Let `final_0 = current_val_if_input_is_0`
    // Let `final_1023 = current_val_if_input_is_1023`

    // We need to find `A_AND`, `A_OR`, `A_XOR` such that:
    // `(x & A_AND | A_OR) ^ A_XOR` is equivalent to the original program.
    // Or, more generally, we need to find a sequence of at most 5 operations.
    // The problem states that the constants are 0 to 1023, so we are interested in 10 bits.

    // For each bit `j` (0 to 9):
    // Let `bit_0_result = (final_0 >> j) & 1`
    // Let `bit_1_result = (final_1023 >> j) & 1`

    // If input bit `x_j` is 0, the output bit is `bit_0_result`.
    // If input bit `x_j` is 1, the output bit is `bit_1_result`.

    // We can determine the effective AND, OR, XOR constants for each bit.
    // Let `and_mask`, `or_mask`, `xor_mask` be the constants for the simplified program.
    int and_mask = 1023; // Initially, all bits are 1 for AND (no effect)
    int or_mask = 0;     // Initially, all bits are 0 for OR (no effect)
    int xor_mask = 0;    // Initially, all bits are 0 for XOR (no effect)

    for (int j = 0; j < 10; ++j) {
        int bit_0_result = (current_val_if_input_is_0 >> j) & 1;
        int bit_1_result = (current_val_if_input_is_1023 >> j) & 1;

        // Case 1: Input bit 0 -> Output bit 0, Input bit 1 -> Output bit 0
        // This means the output bit is always 0, regardless of input.
        // This can be achieved by `& 0`.
        if (bit_0_result == 0 && bit_1_result == 0) {
            and_mask &= ~(1 << j); // Set j-th bit of and_mask to 0
        }
        // Case 2: Input bit 0 -> Output bit 1, Input bit 1 -> Output bit 1
        // This means the output bit is always 1, regardless of input.
        // This can be achieved by `| 1`.
        else if (bit_0_result == 1 && bit_1_result == 1) {
            or_mask |= (1 << j); // Set j-th bit of or_mask to 1
        }
        // Case 3: Input bit 0 -> Output bit 0, Input bit 1 -> Output bit 1
        // This means the output bit is the same as the input bit.
        // This is the identity transformation for this bit.
        // Achieved by `& 1`, `| 0`, `^ 0`.
        else if (bit_0_result == 0 && bit_1_result == 1) {
            // and_mask already has 1, or_mask already has 0, xor_mask already has 0.
            // No change needed for this bit for these masks.
        }
        // Case 4: Input bit 0 -> Output bit 1, Input bit 1 -> Output bit 0
        // This means the output bit is the inverse of the input bit.
        // Achieved by `^ 1`.
        else if (bit_0_result == 1 && bit_1_result == 0) {
            xor_mask |= (1 << j); // Set j-th bit of xor_mask to 1
        }
    }

    std::vector<std::pair<char, int>> simplified_program;

    // The order of operations matters.
    // A common simplification is `(x & A) | B ^ C`.
    // Let's try to construct this.
    // The `and_mask` determines which bits can pass through.
    // The `or_mask` forces certain bits to 1.
    // The `xor_mask` flips certain bits.

    // If `and_mask` is not 1023 (i.e., some bits are forced to 0), add '&' operation.
    if (and_mask != 1023) {
        simplified_program.push_back({'&', and_mask});
    }
    // If `or_mask` is not 0 (i.e., some bits are forced to 1), add '|' operation.
    if (or_mask != 0) {
        simplified_program.push_back({'|', or_mask});
    }
    // If `xor_mask` is not 0 (i.e., some bits are flipped), add '^' operation.
    if (xor_mask != 0) {
        simplified_program.push_back({'^', xor_mask});
    }

    std::cout << simplified_program.size() << "\n";
    for (const auto& op : simplified_program) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> removal_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> removal_order[i];
        removal_order[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process vertices in reverse order of removal
    // This means we are adding vertices one by one to an initially empty graph
    // and updating all-pairs shortest paths.
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = removal_order[k_idx]; // The vertex being added to the active set

        active_vertices[k] = true;

        // Floyd-Warshall update step:
        // Consider vertex k as an intermediate vertex for all pairs (i, j)
        // where i, j are also active.
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;

                // Path i -> k -> j
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // Also update paths involving k itself as an endpoint
        // For any active i, path i -> k
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) { // j is k
                if (!active_vertices[j]) continue;
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }
        // For any active j, path k -> j
        for (int i = 0; i < n; ++i) { // i is k
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }


        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (forward removal order)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
