#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (b_1=a_1, b_n=a_n)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: length of consecutive 0s ending at i
    if (a[0] == 0) L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 0;
        }
    }

    // Calculate R[i]: length of consecutive 0s starting at i
    if (a[n - 1] == 0) R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            int left_zeros = (i > 0) ? L[i - 1] : 0;
            int right_zeros = (i < n - 1) ? R[i + 1] : 0;

            if (left_zeros > 0 && right_zeros > 0) {
                max_k = std::max(max_k, (std::min(left_zeros, right_zeros) + 1) / 2);
            }
        }
    }

    std::vector<int> b = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 1) { // Only 1s can change to 0s
            int left_zeros = (i > 0) ? L[i - 1] : 0;
            int right_zeros = (i < n - 1) ? R[i + 1] : 0;

            if (left_zeros >= max_k && right_zeros >= max_k) {
                b[i] = 0;
            }
        }
    }

    std::cout << max_k << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, std::numeric_limits<long long>::max());

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_max_val = ops[i].val;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], current_max_val);
            }
        }
    }

    std::vector<long long> a_prime(n);
    for (int i = 0; i < n; ++i) {
        if (b[i] == std::numeric_limits<long long>::max()) {
            a_prime[i] = 0; // Default to 0 if no upper bound from type 2 ops
        } else {
            a_prime[i] = b[i];
        }
    }

    std::vector<long long> current_a = a_prime;
    std::vector<long long> delta(n, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
                delta[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, current_a[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_prime[i] - delta[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

