    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::list<Child> children_list;
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_list.push_back({v_val, d_val, p_val, i + 1});
    }

    std::vector<int> cured_children_indices;

    while (!children_list.empty()) {
        Child current_child = children_list.front();
        children_list.pop_front();
        cured_children_indices.push_back(current_child.original_idx);

        long long current_v = current_child.v;
        long long total_d_from_runaways = 0;

        auto it = children_list.begin();
        while (it != children_list.end()) {
            // Apply current_v effect
            if (current_v > 0) {
                it->p -= current_v;
                current_v--;
            }

            // Apply total_d_from_runaways effect
            it->p -= total_d_from_runaways;

            if (it->p < 0) {
                total_d_from_runaways += it->d;
                it = children_list.erase(it); // Child runs away
            } else {
                ++it;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a_suffix(n); // a_suffix[0] is unused, a_suffix[1] is a_2, ..., a_suffix[n-1] is a_n
    for (int i = 1; i < n; ++i) {
        std::cin >> a_suffix[i];
    }

    std::vector<long long> dp_y(n + 1, 0); // dp_y[k] stores the final y value if we start at x=k and perform step 3
    std::vector<int> dp_x(n + 1, 0);     // dp_x[k] stores the final x value if we start at x=k and perform step 3
    std::vector<bool> visited(n + 1, false); // For cycle detection during DP calculation

    for (int k = n; k >= 1; --k) {
        long long current_a_val = a_suffix[k - 1]; // This is a_k

        long long next_x_after_step3 = k - current_a_val;
        long long next_y_after_step3 = current_a_val;

        if (next_x_after_step3 <= 0 || next_x_after_step3 > n) {
            // Terminates after step 3
            dp_x[k] = next_x_after_step3;
            dp_y[k] = next_y_after_step3;
        } else {
            // Continues to step 2 from next_x_after_step3
            // The next step is step 2, which means we need to look up dp_x[next_x_after_step3 + a_suffix[next_x_after_step3 - 1]]
            // and dp_y[next_x_after_step3 + a_suffix[next_x_after_step3 - 1]]
            // This is equivalent to starting a new sequence of (step 2, step 3) from next_x_after_step3
            // The total y will be next_y_after_step3 + (y from starting at next_x_after_step3)
            // The total x will be (x from starting at next_x_after_step3)

            // We need to simulate the (step 2, step 3) sequence starting from next_x_after_step3
            // Let's call this state (x_curr, y_curr)
            long long sim_x = next_x_after_step3;
            long long sim_y = 0;

            // This is the core logic for a single (step 2, step 3) pair
            // The value a_sim_x is a_suffix[sim_x - 1]
            long long a_sim_x = a_suffix[sim_x - 1];

            // Step 2
            sim_x += a_sim_x;
            sim_y += a_sim_x;

            if (sim_x <= 0 || sim_x > n) {
                // Terminates after step 2
                dp_x[k] = sim_x;
                dp_y[k] = next_y_after_step3 + sim_y;
            } else {
                // Continues to step 3 from sim_x
                // We can use the precomputed DP values for sim_x
                if (dp_x[sim_x] == 0 && dp_y[sim_x] == 0 && !visited[sim_x]) {
                    // This means sim_x is part of a cycle or not yet computed.
                    // For this problem, the DP state is defined as starting with step 3.
                    // So, if we are at sim_x, we need to apply step 3, then step 2, then step 3...
                    // This is exactly what dp_x[sim_x] and dp_y[sim_x] store.
                    // If dp_x[sim_x] is 0 and dp_y[sim_x] is 0, it implies a cycle or uncomputed.
                    // Since we compute from n down to 1, if sim_x > k, it should be computed.
                    // If sim_x < k, it's a cycle.
                    // If sim_x == k, it's a cycle.
                    // The problem states that if it never terminates, output -1.
                    // A cycle implies non-termination.
                    dp_x[k] = -1; // Mark as non-terminating
                    dp_y[k] = -1;
                } else if (dp_x[sim_x] == -1) {
                    // If the subsequent path leads to non-termination
                    dp_x[k] = -1;
                    dp_y[k] = -1;
                } else {
                    // Use precomputed DP values
                    dp_x[k] = dp_x[sim_x];
                    dp_y[k] = next_y_after_step3 + sim_y + dp_y[sim_x];
                }
            }
        }
    }

    for (int i = 1; i < n; ++i) {
        long long current_a1 = i;
        long long x = 1;
        long long y = 0;

        // Step 2
        x += current_a1;
        y += current_a1;

        if (x <= 0 || x > n) {
            std::cout << y << "\n";
        } else {
            // Now we are at x, and need to perform step 3, then step 2, then step 3...
            // This is exactly what dp_x[x] and dp_y[x] store.
            if (dp_x[x] == -1) {
                std::cout << -1 << "\n";
            } else {
                std::cout << y + dp_y[x] << "\n";
            }
        }
    }

    return 0;
}

