        // (even if it moves left by T), then this head cannot cover p[p_idx].
        // This head must be used for tracks to its left (which are already processed)
        // or it's effectively wasted for p[p_idx].
        // We move to the next head.
        if (head_right_bound < p[p_idx]) {
            // This head is too far to the left to cover p[p_idx].
            // It cannot cover p[p_idx] or any p_k where k > p_idx.
            // So, this head is useless for the remaining tracks.
            // We just move to the next head.
            continue;
        }

        // If the current target track p[p_idx] is to the left of what this head can reach
        // (even if it moves right by T), then this head cannot cover p[p_idx].
        // This means p[p_idx] cannot be covered by this head or any subsequent head (since h is sorted).
        // So, p[p_idx] cannot be covered at all.
        if (head_left_bound > p[p_idx]) {
            return false;
        }

        // If we reach here, it means head h[h_idx] can cover p[p_idx].
        // We use this head to cover p[p_idx] and all subsequent tracks
        // that fall within its rightmost reach.
        while (p_idx < m && p[p_idx] <= head_right_bound) {
            p_idx++;
        }
    }

    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible difference between p_i and h_i is ~10^10.
                               // A single head might need to move from 1 to 10^10, so 10^10 time.
                               // 2 * 10^10 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> partition(n);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // f(a_i, a_j) = a_i + a_j for all i, j.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    long long goodness_all_one_subsequence = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> best_partition(n, 1);
    long long min_goodness = goodness_all_one_subsequence;

    // Case 2: At least one element in each subsequence.
    // The minimum possible sum a_i + a_j is elements[0].value + elements[1].value.
    // The maximum possible sum a_i + a_j is elements[n-1].value + elements[n-2].value.
    // The minimum possible sum a_i + a_j + h is elements[0].value + elements[1].value + h.
    // The maximum possible sum a_i + a_j + h is elements[n-1].value + elements[n-2].value + h.

    // Consider the partition where elements[0] is in S1 and elements[1] is in S2.
    // Or elements[0] is in S1 and elements[n-1] is in S2.
    // Or elements[0] is in S1 and elements[n-2] is in S2.

    // Let's try to put elements[0] in S1 and elements[1] in S2.
    // All other elements can go to S1.
    // S1: {elements[0], elements[2], ..., elements[n-1]}
    // S2: {elements[1]}
    // min_f: elements[0].value + elements[1].value + h (diff)
    // max_f: elements[n-1].value + elements[n-2].value (same in S1)
    // goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value + h)
    // This is only valid if elements[0].value + elements[1].value + h is indeed the minimum.
    // And elements[n-1].value + elements[n-2].value is indeed the maximum.
    // The minimum of all f values will be min(min_same, min_diff).
    // The maximum of all f values will be max(max_same, max_diff).

    // Let's consider the structure of the optimal partition.
    // The smallest element is elements[0].value.
    // The largest element is elements[n-1].value.
    // The second smallest is elements[1].value.
    // The second largest is elements[n-2].value.

    // The minimum possible value of a_i + a_j is elements[0].value + elements[1].value.
    // The maximum possible value of a_i + a_j is elements[n-1].value + elements[n-2].value.

    // If elements[0] and elements[1] are in different subsequences, then min_f could be elements[0].value + elements[1].value + h.
    // If elements[0] and elements[1] are in the same subsequence, then min_f could be elements[0].value + elements[1].value.

    // If elements[n-1] and elements[n-2] are in different subsequences, then max_f could be elements[n-1].value + elements[n-2].value + h.
    // If elements[n-1] and elements[n-2] are in the same subsequence, then max_f could be elements[n-1].value + elements[n-2].value.

    // Consider the case where elements[0] is in S1 and elements[n-1] is in S2.
    // All other elements can be in S1.
    // S1: {elements[0], elements[1], ..., elements[n-2]}
    // S2: {elements[n-1]}
    // min_f: elements[0].value + elements[n-1].value + h (diff)
    // max_f: elements[n-2].value + elements[n-3].value (same in S1, if n >= 3)
    // If n=2, S1={elements[0]}, S2={elements[1]}. Only diff pairs. min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    // This is covered by the general logic below.

    // Let's analyze the four critical sums:
    // S_min = elements[0].value + elements[1].value
    // S_max = elements[n-1].value + elements[n-2].value
    // S_0_n_1 = elements[0].value + elements[n-1].value
    // S_0_n_2 = elements[0].value + elements[n-2].value (if n >= 3)
    // S_1_n_1 = elements[1].value + elements[n-1].value (if n >= 3)

    // Option A: All elements in one group (already handled). Goodness = S_max - S_min.
    // min_f = S_min, max_f = S_max.

    // Option B: elements[0] is in S1, elements[1] is in S2. All other elements (elements[2]...elements[n-1]) are in S1.
    // S1: {elements[0], elements[2], ..., elements[n-1]}
    // S2: {elements[1]}
    // Pairs in S1: (elements[0], elements[2]), ..., (elements[n-1], elements[n-2])
    // Pairs in S2: None (if n=2, S2 is empty, this case is not possible)
    // Pairs across S1, S2: (elements[0], elements[1]), (elements[2], elements[1]), ..., (elements[n-1], elements[1])
    // min_f: min(elements[0].value + elements[2].value, elements[0].value + elements[1].value + h)
    // max_f: max(elements[n-1].value + elements[n-2].value, elements[n-1].value + elements[1].value + h)
    // This is complex. Let's simplify.

    // The minimum possible value of f is always at least elements[0].value + elements[1].value.
    // The maximum possible value of f is always at most elements[n-1].value + elements[n-2].value + h.

    // Consider the partition where elements[0] is in S1, and all other elements are in S2.
    // S1: {elements[0]}
    // S2: {elements[1], ..., elements[n-1]}
    // min_f: elements[0].value + elements[1].value + h (diff)
    // max_f: max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    // If elements[0].value + elements[1].value + h <= elements[n-1].value + elements[n-2].value,
    // then min_f = elements[0].value + elements[1].value + h.
    // If elements[0].value + elements[1].value + h > elements[n-1].value + elements[n-2].value,
    // then min_f = elements[0].value + elements[1].value. (This implies elements[0] and elements[1] are in the same group, which contradicts the assumption that elements[0] is in S1 and elements[1] is in S2).
    // So, min_f is either elements[0].value + elements[1].value (if they are in the same group) or elements[0].value + elements[1].value + h (if they are in different groups).
    // Similarly for max_f.

    // Let's consider the four boundary values:
    // v1 = elements[0].value + elements[1].value
    // v2 = elements[0].value + elements[n-1].value + h
    // v3 = elements[n-1].value + elements[n-2].value
    // v4 = elements[1].value + elements[n-1].value + h (if n >= 3)

    // The minimum possible value of f is `min_f_val`.
    // The maximum possible value of f is `max_f_val`.

    // Case 1: All elements in one group (already handled).
    // min_f_val = elements[0].value + elements[1].value
    // max_f_val = elements[n-1].value + elements[n-2].value
    // Goodness = max_f_val - min_f_val

    // Case 2: elements[0] is in S1, elements[1] is in S2. All other elements (elements[2]...elements[n-1]) are in S1.
    // This is a specific partition.
    // S1: {elements[0], elements[2], ..., elements[n-1]}
    // S2: {elements[1]}
    //
    // min_f_val:
    //   Pairs within S1: min(elements[0].value + elements[2].value, elements[0].value + elements[3].value, ...)
    //     This is elements[0].value + elements[2].value (if n >= 3).
    //   Pairs within S2: None.
    //   Pairs across S1, S2: elements[0].value + elements[1].value + h, elements[2].value + elements[1].value + h, ..., elements[n-1].value + elements[1].value + h.
    //     This is elements[0].value + elements[1].value + h.
    //   So, min_f_val = std::min(elements[0].value + elements[2].value, elements[0].value + elements[1].value + h) (if n >= 3).
    //   If n=2, S1={elements[0]}, S2={elements[1]}. Only one pair: elements[0].value + elements[1].value + h.
    //
    // max_f_val:
    //   Pairs within S1: elements[n-1].value + elements[n-2].value (if n >= 3).
    //   Pairs within S2: None.
    //   Pairs across S1, S2: elements[n-1].value + elements[1].value + h.
    //   So, max_f_val = std::max(elements[n-1].value + elements[n-2].value, elements[n-1].value + elements[1].value + h) (if n >= 3).
    //   If n=2, max_f_val = elements[0].value + elements[1].value + h.

    // Let's consider the general case for n >= 2.
    // The minimum possible sum of two elements is elements[0].value + elements[1].value.
    // The maximum possible sum of two elements is elements[n-1].value + elements[n-2].value.

    // Let's try to put elements[0] in S1 and elements[n-1] in S2.
    // All other elements (elements[1]...elements[n-2]) can go to S1.
    // S1: {elements[0], elements[1], ..., elements[n-2]}
    // S2: {elements[n-1]}
    //
    // min_f_val:
    //   Pairs within S1: elements[0].value + elements[1].value (if n >= 2, S1 has at least 2 elements)
    //   Pairs within S2: None.
    //   Pairs across S1, S2: elements[0].value + elements[n-1].value + h.
    //   So, min_f_val = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h).
    //
    // max_f_val:
    //   Pairs within S1: elements[n-2].value + elements[n-3].value (if n >= 3, S1 has at least 3 elements)
    //     If n=2, S1 has only elements[0], so no pairs within S1.
    //   Pairs within S2: None.
    //   Pairs across S1, S2: elements[n-2].value + elements[n-1].value + h.
    //   So, max_f_val = std::max( (n >= 3 ? elements[n-2].value + elements[n-3].value : -1), elements[n-2].value + elements[n-1].value + h).
    //   If n=2, S1={elements[0]}, S2={elements[1]}. min_f_val = max_f_val = elements[0].value + elements[1].value + h. Goodness = 0.
    //   This is a special case.

    if (n == 2) {
        // Only one pair (a_0, a_1). They must be in different subsequences.
        // f(a_0, a_1) = a_0 + a_1 + h.
        // min_f = max_f = a_0 + a_1 + h. Goodness = 0.
        std::cout << 0 << "\n";
        partition[elements[0].original_index] = 1;
        partition[elements[1].original_index] = 2;
        for (int i = 0; i < n; ++i) {
            std::cout << partition[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    // General case for n >= 3.
    // We have two main strategies for partitioning:
    // 1. All elements in one group (already calculated `goodness_all_one_subsequence`).
    //    min_f = elements[0].value + elements[1].value
    //    max_f = elements[n-1].value + elements[n-2].value
    //    Goodness = max_f - min_f

    // 2. Split elements[0] and elements[1] into different groups.
    //    Let elements[0] be in S1, elements[1] be in S2.
    //    All other elements (elements[2]...elements[n-1]) can be in S1.
    //    S1: {elements[0], elements[2], ..., elements[n-1]}
    //    S2: {elements[1]}
    //
    //    min_f_val:
    //      Pairs within S1: elements[0].value + elements[2].value
    //      Pairs across S1, S2: elements[0].value + elements[1].value + h
    //      min_f_val = std::min(elements[0].value + elements[2].value, elements[0].value + elements[1].value + h)
    //
    //    max_f_val:
    //      Pairs within S1: elements[n-1].value + elements[n-2].value
    //      Pairs across S1, S2: elements[n-1].value + elements[1].value + h
    //      max_f_val = std::max(elements[n-1].value + elements[n-2].value, elements[n-1].value + elements[1].value + h)
    //
    //    Goodness for this partition: max_f_val - min_f_val.
    long long current_min_f_val = std::min(elements[0].value + elements[2].value, elements[0].value + elements[1].value + h);
    long long current_max_f_val = std::max(elements[n-1].value + elements[n-2].value, elements[n-1].value + elements[1].value + h);
    long long goodness_split_0_1 = current_max_f_val - current_min_f_val;

    if (goodness_split_0_1 < min_goodness) {
        min_goodness = goodness_split_0_1;
        partition[elements[0].original_index] = 1;
        partition[elements[1].original_index] = 2;
        for (int i = 2; i < n; ++i) {
            partition[elements[i].original_index] = 1;
        }
    } else {
        // Keep the all-in-one partition
        for (int i = 0; i < n; ++i) {
            partition[elements[i].original_index] = 1;
        }
    }

    // There's one more critical case:
    // What if h is very large? Then we want to avoid pairs in different subsequences.
    // The best way to do this is to put all elements in one subsequence. This is already covered.
    // What if h is very small? Then the +h term doesn't change much.

    // The problem states that the minimum goodness is required.
    // The minimum possible value of f is `elements[0].value + elements[1].value`.
    // The maximum possible value of f is `elements[n-1].value + elements[n-2].value + h`.

    // Let's consider the range of values.
    // The smallest possible sum is `elements[0].value + elements[1].value`.
    // The largest possible sum is `elements[n-1].value + elements[n-2].value`.
    // The smallest possible sum with `h` is `elements[0].value + elements[1].value + h`.
    // The largest possible sum with `h` is `elements[n-1].value + elements[n-2].value + h`.

    // The overall minimum `min_f` will be `elements[0].value + elements[1].value`.
    // The overall maximum `max_f` will be `elements[n-1].value + elements[n-2].value + h`.
    // The goodness would be `(elements[n-1].value + elements[n-2].value + h) - (elements[0].value + elements[1].value)`.
    // This goodness is achieved if there is at least one pair in the same group (e.g., elements[0], elements[1])
    // AND at least one pair in different groups (e.g., elements[n-1], elements[0]).
    //
    // Consider the partition:
    // S1: {elements[0]}
    // S2: {elements[1], ..., elements[n-1]}
    //
    // min_f_val:
    //   Pairs within S1: None.
    //   Pairs within S2: elements[1].value + elements[2].value (if n >= 3)
    //   Pairs across S1, S2: elements[0].value + elements[1].value + h
    //   So, min_f_val = std::min( (n >= 3 ? elements[1].value + elements[2].value : -1), elements[0].value + elements[1].value + h);
    //   If n=2, min_f_val = elements[0].value + elements[1].value + h.
    //
    // max_f_val:
    //   Pairs within S1: None.
    //   Pairs within S2: elements[n-1].value + elements[n-2].value (if n >= 3)
    //   Pairs across S1, S2: elements[0].value + elements[n-1].value + h
    //   So, max_f_val = std::max( (n >= 3 ? elements[n-1].value + elements[n-2].value : -1), elements[0].value + elements[n-1].value + h);
    //   If n=2, max_f_val = elements[0].value + elements[1].value + h.

    // Let's re-evaluate the two main candidates for optimal partition:
    // Candidate 1: All elements in one group (e.g., all in S1).
    //   min_f = elements[0].value + elements[1].value
    //   max_f = elements[n-1].value + elements[n-2].value
    //   Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    //   This is `goodness_all_one_subsequence`.

    // Candidate 2: elements[0] in S1, elements[1] in S2, and all other elements (elements[2]...elements[n-1]) in S1.
    //   S1: {elements[0], elements[2], ..., elements[n-1]}
    //   S2: {elements[1]}
    //   min_f:
    //     From S1: elements[0].value + elements[2].value (if n >= 3)
    //     From S1-S2: elements[0].value + elements[1].value + h
    //     min_f = std::min(elements[0].value + elements[2].value, elements[0].value + elements[1].value + h)
    //   max_f:
    //     From S1: elements[n-1].value + elements[n-2].value
    //     From S1-S2: elements[n-1].value + elements[1].value + h
    //     max_f = std::max(elements[n-1].value + elements[n-2].value, elements[n-1].value + elements[1].value + h)
    //   Goodness = max_f - min_f. This is `goodness_split_0_1`.

    // The logic for n=2 is already handled. For n >= 3:
    // The two candidates are:
    // 1. All elements in group 1.
    //    min_f = elements[0].value + elements[1].value
    //    max_f = elements[n-1].value + elements[n-2].value
    //    Goodness = max_f - min_f
    //
    // 2. elements[0] in group 1, elements[1] in group 2, elements[2...n-1] in group 1.
    //    min_f = std::min(elements[0].value + elements[2].value, elements[0].value + elements[1].value + h)
    //    max_f = std::max(elements[n-1].value + elements[n-2].value, elements[n-1].value + elements[1].value + h)
    //    Goodness = max_f - min_f

    // Let's re-calculate and compare.
    long long current_best_goodness = goodness_all_one_subsequence;
    std::vector<int> current_best_partition(n);
    for (int i = 0; i < n; ++i) {
        current_best_partition[elements[i].original_index] = 1;
    }

    // Candidate 2:
    long long cand2_min_f = std::min(elements[0].value + elements[2].value, elements[0].value + elements[1].value + h);
    long long cand2_max_f = std::max(elements[n-1].value + elements[n-2].value, elements[n-1].value + elements[1].value + h);
    long long cand2_goodness = cand2_max_f - cand2_min_f;

    if (cand2_goodness < current_best_goodness) {
        current_best_goodness = cand2_goodness;
        current_best_partition[elements[0].original_index] = 1;
        current_best_partition[elements[1].original_index] = 2;
        for (int i = 2; i < n; ++i) {
            current_best_partition[elements[i].original_index] = 1;
        }
    }

    std::cout << current_best_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << current_best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

