int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = k + 1; // Initialize with a value larger than any possible a_i or k
        int min_idx = -1;

        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long operations = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself
            }
            // For each other pile a[i], we can add min_val until a[i] exceeds k
            // The number of times we can add min_val to a[i] is (k - a[i]) / min_val
            // Integer division naturally handles the "strictly more than k" condition.
            // If a[i] + min_val > k, then (k - a[i]) / min_val will be 0.
            // If a[i] + min_val <= k, then (k - a[i]) / min_val will be at least 1.
            operations += (k - a[i]) / min_val;
        }
        std::cout << operations << "\n";
    }
    return 0;
}

