    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    // int count_e = 0; // Not strictly needed as 'n' and 'z' are unique identifiers for 'one' and 'zero'
    // int count_r = 0;
    // int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        }
        // The other characters ('e', 'r', 'o') are shared or not unique to a digit.
        // 'n' uniquely identifies a '1'.
        // 'z' uniquely identifies a '0'.
        // Since the problem guarantees that it's possible to form a sequence of "zero" and "one",
        // we only need to count the unique letters that determine the number of '1's and '0's.
        // Each 'n' corresponds to one "one".
        // Each 'z' corresponds to one "zero".
        // The counts of 'e', 'r', 'o' will naturally satisfy the requirements if 'n' and 'z' counts are met.
    }

    // To maximize the binary number, we want to place all '1's before all '0's.
    // The number of '1's is determined by the count of 'n's.
    // The number of '0's is determined by the count of 'z's.

    bool first_digit = true;
    for (int i = 0; i < count_n; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < count_z; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
