int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k sticks and k coal.
        // To get k coal, we need k * y sticks. Each coal trade costs 1 trade.
        // So, k coal trades will cost k trades.
        // Total sticks needed for coal: k * y
        // Total sticks needed for crafting: k
        // Total sticks to acquire: k * y + k

        // We start with 1 stick.
        // We need to acquire (k * y + k - 1) more sticks using the first trade offer.
        // The first trade offer: 1 stick -> x sticks. Net gain: (x - 1) sticks per trade.
        // Let num_stick_trades be the number of times we use the first trade offer.
        // num_stick_trades * (x - 1) >= (k * y + k - 1)
        // num_stick_trades = ceil((k * y + k - 1) / (x - 1))

        long long sticks_for_coal = k * y;
        long long total_sticks_needed = sticks_for_coal + k;

        // We start with 1 stick, so we need to acquire (total_sticks_needed - 1) more sticks.
        long long sticks_to_generate = total_sticks_needed - 1;

        // Each stick trade gives (x - 1) net sticks.
        // Number of stick trades = ceil(sticks_to_generate / (x - 1))
        long long num_stick_trades = (sticks_to_generate + (x - 1) - 1) / (x - 1);

        // Total trades = num_stick_trades + num_coal_trades
        // num_coal_trades = k
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

