    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum += a[i];
    }

    if (total_sum % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_duration = total_sum / k;
    std::vector<int> s_lengths;
    long long current_sum = 0;
    int current_length = 0;
    int posts_found = 0;

    for (int i = 0; i < n; ++i) {
        current_sum += a[i];
