        }
        std::cout << "\n";
    } else {
        // This case should ideally be caught by current_sum > target_duration
        // or total_sum % k != 0, but as a safeguard.
        // It means we didn't form exactly k posts with the target duration.
        std::cout << "No\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation needed for this position.
        // The flags for has_pos_one and has_neg_one are updated based on original a[k] for k < i.
        // This is correct because a[k] for k < i are the values that can be added to a[i].
        // The problem statement implies that a[k] values are fixed for operations on a[i].
        // "Add a_i to a_j" means the value of a_i at the time of operation.
        // However, the crucial observation is that if a[k] (k<i) is 1, it can be used to increase a[i].
        // If a[k] (k<i) is -1, it can be used to decrease a[i].
        // The values a[k] themselves can be changed, but the *existence* of an original 1 or -1 at an earlier index
        // is what matters for enabling increases/decreases.
        // If a[k] was originally 1, it can be used to increase a[i].
        // If a[k] was originally -1, it can be used to decrease a[i].
        // The problem is subtle: "Add a_i to a_j". Does a_i refer to the *original* a_i or the *current* a_i?
        // The example "if you are given array [1, -1, 0], you can transform it only to [1, -1, -1], [1, 0, 0] and [1, -1, 1] by one operation."
        // This implies current values.
        // However, the key is that a[k] for k < i can be used to modify a[i].
        // If there was an original 1 at index k < i, then a[k] can be made 1 again (if it was changed) or kept 1.
        // If a[k] was 1, it can be used to increase a[i].
        // If a[k] was -1, it can be used to decrease a[i].
        // The crucial part is that a[k] for k < i can be used to modify a[i].
        // If a[k] is 1, it can be used to increase a[i].
        // If a[k] is -1, it can be used to decrease a[i].
        // The values a[k] themselves can be changed, but the *existence* of an original 1 or -1 at an earlier index
        // is what matters for enabling increases/decreases.
        // If a[k] was originally 1, it can be used to increase a[i].
        // If a[k] was originally -1, it can be used to decrease a[i].
        // The values a[k] for k < i are the ones that can be added to a[i].
        // If any a[k] (k < i) is 1, we can increase a[i].
        // If any a[k] (k < i) is -1, we can decrease a[i].
        // The flags `has_pos_one` and `has_neg_one` should track if there's *any* `a[k]` with `k < current_index` that was originally 1 or -1.
        // This is what the current logic does. `has_pos_one` and `has_neg_one` are updated based on `a[i]` *after* checking `a[i]` vs `b[i]`.
        // This means for `a[i]`, we consider `a[0]...a[i-1]` for `has_pos_one` and `has_neg_one`.
        // This is correct.
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

