        for (int j = 0; j < n; ++j) {
            int a_ij;
            std::cin >> a_ij;
            if (i != j) {
                max_val_for_i = std::max(max_val_for_i, a_ij);
            }
        }
        // If max_val_for_i is n-1, it means p[i] must be n.
        // Otherwise, p[i] must be max_val_for_i.
        // This logic works because if p[i] is not n, then there must be some p[k] > p[i].
        // In that case, min(p[i], p[k]) = p[i].
        // If p[i] is n, then for all j != i, p[j] < p[i], so min(p[i], p[j]) = p[j].
        // The maximum of these p[j] values would be n-1.
        if (max_val_for_i == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_for_i;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
