int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This can be done by alternating between left and right pointers
    // For example, if k=2, we use 1, 2, 3.
    // Sequence: 1, 3, 2
    // Differences: |1-3|=2, |3-2|=1. Distinct: {1,2}
    // If k=3, we use 1, 2, 3, 4.
    // Sequence: 1, 4, 2, 3
    // Differences: |1-4|=3, |4-2|=2, |2-3|=1. Distinct: {1,2,3}

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            std::cout << left++;
        } else {
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // For the remaining n - (k + 1) elements,
    // we need to ensure no new distinct differences are introduced.
    // The simplest way is to continue with increasing numbers,
    // which will only produce a difference of 1 (if the previous number was `x`, print `x+1`).
    // Since 1 is already among the k distinct differences generated, this is safe.
    for (int i = k + 1; i < n; ++i) {
        std::cout << left++; // left now holds the next available number
        std::cout << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

