#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_values.insert(q[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_values.count(q[i])) {
                // This should not happen if q is valid and p is a permutation
                // because q_i > q_{i-1} implies q_i is a new value.
                // However, for safety or if q could be invalid in other ways.
                possible = false;
                break;
            }
            used_values.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some value less than or equal to q_i
            // and not yet used. To maximize chances of finding a solution,
            // we should pick the smallest available value.
            // The smallest available value must be less than q_i.
            // If we pick a value equal to q_i, it would have been used in a previous q_j=q_i.
            // So p_i must be < q_i.
            // We need to find the largest available number that is less than q_i.
            // This is equivalent to finding the largest number in [1, n] not yet used,
            // that is also less than q_i.
            // Let's find the smallest available number that is not used.
            // We need to fill p_i with a value that is not q_i and not used.
            // The values that are *not* in `used_values` are candidates.
            // We need to pick one such that it's <= q_i.
            // To ensure we can fill subsequent positions, it's best to use the largest
            // available number that is less than q_i.
            // Or, to be safe, we can use the smallest available number that is less than q_i.
            // Let's try to use the smallest available number.
            // The numbers not yet used are `1, ..., n` excluding `used_values`.
            // We need to find the largest number `x` such that `x < q_i` and `x` is not in `used_values`.
            // This is equivalent to finding the largest number `x` in `[1, q_i-1]` that is not in `used_values`.
            // Let's iterate downwards from `q_i - 1` to `1` to find the largest available.
            // This strategy is more robust.

            int current_val = q[i] - 1;
            while (current_val >= 1 && used_values.count(current_val)) {
                current_val--;
            }

            if (current_val < 1) { // No available number less than q_i
                possible = false;
                break;
            }
            p[i] = current_val;
            used_values.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

