    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    int horizontal_moves = std::min(counts['L'], counts['R']);
    int vertical_moves = std::min(counts['U'], counts['D']);

    std::string result = "";
    if (horizontal_moves == 0 && vertical_moves == 0) {
        // No moves possible
    } else if (horizontal_moves == 0) {
        // Only vertical moves possible, must be U and D
        // Path must be U...UD...D
        // To satisfy "no cell (except (0,0)) visited twice",
        // we can only have one U and one D.
        // Example: UD or DU.
        // If we have more, e.g., UUDD, then (0,1) is visited twice.
        // So, if vertical_moves > 0, we can use one U and one D.
        result = "UD";
    } else if (vertical_moves == 0) {
        // Only horizontal moves possible, must be L and R
        // Path must be L...LR...R
        // Similar to vertical, we can only have one L and one R.
        // Example: LR or RL.
        // If horizontal_moves > 0, we can use one L and one R.
        result = "LR";
    } else {
        // Both horizontal and vertical moves are possible.
        // We can use all available paired moves.
        // The path will look like U...UR...RD...DL...L
        // Example: UURRDDLL
        for (int i = 0; i < vertical_moves; ++i) {
            result += 'U';
        }
        for (int i = 0; i < horizontal_moves; ++i) {
            result += 'R';
        }
        for (int i = 0; i < vertical_moves; ++i) {
            result += 'D';
        }
        for (int i = 0; i < horizontal_moves; ++i) {
            result += 'L';
        }
    }

    std::cout << result.length() << std::endl;
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

