#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');
    result[0] = '1'; // m=1 is always beautiful

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 2; m <= n; ++m) {
        // Expand the window to include 'm'
        // 'm' is at pos[m]
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current window [current_min_idx, current_max_idx]
        // contains all numbers from 1 to m and has length m.
        // The length of the window is (current_max_idx - current_min_idx + 1).
        // If this length equals m, then it must contain exactly numbers 1 to m
        // because all numbers 1 to m are distinct and within this window,
        // and there are no other numbers.
        if (current_max_idx - current_min_idx + 1 == m) {
            result[m - 1] = '1';
        }
    }
    std::cout << result << "\n";
}

