#include <set>

// Function to check if a sub-array is a permutation
// `arr` is the full array, `start_idx` is the 0-based starting index, `len` is the length
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) {
        return true; // An empty sequence can be considered a permutation of length 0, though problem constraints imply len >= 1
    }
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix permutation checks
    // `prefix_is_perm[i]` is true if a[0...i-1] is a permutation of length i
    std::vector<bool> prefix_is_perm(n + 1, false);
    if (n > 0) {
        std::vector<bool> seen_prefix(n + 1, false);
        int current_max_prefix = 0;
        bool possible_prefix = true;
        for (int i = 0; i < n; ++i) {
            int val = a[i];
            if (val < 1 || val > (i + 1) || seen_prefix[val]) {
                possible_prefix = false;
            }
            if (possible_prefix) {
                seen_prefix[val] = true;
                if (val > current_max_prefix) {
                    current_max_prefix = val;
                }
                if (current_max_prefix == (i + 1)) {
                    prefix_is_perm[i + 1] = true;
                }
            }
        }
    }

    // Precompute suffix permutation checks
    // `suffix_is_perm[i]` is true if a[i...n-1] is a permutation of length n-i
    std::vector<bool> suffix_is_perm(n + 1, false);
    if (n > 0) {
        std::vector<bool> seen_suffix(n + 1, false);
        int current_max_suffix = 0;
        bool possible_suffix = true;
        for (int i = n - 1; i >= 0; --i) {
            int len = n - i;
            int val = a[i];
            if (val < 1 || val > len || seen_suffix[val]) {
                possible_suffix = false;
            }
            if (possible_suffix) {
                seen_suffix[val] = true;
                if (val > current_max_suffix) {
                    current_max_suffix = val;
                }
                if (current_max_suffix == len) {
                    suffix_is_perm[i] = true;
                }
            }
        }
    }

    // Iterate through all possible split points l1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l1]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int calculate_score(const std::string& s) {
    int score = 0;
    if (s.empty()) {
        return 0;
    }
    if (s[0] == 'W') {
        score += 1;
    }
    for (size_t i = 1; i < s.length(); ++i) {
        if (s[i] == 'W') {
            if (s[i - 1] == 'W') {
                score += 2;
            } else {
                score += 1;
            }
        }
    }
    return score;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_wins = 0;
        for (char c : s) {
            if (c == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins + k >= n) { // Can make all games 'W'
            if (n == 0) { // Edge case for n=0, though constraints say n>=1
                std::cout << 0 << "\n";
            } else {
                std::cout << 1 + (n - 1) * 2 << "\n";
            }
            continue;
        }

        if (initial_wins == 0) { // All 'L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                std::cout << 1 << "\n"; // Change one 'L' to 'W', get 1 point
            }
            continue;
        }

        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        // Collect gaps between 'W's
        int current_gap = 0;
        for (int i = first_W + 1; i < last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        if (current_gap > 0) { // Last gap if string ends with W
            gaps.push_back(current_gap);
        }
        std::sort(gaps.begin(), gaps.end());

        int score = calculate_score(s);

        // Fill internal gaps
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                score += gap_len * 2 + 1; // Each L becomes W, connects two Ws, adds 2 points. The first L in the gap connects to a W, gets 2 points. The last L in the gap connects to a W, gets 2 points. All intermediate Ls get 2 points. The total increase is 2*gap_len + 1 (for the connection).
                k -= gap_len;
            } else {
                score += k * 2; // Can only fill part of the gap, each L gives 2 points
                k = 0;
                break;
            }
        }

        // Fill 'L's before first 'W'
        if (k > 0 && first_W > 0) {
            int L_before_first_W = first_W;
            int changes_to_make = std::min(k, L_before_first_W);
            score += changes_to_make * 2; // Each L becomes W, connects to a W (or starts a chain), gets 2 points
            k -= changes_to_make;
        }

        // Fill 'L's after last 'W'
        if (k > 0 && last_W < n - 1) {
            int L_after_last_W = n - 1 - last_W;
            int changes_to_make = std::min(k, L_after_last_W);
            score += changes_to_make * 2; // Each L becomes W, connects to a W, gets 2 points
            k -= changes_to_make;
        }

        std::cout << score << "\n";
    }
    return 0;
}

