// Helper function to print "Ya" or "Tidak"
void print_bool(bool b) {
    if (b) {
        std::cout << "Ya";
    } else {
        std::cout << "Tidak";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        long long total_toys = A + B + C + D;

        // If only one toy, it's the super toy and its box is the special box.
        if (total_toys == 1) {
            print_bool(A == 1);
            std::cout << " ";
            print_bool(B == 1);
            std::cout << " ";
            print_bool(C == 1);
            std::cout << " ";
            print_bool(D == 1);
            std::cout << "\n";
            continue;
        }

        // Determine if Box 1 (fun <= -1) can be the special box
        // Final product must be negative and magnitude >= 1
        // For negative: odd number of negative factors.
        // For magnitude >= 1: at least one factor >= 1, or multiple factors > 1/x.
        bool can_be_box1 = false;
        if (A + B > 0) { // Must have at least one negative toy to make a negative product
            // Case 1: Final product is negative, magnitude >= 1
            // Number of negative factors (A+B) must be odd.
            // To achieve magnitude >= 1:
            //   - If D > 0, we can always make magnitude >= 1 by multiplying with a large positive.
            //   - If D == 0, we need A > 0. If A > 0, we can use a toy from Box 1 to ensure magnitude >= 1.
            //   - If D == 0 and A == 0, then all initial toys are from B and C.
            //     Product of B and C toys will always have magnitude < 1. So this case is impossible.
            if ((A + B) % 2 == 1) { // Odd number of negative factors
                if (D > 0 || A > 0) {
                    can_be_box1 = true;
                }
            }
            // Case 2: Final product is positive, magnitude >= 1, but we can introduce a negative toy at the end.
            // Number of negative factors (A+B) must be even.
            // We need to ensure we can make a positive product with magnitude >= 1, AND have at least one negative toy left to multiply with.
            // This means A+B >= 1 (already checked by A+B > 0)
            // And we need to be able to make a positive product with magnitude >= 1.
            // This requires D > 0 or A > 0.
            // And we need to have an odd number of negative toys remaining for the final multiplication.
            // This means (A+B) must be odd, or (A+B) must be even and we use one negative toy to make the final product negative.
            // If (A+B) is even, we need to ensure we can make a positive product with magnitude >= 1, and then multiply by a negative toy.
            // This means we need at least one negative toy (A+B > 0) and we need to be able to make a product with magnitude >= 1 (D > 0 or A > 0).
            // If A+B is even, we can make a positive product. If we have at least one negative toy (A+B > 0), we can save one for the last step.
            // The remaining A+B-1 negative toys, plus C and D toys, form a product.
            // If A+B-1 is odd, the product is negative. If A+B-1 is even, the product is positive.
            // This logic is getting complicated. Let's simplify.
            // To get to Box 1: final product is negative, magnitude >= 1.
            // This means the total count of negative numbers used in multiplications must be odd.
            // And the total count of numbers with magnitude >= 1 (from A or D) must be at least one, OR
            // we must be able to construct a product with magnitude >= 1 from other numbers.
            // The simplest way to ensure magnitude >= 1 is if A > 0 or D > 0.
            // If A > 0 or D > 0:
            //   If (A+B) is odd, we can make a negative product. We can arrange multiplications to keep magnitude >= 1.
            //   If (A+B) is even, we can make a positive product. If A+B >= 1, we can save one negative toy.
            //   Multiply all other toys (A+B-1 negative, C positive, D positive).
            //   If (A+B-1) is odd, this intermediate product is negative.
            //   If (A+B-1) is even, this intermediate product is positive.
            //   Then multiply by the saved negative toy.
            //   The final product will be negative.
            //   So, if A+B > 0 and (A > 0 or D > 0), Box 1 is possible.
            if (D > 0 || A > 0) { // Can achieve magnitude >= 1
                can_be_box1 = true;
            } else { // D == 0 and A == 0. All toys are from B and C.
                // Product of B and C toys will always have magnitude < 1.
                // So Box 1 is impossible.
                can_be_box1 = false;
            }
        }

        // Determine if Box 2 (fun in (-1, 0)) can be the special box
        // Final product must be negative and magnitude < 1
        // For negative: odd number of negative factors.
        // For magnitude < 1: all factors have magnitude < 1, or careful multiplication.
        bool can_be_box2 = false;
        if (A + B > 0) { // Must have at least one negative toy
            // If (A+B) is odd: we can make a negative product.
            // To make magnitude < 1:
            //   - If C > 0 or B > 0, we can multiply with a small positive or negative to reduce magnitude.
            //   - If A == 0 and D == 0, all toys are from B and C. Product will always have magnitude < 1.
            //   - If A > 0 or D > 0, we need to be careful.
            //     We can always achieve magnitude < 1 if there's at least one toy from B or C.
            //     If B+C > 0, we can multiply by a toy from B or C at the end to make magnitude < 1.
            //     If B+C == 0, then all toys are from A and D.
            //     If A+B is odd, and B+C == 0, then B=0, C=0. So A is odd.
            //     If A is odd and D is anything, the product will be negative.
            //     If A > 0 or D > 0, the magnitude will be >= 1. So Box 2 is impossible.
            //     Unless A=1, D=0, B=0, C=0. Then the toy is in Box 1.
            //     So if B+C == 0, Box 2 is impossible.
            //     If B+C > 0, we can always make magnitude < 1.
            if (B + C > 0) { // Can achieve magnitude < 1
                can_be_box2 = true;
            } else { // B == 0 and C == 0. All toys are from A and D.
                // Product of A and D toys will always have magnitude >= 1.
                // So Box 2 is impossible.
                can_be_box2 = false;
            }
        }

        // Determine if Box 3 (fun in (0, 1)) can be the special box
        // Final product must be positive and magnitude < 1
        // For positive: even number of negative factors.
        // For magnitude < 1: all factors have magnitude < 1, or careful multiplication.
        bool can_be_box3 = false;
        // To get positive: (A+B) must be even.
        // To get magnitude < 1: B+C > 0.
        if ((A + B) % 2 == 0) { // Even number of negative factors
            if (B + C > 0) { // Can achieve magnitude < 1
                can_be_box3 = true;
            }
        }

        // Determine if Box 4 (fun >= 1) can be the special box
        // Final product must be positive and magnitude >= 1
        // For positive: even number of negative factors.
        // For magnitude >= 1: at least one factor >= 1, or multiple factors > 1/x.
        bool can_be_box4 = false;
        // To get positive: (A+B) must be even.
        // To get magnitude >= 1: D > 0 or A > 0.
        if ((A + B) % 2 == 0) { // Even number of negative factors
            if (D > 0 || A > 0) { // Can achieve magnitude >= 1
                can_be_box4 = true;
            }
        }

        // Special case: If A+B+C+D = 0, this case is excluded by A+B+C+D > 0.
        // If A+B+C+D = 1, handled at the beginning.

        // If A+B = 0 (all toys are positive):
        //   Box 1: No (needs negative)
        //   Box 2: No (needs negative)
        //   Box 3: Yes, if C > 0. (Product of C and D toys is positive. If C > 0, can make magnitude < 1)
        //   Box 4: Yes, if D > 0. (Product of C and D toys is positive. If D > 0, can make magnitude >= 1)
        if (A + B == 0) {
            can_be_box1 = false;
            can_be_box2 = false;
            can_be_box3 = (C > 0);
            can_be_box4 = (D > 0);
        }

        // If C+D = 0 (all toys are negative or zero, but zero is not allowed):
        //   Box 1: Yes, if (A+B) is odd AND A > 0. (Product is negative. If A > 0, can make magnitude >= 1)
        //   Box 2: Yes, if (A+B) is odd AND B > 0. (Product is negative. If B > 0, can make magnitude < 1)
        //   Box 3: No (needs positive)
        //   Box 4: No (needs positive)
        // This logic is already covered by the general rules.
        // For example, if C+D=0:
        //   can_be_box1: (A+B)%2==1 && (D>0 || A>0) -> (A+B)%2==1 && A>0. Correct.
        //   can_be_box2: (A+B)%2==1 && (B+C>0) -> (A+B)%2==1 && B>0. Correct.
        //   can_be_box3: (A+B)%2==0 && (B+C>0) -> (A+B)%2==0 && B>0.
        //     But if C+D=0, and A+B is even, the product is positive.
        //     If B>0, the magnitude is <1. So this would be possible.
        //     Example: A=0, B=2, C=0, D=0. (-0.5)*(-0.5) = 0.25. Box 3.
        //     So can_be_box3 should be (A+B)%2==0 && B>0.
        //     My current can_be_box3 logic: (A+B)%2==0 && (B+C>0). If C=0, this becomes (A+B)%2==0 && B>0. This is correct.
        //   can_be_box4: (A+B)%2==0 && (D>0 || A>0) -> (A+B)%2==0 && A>0.
        //     Example: A=2, B=0, C=0, D=0. (-2)*(-2) = 4. Box 4.
        //     So can_be_box4 should be (A+B)%2==0 && A>0.
        //     My current can_be_box4 logic: (A+B)%2==0 && (D>0 || A>0). If D=0, this becomes (A+B)%2==0 && A>0. This is correct.

        print_bool(can_be_box1);
        std::cout << " ";
        print_bool(can_be_box2);
        std::cout << " ";
        print_bool(can_be_box3);
        std::cout << " ";
        print_bool(can_be_box4);
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
