char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Determine the most frequent move.
        // If counts are equal, 'P' > 'R' > 'S' lexicographically.
        // The problem statement implies any optimal answer is fine.
        // So, we can pick any if counts are equal.
        // Let's prioritize P, then R, then S for consistency, though it doesn't matter.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        // If counts are equal, the order of if statements determines priority.
        // For example, if R=2, S=2, P=1, this logic would pick S.
        // If R=2, S=1, P=2, this logic would pick P.
        // This is fine as any optimal answer is accepted.

        char my_optimal_move = get_winning_move(most_frequent_bot_move);

        for (size_t i = 0; i < s.length(); ++i) {
            std::cout << my_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    int k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Friends who receive w_i = 1 integer
    // These friends should get the largest remaining integers to maximize 2 * integer_value
    // They will take from the largest available elements in 'a'.
    // The w_i values are sorted, so w[0]...w[count_ones-1] will be 1s.
    int count_ones = 0;
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            count_ones++;
        } else {
            break;
        }
    }

    // Add the largest 'count_ones' elements twice to total_happiness
    // These are a[n-1], a[n-2], ..., a[n-count_ones]
    for (int i = 0; i < count_ones; ++i) {
        total_happiness += 2 * a[n - 1 - i];
    }

    // Friends who receive w_i > 1 integers
    // These friends will contribute a_max + a_min to happiness.
    // To maximize this, they should get the largest available elements as a_max,
    // and the smallest available elements as a_min.

    // The largest elements for a_max are already taken by friends with w_i=1.
    // The remaining largest elements are a[n-1-count_ones], a[n-2-count_ones], ...
    // These should be assigned as the max_val for friends with w_i > 1.
    // Since w is sorted, friends with larger w_i values are at the end of the w array.
    // We assign the largest remaining elements from 'a' to these friends as their max_val.
    // The friends with w_i > 1 are w[count_ones], ..., w[k-1].
    // We iterate from the largest w_i (w[k-1]) down to w[count_ones].
    // The largest available elements in 'a' are a[n-1-count_ones], a[n-2-count_ones], ...
    // We assign these to friends with w_i > 1 as their max_val.
    int a_idx_for_max = n - 1 - count_ones; // Index of the largest available element in 'a'

    for (int i = k - 1; i >= count_ones; --i) {
        total_happiness += a[a_idx_for_max]; // This is the max_val for friend i
        a_idx_for_max--;
    }

    // Now, for friends with w_i > 1, we need to assign their min_val.
    // These friends also need to receive w_i - 2 additional integers (if w_i > 1).
    // The smallest elements from 'a' should be used for min_val.
    // The remaining elements in 'a' are a[0], a[1], ..., a[a_idx_for_max].
    // We assign the smallest elements from 'a' as min_val for friends with w_i > 1.
    // We iterate from the smallest w_i > 1 (w[count_ones]) up to w[k-1].
    // The smallest available elements in 'a' are a[0], a[1], ...
    int a_idx_for_min = 0; // Index of the smallest available element in 'a'

    for (int i = count_ones; i < k; ++i) {
        total_happiness += a[a_idx_for_min]; // This is the min_val for friend i
        a_idx_for_min += (w[i] - 1); // This friend takes w[i]-1 elements starting from a_idx_for_min
                                     // The first one is min_val, the next w[i]-2 are intermediate,
                                     // and the last one is max_val (already assigned).
                                     // So, we advance a_idx_for_min by w[i]-1 to account for all elements this friend takes.
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
