void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // If current_sum == 2 * current_xor_sum, the array is already good.
    // We can output 0 appended elements.
    // However, the problem statement says "You don't have to minimize the number of added elements!".
    // So, we can always append elements.
    // The strategy below always appends 2 elements.
    // This is simpler and always works.

    // Let S be current_sum and X be current_xor_sum.
    // We want to find b1, b2 such that (S + b1 + b2) = 2 * (X ^ b1 ^ b2).
    // Let b1 = X.
    // Then X ^ b1 = X ^ X = 0.
    // The equation becomes (S + X + b2) = 2 * (0 ^ b2) = 2 * b2.
    // S + X + b2 = 2 * b2
    // S + X = b2
    // So, b2 = S + X.

    // The two elements to append are X and (S + X).
    // Let's verify this:
    // New sum S' = S + X + (S + X) = 2S + 2X.
    // New XOR sum X' = X ^ X ^ (S + X) = 0 ^ (S + X) = S + X.
    // We need S' = 2 * X'.
    // 2S + 2X = 2 * (S + X).
    // This is true.

    // The problem states that appended elements can be up to 10^18.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 (approx 10^9).
    // So S + X can be up to 10^14 + 10^9, which fits in long long and is within 10^18.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

