    long long total_steps = 0;
    long long b_count = 0;
    long long power_of_2 = 1; // Represents 2^k for the current 'a'
    long long MOD = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % MOD;
        } else { // s[i] == 'a'
            // This 'a' needs to jump over all 'b_count' 'b's to its right.
            // Each jump creates a new 'b'.
            // The number of steps for this 'a' is b_count.
            // These steps are added to the total.
            // After this 'a' moves past all 'b_count' 'b's, it effectively
            // creates b_count new 'b's that will be to its left.
            // These new 'b's will be available for 'a's further to the left.
            // The number of 'b's that an 'a' to its left will see is
            // the original b_count * 2 (because this 'a' effectively doubles the 'b's it passes)
            // plus any 'b's that were already there.

            // The logic is:
            // When an 'a' is encountered, it will interact with all 'b's to its right.
            // Let's say there are `k` 'b's to its right.
            // This 'a' will perform `k` operations.
            // Each operation "ab" -> "bba" effectively moves the 'a' past one 'b'
            // and creates an additional 'b'.
            // So, after this 'a' has moved past all `k` 'b's, it will have
            // generated `k` new 'b's.
            // These `k` new 'b's are now to the left of the original `k` 'b's
            // (and to the left of the 'a' itself).
            // So, for the next 'a' to the left, the number of 'b's it sees
            // will be `b_count` (original) + `b_count` (newly generated) = `2 * b_count`.

            // The number of steps for the current 'a' is `b_count`.
            total_steps = (total_steps + b_count) % MOD;

            // For the next 'a' to the left, the number of 'b's it will encounter
            // will be double the current `b_count`.
            b_count = (b_count * 2) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

