int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    long long total_operations = 0;
    int correct_sequences = 0;
    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        if (m > 0 && chain[0] == 1) {
            int current_expected = 1;
            int current_sequence_length = 0;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_expected) {
                    current_sequence_length++;
                    current_expected++;
                } else {
                    break; 
                }
            }
            correct_sequences = current_sequence_length;
        }
    }

    // Total operations to disassemble everything:
    // Each chain of length m_i has m_i-1 existing nestings.
    // To disassemble these, we need m_i-1 'get out' operations.
    // Sum of (m_i - 1) over all chains = (sum of m_i) - k = n - k.
    // This is the number of 'get out' operations.
    //
    // Total operations to assemble the final chain 1->2->...->n:
    // This requires n-1 'put in' operations if all dolls are separate.
    //
    // The problem states that the criminal took out all dolls and assembled them into 1->2->...->n.
    // This implies the initial state is the k chains, and the final state is 1->2->...->n.
    // We need to find the minimum time to go from initial k chains to 1->2->...->n.
    //
    // Operations:
    // 1. Disassemble existing incorrect nestings.
    // 2. Assemble new correct nestings.
    //
    // Consider the target chain 1 -> 2 -> ... -> n.
    // We have identified `correct_sequences` dolls that are already in the correct relative order
    // starting from 1: `1 -> 2 -> ... -> correct_sequences`.
    // These `correct_sequences - 1` nestings (e.g., 1 in 2, 2 in 3, ..., (correct_sequences-1) in correct_sequences)
    // do not need to be disassembled or reassembled.
    //
    // Number of dolls that are part of the correct prefix: `correct_sequences`.
    // Number of dolls NOT part of the correct prefix: `n - correct_sequences`.
    //
    // For the `n - correct_sequences` dolls that are not part of the correct prefix:
    // Each of these dolls must be taken out of whatever it's currently in (if any)
    // and then put into its correct place in the final chain.
    //
    // Number of 'get out' operations:
    // All existing nestings that are NOT part of the `1 -> 2 -> ... -> correct_sequences` prefix
    // must be undone.
    // Total existing nestings in the initial configuration: `n - k`.
    // Nestings that are part of the correct prefix: `correct_sequences - 1`.
    // So, nestings to be undone: `(n - k) - (correct_sequences - 1)`.
    // This is `n - k - correct_sequences + 1`.
    //
    // Number of 'put in' operations:
    // Total nestings required in the final chain: `n - 1`.
    // Nestings already present in the correct prefix: `correct_sequences - 1`.
    // So, nestings to be created: `(n - 1) - (correct_sequences - 1)`.
    // This is `n - correct_sequences`.
    //
    // Total operations = (nestings to undo) + (nestings to create)
    // Total operations = (n - k - correct_sequences + 1) + (n - correct_sequences)
    // Total operations = n - k - correct_sequences + 1 + n - correct_sequences
    // Total operations = 2*n - k - 2*correct_sequences + 1

    total_operations = (long long)2 * n - k - (long long)2 * correct_sequences + 1;

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
