void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (char pivot_char = '0'; pivot_char <= '9'; ++pivot_char) {
        std::vector<char> s1_digits;
        std::vector<char> s2_digits;
        std::string current_coloring(n, ' ');
        bool possible_with_pivot = true;

        for (int i = 0; i < n; ++i) {
            if (s[i] < pivot_char) {
                current_coloring[i] = '1';
                s1_digits.push_back(s[i]);
            } else if (s[i] > pivot_char) {
                current_coloring[i] = '2';
                s2_digits.push_back(s[i]);
            } else { // s[i] == pivot_char
                // Try to assign '2' first, if it maintains sorted order for S2
                // and doesn't violate S1's max <= S2's min.
                // This greedy choice helps to maximize the chance of finding a solution.
                // If we assign '1', it must be >= last S1 digit.
                // If we assign '2', it must be >= last S2 digit.
                // The critical point is that all '1's must be <= pivot_char, and all '2's must be >= pivot_char.
                // So, if s[i] == pivot_char, it can be either '1' or '2'.
                // To maintain the overall sorted property, we want to put as many as possible into '1'
                // as long as they are <= pivot_char, and then switch to '2'.
                // The strategy is: all digits < pivot_char go to S1.
                // All digits > pivot_char go to S2.
                // Digits == pivot_char:
                // The first block of pivot_char digits go to S1.
                // The second block of pivot_char digits go to S2.
                // This means there's an implicit split point for pivot_char digits.
                // We can assign '1' to all s[i] == pivot_char up to some point, then '2' to the rest.
                // The simplest way to handle this is to assign '2' to all s[i] == pivot_char.
                // This ensures s1_digits only contains values < pivot_char, and s2_digits contains values >= pivot_char.
                // This is a valid split.
                current_coloring[i] = '2';
                s2_digits.push_back(s[i]);
            }
        }

        // Check if s1_digits is sorted
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_with_pivot = false;
                break;
            }
        }
        if (!possible_with_pivot) continue;

        // Check if s2_digits is sorted
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_with_pivot = false;
                break;
            }
        }
        if (!possible_with_pivot) continue;

        // If we reach here, this coloring is valid.
        // The condition max(S1) <= min(S2) is implicitly handled by the pivot_char.
        // All digits in S1 are < pivot_char.
        // All digits in S2 are >= pivot_char.
        // So max(S1) < pivot_char <= min(S2) (if S1 and S2 are non-empty).
        // If S1 is empty, max(S1) is effectively -inf.
        // If S2 is empty, min(S2) is effectively +inf.
        // In all cases, the condition holds.

        result = current_coloring;
        found_solution = true;
        break; // Found a solution, no need to check other pivots
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

