void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?'); // Stores the determined character for each position modulo k

    bool possible = true;

    // Step 1: Propagate known characters and check for conflicts within k-periodicity
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            int pos_mod_k = i % k;
            if (fixed_chars[pos_mod_k] == '?') {
                fixed_chars[pos_mod_k] = s[i];
            } else if (fixed_chars[pos_mod_k] != s[i]) {
                possible = false; // Conflict found
                break;
            }
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Step 2: Count 0s and 1s in the first k positions based on fixed_chars
    int count0 = 0;
    int count1 = 0;
    int count_q = 0; // Count of '?' in fixed_chars

    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            count0++;
        } else if (fixed_chars[i] == '1') {
            count1++;
        } else { // fixed_chars[i] == '?'
            count_q++;
        }
    }

    // Check if it's possible to fill '?'s to satisfy k/2 zeros and k/2 ones
    if (count0 > k / 2 || count1 > k / 2) {
        possible = false;
    } else {
        // We need (k/2 - count0) more zeros and (k/2 - count1) more ones.
        // The remaining '?'s must be able to cover these counts.
        // The total number of '?'s is count_q.
        // If (k/2 - count0) + (k/2 - count1) > count_q, it's impossible.
        // This simplifies to k - (count0 + count1) > count_q, which is always true if count_q is the number of '?'s.
        // The actual check is if we have enough '?'s to satisfy the deficit.
        // The number of '?'s needed is (k/2 - count0) + (k/2 - count1).
        // This sum must be less than or equal to count_q.
        // (k/2 - count0) + (k/2 - count1) = k - (count0 + count1).
        // Since count_q = k - (count0 + count1), this condition is always met if count0 <= k/2 and count1 <= k/2.
        // The only constraint is that we can't have too many 0s or 1s already.
        // The logic `count0 > k / 2 || count1 > k / 2` already covers the impossible cases.
        // If we reach here, it means we can always fill the '?'s in the first k positions to satisfy the k/2 condition.
        // For example, if k=4, k/2=2. fixed_chars = {'0', '?', '?', '1'}. count0=1, count1=1, count_q=2.
        // We need 1 more '0' and 1 more '1'. We have 2 '?'s. We can fill them as '0' and '1'.
        // So, if count0 <= k/2 and count1 <= k/2, it's always possible for the first block.
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

