    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1}^{b-1} r
    // This is (b-1) * b / 2
    long long sum_r_term = (b - 1);
    long long sum_r_val = (sum_r_term % MOD * (b % MOD)) % MOD;

    // We need to divide by 2. Since MOD is prime, we can multiply by modular inverse of 2.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004
    long long inv2 = 500000004;
    sum_r_val = (sum_r_val * inv2) % MOD;

    // Calculate sum_k_term = sum_{k=1}^{a} (k * b + 1)
    // This is b * sum_{k=1}^{a} k + sum_{k=1}^{a} 1
    // = b * (a * (a + 1) / 2) + a

    // Calculate sum_{k=1}^{a} k = a * (a + 1) / 2
    long long sum_k_val = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD;

    // Calculate b * sum_{k=1}^{a} k
    long long b_times_sum_k = (b % MOD * sum_k_val) % MOD;

    // Add a
    long long sum_k_total_term = (b_times_sum_k + (a % MOD)) % MOD;

    // Final result is (sum_k_total_term * sum_r_val) % MOD
    long long result = (sum_k_total_term * sum_r_val) % MOD;

    std::cout << result << std::endl;

    return 0;
}

