            if (remaining_moves % 2 == 0) {
                // If remaining_moves is even, we can use pairs of moves that cancel out (e.g., (1,0) then (-1,0))
                // or (1,1) then (-1,-1) without changing the parity of coordinates.
                // Each such pair adds 2 to k but doesn't change the final position.
                // So, we can make all min_moves diagonal if possible, then add remaining_moves.
                // The maximum number of diagonal moves is k.
                result = k;
            } else {
                // If remaining_moves is odd, we must end up with a coordinate parity mismatch
                // if we only use diagonal moves for min_moves and then cancel out.
                // Example: (0,0) -> (1,1) -> (2,2) in 2 moves. k=3.
                // (0,0) -> (1,1) -> (2,2) -> (2,1) (straight move)
                // (0,0) -> (1,1) -> (1,0) -> (2,0) (straight move)
                // The parity of (x+y) changes with each move.
                // (0,0) -> (N,M)
                // Parity of (N+M) must be same as parity of K.
                // If (N+M) % 2 != K % 2, it's impossible.
                //
                // Let's re-evaluate based on the parity of (abs_n + abs_m) and k.
                // Each move changes the sum of coordinates (x+y) by -2, -1, 0, 1, or 2.
                // This means each move changes the parity of (x+y) by 1.
                // So, (abs_n + abs_m) % 2 must be equal to k % 2.
                if ((abs_n + abs_m) % 2 != k % 2) {
                    std::cout << -1 << "\n";
                    continue;
                }

                // If (abs_n + abs_m) % 2 == k % 2, and remaining_moves is odd.
                // This means we need to make an odd number of "compensating" moves.
                // We can't just add remaining_moves to k, because that would imply
                // we can always make all k moves diagonal.
                //
                // Consider the case where we need to reach (abs_n, abs_m) in k moves.
                // We make abs_m diagonal moves to reach (abs_m, abs_m).
                // Then abs_n - abs_m straight moves to reach (abs_n, abs_m).
                // Total moves so far: abs_m + (abs_n - abs_m) = abs_n.
                // Number of diagonal moves: abs_m.
                //
                // We have k - abs_n remaining moves.
                // If k - abs_n is odd, we need to adjust.
                // We can change a diagonal move to a straight move and back, or vice versa.
                //
                // If k - abs_n is odd, it means we need to make an odd number of "parity-flipping" moves.
                // We can achieve this by changing one of the final moves.
                // For example, instead of (X,Y) -> (X+1, Y+1) (diagonal), we do (X,Y) -> (X+1, Y) -> (X+1, Y+1)
                // This uses 2 moves instead of 1, and changes the parity of moves.
                //
                // The maximum number of diagonal moves is k - 2.
                // This is because if k - abs_n is odd, we must use at least one pair of moves
                // that effectively "wastes" two moves to adjust parity.
                // For example, instead of reaching (X,Y) in 1 move, we reach it in 3 moves:
                // (0,0) -> (1,0) -> (0,0) -> (1,0)
                // This uses 3 moves, 0 diagonal.
                //
                // The logic is:
                // If k - abs_n is even, we can make k diagonal moves.
                // If k - abs_n is odd, we must make k-2 diagonal moves.
                // This is because we need to "waste" two moves to maintain the parity of (x+y) % 2 == k % 2.
                // For example, if we are at (X,Y) and need to reach (X+1, Y+1) in 1 move (diagonal).
                // If k is 3, and we need to reach (X+1, Y+1).
                // We can do (X,Y) -> (X+1, Y) -> (X,Y) -> (X+1, Y+1). This is 1 diagonal, 2 straight. Total 3 moves.
                // Or (X,Y) -> (X+1, Y+1) -> (X+1, Y) -> (X+1, Y+1). This is 2 diagonal, 1 straight. Total 3 moves.
                //
                // The maximum number of diagonal moves is k - 2.
                result = k - 2;
            }
            std::cout << result << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<long long> left_max_dist(n);
    std::deque<std::pair<long long, int>> dq_left; // {height, index}

    for (int i = 0; i < n; ++i) {
        while (!dq_left.empty() && dq_left.back().first >= h[i]) {
            dq_left.pop_back();
        }
        long long current_dist;
        if (dq_left.empty()) {
            current_dist = h[i];
        } else {
            current_dist = std::min(h[i], dq_left.back().first + (i - dq_left.back().second));
        }
        left_max_dist[i] = current_dist;
        dq_left.push_back({h[i], i});
    }

    std::vector<long long> right_max_dist(n);
    std::deque<std::pair<long long, int>> dq_right; // {height, index}

    for (int i = n - 1; i >= 0; --i) {
        while (!dq_right.empty() && dq_right.back().first >= h[i]) {
            dq_right.pop_back();
        }
        long long current_dist;
        if (dq_right.empty()) {
            current_dist = h[i];
        } else {
            current_dist = std::min(h[i], dq_right.back().first + (dq_right.back().second - i));
        }
        right_max_dist[i] = current_dist;
        dq_right.push_back({h[i], i});
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(left_max_dist[i], right_max_dist[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int start_block_val = std::max(1, current_val - k + 1);
        for (int j = 0; j < k && current_val >= 1; ++j) {
            if (i + j < n) { // Ensure we don't write past the end of the permutation
                p[i + j] = current_val;
                current_val--;
            } else {
                break; // No more elements to place
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            // Chanek's turn
            if (n % 2 == 1) {
                // If N is odd, Chanek must take 1.
                chanek_coins += 1;
                n -= 1;
            } else {
                // N is even. Chanek has two choices: take 1 or take N/2.
                // If N is 2, taking 1 leaves 1 for opponent, taking N/2 leaves 1 for opponent. Both give 1 to Chanek.
                // If N is 4, taking 1 leaves 3. Opponent takes 1, leaves 2. Chanek takes 1, leaves 1. Opponent takes 1. Chanek: 1+1=2.
                // If N is 4, taking N/2=2 leaves 2. Opponent takes 1, leaves 1. Chanek takes 1. Chanek: 2+1=3.
                // So for N=4, Chanek takes N/2.
                //
                // The strategy is: if N is even, and N/2 is odd, taking N/2 is good because it forces the opponent to take 1.
                // If N is even, and N/2 is even, taking N/2 might be bad if the opponent can also take N/4.
                //
                // Consider the case where N is a power of 2 (e.g., 2, 4, 8, 16, ...).
                // If N = 2^k:
                // Chanek takes N/2 = 2^(k-1). Remaining N = 2^(k-1).
                // Opponent takes N/2 = 2^(k-2). Remaining N = 2^(k-2).
                // This continues until N=2.
                // Chanek takes 2^(k-1) + 2^(k-3) + ...
                // Opponent takes 2^(k-2) + 2^(k-4) + ...
                //
                // If N is even and N/2 is odd (e.g., N=2, 6, 10, 14, ...):
                // Chanek takes N/2. N becomes N/2 (odd).
                // Opponent must take 1. N becomes N/2 - 1 (even).
                // This seems like a good move for Chanek.
                //
                // If N is even and N/2 is even (e.g., N=4, 8, 12, 16, ...):
                // Chanek takes N/2. N becomes N/2 (even).
                // Opponent can also take N/4.
                //
                // The optimal strategy for Chanek when N is even:
                // If N is a power of 2 (N = 2^k, k >= 1):
                //   Chanek takes N/2. N becomes N/2.
                //   Opponent takes N/4. N becomes N/4.
                //   ...
                //   This continues until N=2.
                //   Chanek takes 2^(k-1) + 2^(k-3) + ...
                //   Opponent takes 2^(k-2) + 2^(k-4) + ...
                //   Chanek will get 2/3 of the total coins (approximately) if k is large.
                //   Example N=4: Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 2+1=3. Opponent: 1.
                //   Example N=8: Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 4+1=5. Opponent: 2+1=3.
                //
                // If N is even but not a power of 2:
                //   N = 2^k * M, where M is odd and M > 1.
                //   If Chanek takes N/2: N becomes 2^(k-1) * M.
                //   If Chanek takes 1: N becomes N-1 (odd).
                //
                // Let's re-evaluate the greedy choice.
                // If N is even:
                // Option A: Take 1. Remaining N-1 (odd). Opponent takes 1. N-2 (even).
                // Option B: Take N/2. Remaining N/2.
                //
                // If N/2 is odd (e.g., N=6, N/2=3):
                //   Chanek takes N/2. Chanek gets 3. N becomes 3.
                //   Opponent must take 1. Opponent gets 1. N becomes 2.
                //   Chanek takes 1. Chanek gets 1. N becomes 1.
                //   Opponent takes 1. Opponent gets 1. N becomes 0.
                //   Chanek total: 3+1=4. Opponent total: 1+1=2.
                //   If Chanek took 1 initially: Chanek gets 1. N becomes 5.
                //   Opponent takes 1. Opponent gets 1. N becomes 4.
                //   Chanek takes N/2=2. Chanek gets 2. N becomes 2.
                //   Opponent takes 1. Opponent gets 1. N becomes 1.
                //   Chanek takes 1. Chanek gets 1. N becomes 0.
                //   Chanek total: 1+2+1=4. Opponent total: 1+1=2.
                //   In this case, both strategies yield the same result for Chanek.
                //   However, taking N/2 is generally better as it reduces N faster.
                //
                // The key insight is that if N is even, and N/2 is odd, taking N/2 is always optimal for the current player.
                // Because it leaves an odd number of coins for the opponent, forcing them to take 1.
                // This is a strong move.
                //
                // What if N is even and N/2 is also even? (N is a multiple of 4)
                // Example N=4:
                //   Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0. Chanek: 1+1=2.
                //   Chanek takes N/2=2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0. Chanek: 2+1=3.
                //   Here, taking N/2 is better.
                //
                // It seems the greedy strategy is:
                // If N is odd, take 1.
                // If N is even:
                //   If N/2 is odd (N = 2 * odd_number, e.g., 2, 6, 10, 14, ...): take N/2.
                //   If N/2 is even (N = 4 * even_number, e.g., 4, 8, 12, 16, ...): take N/2.
                //
                // This simplifies to: if N is even, always take N/2.
                // This is because taking N/2 reduces the total number of turns faster, and if the opponent is also playing optimally,
                // they will also try to take N/2 if possible.
                //
                // Let's test this hypothesis:
                // N=5:
                // C: take 1. N=4. C_coins=1.
                // O: take N/2=2. N=2. O_coins=2.
                // C: take N/2=1. N=1. C_coins=1+1=2.
                // O: take 1. N=0. O_coins=2+1=3.
                // Chanek gets 2. Matches example.
                //
                // N=6:
                // C: take N/2=3. N=3. C_coins=3.
                // O: take 1. N=2. O_coins=1.
                // C: take N/2=1. N=1. C_coins=3+1=4.
                // O: take 1. N=0. O_coins=1+1=2.
                // Chanek gets 4. Matches example.
                //
                // This greedy strategy seems to work for the examples.
                // The logic is that taking N/2 is always better or equal to taking 1 if N is even.
                // Taking N/2 reduces N by a larger amount, giving the current player a larger chunk of coins.
                // The only exception might be if taking N/2 leaves the opponent in a state where they can take a huge amount,
                // but since the opponent also plays optimally, they would take N/2 anyway if N is even.
                //
                // The only edge case is when N is even, and taking N/2 leaves N/2 = 1. This happens when N=2.
                // If N=2:
                //   Chanek takes N/2=1. N=1. Chanek_coins=1.
                //   Opponent takes 1. N=0. Opponent_coins=1.
                //   Chanek gets 1.
                // If Chanek takes 1: N=1. Chanek_coins=1.
                //   Opponent takes 1. N=0. Opponent_coins=1.
                //   Chanek gets 1.
                // Same result. So taking N/2 is fine.
                //
                // The strategy is:
                // If N is odd, take 1.
                // If N is even, take N/2.
                // This is the simplest greedy approach. Let's verify it.

                // The problem states "Both players will try to maximize the number of coins they have."
                // This is a standard game theory problem.
                // If N is odd, the current player must take 1.
                // If N is even, the current player can take 1 or N/2.
                //   If taking N/2 is better than taking 1, they take N/2.
                //   If taking 1 is better than taking N/2, they take 1.
                //   "Better" means maximizing their final score.

                // Let's consider the state (N, current_player_score, other_player_score).
                // This is a recursive problem.
                // f(N, is_chanek_turn) returns (chanek_score, opponent_score)
                //
                // If N is odd:
                //   Current player takes 1. N becomes N-1.
                //   (c, o) = f(N-1, !is_chanek_turn)
                //   If is_chanek_turn: return (c+1, o)
                //   Else: return (c, o+1)
                //
                // If N is even:
                //   Option 1: Take 1. N becomes N-1.
                //     (c1, o1) = f(N-1, !is_chanek_turn)
                //     If is_chanek_turn: (c1_final, o1_final) = (c1+1, o1)
                //     Else: (c1_final, o1_final) = (c1, o1+1)
                //
                //   Option 2: Take N/2. N becomes N/2.
                //     (c2, o2) = f(N/2, !is_chanek_turn)
                //     If is_chanek_turn: (c2_final, o2_final) = (c2+N/2, o2)
                //     Else: (c2_final, o2_final) = (c2, o2+N/2)
                //
                //   Current player chooses the option that maximizes their score.
                //   If is_chanek_turn: choose max(c1_final, c2_final)
                //   Else: choose max(o1_final, o2_final)
                //
                // This is still too slow for N=10^18.
                //
                // Let's look at the structure of the game.
                // The game always ends.
                // The total coins are N.
                //
                // Consider the total coins taken by Chanek (C) and Opponent (O). C+O = initial N.
                // Chanek wants to maximize C. Opponent wants to maximize O (which is equivalent to minimizing C).
                // This is a zero-sum game if we consider C - O.
                //
                // The greedy strategy:
                // If N is odd, take 1.
                // If N is even, take N/2.
                //
                // Let's trace N=10:
                // C: N=10 (even). Take N/2=5. C_coins=5. N=5.
                // O: N=5 (odd). Take 1. O_coins=1. N=4.
                // C: N=4 (even). Take N/2=2. C_coins=5+2=7. N=2.
                // O: N=2 (even). Take N/2=1. O_coins=1+1=2. N=1.
                // C: N=1 (odd). Take 1. C_coins=7+1=8. N=0.
                // Final: Chanek=8, Opponent=2.
                //
                // What if Chanek took 1 at N=10?
                // C: N=10 (even). Take 1. C_coins=1. N=9.
                // O: N=9 (odd). Take 1. O_coins=1. N=8.
                // C: N=8 (even). Take N/2=4. C_coins=1+4=5. N=4.
                // O: N=4 (even). Take N/2=2. O_coins=1+2=3. N=2.
                // C: N=2 (even). Take N/2=1. C_coins=5+1=6. N=1.
                // O: N=1 (odd). Take 1. O_coins=3+1=4. N=0.
                // Final: Chanek=6, Opponent=4.
                //
                // In this case, taking N/2 (5) was better for Chanek (8 vs 6).
                //
                // The greedy strategy (take 1 if odd, take N/2 if even) seems to be correct.
                // Why?
                // When N is odd, you *must* take 1. No choice.
                // When N is even, you can take 1 or N/2.
                //   Taking N/2 gives you more coins immediately (unless N=2, where both give 1).
                //   It also reduces N faster.
                //   If N/2 is odd, then the opponent is forced to take 1 on their next turn, which is good for you.
                //   If N/2 is even, then the opponent can also take N/4. This continues the pattern.
                //
                // The crucial observation might be that the game is symmetric in terms of moves available.
                // Both players want to maximize their own score.
                // If a player can take N/2, they will almost always do it because it's a larger chunk.
                // The only reason not to take N/2 would be if it sets up the opponent for an even bigger gain,
                // but since the opponent also plays optimally, they would take N/2 if available anyway.
                //
                // The only time taking 1 might be better than taking N/2 is if N/2 is very small (e.g., N=2, N/2=1)
                // AND taking 1 leaves the opponent in a much worse state.
                // But if N=2, taking 1 or N/2 both leave N=1, so the outcome is the same.
                //
                // So the simple greedy strategy:
                // If N is odd, take 1.
                // If N is even, take N/2.
                // This is the strategy that maximizes the current player's immediate gain.
                // Since the game is finite and deterministic, and both players are rational,
                // this simple greedy strategy works because the "optimal" move for the current player
                // is to take the largest possible amount, as it doesn't create a disadvantage for them
                // in the long run compared to the opponent, who would also take the largest amount.

                // Let's consider the case where N is even.
                // Option 1: Take 1. N becomes N-1.
                // Option 2: Take N/2. N becomes N/2.
                //
                // If N is a power of 2, say N = 2^k.
                // Chanek takes N/2 = 2^(k-1). N becomes 2^(k-1).
                // Opponent takes N/4 = 2^(k-2). N becomes 2^(k-2).
                // ...
                // This continues until N=2.
                // Chanek takes 2^(k-1) + 2^(k-3) + ...
                // Opponent takes 2^(k-2) + 2^(k-4) + ...
                //
                // If N is not a power of 2, N = 2^k * M, where M is odd and M > 1.
                // Example N=12 (k=2, M=3).
                // C: N=12. Take N/2=6. C_coins=6. N=6.
                // O: N=6. Take N/2=3. O_coins=3. N=3.
                // C: N=3. Take 1. C_coins=6+1=7. N=2.
                // O: N=2. Take N/2=1. O_coins=3+1=4. N=1.
                // C: N=1. Take 1. C_coins=7+1=8. N=0.
                // Final: Chanek=8, Opponent=4.
                //
                // What if Chanek took 1 at N=12?
                // C: N=12. Take 1. C_coins=1. N=11.
                // O: N=11. Take 1. O_coins=1. N=10.
                // C: N=10. Take N/2=5. C_coins=1+5=6. N=5.
                // O: N=5. Take 1. O_coins=1+1=2. N=4.
                // C: N=4. Take N/2=2. C_coins=6+2=8. N=2.
                // O: N=2. Take N/2=1. O_coins=2+1=3. N=1.
                // C: N=1. Take 1. C_coins=8+1=9. N=0.
                // Final: Chanek=9, Opponent=3.
                //
                // Here, taking 1 at N=12 was better for Chanek (9 vs 8).
                // So the simple greedy strategy (always take N/2 if even) is NOT correct.

                // The optimal strategy for an even N:
                // If N is even, the current player can choose to take 1 or N/2.
                // Let C(N) be the maximum coins Chanek can get if it's Chanek's turn with N coins.
                // Let O(N) be the maximum coins Opponent can get if it's Opponent's turn with N coins.
                //
                // If N is odd:
                //   Chanek's turn: Chanek takes 1. Chanek gets 1 + (N-1 - O(N-1)).
                //   Opponent's turn: Opponent takes 1. Opponent gets 1 + (N-1 - C(N-1)).
                //
                // If N is even:
                //   Chanek's turn:
                //     Option 1 (take 1): 1 + (N-1 - O(N-1))
                //     Option 2 (take N/2): N/2 + (N/2 - O(N/2))
                //     Chanek chooses max of these two.
                //   Opponent's turn:
                //     Option 1 (take 1): 1 + (N-1 - C(N-1))
                //     Option 2 (take N/2): N/2 + (N/2 - C(N/2))
                //     Opponent chooses max of these two.
                //
                // This is still a recursive definition.
                //
                // Let's analyze the N=12 case again.
                // C: N=12.
                //   Option 1 (take 1): C gets 1. N=11. Opponent's turn.
                //     O: N=11. Take 1. O gets 1. N=10. Chanek's turn.
                //       C: N=10.
                //         Option 1 (take 1): C gets 1. N=9. O's turn.
                //           O: N=9. Take 1. O gets 1. N=8. C's turn.
                //             C: N=8. Take N/2=4. C gets 4. N=4. O's turn.
                //               O: N=4. Take N/2=2. O gets 2. N=2. C's turn.
                //                 C: N=2. Take N/2=1. C gets 1. N=1. O's turn.
                //                   O: N=1. Take 1. O gets 1. N=0.
                //                 C total from N=2: 1. O total from N=2: 1.
                //               O total from N=4: 2+1=3. C total from N=4: 1.
                //             C total from N=8: 4+1=5. O total from N=8: 3.
                //           O total from N=9: 1+3=4. C total from N=9: 5.
                //         C total from N=10 (take 1): 1+5=6. O total from N=10 (take 1): 4.
                //
                //         Option 2 (take N/2=5): C gets 5. N=5. O's turn.
                //           O: N=5. Take 1. O gets 1. N=4. C's turn.
                //             C: N=4. Take N/2=2. C gets 2. N=2. O's turn.
                //               O: N=2. Take N/2=1. O gets 1. N=1. C's turn.
                //                 C: N=1. Take 1. C gets 1. N=0.
                //               C total from N=2: 1. O total from N=2: 1.
                //             C total from N=4: 2+1=3. O total from N=4: 1.
                //           O total from N=5: 1+1=2. C total from N=5: 3.
                //         C total from N=10 (take 5): 5+3=8. O total from N=10 (take 5): 2.
                //       For N=10, Chanek chooses Option 2 (take 5) because 8 > 6. Chanek gets 8. Opponent gets 2.
                //     O total from N=11: 1+2=3. C total from N=11: 8.
