int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total possible substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // To maximize f(s), we need to minimize the number of substrings consisting only of zeros.
        // This is achieved by distributing the zeros as evenly as possible among the m+1 possible blocks
        // created by m ones.
        // For example, if s = "0...010...01...10...0"
        // There are m ones, which divide the string into m+1 potential blocks of zeros.
        // Let k be the number of zeros.
        // We want to distribute k zeros into m+1 blocks.
        // Let q be the quotient and r be the remainder when k is divided by (m+1).
        // k = q * (m+1) + r
        // This means r blocks will have length (q+1) zeros, and (m+1-r) blocks will have length q zeros.

        long long num_blocks_of_zeros = m + 1;
        long long q = num_zeros / num_blocks_of_zeros; // length of smaller blocks of zeros
        long long r = num_zeros % num_blocks_of_zeros; // number of blocks with length q+1

        long long num_substrings_all_zeros = 0;

        // r blocks of length (q+1)
        if (q + 1 > 0) { // Only count if block length is positive
            num_substrings_all_zeros += r * (q + 1) * (q + 2) / 2;
        }

        // (num_blocks_of_zeros - r) blocks of length q
        if (q > 0) { // Only count if block length is positive
            num_substrings_all_zeros += (num_blocks_of_zeros - r) * q * (q + 1) / 2;
        }

        long long max_f_s = total_substrings - num_substrings_all_zeros;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

