int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << 1 << " " << 1 << "\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operations 2 and 3: Do nothing
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
    } else {
        // Operation 1: Make a[0]...a[n-2] divisible by n
        // Select segment [1, n-1] (0-indexed: [0, n-2])
        // Length is n-1.
        // For each a[i] in this segment, add (n-1) * k_i such that a[i] becomes a multiple of n.
        // a[i] + (n-1)*k_i = 0 (mod n)
        // a[i] - k_i = 0 (mod n)
        // k_i = a[i] (mod n)
        // So we need to add (n-1) * (a[i] % n) to a[i] if a[i]%n != 0.
        // Or more generally, we want a[i] + b_i = 0 (mod n).
        // b_i must be a multiple of (n-1).
        // Let b_i = (n-1) * x_i.
        // a[i] + (n-1) * x_i = 0 (mod n)
        // a[i] - x_i = 0 (mod n)
        // x_i = a[i] (mod n)
        // If a[i] % n == 0, then x_i = 0. b_i = 0.
        // If a[i] % n != 0, then x_i = a[i] % n. b_i = (n-1) * (a[i] % n).
        // This makes a[i] + b_i a multiple of n.
        // The value to add is (n - (a[i] % n)) % n * (n - 1).
        // If a[i] % n == 0, this is 0.
        // If a[i] % n != 0, this is (n - (a[i] % n)) * (n - 1).
        // This is equivalent to (n-1) * (a[i] % n) if we consider negative multiples.
        // Let's use the property: a[i] + x * (n-1) = 0 (mod n) => a[i] - x = 0 (mod n) => x = a[i] (mod n).
        // So we add (a[i] % n) * (n-1) to a[i].
        // If a[i] % n is negative, we need to adjust.
        // (a[i] % n + n) % n gives a positive remainder.
        // Let rem = (a[i] % n + n) % n.
        // We want to add b_i such that a[i] + b_i is a multiple of n.
        // b_i must be a multiple of (n-1).
        // We need a[i] + b_i = 0 (mod n).
        // Let b_i = k * (n-1).
        // a[i] + k * (n-1) = 0 (mod n)
        // a[i] - k = 0 (mod n)
        // k = a[i] (mod n)
        // So k = (a[i] % n + n) % n.
        // The value to add is k * (n-1).
        // This makes a[i] become a[i] + k * (n-1), which is a multiple of n.

        std::cout << 1 << " " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long rem = (a[i] % n + n) % n;
            long long add_val = rem * (n - 1);
            std::cout << add_val << (i == n - 2 ? "" : " ");
            a[i] += add_val;
        }
        std::cout << "\n";

        // Operation 2: Make a[n-1] divisible by n
        // Select segment [n, n] (0-indexed: [n-1, n-1])
        // Length is 1.
        // We can add any multiple of 1.
        // We want a[n-1] to be a multiple of n.
        // Add (n - (a[n-1] % n)) % n to a[n-1].
        // Or simply, add -a[n-1] to make it 0, then it's a multiple of n.
        // No, we need it to be a multiple of n, not necessarily 0.
        // Let rem = (a[n-1] % n + n) % n.
        // We need to add (n - rem) % n.
        // This makes a[n-1] become a multiple of n.
        // The problem is that we need to make it 0 eventually.
        // The strategy is to make all a[i] divisible by n.
        // For a[n-1], we can add any multiple of 1.
        // We want a[n-1] + b_{n-1} = 0 (mod n).
        // We can add b_{n-1} = (n - (a[n-1] % n + n) % n).
        // This makes a[n-1] a multiple of n.
        // Example: a[n-1] = 5, n = 4. rem = 1. Add (4-1)%4 = 3. a[n-1] becomes 8.
        // Example: a[n-1] = 4, n = 4. rem = 0. Add (4-0)%4 = 0. a[n-1] becomes 4.
        // This is correct.
        std::cout << n << " " << n << "\n";
        long long rem_last = (a[n - 1] % n + n) % n;
        long long add_last = (n - rem_last) % n;
        std::cout << add_last << "\n";
        a[n - 1] += add_last;

        // Operation 3: Make all elements zero
        // All a[i] are now multiples of n.
        // Select segment [1, n] (0-indexed: [0, n-1])
        // Length is n.
        // For each a[i], add -a[i]. Since a[i] is a multiple of n, -a[i] is also a multiple of n.
        std::cout << 1 << " " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // balance[i] = (count of 1s) - (count of 2s) in a[0...i-1]
    // For left half, we are interested in balance of a[0...k-1] for k from 0 to n.
    // This is equivalent to prefix_balance[k]
    std::vector<int> left_prefix_balance(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        left_prefix_balance[i + 1] = left_prefix_balance[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // balance[i] = (count of 1s) - (count of 2s) in a[i...2n-1]
    // For right half, we are interested in balance of a[2n-k...2n-1] for k from 0 to n.
    // This is equivalent to suffix_balance[k]
    std::vector<int> right_suffix_balance(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        right_suffix_balance[i + 1] = right_suffix_balance[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars removed from the left half
    // to achieve a certain balance.
    // key: balance value, value: number of jars removed (k_L)
    std::map<int, int> left_balance_to_kL;
    for (int kL = 0; kL <= n; ++kL) {
        int current_balance = left_prefix_balance[kL];
        if (left_balance_to_kL.find(current_balance) == left_balance_to_kL.end()) {
            left_balance_to_kL[current_balance] = kL;
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible removed jars

    // Iterate through all possible numbers of jars removed from the right half (k_R)
    for (int kR = 0; kR <= n; ++kR) {
        int current_right_balance = right_suffix_balance[kR];
        // We need the total balance of remaining jars to be 0.
        // This means (balance of remaining left jars) + (balance of remaining right jars) = 0
        // (left_prefix_balance[n] - left_prefix_balance[kL]) + (right_suffix_balance[n] - right_suffix_balance[kR]) = 0
        // Let's rephrase:
        // Total initial balance: left_prefix_balance[n] + right_suffix_balance[n]
        // Balance of removed left jars: left_prefix_balance[kL]
        // Balance of removed right jars: right_suffix_balance[kR]
        // Remaining balance = (Total initial balance) - (Balance of removed left jars) - (Balance of removed right jars)
        // This is not quite right.
        //
        // Let's consider the balance of the *remaining* jars.
        // The remaining jars are a[kL...n-1] and a[n...2n-1-kR].
        //
        // The problem statement implies Karlsson removes jars from the ends.
        // So if he removes kL jars from the left, jars a[0...kL-1] are gone.
        // If he removes kR jars from the right, jars a[2n-kR...2n-1] are gone.
        // The remaining jars are a[kL...2n-1-kR].
        //
        // Let B_total be the balance of all 2n jars.
        // B_total = left_prefix_balance[n] + right_suffix_balance[n] (if right_suffix_balance is defined from a[n] to a[2n-1])
        //
        // Let's use the definition of balance as (count of 1s) - (count of 2s).
        //
        // Total balance of all 2n jars:
        int total_initial_balance = 0;
        for(int x : a) {
            total_initial_balance += (x == 1 ? 1 : -1);
        }

        // If we remove kL jars from the left (a[0...kL-1]) and kR jars from the right (a[2n-kR...2n-1]),
        // the balance of the removed left jars is left_prefix_balance[kL].
        // The balance of the removed right jars is right_suffix_balance[kR].
        //
        // The balance of the remaining jars must be 0.
        // So, total_initial_balance - left_prefix_balance[kL] - right_suffix_balance[kR] = 0
        // This means left_prefix_balance[kL] = total_initial_balance - right_suffix_balance[kR].
        //
        // We need to find a kL such that this condition holds.
        int target_left_balance = total_initial_balance - current_right_balance;

        if (left_balance_to_kL.count(target_left_balance)) {
            int kL = left_balance_to_kL[target_left_balance];
            min_removed_jars = std::min(min_removed_jars, kL + kR);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

