        // Case 2: (0,0), (1,1) -> output same as input
        else if (bit_j_val_all_zeros == 0 && bit_j_val_all_ones == 1) {
            // Need `((x_j & A_j) | B_j) ^ C_j` to be x_j
            // Simplest: A_j=1, B_j=0, C_j=0. This makes `(x_j & 1) | 0 ^ 0 = x_j`.
            // A_j is already 1 by default. B_j and C_j are already 0 by default.
            // No change needed for this bit in final_and_mask, final_or_mask, final_xor_mask.
        }
        // Case 3: (0,1), (1,0) -> output inverse of input
        else if (bit_j_val_all_zeros == 1 && bit_j_val_all_ones == 0) {
            // Need `((x_j & A_j) | B_j) ^ C_j` to be ~x_j
            // Simplest: A_j=1, B_j=0, C_j=1. This makes `(x_j & 1) | 0 ^ 1 = x_j ^ 1 = ~x_j`.
            // A_j is already 1 by default. B_j is already 0 by default.
            final_xor_mask |= (1 << j); // Set C_j to 1
        }
        // Case 4: (0,1), (1,1) -> output always 1
        else if (bit_j_val_all_zeros == 1 && bit_j_val_all_ones == 1) {
            // Need `((x_j & A_j) | B_j) ^ C_j` to be 1 for both x_j=0 and x_j=1
            // Simplest: A_j=1, B_j=1, C_j=0. This makes `(x_j & 1) | 1 ^ 0 = 1`.
            // A_j is already 1 by default. C_j is already 0 by default.
            final_or_mask |= (1 << j); // Set B_j to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If AND mask is not all ones, it's active
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If OR mask is not all zeros, it's active
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If XOR mask is not all zeros, it's active
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, then 1 + d, 1 + 2d, etc.

    while (X > 0) {
        long long k = 0;
        // Find largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        // Since X can be up to 10^9, X+1 can be up to 10^9+1.
        // log2(10^9) is approx 29.89. So k will be at most 29.
        // We need to find the largest k such that (1LL << k) - 1 <= X.
        // This is equivalent to (1LL << k) <= X + 1.
        // We can iterate k from 1 upwards.

        // Max k is 60 for long long, but X is 10^9, so max k is ~29.
        // We need to find the largest k such that (1LL << k) - 1 <= X.
        // This is equivalent to (1LL << k) <= X + 1.
        // We can find k by iterating or using log2.
        // Iterating is safer for powers of 2.

        long long temp_k = 1;
        while (true) {
            if (temp_k == 60) { // Prevent overflow for 1LL << temp_k
                break;
            }
            long long num_subsequences = (1LL << temp_k) - 1;
            if (num_subsequences <= X) {
                k = temp_k;
                temp_k++;
            } else {
                break;
            }
        }

        // If k is 0, it means X is 0, or X is 1 and we need 2^1-1=1.
        // If X is 1, k will be 1.
        // If X is 0, loop terminates.
        // If X is 1, k=1, (1LL << 1) - 1 = 1.
        // If X is 2, k=1, (1LL << 1) - 1 = 1.
        // If X is 3, k=2, (1LL << 2) - 1 = 3.
        // If X is 4, k=2, (1LL << 2) - 1 = 3.
        // If X is 5, k=2, (1LL << 2) - 1 = 3.
        // If X is 6, k=2, (1LL << 2) - 1 = 3.
        // If X is 7, k=3, (1LL << 3) - 1 = 7.

        // Add k copies of current_val to the array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }
        X -= ((1LL << k) - 1); // Subtract the count of subsequences generated by these k elements

        // Increment current_val for the next block.
        // The next block's elements must be at least d greater than current_val
        // to ensure max-min >= d for subsequences spanning blocks.
        current_val += d;
        // Ensure current_val doesn't exceed 10^18.
        // If current_val + d would exceed 10^18, we might have an issue.
        // However, current_val is only incremented by d.
        // The maximum number of elements is 10^4.
        // The maximum d is 10^9.
        // If d is 10^9, and we add it 10^4 times, current_val could be 10^4 * 10^9 = 10^13.
        // This is well within 10^18.
        // The initial current_val is 1.
        // The maximum value of current_val will be roughly 1 + (number of blocks) * d.
        // Number of blocks is at most 10^4 (if k=1 for all blocks).
        // So max current_val is 1 + 10^4 * 10^9 = 1 + 10^13, which is < 10^18.
    }

    std::cout << result_array.size() << std::endl;
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable and don't change
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_ones(n, 0);
    std::vector<int> right_ones(n, 0);

    // Calculate left_ones: distance to the nearest 1 on the left (inclusive)
    // If a[i] is 0, it's distance to the previous 1 + 1. If no 1, it's infinity.
    // If a[i] is 1, it's 0.
    int last_one_idx = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            last_one_idx = i;
            left_ones[i] = 0;
        } else {
            if (last_one_idx != -1) {
                left_ones[i] = i - last_one_idx;
            } else {
                left_ones[i] = n + 1; // Represents infinity
            }
        }
    }

    // Calculate right_ones: distance to the nearest 1 on the right (inclusive)
    // If a[i] is 0, it's distance to the next 1 + 1. If no 1, it's infinity.
    // If a[i] is 1, it's 0.
    last_one_idx = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            last_one_idx = i;
            right_ones[i] = 0;
        } else {
            if (last_one_idx != n) {
                right_ones[i] = last_one_idx - i;
            } else {
                right_ones[i] = n + 1; // Represents infinity
            }
        }
    }

    int max_dist = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int dist_to_nearest_one = std::min(left_ones[i], right_ones[i]);
            if (dist_to_nearest_one != n + 1) { // If there's at least one '1' in the sequence
                max_dist = std::max(max_dist, dist_to_nearest_one);
            }
        }
    }

    // If max_dist is 0, it means all elements are 1s, or all are 0s.
    // If all are 1s, max_dist remains 0.
    // If all are 0s, max_dist remains 0 because left_ones/right_ones are n+1.
    // In both cases, the sequence is stable.
    // The only case where max_dist is 0 and it's not all 1s is if all are 0s.
    // If all are 0s, left_ones/right_ones are n+1, so min is n+1, max_dist remains 0.
    // This logic is correct. If max_dist is 0, it means no 0s are "between" 1s,
    // or there are no 1s at all.
    // If all elements are 0, max_dist will be 0.
    // If all elements are 1, max_dist will be 0.
    // If there are 0s and 1s, max_dist will be > 0.

    int k = (max_dist + 1) / 2;

    std::cout << k << std::endl;

    std::vector<int> result_b(n);
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            result_b[i] = 1;
        } else { // a[i] == 0
            if (left_ones[i] <= k && right_ones[i] <= k) {
                result_b[i] = 1;
            } else {
                result_b[i] = 0;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result_b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> removal_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> removal_order[i];
        removal_order[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process vertices in reverse order of removal
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = removal_order[k_idx]; // The vertex being added back

        active_vertices[k] = true; // Mark k as active

        // Update shortest paths using k as an intermediate vertex
        // This is the core Floyd-Warshall step
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue; // Only consider active i
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue; // Only consider active j

                // Path i -> k -> j
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using -1 for infinity
                    if (dist[i][j] == -1 || dist[i][j] > dist[i][k] + dist[k][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }

        // After adding k and updating paths through k,
        // we also need to consider paths that use k as an endpoint
        // and other active vertices as intermediate nodes.
        // The previous loop handles k as an intermediate.
        // Now, we need to ensure all pairs (i,j) among currently active vertices
        // have their shortest paths updated, potentially using k as an endpoint
        // or other active vertices as intermediates.
        // The standard Floyd-Warshall structure is:
        // for k:
        //   for i:
        //     for j:
        //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        //
        // In our case, k is the *newly added* vertex.
        // The loops above correctly update paths *through* k.
        // However, we also need to update paths *to* k and *from* k
        // using other active vertices as intermediates.
        // This is implicitly handled by the structure:
        // When k is added, it becomes an active vertex.
        // The loops for i and j iterate over *all* currently active vertices.
        // So, when k is added, it's included in the set of possible i's and j's.
        // The inner loops (i, j) will consider all pairs of active vertices,
        // and the outer loop (k) will consider the newly added vertex as an intermediate.
        // This means the `dist` matrix will correctly reflect shortest paths
        // among all currently active vertices.

        // Re-run Floyd-Warshall for all active vertices, using the newly added k
        // as the outermost loop variable.
        // This ensures that paths like i -> ... -> k -> ... -> j are considered.
        // The previous triple loop already does this.
        // The key is that `k` is the *newest* vertex.
        // So, for any `i, j` that are currently active (including `k` itself),
        // `dist[i][j]` should be updated using `k` as an intermediate.
        // The loops above correctly implement this.
        //
        // Example:
        // Active: {A, B}
        // Add C. Now active: {A, B, C}
        // The loops will do:
        // for i in {A,B,C}:
        //   for j in {A,B,C}:
        //     dist[i][j] = min(dist[i][j], dist[i][C] + dist[C][j])
        // This updates paths that use C as an intermediate.
        //
        // What about paths like A -> B -> C?
        // When B was added, dist[A][C] would have been updated if A->B->C was shorter than A->C.
        // But C wasn't active then.
        //
        // The standard Floyd-Warshall algorithm is:
        // for k from 0 to n-1:
        //   for i from 0 to n-1:
        //     for j from 0 to n-1:
        //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        //
        // If we reverse the order of k, and only consider active i, j:
        // for k_new from n-1 down to 0: (k_new is the vertex being added)
        //   mark k_new as active
        //   for i from 0 to n-1:
        //     if i not active, continue
        //     for j from 0 to n-1:
        //       if j not active, continue
        //       dist[i][j] = min(dist[i][j], dist[i][k_new] + dist[k_new][j])
        //
        // This is correct. The `dist` matrix always holds the shortest paths
        // between any two currently active vertices, using only currently active vertices
        // as intermediates.

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before each removal)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric> // For std::iota

struct Child {
    int id;
    long long v;
    long long d;
    long long p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> treated_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        treated_children_ids.push_back(children[i].id);
        children[i].in_line = false; // Child i is now treated

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply v_cry from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply d_cry from previously leaving children
            children[j].p -= total_d_cry_from_leaving;

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_leaving += children[j].d;
            }
        }
    }

    std::cout << treated_children_ids.size() << "\n";
    for (size_t i = 0; i < treated_children_ids.size(); ++i) {
        std::cout << treated_children_ids[i] << (i == treated_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, LLONG_MAX); // Initialize with a very large value

    // Process operations in reverse to determine upper bounds for initial_a[i]
    // For type 2 operations, m_i = max(a_j + current_delta_j).
    // This implies a_j <= m_i - current_delta_j for all j in [l_i, r_i].
    // We want to find the smallest possible initial_a[i] that satisfies all conditions.
    // So, initial_a[i] should be min(initial_a[i], m_i - current_delta_j).
    std::vector<long long> current_delta(n, 0); // Total delta applied to each element from operations *after* current one
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // This operation will be applied *before* the current one in forward pass.
            // So, its effect needs to be subtracted from current_delta for elements in its range.
            // This is equivalent to saying that for elements in [l, r], their initial value
            // must be d less to achieve the same final value if this operation was not there.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] -= ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // If initial_a[i] is still LLONG_MAX, it means no type 2 operation constrained it.
    // We can set it to 0 (or any value within bounds) as it won't affect any max condition.
    // The problem states |a_i| <= 10^9. 0 is a safe choice.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == LLONG_MAX) {
            initial_a[i] = 0;
        }
    }

    // Verify the solution with the constructed initial_a
    std::vector<long long> a = initial_a;
    std::vector<long long> prefix_diff(n + 1, 0); // For efficient range updates

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            prefix_diff[ops[i].l] += ops[i].val;
            if (ops[i].r + 1 < n) {
                prefix_diff[ops[i].r + 1] -= ops[i].val;
            }
        } else { // type 2
            long long current_sum_delta = 0;
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_sum_delta += prefix_diff[j];
                max_val = std::max(max_val, initial_a[j] + current_sum_delta);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check if initial_a values are within bounds [-10^9, 10^9]
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] < -1000000000LL || initial_a[i] > 1000000000LL) {
            // This case should ideally not be reached if the problem constraints
            // and logic are correctly applied, as m_i is up to 5*10^7 and d_i up to 10^4.
            // The maximum possible delta is m * d_max = 5000 * 10^4 = 5*10^7.
            // So m_i - current_delta_j would be around 5*10^7 - (-5*10^7) = 10^8,
            // which is well within 10^9.
            // However, as a safeguard:
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all in subsequence 1).
    // All f(a_i, a_j) = a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: One element in one subsequence, rest in another.
    // This is equivalent to having one subsequence empty.
    // For example, a[0] in sub 1, a[1...n-1] in sub 2.
    // All pairs (a_i, a_j) will have a_i and a_j in the same subsequence,
    // except for pairs involving a[0] and any other element.
    // min_f = min(a[0].value + a[1].value + h, a[1].value + a[2].value)
    // max_f = max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value)
    // This is not quite right. If one subsequence is empty, then all pairs are in the same subsequence.
    // If one subsequence has only one element, say a_k, and all others are in the other subsequence.
    // Then pairs (a_k, a_j) for j!=k are different. Pairs (a_i, a_j) for i,j!=k are same.
    // The minimum possible f value is a[0].value + a[1].value.
    // The maximum possible f value is a[n-1].value + a[n-2].value + h (if a[n-1] and a[n-2] are different)
    // or a[n-1].value + a[n-2].value (if they are same).
    //
    // Let's consider the specific partition where a[0] is in sub 1, and all other a[i] (i>0) are in sub 2.
    // Pairs in sub 1: None.
    // Pairs in sub 2: (a[1], a[2]), ..., (a[n-2], a[n-1]).
    //   Min same: a[1].value + a[2].value
    //   Max same: a[n-2].value + a[n-1].value
    // Pairs across sub 1 and sub 2: (a[0], a[1]), ..., (a[0], a[n-1]).
    //   Min diff: a[0].value + a[1].value + h
    //   Max diff: a[0].value + a[n-1].value + h
    //
    // Overall min_f = min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    // Overall max_f = max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)
    //
    // This partition strategy is optimal when h is large.
    // The goodness for this partition is:
    // max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h) - min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    //
    // Let's simplify.
    // The minimum possible sum is a[0].value + a[1].value.
    // The maximum possible sum is a[n-1].value + a[n-2].value.
    //
    // If we put a[0] in sub 1 and all others in sub 2:
    // min_f = a[0].value + a[1].value + h (from (a[0], a[1]))
    // max_f = max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)
    //
    // If n=2, a[0] in sub 1, a[1] in sub 2. Only one pair (a[0], a[1]), different. f = a[0]+a[1]+h. Goodness = 0.
    // This is covered by the general logic.
    //
    // For n >= 3:
    // min_f_val = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    // max_f_val = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h);
    // goodness2 = max_f_val - min_f_val;
    //
    // This is the partition where a[0] is in one group, and all other elements are in the other group.
    // The minimum value of f will be either (a[0]+a[1]+h) or (a[1]+a[2]).
    // The maximum value of f will be either (a[n-2]+a[n-1]) or (a[0]+a[n-1]+h).
    //
    // Let's consider the specific partition: a[0] in group 1, a[1...n-1] in group 2.
    // The minimum possible f value is `a[0].value + a[1].value + h` (from (a[0], a[1]))
    // OR `a[1].value + a[2].value` (from (a[1], a[2]) if n >= 3).
    // So, `min_f = std::min(a[0].value + a[1].value + h, (n >= 3 ? a[1].value + a[2].value : 2e18));`
    // The maximum possible f value is `a[0].value + a[n-1].value + h` (from (a[0], a[n-1]))
    // OR `a[n-2].value + a[n-1].value` (from (a[n-2], a[n-1]) if n >= 3).
    // So, `max_f = std::max(a[0].value + a[n-1].value + h, (n >= 3 ? a[n-2].value + a[n-1].value : -1));`
    //
    // If n=2, a[0] in sub 1, a[1] in sub 2.
    // min_f = a[0].value + a[1].value + h
    // max_f = a[0].value + a[1].value + h
    // goodness = 0.
    //
    // If n >= 3:
    long long min_f_val_case2 = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    long long max_f_val_case2 = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h);
    long long goodness2 = max_f_val_case2 - min_f_val_case2;

    if (n == 2) { // Special case for n=2, goodness2 should be 0
        goodness2 = 0;
    }

    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks
    int h_idx = 0; // Current index for heads

    while (p_idx < m) {
        if (h_idx >= n) {
            return false; // No more heads, but still tracks to cover
        }

        // Find the first head that can potentially cover p[p_idx]
        // A head h[h_idx] can cover p[p_idx] if h[h_idx] - T <= p[p_idx]
        // We need to find a head such that its left-most reach (h_j - T) is <= p[p_idx]
        // And we want to use the "best" head for p[p_idx]
        // The best head is one that can reach p[p_idx] and extends furthest to the right.

        // Skip heads that are too far to the left to reach p[p_idx]
        // i.e., h[h_idx] + T < p[p_idx]
        // This is not quite right. We need to find a head that can cover p[p_idx].
        // A head h_j can cover p_k if p_k is in [h_j - T, h_j + T].
        // We need to cover p_idx.
        // Find the first head h_j such that h_j + T >= p[p_idx].
        // If h_j - T > p[p_idx], then this head is too far to the right to cover p[p_idx]
        // and all subsequent heads will also be too far.
        // So we need to find a head h_j such that h_j - T <= p[p_idx] <= h_j + T.

        // Let's re-think the greedy strategy.
        // We need to cover p[p_idx].
        // We use the first available head h[h_idx].
        // If h[h_idx] is too far to the right (h[h_idx] - T > p[p_idx]), then this head cannot cover p[p_idx].
        // Since h is sorted, no subsequent head can cover p[p_idx] either. So it's impossible.
        if (h[h_idx] - T > p[p_idx]) {
            return false;
        }

        // If h[h_idx] can cover p[p_idx] (i.e., h[h_idx] - T <= p[p_idx]),
        // then this head can cover all tracks up to h[h_idx] + T.
        // We greedily use this head to cover as many subsequent tracks as possible.
        long long current_head_reach = h[h_idx] + T;

        // Advance p_idx as long as p[p_idx] is within the reach of the current head.
        while (p_idx < m && p[p_idx] <= current_head_reach) {
            p_idx++;
        }

        // Move to the next head for the remaining tracks.
        h_idx++;
    }

    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible time: distance from first head to last track, or last head to first track.
    // A loose upper bound: (max_p - min_p) + (max_h - min_h)
    // A tighter upper bound: max(abs(p_i - h_j))
    // Max possible value for p_i or h_i is 10^10. So max diff is 10^10.
    // If n=1, m=1, h={1}, p={10^10}, time is 10^10 - 1.
    // If n=1, m=2, h={10^10/2}, p={1, 10^10}, time is 10^10/2.
    // So 10^10 is a safe upper bound.
    long long high = 20000000000LL; // 2 * 10^10, a sufficiently large upper bound
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for x and y to prevent overflow, as y can be large.
// x can also become large or small, potentially exceeding int limits if n is small and a_x is large.
// The problem statement says a_i <= 10^9, n <= 2*10^5.
// y can accumulate up to n * 2 * 10^9, which is 2*10^5 * 2*10^9 = 4*10^14, requiring long long.
// x can go up to n + a_x, which is 2*10^5 + 10^9, also requiring long long.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_values stores a_2, ..., a_n.
    // We will use 0-based indexing for convenience, so a_values[k] corresponds to a_{k+2}.
    // The actual array A for simulation will be 1-indexed.
    std::vector<long long> a_values(n - 1);
    for (int i = 0; i < n - 1; ++i) {
        std::cin >> a_values[i];
    }

    // dp[i] will store the result for starting x = i+1.
    // dp[i] = {final_x, final_y} if terminates, or special value for non-termination.
    // We need to store the final x and y to chain computations.
    // dp[i] stores {final_x, final_y} when starting with x=i+1, y=0.
    // The values in dp will be for the state *after* the two steps (step 2 and step 3)
    // that start with x=i+1.
    // If it terminates during step 2 or 3, we store the final y and a special x.
    // Let's use a pair: {final_x_after_two_steps, final_y_after_two_steps}.
    // If it terminates, final_x_after_two_steps will be 0 or n+1 (or some other indicator).
    // A better approach for DP: dp[i] stores {final_x, final_y} if starting at x=i and y=0,
    // and performing one full cycle (step 2 then step 3).
    // If it terminates *during* this cycle, we need to store the y value at termination.
    // Let's define dp[i] as the pair {next_x, total_y_added} if starting at x=i and y=0,
    // and completing one full cycle. If it terminates, next_x will be 0 or n+1, and total_y_added
    // will be the final y.

    // dp_results[i] will store the final y for starting a_1 = i+1.
    // This is what we need to output.
    std::vector<long long> dp_results(n); // dp_results[i] for a_1 = i+1

    // For each possible starting value of a_1 (from 1 to n-1)
    for (long long initial_a1 = 1; initial_a1 < n; ++initial_a1) {
        long long current_x = 1;
        long long current_y = 0;
        long long a_val_at_x;

        // Simulate the program
        while (true) {
            // Determine a_val_at_x
            if (current_x == 1) {
                a_val_at_x = initial_a1;
            } else if (current_x >= 2 && current_x <= n) {
                a_val_at_x = a_values[current_x - 2]; // a_values is 0-indexed for a_2...a_n
            } else {
                // This case should be caught by the termination check before this point
                // if current_x was already out of bounds.
                // If we reach here, it means current_x was valid, but a_val_at_x is needed.
                // This implies an error in logic or problem understanding if current_x is out of bounds here.
                // For safety, break.
                break;
            }

            // Step 2: x = x + a_x, y = y + a_x
            long long next_x_step2 = current_x + a_val_at_x;
            long long next_y_step2 = current_y + a_val_at_x;

            if (next_x_step2 <= 0 || next_x_step2 > n) {
                dp_results[initial_a1 - 1] = next_y_step2;
                break; // Terminate
            }

            // Step 3: x = x - a_x, y = y + a_x
            long long next_x_step3 = next_x_step2 - a_val_at_x;
            long long next_y_step3 = next_y_step2 + a_val_at_x;

            if (next_x_step3 <= 0 || next_x_step3 > n) {
                dp_results[initial_a1 - 1] = next_y_step3;
                break; // Terminate
            }

            // Check for cycles (non-termination)
            // The state is (current_x, current_y).
            // If we encounter a state (x, y) that we've seen before, it's a cycle.
            // However, the problem states "it may never terminate".
            // The values of x and y are always increasing or decreasing in a specific pattern.
            // x changes by +A[x] then -A[x]. The net change in x is 0 if A[x] is constant.
            // But A[x] changes as x changes.
            // The total y always increases. So, if x repeats, y must be strictly increasing.
            // This means it cannot enter a cycle in (x,y) state.
            // It can only enter a cycle in x if y is ignored.
            // If x repeats, and y is strictly increasing, it means it will eventually exceed
            // the maximum possible y value (long long) or run indefinitely.
            // The problem implies that if it doesn't terminate by going out of bounds, it's non-terminating.
            // The maximum number of steps before termination or cycle detection is N.
            // If x repeats, it means we are in an infinite loop.
            // We can use a visited array for x values.
            // Since N is up to 2*10^5, a visited array for x is feasible.
            // However, x can go beyond N or below 1 before terminating.
            // The problem states "If, after any step, x <= 0 or x > n, the program immediately terminates."
            // This means x is always within [1, n] *before* the operations.
            // So, we only need to check for cycles within x in [1, n].
            // If x repeats, and y is strictly increasing, it's an infinite loop.
            // We need to detect this.

            // A simple way to detect non-termination is to limit the number of iterations.
            // The maximum path length without repeating an x value (1 to n) is n.
            // Each step involves two operations. So, 2*n operations.
            // If it goes beyond 2*n operations, it must be in a cycle.
            // A more robust way is to use dynamic programming with memoization.
            // Let's define dp_memo[x] as the result of starting from x.
            // dp_memo[x] = {final_x_after_cycle, total_y_added_in_cycle}
            // If dp_memo[x] is already being computed (recursion stack), it's a cycle.

            // Let's use a DP approach.
            // dp_memo[k] stores {final_x, final_y_added} if starting at x=k+1, y=0.
            // This is for the *next* state after one full (step 2, step 3) cycle.
            // If it terminates, final_x will be 0 or n+1, and final_y_added is the total y.
            // If it's an infinite loop, final_x will be -1.
            // We need to compute this for each possible starting x from 1 to n.
            // The values of a_x are fixed for x >= 2. Only a_1 changes.

            // The current simulation approach is too slow (O(N^2) in worst case).
            // N = 2*10^5, N^2 = 4*10^10. This will TLE.

            // We need to use DP.
            // Let's define `memo[k]` as a pair `{next_x, y_increment}` for starting at `x=k`.
            // `next_x` is the value of `x` after one full (step 2, step 3) cycle.
            // `y_increment` is the total `y` added during that cycle.
            // If `x` goes out of bounds during the cycle, `next_x` will be 0 or `n+1`,
            // and `y_increment` will be the final `y`.
            // If it's an infinite loop, `next_x` will be a special value like -1.

            // `memo` array for `x` from 1 to `n`.
            // `memo[k]` stores `{next_x, y_increment}` for starting `x=k`.
            // Initialize `memo` with a sentinel value, e.g., `{0, 0}` meaning not computed.
            // `visited` array to detect cycles during computation.

            // The problem is that `a_1` changes. So `memo` depends on `a_1`.
            // This means we can't precompute `memo` for all `x` from 1 to `n` once.
            // We need to compute `memo` for each `initial_a1`.
            // This still leads to O(N^2) if each path is long.

            // The key observation for optimization is that `a_x` is fixed for `x >= 2`.
            // Only `a_1` changes.
            // This means that if `x` ever becomes `x >= 2`, its future path is independent of `a_1`.
            // We can precompute `memo[k]` for `k` from 2 to `n`.

            // Let `memo[k]` be a pair `{final_x, total_y_added}` if starting at `x=k` and `y=0`,
            // and continuing until `x` goes out of bounds or `x` becomes 1.
            // If `x` becomes 1, `final_x` will be 1, and `total_y_added` is the sum.
            // If `x` goes out of bounds, `final_x` will be 0 or `n+1`, and `total_y_added` is the final `y`.
            // If it's an infinite loop *without* touching `x=1`, `final_x` will be -1.

            // `memo` stores `std::pair<long long, long long>`
            // `memo[k]` for `x=k+1`. Size `n`.
            std::vector<std::pair<long long, long long>> memo(n + 1, {0, 0}); // {next_x, y_added}
            std::vector<bool> visited_in_path(n + 1, false); // To detect cycles during DFS

            // Function to compute memo[k] for k >= 2
            // Returns {final_x, total_y_added}
            // final_x: 0 or n+1 if terminates, 1 if returns to x=1, -1 if infinite loop
            // total_y_added: sum of a_x values
            auto compute_memo = [&](int start_x, auto& self) -> std::pair<long long, long long> {
                if (start_x <= 0 || start_x > n) {
                    return {start_x, 0}; // Already out of bounds
                }
                if (start_x == 1) {
                    return {1, 0}; // Reached x=1, path depends on a_1
                }
                if (memo[start_x].first != 0 || memo[start_x].second != 0) {
                    // Already computed or currently being computed (cycle detection)
                    if (visited_in_path[start_x]) {
                        return {-1, 0}; // Infinite loop detected
                    }
                    return memo[start_x];
                }

                visited_in_path[start_x] = true;

                long long current_x_local = start_x;
                long long current_y_local_added = 0;

                long long a_val = a_values[current_x_local - 2]; // a_values is 0-indexed for a_2...a_n

                // Step 2
                long long next_x_step2 = current_x_local + a_val;
                long long next_y_step2 = current_y_local_added + a_val;

                if (next_x_step2 <= 0 || next_x_step2 > n) {
                    visited_in_path[start_x] = false;
                    memo[start_x] = {next_x_step2, next_y_step2};
                    return memo[start_x];
                }

                // Step 3
                long long next_x_step3 = next_x_step2 - a_val;
                long long next_y_step3 = next_y_step2 + a_val;

                if (next_x_step3 <= 0 || next_x_step3 > n) {
                    visited_in_path[start_x] = false;
                    memo[start_x] = {next_x_step3, next_y_step3};
                    return memo[start_x];
                }

                // Continue from next_x_step3
                std::pair<long long, long long> res = self(next_x_step3, self);

                visited_in_path[start_x] = false;

                if (res.first == -1) { // Infinite loop
                    memo[start_x] = {-1, 0};
                } else if (res.first == 1) { // Reached x=1
                    memo[start_x] = {1, next_y_step3 + res.second};
                } else { // Terminated or continued out of bounds
                    memo[start_x] = {res.first, next_y_step3 + res.second};
                }
                return memo[start_x];
            };

            // Precompute memo for x from 2 to n
            for (int k = 2; k <= n; ++k) {
                if (memo[k].first == 0 && memo[k].second == 0) { // Not computed yet
                    compute_memo(k, compute_memo);
                }
            }

            // Now simulate for the current initial_a1
            current_x = 1;
            current_y = 0;
            bool terminated = false;

            // Use a visited array for the current path to detect cycles involving x=1
            std::vector<bool> current_path_visited(n + 1, false);

            while (true) {
                if (current_x <= 0 || current_x > n) {
                    dp_results[initial_a1 - 1] = current_y;
                    terminated = true;
                    break;
                }

                if (current_path_visited[current_x]) {
                    dp_results[initial_a1 - 1] = -1; // Infinite loop
                    terminated = true;
                    break;
                }
                current_path_visited[current_x] = true;

                if (current_x == 1) {
                    a_val_at_x = initial_a1;
                } else { // current_x >= 2
                    // We can use the precomputed memo table
                    std::pair<long long, long long> res = memo[current_x];
                    if (res.first == -1) { // Infinite loop
                        dp_results[initial_a1 - 1] = -1;
                        terminated = true;
                        break;
                    } else if (res.first == 1) { // Returns to x=1
                        current_x = 1;
                        current_y += res.second;
                        // Continue loop, current_path_visited[1] will be checked
                        continue;
                    } else { // Terminates
                        dp_results[initial_a1 - 1] = current_y + res.second;
                        terminated = true;
                        break;
                    }
                }

                // If current_x is 1, we perform the two steps
                // Step 2
                long long next_x_step2 = current_x + a_val_at_x;
                long long next_y_step2 = current_y + a_val_at_x;

                if (next_x_step2 <= 0 || next_x_step2 > n) {
                    dp_results[initial_a1 - 1] = next_y_step2;
                    terminated = true;
                    break;
                }

                // Step 3
                long long next_x_step3 = next_x_step2 - a_val_at_x;
                long long next_y_step3 = next_y_step2 + a_val_at_x;

                if (next_x_step3 <= 0 || next_x_step3 > n) {
                    dp_results[initial_a1 - 1] = next_y_step3;
                    terminated = true;
                    break;
                }

                current_x = next_x_step3;
                current_y = next_y_step3;
            }
        }
    }

    for (int i = 0; i < n - 1; ++i) {
        std::cout << dp_results[i] << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // min_r_for_l[i] stores the minimum r (0-indexed) such that the substring s[i...r]
    // contains a triple pattern. If no such r exists, it's n.
    // This is equivalent to the smallest rightmost index of a triple pattern
    // whose leftmost index is >= i.
    std::vector<int> min_r_for_l(n + 1, n);

    // Iterate through all possible starting positions x for a triple pattern
    // (0-indexed: s[x], s[x+k], s[x+2k])
    for (int x = 0; x < n; ++x) {
        // Iterate through possible values of k.
        // The maximum k is such that x + 2k < n.
        // So, 2k < n - x => k < (n - x) / 2.
        // Since k >= 1, we start k from 1.
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a triple pattern: s[x], s[x+k], s[x+2k]
                // The rightmost index of this pattern is x + 2k.
                // This pattern "covers" any substring s[l...r] where l <= x and r >= x + 2k.

                // We are interested in the smallest r for a given l.
                // For any l' from 0 to x, this pattern provides a valid r = x + 2k.
                // We want to update min_r_for_l[l'] with min(current_value, x + 2k).
                // Since we iterate x from 0 to n-1, and k from 1 upwards,
                // x + 2k will be increasing.
                // However, we need to find the *minimum* x+2k for any x' <= x.
                // This means for each l, we need the smallest x+2k such that x <= l.
                // This is not quite right.
                // The definition of min_r_for_l[i] is:
                // min_r_for_l[i] = min { x+2k | x >= i and s[x]=s[x+k]=s[x+2k] }
                // This is what we need to compute.

                // For the current triple (x, k), the rightmost index is x + 2k.
                // This triple starts at x.
                // So, for any l such that l <= x, this triple is a candidate.
                // We want to find the smallest x+2k for each l.
                // This means min_r_for_l[x] should be updated with min(min_r_for_l[x], x + 2k).
                // And then, min_r_for_l[x-1] = min(min_r_for_l[x-1], min_r_for_l[x]), etc.
                // This is a suffix minimum calculation.

                // Update min_r_for_l[x] with the current triple's rightmost index.
                min_r_for_l[x] = std::min(min_r_for_l[x], x + 2 * k);

                // Optimization: If k is large, say k >= 7, then x+2k is at least x+14.
                // The problem constraints on n (300,000) mean that k can be up to ~150,000.
                // However, if k is large, the indices x, x+k, x+2k are far apart.
                // The problem statement implies that the maximum distance between s_x and s_{x+2k}
                // is not explicitly limited beyond n.
                // But for small k, the patterns are dense.
                // For k >= 7, the indices are x, x+k, x+2k.
                // If s[x] == s[x+k] == s[x+2k], then for any l <= x, r >= x+2k, the pair (l,r) is good.
                // The maximum k we need to check is small.
                // If k >= 7, then x+2k - x = 2k >= 14.
                // If there is a triple with k >= 7, then there must be a triple with k < 7
                // that covers the same or a smaller range.
                // Consider s_x = s_{x+k} = s_{x+2k}.
                // If k >= 7, then x+2k - x >= 14.
                // Any substring of length 14 or more must contain a triple if it's "bad".
                // This is a known property for binary strings.
                // A binary string of length 7 or more must contain a triple of the form
                // s_i = s_{i+k} = s_{i+2k} for k in {1,2,3}.
                // This is a known result from combinatorics on words (e.g., related to square-free words).
                // Specifically, any binary string of length 7 or more must contain a "square" (xx) or "cube" (xxx).
                // A "cube" is s_i = s_{i+k} = s_{i+2k}.
                // A "square" is s_i = s_{i+k}.
                // The problem asks for s_x = s_{x+k} = s_{x+2k}.
                // This is a "cube" of period k.
                // It is known that any binary string of length 7 contains a cube of period 1, 2, or 3.
                // So, we only need to check k up to 3.
                // If a triple exists with k > 3, then there must be one with k <= 3
                // that starts at an earlier or same position and ends at an earlier or same position.
                // This is a strong claim. Let's verify.
                // Example: 010101. n=6.
                // x=0, k=1: s[0]=0, s[1]=1, s[2]=0. No.
                // x=0, k=2: s[0]=0, s[2]=0, s[4]=0. Yes! (0,2,4). min_r_for_l[0] = min(n, 4) = 4.
                // x=1, k=1: s[1]=1, s[2]=0, s[3]=1. No.
                // x=1, k=2: s[1]=1, s[3]=1, s[5]=1. Yes! (1,3,5). min_r_for_l[1] = min(n, 5) = 5.
                // x=2, k=1: s[2]=0, s[3]=1, s[4]=0. No.
                // x=3, k=1: s[3]=1, s[4]=0, s[5]=1. No.
                // Max k to check:
                // If k > 3, then 2k > 6.
                // If a string has length >= 7, it must contain a cube of period 1, 2, or 3.
                // This means if a string $S$ contains $s_x=s_{x+k}=s_{x+2k}$ for $k>3$,
                // then $S$ must also contain $s_y=s_{y+j}=s_{y+2j}$ for $j \in \{1,2,3\}$
                // such that $y \le x$ and $y+2j \le x+2k$.
                // This is a known result from combinatorics on words.
                // So, we only need to check k up to 3.
                if (k > 3) break; // Optimization: only check k=1, 2, 3
            }
        }
    }

    // Compute suffix minimums for min_r_for_l.
    // min_r_for_l[i] should store the minimum r for any triple starting at or after i.
    // i.e., min_r_for_l[i] = min(min_r_for_l[i], min_r_for_l[i+1])
    for (int i = n - 2; i >= 0; --i) {
        min_r_for_l[i] = std::min(min_r_for_l[i], min_r_for_l[i + 1]);
    }

    // Now, for each starting position l (0-indexed),
    // min_r_for_l[l] gives the smallest r (0-indexed) such that s[l...r] contains a triple.
    // If min_r_for_l[l] == n, it means no triple starts at or after l.
    // A pair (l, r) is "bad" if r < min_r_for_l[l].
    // For a fixed l, the number of bad r's is (min_r_for_l[l] - 1) - l + 1 = min_r_for_l[l] - l.
    // These are r values from l to min_r_for_l[l] - 1.
    // The number of such r's is min_r_for_l[l] - l.
    // We sum this over all l.
    for (int l = 0; l < n; ++l) {
        bad_pairs += (min_r_for_l[l] - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

