        // All numbers are distinct and within [1, 4n].
        // The smallest is 2n, largest is 4n-2. Both are <= 4n.

        // Let's try a simpler sequence: 2n, 2n+2, ..., 4n-2.
        // This is n numbers.
        // For n=2: 2*2=4, 2*3=6. Output: 4 6. Matches example (order doesn't matter).
        // For n=3: 2*3=6, 2*4=8, 2*5=10. Output: 6 8 10. Example: 4 6 10.
        // My sequence for n=3: {6, 8, 10}.
        // (6,8): gcd=2. No division. OK.
        // (6,10): gcd=2. No division. OK.
        // (8,10): gcd=2. No division. OK.
        // This also works.

        // For n=4: 2*4=8, 2*5=10, 2*6=12, 2*7=14. Output: 8 10 12 14. Matches example.

        // So the sequence 2n, 2n+2, ..., 4n-2 works.
        // This is equivalent to 2 * i for i from n to 2n-1.
        for (int i = n; i < 2 * n; ++i) {
            std::cout << 2 * i << (i == 2 * n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

