int main() {
    // Optimize C++ standard streams for faster input/output.
    // This unties cin/cout from stdio and prevents flushing cout before cin.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a vector to store prices.
        // Using a fixed-size array or dynamically allocated array could also work,
        // but vector is convenient and safe.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n <= 1) {
            // If there's only one day or no days, no price can be "bad"
            // because there are no later days.
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_price_so_far with the price on the last day.
        // This variable will store the minimum price encountered
        // from the current day 'i' to the end of the array (n-1).
        int min_price_suffix = a[n - 1];

        // Iterate from the second to last day backwards to the first day.
        // The last day (n-1) can never be bad, so we start from n-2.
        for (int i = n - 2; i >= 0; --i) {
            // If the current price a[i] is greater than the minimum price
            // found in the days after it (min_price_suffix), then a[i] is a bad price.
            if (a[i] > min_price_suffix) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_price_suffix, it means a[i]
                // is either equal to or less than min_price_suffix.
                // In this case, a[i] becomes the new minimum price for the suffix
                // starting from day 'i'.
                min_price_suffix = a[i];
            }
        }

        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0; // Indicate successful execution
}

