#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences: 1, 2, ..., k
    // We can achieve this by alternating between left and right pointers
    // For example, if k=3, we use numbers 1, 2, 3, 4.
    // Sequence: 1, 4, 2, 3
    // Differences: |1-4|=3, |4-2|=2, |2-3|=1. Distinct: {1,2,3}
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left
            p[i] = left;
            left++;
        } else { // Odd index, take from right
            p[i] = right;
            right--;
        }
    }

    // After generating k distinct differences, the remaining numbers
    // should be filled in increasing order to only generate difference 1.
    // The numbers used so far are 1, ..., left-1 and right+1, ..., k+1.
    // The next available number is 'left' (which is now right+1 if k is odd, or left if k is even).
    // Or more simply, the next available number is the one that was not used in the alternating sequence.
    // The numbers used are 1, ..., k+1.
    // The alternating sequence uses all numbers from 1 to k+1 exactly once.
    // So, the next available number is k+2.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // Fill with remaining numbers in increasing order
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i from 1 to n-1
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, then p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i was not seen before as a prefix max.
                // But it's good to check for robustness.
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else { // q_i == q_{i-1}
            // If q_i is not a new maximum, p_i must be some unused number less than q_i.
            // To maximize chances of finding a solution, we should pick the smallest available number.
            // This is because larger numbers might be needed later for new maximums.
            // However, the problem asks for *any* suitable permutation.
            // A greedy approach: pick the largest available number less than q_i.
            // This leaves smaller numbers for later, which might be useful if q_i remains the same for a long time.
            // Let's try to pick the largest available number that is not q_i and has not been used.
            // The numbers available are 1 to n.
            // We need to find an unused number x such that x < q_i.
            // The largest such number is q_i - 1, then q_i - 2, etc.
            // We need to find the largest number `val` such that `1 <= val < q_i` and `val` is not in `used_numbers`.

            int current_val = q[i] - 1;
            while (current_val >= 1 && used_numbers.count(current_val)) {
                current_val--;
            }

            if (current_val < 1) { // No suitable number found
                possible = false;
                break;
            }
            p[i] = current_val;
            used_numbers.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        // Final check: ensure all p_i are distinct and within [1, n]
        // And that the constructed p generates the given q.
        // The construction ensures p_i are distinct and within [1, n] if possible=true.
        // The construction also ensures q_i conditions are met.
        // The only remaining check is if any p_i is outside [1, n], which current_val < 1 handles.
        // And if all numbers 1..n are used, which is not strictly required, but all p_i must be distinct.

        // Let's verify the constructed p generates the given q.
        // This is implicitly handled by the construction logic.
        // The only way it could fail is if we picked a number that was too small for a future q_i,
        // but the problem states "any possible suitable permutation".
        // The greedy choice of picking the largest available number less than q_i for q_i == q_{i-1}
        // is a common strategy for such problems.

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

