#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams 'k' is limited by three factors:
        // 1. The total number of students available: 3 * k <= c + m + x
        // 2. The number of coders available: k <= c
        // 3. The number of mathematicians available: k <= m
        //
        // Combining 2 and 3, k <= min(c, m).
        // So, k must be less than or equal to min(c, m, (c + m + x) / 3).
        //
        // Let's find the maximum possible k.
        // We can use binary search for k.
        // The lower bound for k is 0.
        // The upper bound for k is min(c, m, (c + m + x) / 3).
        // A safe upper bound for binary search is 10^8 (max c, m, x) or (c+m+x)/3.
        // Since c, m, x <= 10^8, (c+m+x)/3 can be up to 10^8.
        // So, max_k = 10^8 is a good upper bound.

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // A tighter upper bound
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // This uses 'mid' coders and 'mid' mathematicians.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining unspecialized: x
            // Total remaining students: (c - mid) + (m - mid) + x
            //
            // Each team needs 3 members. We've already accounted for 1 coder and 1 mathematician.
            // So, each team needs 1 more student.
            // For 'mid' teams, we need 'mid' additional students.
            // These additional students can come from remaining coders, mathematicians, or unspecialized.
            //
            // Condition: The total number of remaining students must be at least 'mid'.
            // (c - mid) + (m - mid) + x >= mid
            // c + m + x - 2 * mid >= mid
            // c + m + x >= 3 * mid
            // This is equivalent to (c + m + x) / 3 >= mid, which is already part of our high bound.
            //
            // The crucial part is that we must have enough coders and mathematicians for the 'mid' teams.
            // This is covered by mid <= c and mid <= m.
            //
            // So, the condition for 'mid' teams to be possible is simply:
            // mid <= c
            // mid <= m
            // 3 * mid <= c + m + x
            //
            // All these conditions are implicitly handled by our choice of 'high' and the binary search logic.
            // If we can form 'mid' teams, we try for more.
            // If we cannot form 'mid' teams, we try for fewer.

            // The check function for binary search:
            // Can we form 'k' teams?
            // Yes, if we have enough coders (c >= k), enough mathematicians (m >= k),
            // AND enough total students for the remaining 'k' slots (c-k + m-k + x >= k).
            // The last condition simplifies to c + m + x >= 3k.
            // So, we just need to check if mid <= c, mid <= m, and 3 * mid <= c + m + x.
            // All these are already incorporated into the initial `high` calculation.
            // So, if mid is within the bounds, it's a valid candidate.
            // The binary search is effectively finding the maximum value that satisfies these.

            // The condition for 'mid' teams to be possible is:
            // 1. We have at least 'mid' coders: c >= mid
            // 2. We have at least 'mid' mathematicians: m >= mid
            // 3. We have enough total students for 'mid' teams: c + m + x >= 3 * mid
            //
            // If all these are true, then 'mid' teams are possible.
            // We try to find a larger number of teams.
            if (c >= mid && m >= mid && (c + m + x) >= 3 * mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

