            break;
        }

        if (c == '(') {
            // If we still need opening brackets and adding one won't make it impossible to close later
            // The condition `open_count < k / 2` ensures we don't take too many opening brackets.
            // The condition `balance + 1 <= k / 2` is implicitly handled by `open_count < k / 2`
            // because `balance` can't exceed `open_count`.
            if (open_count < k / 2) {
                result += c;
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // If we still need closing brackets and there's an open bracket to match it
            if (close_count < k / 2 && balance > 0) {
                result += c;
                close_count++;
                balance--;
            }
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index 'i' such that a[i] < a[i+1]
    // This marks the end of the non-increasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is non-increasing.
    // If i is 0, the whole array is non-increasing.

    // Find the rightmost index 'j' such that a[j] > a[j+1]
    // This marks the end of the non-decreasing suffix
    int j = i; // Start search from 'i'
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now, a[j...n-1] is a "good" candidate suffix.
    // The prefix to remove has length 'j'.

    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        std::string s;
        std::cin >> s;
        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        int horizontal_moves = std::min(counts['L'], counts['R']);
        int vertical_moves = std::min(counts['U'], counts['D']);

        if (horizontal_moves == 0 && vertical_moves == 0) {
            std::cout << 0 << "\n\n";
        } else if (horizontal_moves == 0) { // Only vertical moves possible
            std::cout << 2 << "\n";
            std::cout << "UD\n";
        } else if (vertical_moves == 0) { // Only horizontal moves possible
            std::cout << 2 << "\n";
            std::cout << "LR\n";
        } else {
            std::cout << 2 * (horizontal_moves + vertical_moves) << "\n";
            for (int i = 0; i < horizontal_moves; ++i) {
                std::cout << 'L';
            }
            for (int i = 0; i < vertical_moves; ++i) {
                std::cout << 'U';
            }
            for (int i = 0; i < horizontal_moves; ++i) {
                std::cout << 'R';
            }
            for (int i = 0; i < vertical_moves; ++i) {
                std::cout << 'D';
            }
            std::cout << "\n";
        }
    }
    return 0;
}

