        pos[p[i]] = i;
    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For current m, we need to check if the numbers 1 to m
        // form a contiguous subsegment in p.
