#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[left_ptr] <= d

    for (int left_ptr = 0; left_ptr < n; ++left_ptr) {
        // Move right_ptr forward until x[right_ptr] - x[left_ptr] > d
        // or until right_ptr reaches the end of the array.
        // The condition x[right_ptr] - x[left_ptr] <= d means x[right_ptr] <= x[left_ptr] + d.
        while (right_ptr < n && x[right_ptr] <= x[left_ptr] + d) {
            right_ptr++;
        }
        // At this point, all points from x[left_ptr] to x[right_ptr - 1] satisfy the condition
        // that their distance from x[left_ptr] is <= d.
        // The number of such points (including x[left_ptr] itself) is (right_ptr - 1) - left_ptr + 1 = right_ptr - left_ptr.
        // Let k = right_ptr - left_ptr. These are the points x[left_ptr], ..., x[right_ptr-1].
        // We need to choose 2 more points from the remaining k-1 points (i.e., from x[left_ptr+1], ..., x[right_ptr-1]).
        // The number of ways to choose 2 points from k-1 points is (k-1) * (k-2) / 2.
        // This is equivalent to choosing 3 points from k points, where x[left_ptr] is one of them.
        // The number of points available for selection (including x[left_ptr]) is `right_ptr - left_ptr`.
        // Let this be `num_available_points`.
        // If `num_available_points` is less than 3, we cannot form a triplet.
        // Otherwise, we can choose 2 additional points from the `num_available_points - 1` points
        // that are to the right of `x[left_ptr]` and satisfy the distance condition.
        // The number of ways to choose 2 points from `m` points is `m * (m - 1) / 2`.
        // Here, `m = num_available_points - 1 = (right_ptr - left_ptr) - 1`.

        long long num_points_in_range = right_ptr - left_ptr;
        if (num_points_in_range >= 3) {
            // We have num_points_in_range points (x[left_ptr]...x[right_ptr-1])
            // from which we can choose 3 points.
            // The number of ways to choose 3 points from N points is N * (N-1) * (N-2) / 6.
            // However, we are fixing x[left_ptr] as the leftmost point.
            // So we need to choose 2 more points from the remaining (num_points_in_range - 1) points.
            // The number of ways to choose 2 points from (num_points_in_range - 1) points is
            // (num_points_in_range - 1) * (num_points_in_range - 2) / 2.
            long long m = num_points_in_range - 1;
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

