struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A_sorted(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A_sorted[i].value;
        A_sorted[i].original_index = i;
    }

    std::vector<ElementB> B_sorted(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B_sorted[i].value;
        B_sorted[i].original_index = i;
    }

    std::sort(A_sorted.begin(), A_sorted.end(), compareA);
    std::sort(B_sorted.begin(), B_sorted.end(), compareB);

    std::vector<long long> result_A_prime(m);

    // The optimal strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // This means A_sorted[i] should be paired with B_sorted[i].
    // However, the output needs to be in the original order of B.
    // So, if B_sorted[i] was originally at index B_sorted[i].original_index,
    // then A_sorted[i].value should be placed at result_A_prime[B_sorted[i].original_index].
    for (int i = 0; i < m; ++i) {
        result_A_prime[B_sorted[i].original_index] = A_sorted[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_A_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

