// Function to determine if Box 1 can be the special box
// Box 1: (-inf, -1]
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Total number of toys
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // If only one toy, it must be in Box 1
    if (total_toys == 1) {
        return A == 1;
    }

    // To end up in Box 1, the final toy must be negative and have magnitude >= 1.

    // Condition for negative sign:
    // The number of negative toys (A + B) must be odd.
    // If (A + B) is even, the final toy will be positive.
    if ((A + B) % 2 == 0) {
        return false;
    }

    // Condition for magnitude >= 1:
    // We need at least one toy with magnitude >= 1 (from Box 1 or Box 4)
    // OR we need to be able to generate a magnitude >= 1 from toys with magnitude < 1.

    // Case 1: There is at least one toy with magnitude >= 1 initially (A > 0 or D > 0).
    // If A > 0 or D > 0, we can always ensure the final magnitude is >= 1.
    // We can pick a toy with magnitude >= 1 and multiply it by other toys.
    // If we have a toy with magnitude >= 1, say X, and a toy with magnitude < 1, say Y.
    // We can choose X to be very large (e.g., -1000 or 1000) and Y to be very small (e.g., -0.001 or 0.001).
    // Then X*Y can be < 1 in magnitude.
    // However, we can also choose X to be just -1 or 1, and Y to be -0.5 or 0.5.
    // Then X*Y will be -0.5 or 0.5.
    // The key is that we can control the magnitude.
    // If we have A > 0 or D > 0, we have at least one "strong" toy.
    // We can always make sure that the final product has magnitude >= 1.
    // For example, if we have a toy X from Box 1 or Box 4, and other toys Y1, Y2, ..., Yk.
    // We can multiply all Y_i together first to get Y_prod.
    // Then multiply X by Y_prod.
    // If Y_prod has magnitude < 1, then X * Y_prod might have magnitude < 1.
    // But we can choose the values.
    // If A > 0 or D > 0, we can always pick a toy with magnitude >= 1.
    // Let's say we have a toy X with |X| >= 1.
    // We can choose X to be very large (e.g., 1000).
    // We can choose all other toys to be very small (e.g., 0.001).
    // The product of all other toys will be very small.
    // Then X * (product of others) will still be very large.
    // So, if A > 0 or D > 0, we can always achieve magnitude >= 1.
    if (A > 0 || D > 0) {
        return true;
    }

    // Case 2: All initial toys have magnitude < 1 (A = 0 and D = 0).
    // This means all toys are from Box 2 or Box 3.
    // B + C > 0 (since total_toys > 0)
    // The product of any number of toys from Box 2 or Box 3 will always have magnitude < 1.
    // e.g., (-0.5) * (0.5) = -0.25. Magnitude is 0.25 < 1.
    // So, if A = 0 and D = 0, it's impossible to get a final toy with magnitude >= 1.
    return false;
}

// Function to determine if Box 2 can be the special box
// Box 2: (-1, 0)
bool can_be_box2(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false;

    // If only one toy, it must be in Box 2
    if (total_toys == 1) {
        return B == 1;
    }

    // To end up in Box 2, the final toy must be negative and have magnitude < 1.

    // Condition for negative sign:
    // The number of negative toys (A + B) must be odd.
    if ((A + B) % 2 == 0) {
        return false;
    }

    // Condition for magnitude < 1:
    // We need to be able to make the final magnitude < 1.
    // This is always possible unless all toys have magnitude >= 1 (A=0, B=0, C=0, D>0).
    // If we have at least one toy with magnitude < 1 (B > 0 or C > 0),
    // we can choose its value to be very small (e.g., -0.001 or 0.001).
    // Then, no matter what other toys are, the final product can be made to have magnitude < 1.
    // For example, if we have a toy Y from Box 2 or Box 3, and other toys X1, X2, ..., Xk.
    // We can choose Y to be very close to 0 (e.g., 0.001).
    // We can choose all X_i to be large (e.g., 1000).
    // The product of all X_i will be large.
    // But Y * (product of X_i) can still be made < 1 in magnitude.
    // Example: 0.001 * 1000 * 1000 = 1000 (magnitude > 1). This logic is flawed.

    // Let's re-evaluate magnitude < 1.
    // If we have at least one toy from Box 2 or Box 3 (B > 0 or C > 0),
    // we can choose its value to be very close to 0 (e.g., 0.00001).
    // We can choose all other toys to be large (e.g., 1000).
    // The product of all toys will be (0.00001) * (1000)^(total_toys - 1).
    // This can be made < 1 if total_toys - 1 is small enough, or > 1 if total_toys - 1 is large.
    // Example: 0.00001 * 1000 = 0.01 (magnitude < 1).
    // Example: 0.00001 * 1000 * 1000 = 10 (magnitude > 1).

    // The crucial insight is that we can choose the values.
    // To get magnitude < 1, we need to be able to "dampen" the product.
    // This is possible if there is at least one toy from Box 2 or Box 3 (B > 0 or C > 0).
    // If B > 0 or C > 0, we can pick one such toy, say Y, and set its value very close to 0 (e.g., 0.0000001).
    // All other toys can be set to their maximum possible magnitude (e.g., -1000 or 1000).
    // The product of all other toys will be some large number P.
    // The final product will be Y * P.
    // We can always choose Y small enough such that |Y * P| < 1.
    // This strategy works unless all toys are from Box 1 or Box 4 (A > 0 or D > 0).
    // If all toys are from Box 1 or Box 4, then all initial magnitudes are >= 1.
    // The product of any number of toys with magnitude >= 1 will always have magnitude >= 1.
    // So, if B = 0 and C = 0, it's impossible to get a final toy with magnitude < 1.

    if (B == 0 && C == 0) { // All toys are from Box 1 or Box 4
        return false;
    }

    // If (A+B) is odd AND (B > 0 or C > 0), then Box 2 is possible.
    return true;
}

