bool is_permutation(const std::vector<int>& arr, int len) {
    if (len == 0) return true; // An empty sequence can be considered a permutation of length 0, though problem states non-zero lengths.
                               // For this problem, l1, l2 >= 1.
    if (len > arr.size()) return false; // Should not happen if called correctly

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (arr[i] <= 0 || arr[i] > len || seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    return max_val == len;
}

