        }
    }

    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_valid(n + 1, false); // suffix_valid[k] is true if a[n-k...n-1] is a permutation of length k
    std::vector<bool> seen_suffix(n + 1, false);
    current_max = 0;
    bool current_suffix_ok = true;
    for (int i = n - 1; i >= 0; --i) {
        int len = n - i;
        if (a[i] <= 0 || a[i] > len || seen_suffix[a[i]]) {
            current_suffix_ok = false;
        }
        seen_suffix[a[i]] = true;
        if (a[i] > current_max) {
            current_max = a[i];
        }
        suffix_max[i] = current_max;
        if (current_suffix_ok && current_max == len) {
            suffix_valid[len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 can be from 1 to n-1
        int l2 = n - l1;
        if (prefix_valid[l1] && suffix_valid[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

