#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        long long current_score = 0;
        int wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                wins++;
                if (i > 0 && s[i - 1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        if (wins == n) { // All games are already won
            std::cout << current_score << "\n";
            continue;
        }

        if (k == 0) { // No changes allowed
            std::cout << current_score << "\n";
            continue;
        }

        // If k > 0 and there are L's, we can potentially improve.
        // First, change L's to W's that are not part of any streak.
        // These are L's at the beginning or end, or L's between W's.
        // The most efficient way to use k is to fill gaps between W's.

        std::vector<int> gap_lengths;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        if (first_W == -1) { // All games are L
            if (k >= 1) {
                std::cout << 1 + (k - 1) * 2 << "\n"; // Change k L's to W's. First W is 1 point, subsequent k-1 W's are 2 points each.
            } else {
                std::cout << 0 << "\n";
            }
            continue;
        }

        // Calculate gaps between W's
        int current_gap = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gap_lengths.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gap_lengths.begin(), gap_lengths.end());

        for (int gap_len : gap_lengths) {
            if (k >= gap_len) {
                k -= gap_len;
                current_score += gap_len * 2 + 1; // Each L becomes W (2 points), plus 1 point for connecting the streak
                wins += gap_len;
            } else {
                current_score += k * 2; // Can't connect, but can make k L's into W's, each giving 2 points (as they extend a streak)
                wins += k;
                k = 0;
                break;
            }
        }

        // After filling internal gaps, if k is still available,
        // we can change L's at the beginning or end of the string.
        // These L's will extend existing W streaks, each giving 2 points.
        if (k > 0) {
            // L's before first_W
            int leading_L = first_W;
            long long changes_from_leading = std::min(k, (long long)leading_L);
            current_score += changes_from_leading * 2;
            wins += changes_from_leading;
            k -= changes_from_leading;

            if (k > 0) {
                // L's after last_W
                int trailing_L = n - 1 - last_W;
                long long changes_from_trailing = std::min(k, (long long)trailing_L);
                current_score += changes_from_trailing * 2;
                wins += changes_from_trailing;
                k -= changes_from_trailing;
            }
        }

        std::cout << current_score << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, Chanek takes 1
                    chanek_coins += 1;
                    n -= 1;
                } else { // N is even and N > 2
                    // Chanek has two choices: take 1 or take N/2
                    // If Chanek takes 1, opponent faces N-1 (odd). Opponent takes 1.
                    // If Chanek takes N/2, opponent faces N/2 (even or odd).
                    // The opponent will try to maximize their own coins.
                    // If N/2 is odd, opponent takes 1.
                    // If N/2 is even, opponent takes N/4.

                    // Consider taking N/2:
                    // Chanek gets N/2. Remaining N/2. Opponent's turn.
                    // Opponent will take 1 if N/2 is odd.
                    // Opponent will take N/4 if N/2 is even.
                    // In either case, opponent takes a smaller amount than N/2.
                    // This seems to be the greedy choice for Chanek.

                    // The only exception is when N/2 is odd, and N/2 - 1 is a power of 2.
                    // For example, N=6. Chanek takes 3. Remaining 3. Opponent takes 1. Chanek takes 1. Opponent takes 1.
                    // Chanek: 3+1=4. Opponent: 1+1=2.
                    // If Chanek takes 1. Remaining 5. Opponent takes 1. Remaining 4. Chanek takes 2. Remaining 2. Opponent takes 1. Remaining 1. Chanek takes 1.
                    // Chanek: 1+2+1=4. Opponent: 1+1=2.
                    // In this case, both lead to 4.

                    // The optimal strategy for Chanek when N is even and N > 2:
                    // If N/2 is odd, Chanek takes N/2.
                    // If N/2 is even, Chanek takes N/2.
                    // This is because taking N/2 leaves N/2 for the opponent.
                    // Taking 1 leaves N-1 for the opponent.
                    // If N-1 is odd, opponent takes 1.
                    // If N-1 is even, opponent takes (N-1)/2.
                    // Since N is even, N-1 is odd. So if Chanek takes 1, opponent takes 1.
                    // This means Chanek gets 1, and opponent gets 1.
                    // If Chanek takes N/2, Chanek gets N/2.
                    // N/2 is always greater than 1 for N > 2.
                    // So Chanek always takes N/2 if N is even and N > 2.

                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, opponent takes 1
                    n -= 1;
                } else { // N is even and N > 2
                    // Opponent also plays optimally to maximize their coins.
                    // Same logic as Chanek: take N/2.
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

