int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end());

        long long total_happiness = 0;
        int a_ptr_left = 0;
        int a_ptr_right = n - 1;

        // First, handle friends with w_i = 1.
        // These friends get 2 * largest available numbers.
        // Assign them the largest numbers from 'a'.
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] == 1) {
                total_happiness += 2 * a[a_ptr_right];
                a_ptr_right--;
            } else {
                // Since w is sorted, all remaining w[i] will be > 1.
                // Break and handle them in the next loop.
                break;
            }
        }

        // Now, handle friends with w_i > 1.
        // These friends get max_val + min_val.
        // To maximize sum, they should get the largest available max_val (from a_ptr_right)
        // and the smallest available min_val (from a_ptr_left).
        // The w_i - 2 intermediate numbers don't affect max/min.
        // Assign largest w_i to smallest available numbers to "consume" them.
        // The friends with larger w_i values will consume more of the smallest numbers.
        // The friends with smaller w_i values (but > 1) will consume fewer smallest numbers.
        // Since w is sorted ascending, w[0] is the smallest w_i > 1.
        // We iterate from the smallest w_i (which is w[0]) to the largest w_i (which is w[k-1] or the last one not equal to 1).
        // This ensures that friends who need to consume more numbers (larger w_i)
        // take from the smallest available numbers (a_ptr_left).
        for (int i = 0; i < k; ++i) {
            if (w[i] > 1) {
                total_happiness += a[a_ptr_right]; // Max value for this friend
                a_ptr_right--;
                total_happiness += a[a_ptr_left];   // Min value for this friend
                a_ptr_left += (w[i] - 1); // Consume w[i]-1 smallest numbers (including the one just used as min_val)
                                          // No, it's w[i]-1 numbers *after* the min_val.
                                          // So, a_ptr_left moves by w[i]-1 positions.
                                          // The min_val is a[a_ptr_left], then a_ptr_left moves to a_ptr_left + (w[i]-1).
                                          // The next available smallest number will be at a_ptr_left.
            }
        }

        std::cout << total_happiness << "\n";
    }
    return 0;
}

