int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long mod = 1000000007;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % mod;
        } else { // s[i] == 'a'
            // An 'a' at this position will combine with all 'b's to its right.
            // Each such 'ab' transformation results in 'bba'.
            // The 'a' effectively moves past the 'b's, and for each 'b' it passes,
            // it generates a new 'b'.
            // So, if there are 'k' 'b's to its right, this 'a' will cause 'k' steps.
            // After these 'k' steps, this 'a' is now to the right of all those 'k' 'b's,
            // and it has generated 'k' new 'b's.
            // These 'k' new 'b's are now available to interact with 'a's further to the left.
            // So, the number of 'b's available for 'a's to the left effectively doubles.
            total_steps = (total_steps + b_count) % mod;
            b_count = (b_count * 2) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // If s[i] is '0', then w[i-x] (if exists) and w[i+x] (if exists) must be '0'.
    // This is the only way to definitively set characters in w to '0'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce s.
    // For each s[i], check if it matches the rule based on our w.
    for (int i = 0; i < n; ++i) {
        bool s_i_should_be_1 = false;
        if (i - x >= 0 && w[i - x] == '1') {
            s_i_should_be_1 = true;
        }
        if (i + x < n && w[i + x] == '1') {
            s_i_should_be_1 = true;
        }

        if ((s[i] == '1' && !s_i_should_be_1) || (s[i] == '0' && s_i_should_be_1)) {
            // Mismatch: s[i] is '1' but our w implies '0', OR
            // s[i] is '0' but our w implies '1'.
            // The second case (s[i] is '0' but s_i_should_be_1) should not happen
            // if our logic for setting w is correct, because if s[i] was '0',
            // we explicitly set w[i-x] and w[i+x] to '0' if they exist.
            // So, this check primarily catches the first case: s[i] is '1' but
            // both w[i-x] and w[i+x] are '0' (meaning s_i_should_be_1 is false).
            std::cout << -1 << std::endl;
            return;
        }
    }

    std::cout << w << std::endl;
}

