void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, ... such that (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor_sum(b_i))
    // Let S' = current_sum + sum(b_i)
    // Let X' = current_xor_sum ^ xor_sum(b_i)
    // We need S' = 2 * X'

    // The problem statement guarantees a solution always exists by appending at most 3 elements.
    // A common strategy for these problems is to try to make the sum and XOR sum equal,
    // then double the XOR sum.
    // If current_sum == 2 * current_xor_sum, we need to append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // Strategy: Append two elements, X and S.
    // Let the two appended elements be b1 and b2.
    // New sum S' = current_sum + b1 + b2
    // New XOR sum X' = current_xor_sum ^ b1 ^ b2
    // We want S' = 2 * X'

    // Consider appending two elements: current_xor_sum and current_sum.
    // This doesn't quite work because current_sum can be very large.
    // The problem states that appended elements can be up to 10^18.

    // Let's try to append two elements such that the new XOR sum becomes current_xor_sum.
    // This means we need to append two identical elements, say Y.
    // Then new XOR sum X' = current_xor_sum ^ Y ^ Y = current_xor_sum.
    // New sum S' = current_sum + Y + Y = current_sum + 2Y.
    // We need S' = 2 * X'
    // current_sum + 2Y = 2 * current_xor_sum
    // 2Y = 2 * current_xor_sum - current_sum
    // Y = current_xor_sum - current_sum / 2
    // This requires (2 * current_xor_sum - current_sum) to be even and non-negative.
    // current_sum and current_xor_sum can be large, so Y can be large.
    // The condition S = 2X implies S is even.
    // We know that S - X is always even.
    // So current_sum - current_xor_sum is even.
    // 2 * current_xor_sum - current_sum = current_xor_sum - (current_sum - current_xor_sum).
    // This value is also even. So Y will be an integer.
    // However, Y could be negative. We need non-negative elements.
    // This strategy works if current_sum <= 2 * current_xor_sum.
    // If current_sum > 2 * current_xor_sum, then Y would be negative.

    // A simpler strategy that always works with 2 elements:
    // Let the current sum be S and current XOR sum be X.
    // We want to append two numbers, say A and B, such that:
    // (S + A + B) = 2 * (X ^ A ^ B)
    // Let's choose A = X.
    // Then the new XOR sum becomes X ^ X ^ B = B.
    // The new sum becomes S + X + B.
    // So we need S + X + B = 2 * B
    // S + X = B
    // So, if we append X and (S+X), the new array will be good.
    // Let's check:
    // New sum S' = S + X + (S+X) = 2S + 2X
    // New XOR sum X' = X ^ X ^ (S+X) = S+X
    // Is S' = 2 * X'?
    // 2S + 2X = 2 * (S+X)
    // Yes, this is true.
    // The elements to append are X and S+X.
    // Both X and S+X are non-negative since all initial elements are non-negative.
    // X is current_xor_sum. S is current_sum.
    // So we append current_xor_sum and (current_sum + current_xor_sum).
    // This uses 2 elements.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
}

