int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long correct_pairs = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        if (m == 0) continue; // Should not happen based on constraints (m_i >= 1)

        int prev_val;
        std::cin >> prev_val; // a_i1

        if (prev_val == 1) { // Check if the chain starts with 1
            correct_pairs++; // 1 is correctly placed as the start of the target chain
            for (int j = 1; j < m; ++j) {
                int current_val;
                std::cin >> current_val;
                if (current_val == prev_val + 1) {
                    correct_pairs++;
                } else {
                    // If a sequence 1 -> 2 -> ... -> X is broken,
                    // no further elements in this chain can extend the correct sequence from 1.
                    // We can stop checking this chain for correct pairs starting from 1.
                    // However, we still need to read the remaining elements of the chain.
                    for (int l = j + 1; l < m; ++l) {
                        std::cin >> current_val; // Just read to consume input
                    }
                    break; // Exit inner loop for this chain
                }
                prev_val = current_val;
            }
        } else {
            // If the chain does not start with 1, it cannot contribute to the 1 -> 2 -> ... -> n sequence
            // by having 1 -> 2 -> ... -> X.
            // We still need to read all elements of this chain.
            for (int j = 1; j < m; ++j) {
                int dummy;
                std::cin >> dummy;
            }
        }
    }

    // Total operations = (n - 1) (to form the final chain)
    //                  + (n - k) (to disassemble initial chains)
    //                  - 2 * (correct_pairs - 1) (savings for already correct 1->2->...->X sequence)
    //
    // (n - 1) is the number of 'put' operations needed for the final chain.
    // (n - k) is the number of 'get out' operations needed to flatten all initial chains.
    //
    // For each correct pair (i, i+1) that is part of the 1->2->...->X sequence:
    // - We save one 'get out' operation for 'i' from 'i+1'.
    // - We save one 'put' operation for 'i' into 'i+1'.
    // So, each correct pair saves 2 operations.
    //
    // The 'correct_pairs' count includes the '1' itself.
    // If correct_pairs = 1 (only '1' is present, not '1->2'), then 0 pairs are saved.
    // If correct_pairs = X (1->2->...->X), then X-1 actual nesting pairs are saved.
    // Each of these X-1 pairs saves 2 operations.
    // So, total savings = 2 * (correct_pairs - 1).
    //
    // Total time = (n - 1) + (n - k) - 2 * (correct_pairs - 1)
    //            = n - 1 + n - k - 2 * correct_pairs + 2
    //            = 2*n - k - 2*correct_pairs + 1

    long long result = (long long)(n - 1) + (n - k) - 2 * (correct_pairs - 1);

    std::cout << result << std::endl;

    return 0;
}

