        // Adjust to 0-based indexing
        --l; 
        // r is already 1-based end, so it's correct for prefix_counts[r]

        if (r - l < 3) { // Substring length is less than 3, no 3-char subsequences
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[r][0] - prefix_counts[l][0];
        int count_y = prefix_counts[r][1] - prefix_counts[l][1];
        int count_z = prefix_counts[r][2] - prefix_counts[l][2];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
