#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_pattern(k, '?'); // Stores the determined pattern for s[i % k]

    // Step 1: Propagate known characters and check for conflicts
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            if (fixed_pattern[i % k] == '?') {
                fixed_pattern[i % k] = s[i];
            } else if (fixed_pattern[i % k] != s[i]) {
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Count 0s and 1s in the fixed_pattern for the first k characters
    int count0 = 0;
    int count1 = 0;
    for (int i = 0; i < k; ++i) {
        if (fixed_pattern[i] == '0') {
            count0++;
        } else if (fixed_pattern[i] == '1') {
            count1++;
        }
    }

    // Step 3: Check if it's possible to satisfy the k/2 condition
    // We need k/2 zeros and k/2 ones in total for the first k characters.
    // We have 'count0' zeros and 'count1' ones.
    // The remaining 'k - count0 - count1' characters are '?'.
    // We need to assign 'k/2 - count0' zeros and 'k/2 - count1' ones to these '?'.
    // This is possible if:
    // 1. We don't need more zeros/ones than k/2 (i.e., count0 <= k/2 and count1 <= k/2).
    // 2. The number of '?' is sufficient to fill the remaining slots.
    //    (k - count0 - count1) >= (k/2 - count0) + (k/2 - count1)
    //    This simplifies to k - count0 - count1 >= k - count0 - count1, which is always true.
    // So, we only need to check if count0 and count1 do not exceed k/2.
    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    std::cout << "YES\n";
}

