long long solve() {
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        return 0;
    }
    if (n == 1) {
        return h[0];
    }

    std::vector<long long> L(n);
    L[0] = 1;
    for (int i = 1; i < n; ++i) {
        L[i] = std::min(h[i], L[i - 1] + 1);
    }

    std::vector<long long> R(n);
    R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        R[i] = std::min(h[i], R[i + 1] + 1);
    }

    long long max_min_lr = 0;
    for (int i = 0; i < n; ++i) {
        max_min_lr = std::max(max_min_lr, std::min(L[i], R[i]));
    }

    return max_min_lr;
}

