#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) {
        return 0;
    }
    long long MOD = 1000000007;
    long long n_mod = n % MOD;
    long long n_plus_1_mod = (n + 1) % MOD;

    // (n * (n + 1) / 2) % MOD
    // We need to handle division by 2.
    // Since MOD is prime (10^9 + 7), we can use modular multiplicative inverse.
    // The inverse of 2 modulo MOD is (MOD + 1) / 2.
    long long inv2 = (MOD + 1) / 2; // (1000000007 + 1) / 2 = 500000004

    long long term1 = n_mod;
    long long term2 = n_plus_1_mod;

    long long product = (term1 * term2) % MOD;
    long long result = (product * inv2) % MOD;

    return result;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // The sum is Sum_{k=1 to a} Sum_{r=1 to b-1} [r * (k * b + 1)]
    // This can be rewritten as:
    // Sum_{k=1 to a} [(k * b + 1) * Sum_{r=1 to b-1} r]

    // Calculate Sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r_part;
    if (b == 1) { // If b=1, then b-1=0, so sum_r_part is 0.
        sum_r_part = 0;
    } else {
        sum_r_part = sum_arithmetic_series(b - 1);
    }

    // Now we need to calculate Sum_{k=1 to a} [(k * b + 1) * sum_r_part]
    // This is sum_r_part * Sum_{k=1 to a} (k * b + 1)
    // Sum_{k=1 to a} (k * b + 1) = Sum_{k=1 to a} (k * b) + Sum_{k=1 to a} 1
    // = b * Sum_{k=1 to a} k + a
    // = b * (a * (a + 1) / 2) + a

    long long sum_k_b_plus_1_part;
    long long sum_k = sum_arithmetic_series(a); // a * (a + 1) / 2

    long long term1 = (b % MOD * sum_k) % MOD;
    long long term2 = a % MOD;
    sum_k_b_plus_1_part = (term1 + term2) % MOD;

    long long total_sum = (sum_r_part * sum_k_b_plus_1_part) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) {
        std::string colors(n, ' ');
        int last1 = -1; // Last digit colored 1
        int first2 = -1; // First digit colored 2

        bool possible_p = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                colors[i] = '1';
                if (d[i] < last1) { // Check non-decreasing for color 1
                    possible_p = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > p) {
                colors[i] = '2';
                if (first2 == -1) { // Initialize first2 if this is the first digit colored 2
                    first2 = d[i];
                }
                if (d[i] < first2) { // Check non-decreasing for color 2
                    possible_p = false;
                    break;
                }
                first2 = d[i]; // Update first2 to current digit for next comparison
            }
        }

        if (!possible_p) {
            continue;
        }

        // Now handle digits equal to p
        // Digits equal to p that appear before the first digit colored 2 (if any) must be 1.
        // Digits equal to p that appear after the last digit colored 1 (if any) must be 2.
        // This logic is simplified: we can assign '1' to all 'p's up to a certain point, then '2' to the rest.
        // The split point for 'p's is determined by the first 'p' that is greater than or equal to 'last1'
        // and less than or equal to 'first2'.

        int current_last1_for_p = last1;
        for (int i = 0; i < n; ++i) {
            if (d[i] == p) {
                if (d[i] >= current_last1_for_p) {
                    colors[i] = '1';
                    current_last1_for_p = d[i];
                } else {
                    // This 'p' cannot be colored '1' because it would violate non-decreasing for color 1.
                    // It must be colored '2'.
                    colors[i] = '2';
                }
            }
        }

        // After assigning '1's greedily to 'p's, check if '2's are valid.
        // The 'p's that were assigned '2' must maintain non-decreasing order among themselves
        // and with other '2's.
        // Also, the last '1' must be <= first '2'.

        int final_last1 = -1;
        int final_first2 = -1;
        bool final_check_ok = true;

        for (int i = 0; i < n; ++i) {
            if (colors[i] == '1') {
                if (d[i] < final_last1) {
                    final_check_ok = false;
                    break;
                }
                final_last1 = d[i];
            } else if (colors[i] == '2') {
                if (final_first2 == -1) {
                    final_first2 = d[i];
                }
                if (d[i] < final_first2) {
                    final_check_ok = false;
                    break;
                }
                final_first2 = d[i];
            }
        }

        if (!final_check_ok) {
            continue;
        }

        if (final_last1 != -1 && final_first2 != -1 && final_last1 > final_first2) {
            continue;
        }

        std::cout << colors << "\n";
        return;
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

