#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total possible substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // To maximize f(s), we need to minimize the number of substrings
        // consisting only of zeros. This is achieved by distributing the
        // zeros as evenly as possible among the m+1 potential blocks
        // created by the m ones.
        //
        // If we have m ones, they divide the string into m+1 segments
        // where zeros can be placed.
        // For example, _1_1_..._1_ (m ones, m+1 underscores for zero blocks)
        //
        // Let k be the number of zeros in each of the 'm+1' blocks.
        // We want to make these blocks as small as possible.
        //
        // The number of blocks of zeros is m+1.
        // The number of zeros is num_zeros.
        //
        // We distribute num_zeros among m+1 blocks.
        // Some blocks will have floor(num_zeros / (m+1)) zeros.
        // Some blocks will have ceil(num_zeros / (m+1)) zeros.
        //
        // Let q = num_zeros / (m+1) (integer division, floor)
        // Let r = num_zeros % (m+1)
        //
        // This means r blocks will have (q+1) zeros.
        // And (m+1 - r) blocks will have q zeros.
        //
        // The number of substrings consisting only of zeros from a block of size k is k*(k+1)/2.
        //
        // Calculate the sum of k*(k+1)/2 for all these blocks.

        long long q = num_zeros / (m + 1);
        long long r = num_zeros % (m + 1);

        long long substrings_from_zeros = 0;

        // r blocks of size (q+1)
        substrings_from_zeros += r * (q + 1) * (q + 2) / 2;

        // (m+1 - r) blocks of size q
        substrings_from_zeros += (m + 1 - r) * q * (q + 1) / 2;

        long long max_f_s = total_substrings - substrings_from_zeros;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // and suffix sums for the right side (jars n+1 to 2n)
    // A value of 1 means strawberry, -1 means blueberry.
    // We want the total sum of remaining jars to be 0.

    // Left side: jars 0 to n-1 (original 1 to n)
    // Right side: jars n to 2n-1 (original n+1 to 2n)

    // Map to store the minimum number of jars removed from the left side
    // to achieve a certain balance.
    // key: balance, value: number of jars removed (k_L)
    std::map<int, int> left_balance_to_removed_count;

    // Initial state: 0 jars removed from left, balance 0
    left_balance_to_removed_count[0] = 0;

    int current_balance_left = 0;
    for (int k_L = 1; k_L <= n; ++k_L) {
        // a[n - k_L] is the k_L-th jar from the left end of the left half
        // (i.e., jar n-k_L+1 in 1-indexed original array)
        // We are considering removing jars from 0 up to n-k_L-1.
        // The remaining jars on the left are from n-k_L to n-1.
        // This is not what we want. We want to remove k_L jars from the left.
        // So we remove jars 0, ..., k_L-1.
        // The balance of the *removed* jars is what we need.
        // Let's rephrase:
        // We are interested in the balance of the jars *remaining* on the left side.
        // If we remove k_L jars from the left (jars 0 to k_L-1),
        // the remaining jars on the left are from k_L to n-1.
        // This is also not quite right.
        // The problem states Karlsson removes jars from the left end (1 to k_L)
        // and from the right end (2n-k_R+1 to 2n).
        // The jars remaining are from k_L+1 to 2n-k_R.
        // The initial state is all jars from 1 to 2n.
        // The total balance of all 2n jars is what we need to consider.

        // Let's calculate the balance of the *entire* left half (jars 0 to n-1)
        // and the *entire* right half (jars n to 2n-1).
        // Then, if we remove k_L jars from the left (0 to k_L-1)
        // and k_R jars from the right (2n-k_R to 2n-1).
        // The remaining jars are from k_L to 2n-k_R-1.

        // Let's define balance as (count of 1s - count of 2s).
        // We want the final balance to be 0.

        // Calculate balance of the left half (jars 0 to n-1)
        // and store the balance of the *prefix* of the left half.
        // `left_balance_to_removed_count[bal]` stores the minimum `k_L`
        // such that the balance of jars `0` to `k_L-1` is `bal`.
        // This is for the jars that are *removed*.
        // No, this is for the jars that are *kept*.
        // Let's use `left_balance_to_removed_count[bal]` to store the minimum `k_L`
        // such that the balance of jars `k_L` to `n-1` is `bal`.
        // This means `k_L` jars are removed from the left.

        // Let's re-evaluate.
        // We want to find `k_L` and `k_R` such that
        // `sum(a[i] == 1 ? 1 : -1 for i from k_L to 2n-k_R-1) == 0`.
        // This is equivalent to `sum(a[i] == 1 ? 1 : -1 for i from 0 to 2n-1) -
        // sum(a[i] == 1 ? 1 : -1 for i from 0 to k_L-1) -
        // sum(a[i] == 1 ? 1 : -1 for i from 2n-k_R to 2n-1) == 0`.

        // Let `total_balance = sum(a[i] == 1 ? 1 : -1 for i from 0 to 2n-1)`.
        // Let `removed_left_balance[k_L] = sum(a[i] == 1 ? 1 : -1 for i from 0 to k_L-1)`.
        // Let `removed_right_balance[k_R] = sum(a[i] == 1 ? 1 : -1 for i from 2n-k_R to 2n-1)`.
        // We want `total_balance - removed_left_balance[k_L] - removed_right_balance[k_R] == 0`.
        // Or `removed_left_balance[k_L] + removed_right_balance[k_R] == total_balance`.

        // Calculate `removed_left_balance` for `k_L` from 0 to `n`.
        // `left_removed_bal[k_L]` stores the balance of the first `k_L` jars (0 to k_L-1).
        // `left_removed_bal_map[balance] = k_L` stores the minimum `k_L` for that balance.
        std::map<int, int> left_removed_bal_map;
        left_removed_bal_map[0] = 0; // 0 jars removed, balance 0
        int current_left_removed_bal = 0;
        for (int k_L = 1; k_L <= n; ++k_L) {
            current_left_removed_bal += (a[k_L - 1] == 1 ? 1 : -1);
            if (left_removed_bal_map.find(current_left_removed_bal) == left_removed_bal_map.end()) {
                left_removed_bal_map[current_left_removed_bal] = k_L;
            }
        }

        // Calculate `removed_right_balance` for `k_R` from 0 to `n`.
        // `right_removed_bal[k_R]` stores the balance of the last `k_R` jars (2n-k_R to 2n-1).
        // `right_removed_bal_map[balance] = k_R` stores the minimum `k_R` for that balance.
        std::map<int, int> right_removed_bal_map;
        right_removed_bal_map[0] = 0; // 0 jars removed, balance 0
        int current_right_removed_bal = 0;
        for (int k_R = 1; k_R <= n; ++k_R) {
            current_right_removed_bal += (a[2 * n - k_R] == 1 ? 1 : -1);
            if (right_removed_bal_map.find(current_right_removed_bal) == right_removed_bal_map.end()) {
                right_removed_bal_map[current_right_removed_bal] = k_R;
            }
        }

        // Calculate total balance of all 2n jars
        int total_balance = 0;
        for (int i = 0; i < 2 * n; ++i) {
            total_balance += (a[i] == 1 ? 1 : -1);
        }

        int min_removed_jars = 2 * n; // Max possible jars to remove

        // Iterate through all possible balances from removing jars from the left
        for (auto const& [left_bal, k_L] : left_removed_bal_map) {
            // We need `left_bal + right_bal == total_balance`
            // So, `right_bal = total_balance - left_bal`
            int required_right_bal = total_balance - left_bal;

            if (right_removed_bal_map.count(required_right_bal)) {
                int k_R = right_removed_bal_map[required_right_bal];
                min_removed_jars = std::min(min_removed_jars, k_L + k_R);
            }
        }

    std::cout << min_removed_jars << std::endl;
}

