#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a_suffix(n + 1); // a_suffix[0] is unused, a_suffix[1] is for initial i
    for (int i = 2; i <= n; ++i) {
        std::cin >> a_suffix[i];
    }

    std::vector<long long> dp_y(n + 1, 0);
    std::vector<int> dp_x(n + 1, 0);
    std::vector<bool> visited(n + 1, false);
    std::vector<bool> in_stack(n + 1, false);

    for (int i = n; i >= 2; --i) {
        long long current_a_val = a_suffix[i];
        long long next_x_after_step2 = i + current_a_val;

        if (next_x_after_step2 > n) {
            dp_y[i] = current_a_val;
            dp_x[i] = next_x_after_step2;
        } else {
            long long final_x_from_next_pos = next_x_after_step2 - a_suffix[next_x_after_step2];
            if (final_x_from_next_pos <= 0) {
                dp_y[i] = current_a_val + a_suffix[next_x_after_step2];
                dp_x[i] = final_x_from_next_pos;
            } else {
                if (dp_x[final_x_from_next_pos] == 0) { // Not computed yet, implies cycle or out of bounds
                    dp_y[i] = -1; // Mark as potentially part of a cycle
                    dp_x[i] = -1; // Mark as potentially part of a cycle
                } else if (dp_x[final_x_from_next_pos] == -1) { // Already known to be part of a cycle
                    dp_y[i] = -1;
                    dp_x[i] = -1;
                } else {
                    dp_y[i] = current_a_val + a_suffix[next_x_after_step2] + dp_y[final_x_from_next_pos];
                    dp_x[i] = dp_x[final_x_from_next_pos];
                }
            }
        }
    }

    for (int i = 1; i < n; ++i) {
        long long current_a_val = i; // a_1 is set to i
        long long next_x_after_step2 = 1 + current_a_val;

        if (next_x_after_step2 > n) {
            std::cout << current_a_val << "\n";
        } else {
            long long final_x_from_next_pos = next_x_after_step2 - a_suffix[next_x_after_step2];
            if (final_x_from_next_pos <= 0) {
                std::cout << current_a_val + a_suffix[next_x_after_step2] << "\n";
            } else {
                if (dp_x[final_x_from_next_pos] == -1) { // Known to be part of a cycle
                    std::cout << -1 << "\n";
                } else {
                    std::cout << current_a_val + a_suffix[next_x_after_step2] + dp_y[final_x_from_next_pos] << "\n";
                }
            }
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, 0);
    std::vector<long long> max_val_constraints(n, std::numeric_limits<long long>::max());

    // Process operations in reverse to find initial_a and max_val_constraints
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If it's an update, it means the initial values in this range
            // must have been smaller by d to satisfy future constraints.
            // So, we subtract d from the current initial_a values.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // If it's a query, it means the maximum in this range was m.
            // This implies that all elements in this range must be <= m.
            // We update the max_val_constraints for this range.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_constraints[j] = std::min(max_val_constraints[j], ops[i].val - initial_a[j]);
            }
        }
    }

    // Construct the candidate array 'b' based on initial_a and max_val_constraints
    std::vector<long long> b(n);
    for (int i = 0; i < n; ++i) {
        b[i] = max_val_constraints[i];
        if (b[i] == std::numeric_limits<long long>::max()) {
            b[i] = 0; // If no upper bound, set to 0 (or any value within range)
        }
    }

    // Verify the constructed array 'b'
    std::vector<long long> current_a = b;
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else { // ops[i].type == 2
            long long max_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_in_range = std::max(max_in_range, current_a[j]);
            }
            if (max_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

