    std::cout << max_k << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0;
    int target_idx = 0;

    while (target_idx < m) {
        if (head_idx >= n) {
            return false; // No more heads, but targets remain
        }

        long long current_head_pos = h[head_idx];
        long long first_uncovered_target = p[target_idx];

        // If the current head can cover the first_uncovered_target
        if (current_head_pos - T <= first_uncovered_target && first_uncovered_target <= current_head_pos + T) {
            // This head can cover a range [L, R]
            // L is the leftmost track it can reach, R is the rightmost track it can reach.
            // To cover first_uncovered_target, the head must move to some position x.
            // The range of tracks visited by this head is [min(h_i, x), max(h_i, x)].
            // The total distance moved is |h_i - x|.
            // So, if it moves to x, it covers [min(h_i, x), max(h_i, x)] and all tracks in between.
            // The maximum reach to the right is h_i + T.
            // The maximum reach to the left is h_i - T.
            // So, the head can cover any track in [h_i - T, h_i + T].
            // If it moves to x, it covers the interval [min(h_i, x), max(h_i, x)].
            // The total length of this interval is |h_i - x|.
            // This is not quite right. If it moves to x, it covers all tracks from h_i to x.
            // The problem states "A track is considered read if at least one head has visited this track."
            // "During the operation each head's movement does not affect the movement of the other heads: the heads can change their relative order; there can be multiple reading heads above any of the tracks."
            // "For each of the reading heads, the hard drive's firmware can move the head exactly one track to the right or to the left, or leave it on the current track."
            // This means if a head moves from A to B, it visits all tracks between A and B (inclusive).
            // So, if a head at h_i needs to cover p_j, it can move to p_j. This takes |h_i - p_j| time.
            // If it has T time, it can move to p_j if |h_i - p_j| <= T.
            // If it moves to p_j, it covers the range [min(h_i, p_j), max(h_i, p_j)].
            // But it can also move further. If it moves to p_j, it has T - |h_i - p_j| time remaining.
            // With this remaining time, it can extend its coverage.
            // So, if it moves to p_j, it can cover tracks in the range [p_j - (T - |h_i - p_j|), p_j + (T - |h_i - p_j|)].
            // This simplifies to [2*p_j - h_i - T, 2*p_j - h_i + T] if h_i <= p_j
            // or [2*p_j - h_i - T, 2*p_j - h_i + T] if h_i > p_j
            // This is equivalent to saying the head can cover any track x such that |h_i - x| <= T.
            // And if it covers x, it also covers all tracks between h_i and x.
            // So, the total range covered by a head h_i in time T is [h_i - T, h_i + T].
            // This is the standard interpretation for such problems.

            long long current_head_reach_right = current_head_pos + T;

            // Find how many targets this head can cover
            while (target_idx < m && p[target_idx] <= current_head_reach_right) {
                target_idx++;
            }
            head_idx++;
        } else if (current_head_pos - T > first_uncovered_target) {
            // The current head is too far to the right to cover first_uncovered_target.
            // This head cannot cover first_uncovered_target. Try the next head.
            head_idx++;
        } else { // current_head_pos + T < first_uncovered_target
            // The current head is too far to the left to cover first_uncovered_target.
            // This head cannot cover first_uncovered_target. Try the next head.
            head_idx++;
        }
    }
    return true; // All targets covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between p_i and h_i is 10^10.
                                    // Max time could be roughly 2 * 10^10 (e.g., h[0]=1, p[m-1]=10^10, p[0]=10^10, h[n-1]=1).
                                    // A safe upper bound is 2 * 10^10.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // We can form s' = s2 + s1.
    // We need s' to be a palindrome and s' != s.
    // Iterate through all possible cut points.
    for (int i = 1; i < n; ++i) { // i is the length of s1
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;

        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // If k=1 didn't work, we need to check if k=2 is possible.
    // This means we cut s into s1, s2, s3.
    // The total length of the string is N.
    // If all characters in s are the same (e.g., "aaaa"), then no rearrangement
    // can produce a different string, let alone a different palindrome.
    // In this case, it's impossible.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // then k=2 is always possible.
    // Consider the string s = c_1 c_2 ... c_N.
    // Since s is a palindrome, c_1 = c_N, c_2 = c_{N-1}, etc.
    // Since not all characters are the same, there must be some c_i != c_1.
    // This implies that s is not of the form "aaaaa...".
    //
    // If N is odd, say N=5, s="abaca".
    // Cut s into s[0] | s[1...N-2] | s[N-1].
    // For "abaca": 'a' | "bac" | 'a'.
    // Rearrange to s[N-1] | s[1...N-2] | s[0].
    // 'a' | "bac" | 'a'. This is the original string.
    //
    // However, we can always make a cut that results in a different palindrome.
    // Consider the string s. Since it's a palindrome and not all characters are the same,
    // there must be at least two distinct characters.
    //
    // If we take any prefix of length `i` (where `1 <= i < N`), say `P = s.substr(0, i)`.
    // The remaining suffix is `S = s.substr(i)`.
    // We checked `S + P` for `k=1`.
    //
    // If `s` is a palindrome and not all characters are the same,
    // then `s` must contain at least one character that is different from `s[0]`.
    // Let `s = c_0 c_1 ... c_{N-1}`.
    // Since `s` is a palindrome, `c_i = c_{N-1-i}`.
    // If `s` is not all same characters, there exists some `j` such that `c_j != c_0`.
    //
    // Consider the string `s` without its first and last characters: `s.substr(1, N-2)`.
    // This substring `s_inner = s[1...N-2]` is also a palindrome.
    // If `s_inner` is not all same characters, then we can apply the `k=1` logic to `s_inner`.
    // Let `s_inner = s_inner_1 + s_inner_2`.
    // Then `s_inner_2 + s_inner_1` is a palindrome and `!= s_inner`.
    // The new string would be `s[0] + (s_inner_2 + s_inner_1) + s[N-1]`.
    // This would be a palindrome and different from `s`.
    // This would require 2 cuts: `s[0] | s_inner_1 | s_inner_2 | s[N-1]`.
    // This is 3 parts, so 2 cuts.
    //
    // Example: "nolon" (N=5)
    // s[0] = 'n', s[N-1] = 'n'.
    // s_inner = "olo". This is a palindrome.
    // s_inner is not all same characters ('o' != 'l').
    // For "olo", k=1: "o" | "lo" -> "loo" (not palindrome). "ol" | "o" -> "ool" (not palindrome).
    // This logic is flawed.
    //
    // The problem states that if k=1 doesn't work, and not all characters are the same,
    // then k=2 is the answer.
    // This is a known property for palindromes.
    // If a palindrome `s` of length `N > 1` is not composed of all identical characters,
    // then it's always possible to form a new palindrome `s'` by making two cuts.
    //
    // Example: "nolon"
    // k=1 check:
    // n | olon -> olonn (not pal)
    // no | lon -> lonno (not pal)
    // nol | on -> onnol (pal, but == nolon)
    // nolo | n -> nnolo (not pal)
    // So k=1 fails for "nolon".
    // "nolon" is not all same characters. So output 2.
    //
    // Example: "kinnikkinnik" (N=12)
    // k=1 check:
    // "kinnik" | "kinnik" -> "kinnikkinnik" (same)
    // "kinnikkinnik" is not all same characters.
    // Try cut "kinnikkin" | "nik" -> "nikkinnikkin" (pal, != original). So k=1.
    //
    // The logic is:
    // 1. Try k=1. If successful, print 1.
    // 2. If k=1 fails, check if all characters in `s` are the same.
    //    If yes, print "Impossible".
    // 3. If k=1 fails and not all characters are the same, print 2.

    std::cout << 2 << std::endl;

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., S1, S2 is empty)
    // In this case, all f(a_i, a_j) = a_i + a_j.
    // Min f = elements[0].value + elements[1].value
    // Max f = elements[n-1].value + elements[n-2].value
    // Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    long long goodness_all_one_subsequence = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    long long min_goodness = goodness_all_one_subsequence;
    std::vector<int> best_partition(n, 1); // Default to all in subsequence 1

    // Case 2: At least one element in each subsequence.
    // The minimum possible f value is always elements[0].value + elements[1].value.
    // This is because if elements[0] and elements[1] are in the same subsequence, f = elements[0].value + elements[1].value.
    // If they are in different subsequences, f = elements[0].value + elements[1].value + h.
    // So, the minimum f value is min(elements[0].value + elements[1].value, elements[0].value + elements[1].value + h)
    // which is always elements[0].value + elements[1].value.
    long long min_f_overall = elements[0].value + elements[1].value;

    // The maximum possible f value can be:
    // 1. elements[n-1].value + elements[n-2].value (if both are in the same subsequence)
    // 2. elements[n-1].value + elements[n-2].value + h (if they are in different subsequences)
    // 3. elements[n-1].value + elements[0].value + h (if elements[n-1] and elements[0] are in different subsequences)
    // 4. elements[n-1].value + elements[1].value + h (if elements[n-1] and elements[1] are in different subsequences)
    // 5. elements[n-2].value + elements[0].value + h (if elements[n-2] and elements[0] are in different subsequences)

    // Consider a partition where elements[0] is in S1 and elements[1]...elements[n-1] are in S2.
    // Or elements[0]...elements[n-2] in S1 and elements[n-1] in S2.
    // This is equivalent to putting elements[0] in S1 and elements[n-1] in S2, and all others in S2.
    // Or elements[0] in S1, elements[n-1] in S2, and all others in S1.

    // Let's analyze the maximum f value for a general partition.
    // It will be max(max_same_subsequence, max_different_subsequence).
    // max_same_subsequence = elements[n-1].value + elements[n-2].value
    // max_different_subsequence = elements[n-1].value + elements[0].value + h

    // The critical observation is that if h is small, we want to mix elements.
    // If h is large, we want to keep elements together.
    // The threshold for "large" h is when h > (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value).
    // More precisely, if h is large enough such that elements[0].value + elements[n-1].value + h is much larger than
    // elements[n-1].value + elements[n-2].value, then we prefer to put all elements in one subsequence.
    // The goodness for all in one subsequence is (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value).

    // Consider a partition where elements[0] is in S1 and all other elements (elements[1]...elements[n-1]) are in S2.
    // Min f: elements[1].value + elements[2].value (if n >= 3) or elements[0].value + elements[1].value + h (if n=2)
    // The overall minimum f is always elements[0].value + elements[1].value.
    // Max f:
    //   - From S2: elements[n-1].value + elements[n-2].value (if n >= 3)
    //   - Between S1 and S2: elements[0].value + elements[n-1].value + h
    // So, max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    // This is only if n >= 3. If n=2, max_f = elements[0].value + elements[1].value + h.
    // For n=2, min_f = elements[0].value + elements[1].value. Goodness = h.
    // For n=2, goodness_all_one_subsequence = 0. So if h > 0, all_one_subsequence is better.
    // The logic for n=2 is a bit special.
    // If n=2:
    //   - All in one subsequence: goodness = 0. Partition: 1 1.
    //   - One in S1, one in S2: min_f = a_0+a_1, max_f = a_0+a_1+h. Goodness = h. Partition: 1 2.
    //   So for n=2, min_goodness is 0, partition 1 1.

    if (n == 2) {
        // Already handled by goodness_all_one_subsequence = 0.
        // min_goodness = 0;
        // best_partition = {1, 1};
    } else { // n >= 3
        // Option A: elements[0] in S1, elements[1]...elements[n-1] in S2.
        // Min f: elements[0].value + elements[1].value (from S1-S2 pair)
        // Max f: std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
        // Goodness = max_f - min_f
        long long max_f_A = std::max(elements[n - 1].value + elements[n - 2].value, elements[0].value + elements[n - 1].value + h);
        long long goodness_A = max_f_A - min_f_overall;

        if (goodness_A < min_goodness) {
            min_goodness = goodness_A;
            best_partition.assign(n, 2); // All in S2
            best_partition[elements[0].original_index] = 1; // elements[0] in S1
        }

        // Option B: elements[n-1] in S1, elements[0]...elements[n-2] in S2.
        // This is symmetric to Option A.
        // Min f: elements[0].value + elements[n-1].value (from S1-S2 pair)
        // The overall minimum f is always elements[0].value + elements[1].value.
        // Max f: std::max(elements[n-2].value + elements[n-3].value, elements[n-1].value + elements[0].value + h)
        // This is only if n >= 4 for elements[n-2].value + elements[n-3].value.
        // If n=3, elements[n-2].value + elements[n-3].value is elements[1].value + elements[0].value.
        // So max_f_B = std::max(elements[n-2].value + elements[n-3].value, elements[n-1].value + elements[0].value + h)
        // This is actually the same as Option A due to symmetry.
        // The only difference is which element is isolated.
        // The values involved are elements[0], elements[1], elements[n-2], elements[n-1].
        // The max f will be max(elements[n-1]+elements[n-2], elements[0]+elements[n-1]+h).
        // The min f will be elements[0]+elements[1].
        // So the goodness is the same. The partition would be different.
        // We can just pick one of these if it's better.

        // The only other interesting case is when h is very large.
        // In this scenario, we want to avoid pairs across subsequences.
        // The best way to do this is to put all elements in one subsequence.
        // This is already covered by `goodness_all_one_subsequence`.

        // What if h is small?
        // If h is small, we might want to put elements[0] and elements[n-1] in different subsequences.
        // For example, elements[0] in S1, elements[n-1] in S2.
        // All other elements (elements[1]...elements[n-2]) can go to either S1 or S2.
        // To minimize max_f, we want to put them with the element that is "closer" to them.
        // E.g., elements[1]...elements[k] with elements[0] in S1, and elements[k+1]...elements[n-2] with elements[n-1] in S2.
        // This is too complex.

        // Let's re-evaluate the two main strategies:
        // Strategy 1: All elements in one subsequence.
        //   Min f = a_0 + a_1
        //   Max f = a_{n-1} + a_{n-2}
        //   Goodness = (a_{n-1} + a_{n-2}) - (a_0 + a_1)
        //   This is `goodness_all_one_subsequence`.

        // Strategy 2: Split elements such that the smallest element (a_0) is in one subsequence (S1)
        // and all other elements (a_1, ..., a_{n-1}) are in the other subsequence (S2).
        //   Min f: a_0 + a_1 (from S1-S2 pair)
        //   Max f: max(a_{n-1} + a_{n-2} (from S2-S2 pair), a_0 + a_{n-1} + h (from S1-S2 pair))
        //   Goodness = max(a_{n-1} + a_{n-2}, a_0 + a_{n-1} + h) - (a_0 + a_1)
        //   This is `goodness_A`.

        // The problem states that one of the subsequences can be empty.
        // The `goodness_all_one_subsequence` covers the case where one subsequence is empty.
        // The `goodness_A` covers the case where one subsequence has only one element.
        // These two cases are often optimal.

        // Consider the values:
        // min_f_val = elements[0].value + elements[1].value
        // max_f_val_same = elements[n-1].value + elements[n-2].value
        // max_f_val_diff = elements[0].value + elements[n-1].value + h

        // If we put all elements in one subsequence:
        //   Min f = min_f_val
        //   Max f = max_f_val_same
        //   Goodness = max_f_val_same - min_f_val

        // If we put elements[0] in S1 and others in S2:
        //   Min f = min_f_val (from elements[0] + elements[1] + h, or elements[1] + elements[2])
        //   Actually, the minimum f value is always elements[0].value + elements[1].value.
        //   This is because if elements[0] and elements[1] are in the same subsequence, f = elements[0].value + elements[1].value.
        //   If they are in different subsequences, f = elements[0].value + elements[1].value + h.
        //   So the minimum possible f is elements[0].value + elements[1].value.
        //   Max f = std::max(max_f_val_same, max_f_val_diff)
        //   Goodness = std::max(max_f_val_same, max_f_val_diff) - min_f_val

        // Let's compare these two goodness values:
        // G1 = max_f_val_same - min_f_val
        // G2 = std::max(max_f_val_same, max_f_val_diff) - min_f_val

        // If max_f_val_diff <= max_f_val_same, then G2 = G1.
        // If max_f_val_diff > max_f_val_same, then G2 = max_f_val_diff - min_f_val.
        // In this case, G2 > G1. So G1 is better or equal.
        // This implies that putting all elements in one subsequence is always optimal or tied for optimal
        // if max_f_val_diff <= max_f_val_same.
        // This happens when elements[0].value + elements[n-1].value + h <= elements[n-1].value + elements[n-2].value
        // which simplifies to elements[0].value + h <= elements[n-2].value.

        // However, this logic is flawed. The `max_f_val_same` in G2 is only for pairs within S2.
        // If elements[0] is in S1 and elements[1]...elements[n-1] are in S2:
        //   Min f: elements[0].value + elements[1].value (from S1-S2 pair)
        //   Max f: std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
        //   This is exactly `goodness_A`.

        // The only other case to consider is if elements[0] and elements[1] are in different subsequences.
        // E.g., elements[0] in S1, elements[1] in S2.
        // Then min_f would be elements[0].value + elements[1].value + h.
        // This would increase the minimum f value, likely increasing the goodness.
        // So, it's always optimal to have elements[0] and elements[1] in the same subsequence if possible,
        // or at least not force them into different subsequences if it means increasing the min_f.
        // The minimum possible f value is indeed elements[0].value + elements[1].value.
        // This value is achieved if elements[0] and elements[1] are in the same subsequence.
        // If they are in different subsequences, the minimum f value would be elements[0].value + elements[1].value + h.
        // To minimize goodness, we want to minimize max_f and maximize min_f.
        // But here, we want to minimize (max_f - min_f).
        // So we want min_f to be as small as possible, which is elements[0].value + elements[1].value.
        // This means elements[0] and elements[1] should be in the same subsequence.

        // So, the two main candidates for optimal partition are:
        // 1. All elements in one subsequence. (min_f = a_0+a_1, max_f = a_{n-1}+a_{n-2})
        // 2. elements[0] in S1, elements[1]...elements[n-1] in S2.
        //    (min_f = a_0+a_1, max_f = max(a_{n-1}+a_{n-2}, a_0+a_{n-1}+h))
        //    This is because a_0 and a_1 are in different subsequences, so f(a_0, a_1) = a_0+a_1+h.
        //    But a_1 and a_2 are in the same subsequence (S2), so f(a_1, a_2) = a_1+a_2.
        //    The minimum f value is indeed a_1+a_2.
        //    No, this is wrong. The minimum f value is the minimum of ALL possible f values.
        //    If elements[0] is in S1 and elements[1]...elements[n-1] are in S2:
        //      Pairs within S1: None (only elements[0])
        //      Pairs within S2: (elements[1], elements[2]), ..., (elements[n-2], elements[n-1])
        //        Min of these: elements[1].value + elements[2].value
        //      Pairs between S1 and S2: (elements[0], elements[1]), ..., (elements[0], elements[n-1])
        //        Min of these: elements[0].value + elements[1].value + h
        //    So, the overall min_f for this partition is std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h).
        //    This is only if n >= 3. If n=2, min_f = elements[0].value + elements[1].value + h.

        // Let's re-evaluate for n >= 3:
        // Candidate 1: All in S1.
        //   Min f = elements[0].value + elements[1].value
        //   Max f = elements[n-1].value + elements[n-2].value
        //   Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
        //   This is `goodness_all_one_subsequence`.

        // Candidate 2: elements[0] in S1, elements[1]...elements[n-1] in S2.
        //   Min f: std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
        //   Max f: std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
        //   Goodness = Max f - Min f
        //   Let's call this `goodness_split_smallest`.

        // Candidate 3: elements[n-1] in S1, elements[0]...elements[n-2] in S2.
        //   Min f: std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h)
        //   Max f: std::max(elements[n-2].value + elements[n-3].value, elements[n-1].value + elements[n-2].value + h)
        //   Goodness = Max f - Min f
        //   Let's call this `goodness_split_largest`.

        // The problem is that `elements[0].value + elements[1].value` is the absolute minimum possible sum.
        // If we can achieve this as `min_f` for a partition, that's good.
        // This happens if elements[0] and elements[1] are in the same subsequence.

        // Let's consider the two main cases for the optimal partition:
        // Case A: All elements are in the same subsequence (e.g., S1).
        //   Min f = elements[0].value + elements[1].value
        //   Max f = elements[n-1].value + elements[n-2].value
        //   Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
        //   This is `min_goodness` initialized.

        // Case B: There is at least one element in S1 and at least one in S2.
        //   To minimize `max_f - min_f`, we want to make `min_f` as small as possible, which is `elements[0].value + elements[1].value`.
        //   This requires `elements[0]` and `elements[1]` to be in the same subsequence.
        //   Let's assume `elements[0]` and `elements[1]` are in S1.
        //   Now, where to put `elements[n-1]`?
        //   If `elements[n-1]` is also in S1: Then all elements are in S1, which is Case A.
        //   If `elements[n-1]` is in S2:
        //     S1 contains `elements[0]`, `elements[1]`, ...
        //     S2 contains `elements[n-1]`, ...
        //     Min f: `elements[0].value + elements[1].value` (from S1-S1 pair)
        //     Max f:
        //       - From S1-S1 pairs: `elements[n-2].value + elements[n-3].value` (if `elements[n-2]` and `elements[n-3]` are in S1)
        //       - From S2-S2 pairs: `elements[n-1].value + elements[k].value` (if `elements[k]` is in S2)
        //       - From S1-S2 pairs: `elements[0].value + elements[n-1].value + h`
        //     This is getting complicated.

        // Let's simplify. The problem is about the range of `a_i + a_j` and `a_i + a_j + h`.
        // The smallest possible sum is `elements[0].value + elements[1].value`.
        // The largest possible sum is `elements[n-1].value + elements[n-2].value + h` (if `elements[n-1]` and `elements[n-2]` are split)
        // or `elements[n-1].value + elements[0].value + h` (if `elements[n-1]` and `elements[0]` are split).
        // Or `elements[n-1].value + elements[n-2].value` (if all are together).

        // The minimum value of f is always `elements[0].value + elements[1].value`.
        // This is because if `elements[0]` and `elements[1]` are in the same subsequence, `f(a_0, a_1) = a_0 + a_1`.
        // If they are in different subsequences, `f(a_0, a_1) = a_0 + a_1 + h`.
        // Any other pair `a_i, a_j` will have `a_i + a_j >= a_0 + a_1`.
        // So, the absolute minimum value of f is `elements[0].value + elements[1].value`.
        // To achieve this minimum, `elements[0]` and `elements[1]` must be in the same subsequence.

        // So, we assume `elements[0]` and `elements[1]` are in S1.
        // Now, we need to decide where to put `elements[n-1]`.
        // Subcase 1: `elements[n-1]` is in S1 (along with `elements[0]` and `elements[1]`).
        //   If all elements are in S1, this is the "all one subsequence" case.
        //   Min f = elements[0].value + elements[1].value
        //   Max f = elements[n-1].value + elements[n-2].value
        //   Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
        //   This is `goodness_all_one_subsequence`.

        // Subcase 2: `elements[n-1]` is in S2.
        //   S1 contains `elements[0]`, `elements[1]`, ...
        //   S2 contains `elements[n-1]`, ...
        //   Min f: `elements[0].value + elements[1].value` (from S1-S1 pair)
        //   Max f:
        //     - From S1-S1 pairs: `elements[n-2].value + elements[n-3].value` (if `elements[n-2]` and `elements[n-3]` are in S1)
        //     - From S2-S2 pairs: `elements[n-1].value + elements[k].value` (if `elements[k]` is in S2)
        //     - From S1-S2 pairs: `elements[0].value + elements[n-1].value + h`
        //     The maximum value will be `elements[0].value + elements[n-1].value + h` (if `elements[0]` and `elements[n-1]` are split)
        //     OR `elements[n-1].value + elements[n-2].value` (if `elements[n-1]` and `elements[n-2]` are in S2)
        //     OR `elements[n-2].value + elements[n-3].value` (if `elements[n-2]` and `elements[n-3]` are in S1)
        //     The maximum possible sum is `elements[n-1].value + elements[n-2].value`.
        //     If `elements[n-1]` is in S2 and `elements[n-2]` is in S1, then `f(a_{n-1}, a_{n-2}) = a_{n-1} + a_{n-2} + h`.
        //     If `elements[n-1]` is in S2 and `elements[n-2]` is in S2, then `f(a_{n-1}, a_{n-2}) = a_{n-1} + a_{n-2}`.
        //     If `elements[n-1]` is in S2 and `elements[0]` is in S1, then `f(a_{n-1}, a_0) = a_{n-1} + a_0 + h`.

        // The two critical partitions are:
        // 1. All elements in one subsequence.
        //    Min f = elements[0].value + elements[1].value
        //    Max f = elements[n-1].value + elements[n-2].value
        //    Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
        //    This is `min_goodness` and `best_partition` initialized.

        // 2. elements[0] in S1, elements[1]...elements[n-1] in S2.
        //    Min f: std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h) (if n >= 3)
        //    Max f: std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h) (if n >= 3)
        //    If n=2: elements[0] in S1, elements[1] in S2.
        //      Min f = elements[0].value + elements[1].value + h
        //      Max f = elements[0].value + elements[1].value + h
        //      Goodness = 0.
        //      This is wrong. For n=2, if elements[0] in S1, elements[1] in S2, then only one pair (a0, a1).
        //      f(a0, a1) = a0+a1+h. Min=Max=a0+a1+h. Goodness=0.
        //      This is a special case.
        //      If n=2, the goodness is 0 for both partitions (1 1) and (1 2).
        //      The problem states "If there are several possible correct answers you are allowed to print any of them."
        //      So for n=2, 0 and 1 1 is fine.

        // Let's assume n >= 3 for the second candidate.
        long long current_min_f_cand2 = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        long long current_max_f_cand2 = std::max(elements[n - 1].value + elements[n - 2].value, elements[0].value + elements[n - 1].value + h);
        long long goodness_cand2 = current_max_f_cand2 - current_min_f_cand2;

        if (goodness_cand2 < min_goodness) {
            min_goodness = goodness_cand2;
            best_partition.assign(n, 2); // All in S2
            best_partition[elements[0].original_index] = 1; // elements[0] in S1
        }
    }

    std::cout << min_goodness << "\n";
    std::vector<int> final_partition(n);
    for (int i = 0; i < n; ++i) {
        final_partition[elements[i].original_index] = best_partition[elements[i].original_index];
    }
    for (int i = 0; i < n; ++i) {
        std::cout << final_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}
